-- Poems batch 454
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-21','嘉陵水','元稹','唐','御定全唐诗','yuding','','[]','爾是無心水，東流有恨無。我心無說處，也共爾何殊。',24,'御定全唐詩/json/410.json','["爾是無心水，東流有恨無。我心無說處，也共爾何殊。"]'),
('yuding-22','漫天嶺贈僧','元稹','唐','御定全唐诗','yuding','','[]','五上兩漫天，因師懺業緣。漫天無盡日，浮世有窮年。',24,'御定全唐詩/json/410.json','["五上兩漫天，因師懺業緣。漫天無盡日，浮世有窮年。"]'),
('yuding-23','百牢關','元稹','唐','御定全唐诗','yuding','','[]','天上無窮路，生期七十間。那堪九年內，五度百牢關。',24,'御定全唐詩/json/410.json','["天上無窮路，生期七十間。那堪九年內，五度百牢關。"]'),
('yuding-24','二月十九日酬王十八全素','元稹','唐','御定全唐诗','yuding','','[]','君念世上川，嗟予老瘴天。那堪十日內，又長白頭年。',24,'御定全唐詩/json/410.json','["君念世上川，嗟予老瘴天。那堪十日內，又長白頭年。"]'),
('yuding-25','滎陽鄭公以稹寓居嚴茅有池塘之勝寄詩四首因有意獻','元稹','唐','御定全唐诗','yuding','','[]','激射分流闊，灣環此地多。暫停隨梗浪，猶閱敗霜荷。',48,'御定全唐詩/json/410.json','["激射分流闊，灣環此地多。暫停隨梗浪，猶閱敗霜荷。", "恨阻還江勢，思深到海波。自傷才畎澮，其奈贈珠何。"]'),
('yuding-26','酬樂天寄蘄州簟','元稹','唐','御定全唐诗','yuding','','[]','蘄簟未經春，君先拭翠筠。知為熱時物，預與瘴中人。',72,'御定全唐詩/json/410.json','["蘄簟未經春，君先拭翠筠。知為熱時物，預與瘴中人。", "碾玉連心潤，編牙小片珍。霜凝青汗簡，冰透碧遊鱗。", "水魄輕涵黛，琉璃薄帶塵。夢成傷冷滑，驚臥老龍身。"]'),
('yuding-27','酬李浙西先因從事見寄之作','元稹','唐','御定全唐诗','yuding','','[]','近日金鑾直，親於漢珥貂。內人傳帝命，丞相讓吾僚。',48,'御定全唐詩/json/410.json','["近日金鑾直，親於漢珥貂。內人傳帝命，丞相讓吾僚。", "浙郡懸旌遠，長安諭日遙。因君蕊珠贈，還一夢煙霄。"]'),
('yuding-28','酬周從事望海亭見寄','元稹','唐','御定全唐诗','yuding','','[]','年老無流輩，行稀足薜蘿。熱時憐水近，高處見山多。',48,'御定全唐詩/json/410.json','["年老無流輩，行稀足薜蘿。熱時憐水近，高處見山多。", "衣袖長堪舞，喉嚨轉解歌。不辭狂複醉，人世有風波。"]'),
('yuding-29','代杭民答樂天','元稹','唐','御定全唐诗','yuding','','[]','翠幕籠斜日，朱衣儼別筵。管弦淒欲罷，城郭望依然。',48,'御定全唐詩/json/410.json','["翠幕籠斜日，朱衣儼別筵。管弦淒欲罷，城郭望依然。", "路溢新城市，農開舊廢田。春坊幸無事，何惜借三年。"]'),
('yuding-0','杏園','元稹','唐','御定全唐诗','yuding','','[]','浩浩長安車馬塵，狂風吹送每年春。',32,'御定全唐詩/json/411.json','["浩浩長安車馬塵，狂風吹送每年春。", "門前本是虛空界，何事栽花誤世人。"]'),
('yuding-1','菊花','元稹','唐','御定全唐诗','yuding','','[]','秋叢繞舍似陶家，遍繞籬邊日漸斜。',32,'御定全唐詩/json/411.json','["秋叢繞舍似陶家，遍繞籬邊日漸斜。", "不是花中偏愛菊，此花開盡更無花。"]'),
('yuding-2','酬哥舒大少府寄同年科第','元稹','唐','御定全唐诗','yuding','','[]','前年科第偏年少，未解知羞最愛狂。九陌爭馳好鞍馬，',40,'御定全唐詩/json/411.json','["前年科第偏年少，未解知羞最愛狂。九陌爭馳好鞍馬，", "賴得官閑且疏散，到君花下憶諸郎。"]'),
('yuding-3','幽棲','元稹','唐','御定全唐诗','yuding','','[]','野人自愛幽棲所，近對長松遠是山。盡日望雲心不系，',40,'御定全唐詩/json/411.json','["野人自愛幽棲所，近對長松遠是山。盡日望雲心不系，", "遼海若思千歲鶴，且留城市會飛還。"]'),
('yuding-4','清都春霽，寄胡三、吳十一','元稹','唐','御定全唐诗','yuding','','[]','蕊珠宮殿經微雨，草樹無塵耀眼光。白日當空天氣暖，',40,'御定全唐詩/json/411.json','["蕊珠宮殿經微雨，草樹無塵耀眼光。白日當空天氣暖，", "時節催年春不住，武陵花謝憶諸郎。"]'),
('yuding-5','華嶽寺','元稹','唐','御定全唐诗','yuding','','[]','山前古寺臨長道，來往淹留為愛山。雙燕營巢始西別，',40,'御定全唐詩/json/411.json','["山前古寺臨長道，來往淹留為愛山。雙燕營巢始西別，", "羞見竇師無外役，竹窗依舊老身閑。"]'),
('yuding-6','天壇上境','元稹','唐','御定全唐诗','yuding','','[]','野人性僻窮深僻，芸署官閑不似官。萬里洞中朝玉帝，',40,'御定全唐詩/json/411.json','["野人性僻窮深僻，芸署官閑不似官。萬里洞中朝玉帝，", "因為南昌檢仙籍，馬君家世奉還丹。"]'),
('yuding-7','尋西明寺僧不在','元稹','唐','御定全唐诗','yuding','','[]','春來日日到西林，飛錫經行不可尋。',32,'御定全唐詩/json/411.json','["春來日日到西林，飛錫經行不可尋。", "蓮池舊是無波水，莫逐狂風起浪心。"]'),
('yuding-8','與吳侍禦春遊','元稹','唐','御定全唐诗','yuding','','[]','蒼龍闕下陪驄馬，紫閣峰頭見白雲。',32,'御定全唐詩/json/411.json','["蒼龍闕下陪驄馬，紫閣峰頭見白雲。", "滿眼流光隨日度，今朝花落更紛紛。"]'),
('yuding-9','晚春','元稹','唐','御定全唐诗','yuding','','[]','晝靜簾疏燕語頻，雙雙鬥雀動階塵。',32,'御定全唐詩/json/411.json','["晝靜簾疏燕語頻，雙雙鬥雀動階塵。", "柴扉日暮隨風掩，落盡閑花不見人。"]'),
('yuding-10','先醉','元稹','唐','御定全唐诗','yuding','','[]','今日樽前敗飲名，三杯未盡不能傾。',32,'御定全唐詩/json/411.json','["今日樽前敗飲名，三杯未盡不能傾。", "怪來花下長先醉，半是春風蕩酒情。"]'),
('yuding-11','獨醉','元稹','唐','御定全唐诗','yuding','','[]','一樹芳菲也當春，漫隨車馬擁行塵。',32,'御定全唐詩/json/411.json','["一樹芳菲也當春，漫隨車馬擁行塵。", "桃花解笑鶯能語，自醉自眠那藉人。"]'),
('yuding-12','宿醉','元稹','唐','御定全唐诗','yuding','','[]','風引春心不自由，等閒沖席飲多籌。',32,'御定全唐詩/json/411.json','["風引春心不自由，等閒沖席飲多籌。", "朝來始向花前覺，度卻醒時一夜愁。"]'),
('yuding-13','懼醉','元稹','唐','御定全唐诗','yuding','','[]','聞道秋來怯夜寒，不辭泥水為杯盤。',32,'御定全唐詩/json/411.json','["聞道秋來怯夜寒，不辭泥水為杯盤。", "殷勤懼醉有深意，愁到醒時燈火闌。"]'),
('yuding-14','羨醉','元稹','唐','御定全唐诗','yuding','','[]','綺陌高樓競醉眠，共期憔悴不相憐。',32,'御定全唐詩/json/411.json','["綺陌高樓競醉眠，共期憔悴不相憐。", "也應自有尋春日，虛度而今正少年。"]'),
('yuding-15','憶醉','元稹','唐','御定全唐诗','yuding','','[]','自歎旅人行意速，每嫌杯酒緩歸期。',32,'御定全唐詩/json/411.json','["自歎旅人行意速，每嫌杯酒緩歸期。", "今朝偏遇醒時別，淚落風前憶醉時。"]'),
('yuding-16','病醉','元稹','唐','御定全唐诗','yuding','','[]','醉伴見儂因病酒，道儂無酒不相窺。',32,'御定全唐詩/json/411.json','["醉伴見儂因病酒，道儂無酒不相窺。", "那知下藥還沽底，人去人來剩一卮。"]'),
('yuding-17','《擬醉','元稹','唐','御定全唐诗','yuding','','[]','九月閑宵初向火，一尊清酒始行杯。',32,'御定全唐詩/json/411.json','["九月閑宵初向火，一尊清酒始行杯。", "憐君城外遙相憶，冒雨沖泥黑地來。"]'),
('yuding-18','勸醉','元稹','唐','御定全唐诗','yuding','','[]','竇家能釀銷愁酒，但是愁人便與銷。',32,'御定全唐詩/json/411.json','["竇家能釀銷愁酒，但是愁人便與銷。", "願我共君俱寂寞，只應連夜複連朝。"]'),
('yuding-19','任醉','元稹','唐','御定全唐诗','yuding','','[]','本怕酒醒渾不飲，因君相勸覺情來。',32,'御定全唐詩/json/411.json','["本怕酒醒渾不飲，因君相勸覺情來。", "殷勤滿酌從聽醉，乍可欲醒還一杯。"]'),
('yuding-20','同醉','元稹','唐','御定全唐诗','yuding','','[]','柏樹台中推事人，杏花壇上煉形真。',32,'御定全唐詩/json/411.json','["柏樹台中推事人，杏花壇上煉形真。", "心源一種閑如水，同醉櫻桃林下春。"]'),
('yuding-21','狂醉','元稹','唐','御定全唐诗','yuding','','[]','一自柏台為禦史，二年辜負兩京春。',32,'御定全唐詩/json/411.json','["一自柏台為禦史，二年辜負兩京春。", "峴亭今日顛狂醉，舞引紅娘亂打人。"]'),
('yuding-22','伴僧行','元稹','唐','御定全唐诗','yuding','','[]','春來求事百無成，因向愁中識道情。',32,'御定全唐詩/json/411.json','["春來求事百無成，因向愁中識道情。", "花滿杏園千萬樹，幾人能伴老僧行。"]'),
('yuding-23','古寺','元稹','唐','御定全唐诗','yuding','','[]','古寺春餘日半斜，竹風蕭爽勝人家。',32,'御定全唐詩/json/411.json','["古寺春餘日半斜，竹風蕭爽勝人家。", "花時不到有花院，意在尋僧不在花。"]'),
('yuding-24','定僧','元稹','唐','御定全唐诗','yuding','','[]','落魄閑行不著家，遍尋春寺賞年華。',32,'御定全唐詩/json/411.json','["落魄閑行不著家，遍尋春寺賞年華。", "野僧偶向花前定，滿樹狂風滿樹花。"]'),
('yuding-25','觀心處','元稹','唐','御定全唐诗','yuding','','[]','滿坐喧喧笑語頻，獨憐方丈了無塵。',32,'御定全唐詩/json/411.json','["滿坐喧喧笑語頻，獨憐方丈了無塵。", "燈前便是觀心處，要似觀心有幾人。"]'),
('yuding-26','智度師二首','元稹','唐','御定全唐诗','yuding','','[]','四十年前馬上飛，功名藏盡擁禪衣。',64,'御定全唐詩/json/411.json','["四十年前馬上飛，功名藏盡擁禪衣。", "石榴園下擒生處，獨自閑行獨自歸。", "三陷思明三突圍，鐵衣拋盡衲禪衣。", "天津橋上無人識，閑憑欄幹望落暉。"]'),
('yuding-27','西明寺牡丹','元稹','唐','御定全唐诗','yuding','','[]','花向琉璃地上生，光風炫轉紫雲英。',32,'御定全唐詩/json/411.json','["花向琉璃地上生，光風炫轉紫雲英。", "自從天女盤中見，直至今朝眼更明。"]'),
('yuding-28','憶楊十二','元稹','唐','御定全唐诗','yuding','','[]','去時芍藥才堪贈，看卻殘花已度春。',32,'御定全唐詩/json/411.json','["去時芍藥才堪贈，看卻殘花已度春。", "只為情深偏愴別，等閒相見莫相親。"]'),
('yuding-29','送複夢赴韋令幕','元稹','唐','御定全唐诗','yuding','','[]','世上於今重檢身，吾徒耽酒作狂人。',32,'御定全唐詩/json/411.json','["世上於今重檢身，吾徒耽酒作狂人。", "西曹舊事多持法，慎莫吐他丞相茵。"]'),
('yuding-30','送劉太白','元稹','唐','御定全唐诗','yuding','','[]','洛陽大底居人少，從善坊西最寂寥。',32,'御定全唐詩/json/411.json','["洛陽大底居人少，從善坊西最寂寥。", "想得劉君獨騎馬，古堤愁樹隔中橋。"]'),
('yuding-31','奉誠園','元稹','唐','御定全唐诗','yuding','','[]','蕭相深誠奉至尊，舊居求作奉誠園。',32,'御定全唐詩/json/411.json','["蕭相深誠奉至尊，舊居求作奉誠園。", "秋來古巷無人掃，樹滿空牆閉戟門。"]'),
('yuding-32','與太白同之東洛至櫟陽太白染疾駐行予九月二十五日至華嶽寺雪後望山','元稹','唐','御定全唐诗','yuding','','[]','共作洛陽千里伴，老劉因疾駐行軒。',32,'御定全唐詩/json/411.json','["共作洛陽千里伴，老劉因疾駐行軒。", "今朝獨自山前立，雪滿三峰倚寺門。"]'),
('yuding-33','野狐泉柳林','元稹','唐','御定全唐诗','yuding','','[]','去日野狐泉上柳，紫牙初綻拂眉低。',32,'御定全唐詩/json/411.json','["去日野狐泉上柳，紫牙初綻拂眉低。", "秋來寥落驚風雨，葉滿空林踏作泥。"]'),
('yuding-34','酬胡三憑人問牡丹','元稹','唐','御定全唐诗','yuding','','[]','竊見胡三問牡丹，為言依舊滿西欄。',32,'御定全唐詩/json/411.json','["竊見胡三問牡丹，為言依舊滿西欄。", "花時何處偏相憶，寥落衰紅雨後看。"]'),
('yuding-35','酬樂天秋興見贈本句云莫怪獨吟秋興苦比君校近二毛年','元稹','唐','御定全唐诗','yuding','','[]','勸君休作悲秋賦，白髮如星也任垂。',32,'御定全唐詩/json/411.json','["勸君休作悲秋賦，白髮如星也任垂。", "畢竟百年同是夢，長年何異少何為。"]'),
('yuding-0','雪後宿同軌店，上法護寺鐘樓望月','元稹','唐','御定全唐诗','yuding','','[]','滿山殘雪滿山風，野寺無門院院空。',32,'御定全唐詩/json/412.json','["滿山殘雪滿山風，野寺無門院院空。", "煙火漸稀孤店靜，月明深夜古樓中。"]'),
('yuding-1','陪韋尚書丈歸履信宅，因贈韋氏兄弟','元稹','唐','御定全唐诗','yuding','','[]','紫垣騶騎入華居，公子文衣護錦輿。',32,'御定全唐詩/json/412.json','["紫垣騶騎入華居，公子文衣護錦輿。", "眠閣書生複何事，也騎羸馬從尚書。"]'),
('yuding-2','永貞二年正月二日上御丹鳳樓赦天下予與李公垂庾順之閒行曲江不及盛觀','元稹','唐','御定全唐诗','yuding','','[]','春來饒夢慵朝起，不看千官擁禦樓。',32,'御定全唐詩/json/412.json','["春來饒夢慵朝起，不看千官擁禦樓。", "卻著閑行是忙事，數人同傍曲江頭。"]'),
('yuding-3','韋居守晚歲常言退休之志因署其居曰大隱洞命予賦詩因贈絕句','元稹','唐','御定全唐诗','yuding','','[]','謝公潛有東山意，已向朱門啟洞門。',32,'御定全唐詩/json/412.json','["謝公潛有東山意，已向朱門啟洞門。", "大隱猶疑戀朝市，不知名作罷歸園。"]'),
('yuding-4','贈李十二牡丹花片，因以餞行','元稹','唐','御定全唐诗','yuding','','[]','鶯澀餘聲絮墮風，牡丹花盡葉成叢。',32,'御定全唐詩/json/412.json','["鶯澀餘聲絮墮風，牡丹花盡葉成叢。", "可憐顏色經年別，收取朱闌一片紅。"]'),
('yuding-5','題李十一修行裏居壁','元稹','唐','御定全唐诗','yuding','','[]','雲闕朝回塵騎合，杏花春盡曲江閑。',32,'御定全唐詩/json/412.json','["雲闕朝回塵騎合，杏花春盡曲江閑。", "憐君雖在城中住，不隔人家便是山。"]'),
('yuding-6','靖安窮居','元稹','唐','御定全唐诗','yuding','','[]','喧靜不由居遠近，大都車馬就權門。',32,'御定全唐詩/json/412.json','["喧靜不由居遠近，大都車馬就權門。", "野人住處無名利，草滿空階樹滿園。"]'),
('yuding-7','贈樂天','元稹','唐','御定全唐诗','yuding','','[]','等閒相見銷長日，也有閒時更學琴。',32,'御定全唐詩/json/412.json','["等閒相見銷長日，也有閒時更學琴。", "不是眼前無外物，不關心事不經心。"]'),
('yuding-8','使東川：駱口驛二首','元稹','唐','御定全唐诗','yuding','','[]','郵亭壁上數行字，崔李題名王白詩。',64,'御定全唐詩/json/412.json','["郵亭壁上數行字，崔李題名王白詩。", "盡日無人共言語，不離牆下至行時。", "二星徼外通蠻服，五夜燈前草禦文。", "我到東川恰相半，向南看月北看雲。"]'),
('yuding-9','使東川：清明日','元稹','唐','御定全唐诗','yuding','','[]','常年寒食好風輕，觸處相隨取次行。',32,'御定全唐詩/json/412.json','["常年寒食好風輕，觸處相隨取次行。", "今日清明漢江上，一身騎馬縣官迎。"]'),
('yuding-10','使東川：亞枝紅','元稹','唐','御定全唐诗','yuding','','[]','平陽池上亞枝紅，悵望山郵事事同。',32,'御定全唐詩/json/412.json','["平陽池上亞枝紅，悵望山郵事事同。", "還向萬竿深竹裏，一枝渾臥碧流中。"]'),
('yuding-11','使東川：梁州夢','元稹','唐','御定全唐诗','yuding','','[]','夢君同繞曲江頭，也向慈恩院院遊。',32,'御定全唐詩/json/412.json','["夢君同繞曲江頭，也向慈恩院院遊。", "亭吏呼人排去馬，所驚身在古梁州。"]'),
('yuding-12','使東川：南秦雪','元稹','唐','御定全唐诗','yuding','','[]','帝城寒盡臨寒食，駱穀春深未有春。才見嶺頭雲似蓋，',40,'御定全唐詩/json/412.json','["帝城寒盡臨寒食，駱穀春深未有春。才見嶺頭雲似蓋，", "飛鳥不飛猿不動，青驄禦史上南秦。"]'),
('yuding-13','使東川：江樓月','元稹','唐','御定全唐诗','yuding','','[]','嘉陵江岸驛樓中，江在樓前月在空。月色滿床兼滿地，',40,'御定全唐詩/json/412.json','["嘉陵江岸驛樓中，江在樓前月在空。月色滿床兼滿地，", "萬一帝鄉還潔白，幾人潛傍杏園東。"]'),
('yuding-14','使東川：慚問囚','元稹','唐','御定全唐诗','yuding','','[]','司馬子微壇上頭，與君深結白雲儔。尚平村落擬連買，',40,'御定全唐詩/json/412.json','["司馬子微壇上頭，與君深結白雲儔。尚平村落擬連買，", "那知今日蜀門路，帶月夜行緣問囚。"]'),
('yuding-15','使東川：江上行','元稹','唐','御定全唐诗','yuding','','[]','悶見漢江流不息，悠悠漫漫竟何成。',32,'御定全唐詩/json/412.json','["悶見漢江流不息，悠悠漫漫竟何成。", "江流不語意相問，何事遠來江上行。"]'),
('yuding-16','使東川：漢江上笛','元稹','唐','御定全唐诗','yuding','','[]','小年為寫游梁賦，最說漢江聞笛愁。',32,'御定全唐詩/json/412.json','["小年為寫游梁賦，最說漢江聞笛愁。", "今夜聽時在何處，月明西縣驛南樓。"]'),
('yuding-17','使東川：郵亭月','元稹','唐','御定全唐诗','yuding','','[]','君多務實我多情，大抵偏嗔步月明。',32,'御定全唐詩/json/412.json','["君多務實我多情，大抵偏嗔步月明。", "今夜山郵與蠻嶂，君應堅臥我還行。"]'),
('yuding-18','使東川：嘉陵驛二首','元稹','唐','御定全唐诗','yuding','','[]','嘉陵驛上空床客，一夜嘉陵江水聲。',64,'御定全唐詩/json/412.json','["嘉陵驛上空床客，一夜嘉陵江水聲。", "仍對牆南滿山樹，野花撩亂月朧明。", "牆外花枝壓短牆，月明還照半張床。", "無人會得此時意，一夜獨眠西畔廊。"]'),
('yuding-19','使東川：百牢關','元稹','唐','御定全唐诗','yuding','','[]','嘉陵江上萬重山，何事臨江一破顏。',32,'御定全唐詩/json/412.json','["嘉陵江上萬重山，何事臨江一破顏。", "自笑只緣任敬仲，等閒身度百牢關。"]'),
('yuding-20','使東川：江花落','元稹','唐','御定全唐诗','yuding','','[]','日暮嘉陵江水東，梨花萬片逐江風。',32,'御定全唐詩/json/412.json','["日暮嘉陵江水東，梨花萬片逐江風。", "江花何處最腸斷，半落江流半在空。"]'),
('yuding-21','使東川：嘉陵江二首','元稹','唐','御定全唐诗','yuding','','[]','秦人惟識秦中水，長想吳江與蜀江。',64,'御定全唐詩/json/412.json','["秦人惟識秦中水，長想吳江與蜀江。", "今日嘉川驛樓下，可憐如練繞明窗。", "千里嘉陵江水聲，何年重繞此江行。", "只應添得清宵夢，時見滿江流月明。"]'),
('yuding-22','使東川：西縣驛','元稹','唐','御定全唐诗','yuding','','[]','去時樓上清明夜，月照樓前撩亂花。',32,'御定全唐詩/json/412.json','["去時樓上清明夜，月照樓前撩亂花。", "今日成陰複成子，可憐春盡未還家。"]'),
('yuding-23','使東川：望喜驛','元稹','唐','御定全唐诗','yuding','','[]','滿眼文書堆案邊，眼昏偷得暫時眠。',32,'御定全唐詩/json/412.json','["滿眼文書堆案邊，眼昏偷得暫時眠。", "子規驚覺燈又滅，一道月光橫枕前。"]'),
('yuding-24','使東川：好時節','元稹','唐','御定全唐诗','yuding','','[]','身騎驄馬峨眉下，面帶霜威卓氏前。',32,'御定全唐詩/json/412.json','["身騎驄馬峨眉下，面帶霜威卓氏前。", "虛度東川好時節，酒樓元被蜀兒眠。"]'),
('yuding-25','使東川：夜深行','元稹','唐','御定全唐诗','yuding','','[]','夜深猶自繞江行，震地江聲似鼓聲。',32,'御定全唐詩/json/412.json','["夜深猶自繞江行，震地江聲似鼓聲。", "漸見戍樓疑近驛，百牢關吏火前迎。"]'),
('yuding-26','使東川：望驛台','元稹','唐','御定全唐诗','yuding','','[]','可憐三月三旬足，悵望江邊望驛台。',32,'御定全唐詩/json/412.json','["可憐三月三旬足，悵望江邊望驛台。", "料得孟光今日語，不曾春盡不歸來。"]'),
('yuding-27','贈咸陽少府蕭郎','元稹','唐','御定全唐诗','yuding','','[]','莫怪逢君淚每盈，仲由多感有深情。陸家幼女托良婿，',40,'御定全唐詩/json/412.json','["莫怪逢君淚每盈，仲由多感有深情。陸家幼女托良婿，", "別時何處最腸斷，日暮渭陽驅馬行。"]'),
('yuding-28','贈呂三校書','元稹','唐','御定全唐诗','yuding','','[]','同年同拜校書郎，觸處潛行爛熳狂。共占花園爭趙辟，',40,'御定全唐詩/json/412.json','["同年同拜校書郎，觸處潛行爛熳狂。共占花園爭趙辟，", "語到欲明歡又泣，傍人相笑兩相傷。"]'),
('yuding-29','封書','元稹','唐','御定全唐诗','yuding','','[]','鶴台南望白雲關，城市猶存暫一還。',32,'御定全唐詩/json/412.json','["鶴台南望白雲關，城市猶存暫一還。", "書出步虛三百韻，蕊珠文字在人間。"]'),
('yuding-30','仁風李著作園醉後寄李十','元稹','唐','御定全唐诗','yuding','','[]','朧明春月照花枝，花下音聲是管兒。',32,'御定全唐詩/json/412.json','["朧明春月照花枝，花下音聲是管兒。", "卻笑西京李員外，五更騎馬趁朝時。"]'),
('yuding-31','燈影','元稹','唐','御定全唐诗','yuding','','[]','洛陽晝夜無車馬，漫掛紅紗滿樹頭。',32,'御定全唐詩/json/412.json','["洛陽晝夜無車馬，漫掛紅紗滿樹頭。", "見說平時燈影裏，玄宗潛伴太真遊。"]'),
('yuding-32','貶江陵途中寄樂天杓直杓直以員外郎判鹽鐵樂天以拾遺在翰林','元稹','唐','御定全唐诗','yuding','','[]','想到江陵無一事，酒杯書卷綴新文。紫芽嫩茗和枝采，',40,'御定全唐詩/json/412.json','["想到江陵無一事，酒杯書卷綴新文。紫芽嫩茗和枝采，", "算緡草詔終須解，不敢將心遠羨君。"]'),
('yuding-33','渡漢江','元稹','唐','御定全唐诗','yuding','','[]','嶓塚去年尋漾水，襄陽今日渡江濆。山遙遠樹才成點，',40,'御定全唐詩/json/412.json','["嶓塚去年尋漾水，襄陽今日渡江濆。山遙遠樹才成點，", "鯢鯨歸穴東溟溢，又作波濤隨伍員。"]'),
('yuding-34','哀病驄呈致用','元稹','唐','御定全唐诗','yuding','','[]','櫪上病驄啼褭褭，江邊廢宅路迢迢。自經梅雨長垂耳，',48,'御定全唐詩/json/412.json','["櫪上病驄啼褭褭，江邊廢宅路迢迢。自經梅雨長垂耳，", "曾聽禁漏驚衙鼓，慣蹋康衢怕小橋。半夜雄嘶心不死，"]'),
('yuding-35','送嶺南崔侍禦','元稹','唐','御定全唐诗','yuding','','[]','我是北人長北望，每嗟南雁更南飛。君今又作嶺南別，',88,'御定全唐詩/json/412.json','["我是北人長北望，每嗟南雁更南飛。君今又作嶺南別，", "黃家賊用鑹刀利，白水郎行旱地稀。蜃吐朝光樓隱隱，", "火布垢塵須火浣，木綿溫軟當綿衣。桄榔面磣檳榔澀，", "此中無限相憂事，請為殷勤事事依。"]'),
('yuding-36','酬樂天八月十五夜禁中獨直玩月見寄','元稹','唐','御定全唐诗','yuding','','[]','一年秋半月偏深，況就煙霄極賞心。金鳳台前波漾漾，',40,'御定全唐詩/json/412.json','["一年秋半月偏深，況就煙霄極賞心。金鳳台前波漾漾，", "何意枚皋正承詔，瞥然塵念到江陰。"]'),
('yuding-37','予病瘴樂天寄通中散碧腴垂雲膏仍題四韻以慰遠懷開坼之間因有酬答','元稹','唐','御定全唐诗','yuding','','[]','紫河變煉紅霞散，翠液煎研碧玉英。金籍真人天上合，',40,'御定全唐詩/json/412.json','["紫河變煉紅霞散，翠液煎研碧玉英。金籍真人天上合，", "唯有思君治不得，膏銷雪盡意還生。"]'),
('yuding-0','陪諸公遊故江西韋大夫通德湖舊居有感題四韻兼呈李六侍御即韋大夫舊寮也','元稹','唐','御定全唐诗','yuding','','[]','高墉行馬接通湖，巨壑藏舟感大夫。塵壁暗埋悲舊劄，',40,'御定全唐詩/json/413.json','["高墉行馬接通湖，巨壑藏舟感大夫。塵壁暗埋悲舊劄，", "唯有滿園桃李下，膺門偏拜阮元瑜。"]'),
('yuding-1','送友封二首','元稹','唐','御定全唐诗','yuding','','[]','桃葉成陰燕引雛，南風吹浪颭檣烏。瘴雲拂地黃梅雨，',80,'御定全唐詩/json/413.json','["桃葉成陰燕引雛，南風吹浪颭檣烏。瘴雲拂地黃梅雨，", "知君兄弟憐詩句，遍為姑將惱大巫。", "惠和坊裏當時別，豈料江陵送上船。鵬翼張風期萬里，", "若見中丞忽相問，為言腰折氣沖天。"]'),
('yuding-2','放言五首','元稹','唐','御定全唐诗','yuding','','[]','近來逢酒便高歌，醉舞詩狂漸欲魔。五鬥解酲猶恨少，',224,'御定全唐詩/json/413.json','["近來逢酒便高歌，醉舞詩狂漸欲魔。五鬥解酲猶恨少，", "死是等閒生也得，擬將何事奈吾何。", "莫將心事厭長沙，雲到何方不是家。酒熟餔糟學漁父。", "飯來開口似神鴉。竹枝待鳳千莖直，柳樹迎風一向斜。", "總被天公沾雨露，等頭成長盡生涯。", "霆轟電烻數聲頻，不奈狂夫不藉身。縱使被雷燒作燼，", "必若乖龍在諸處，何須驚動自來人。", "安得心源處處安，何勞終日望林巒。玉英惟向火中冷，", "孫登不語啟期樂，各自當情各自歡。", "三十年來世上行，也曾狂走趁浮名。兩回左降須知命，", "他時定葬燒缸地，賣與人家得酒盛。"]'),
('yuding-3','劉二十八以文石枕見贈仍題絕句以將厚意因持壁州鞭酬謝兼廣為四韻','元稹','唐','御定全唐诗','yuding','','[]','枕截文瓊珠綴篇，野人酬贈壁州鞭。用長時節君須策，',40,'御定全唐詩/json/413.json','["枕截文瓊珠綴篇，野人酬贈壁州鞭。用長時節君須策，", "張騫卻上知何日，隨會歸期在此年。"]'),
('yuding-4','奉和嚴司空重陽日同崔常侍崔郎中及諸公登龍山落帽臺佳宴','元稹','唐','御定全唐诗','yuding','','[]','謝公愁思眇天涯，蠟屐登高為菊花。貴重近臣光綺席，',40,'御定全唐詩/json/413.json','["謝公愁思眇天涯，蠟屐登高為菊花。貴重近臣光綺席，", "詠碎龍山歸去號，馬奔流電妓奔車。"]'),
('yuding-5','送王十一郎遊剡中','元稹','唐','御定全唐诗','yuding','','[]','越州都在浙河灣，塵土消沉景象閑。百里油盆鏡湖水，',40,'御定全唐詩/json/413.json','["越州都在浙河灣，塵土消沉景象閑。百里油盆鏡湖水，", "想得玉郎乘畫舸，幾回明月墜雲間。"]'),
('yuding-6','送友封','元稹','唐','御定全唐诗','yuding','','[]','輕風略略柳欣欣，晴色空蒙遠似塵。斗柄未回猶帶閏，',40,'御定全唐詩/json/413.json','["輕風略略柳欣欣，晴色空蒙遠似塵。斗柄未回猶帶閏，", "心斷洛陽三兩處，窈娘堤抱古天津。"]'),
('yuding-7','送致用','元稹','唐','御定全唐诗','yuding','','[]','淚沾雙袖血成文，不為悲身為別君。望鶴眼穿期海外，',40,'御定全唐詩/json/413.json','["淚沾雙袖血成文，不為悲身為別君。望鶴眼穿期海外，", "欲識九回腸斷處，潯陽流水逐條分。"]'),
('yuding-8','早春登龍山靜勝寺時非休浣司空特許是行因贈幕中諸公','元稹','唐','御定全唐诗','yuding','','[]','謝傅知憐景氣新，許尋高寺望江春。龍文遠水吞平岸，',40,'御定全唐詩/json/413.json','["謝傅知憐景氣新，許尋高寺望江春。龍文遠水吞平岸，", "歸來笑問諸從事，占得閒行有幾人。"]'),
('yuding-9','書樂天紙','元稹','唐','御定全唐诗','yuding','','[]','金鑾殿裏書殘紙，乞與荊州元判司。',32,'御定全唐詩/json/413.json','["金鑾殿裏書殘紙，乞與荊州元判司。", "不忍拈將等閒用，半封京信半題詩。"]'),
('yuding-10','酬孝甫見贈十首','元稹','唐','御定全唐诗','yuding','','[]','宋玉秋來續楚詞，陰鏗官漫足閑詩。',320,'御定全唐詩/json/413.json','["宋玉秋來續楚詞，陰鏗官漫足閑詩。", "親情書劄相安慰，多道蕭何作判司。", "杜甫天材頗絕倫，每尋詩卷似情親。", "憐渠直道當時語，不著心源傍古人。", "十歲荒狂任博徒，挼莎五木擲梟盧。", "野詩良輔偏憐假，長借金鞍迓酒胡。", "曾經綽立侍丹墀，綻蕊宮花拂面枝。", "雉尾扇開朝日出，柘黃衫對碧霄垂。", "一自低心翰墨場，箭靫拋盡負書囊。", "近來兼愛休糧藥，柏葉紗羅雜豆黃。", "莫笑風塵滿病顏，此生元在有無間。", "卷舒蓮葉終難濕，去住雲心一種閑。", "無事拋棋侵虎口，幾時開眼複聯行。", "終須殺盡緣邊敵，四面通同掩大荒。", "原憲甘貧每自開，子春傷足少人哀。", "巷南唯有陳居士，時學文殊一問來。", "每識閒人如未識，與君相識更相憐。", "經旬不解來過宿，忍見空床夜夜眠。", "開坼新詩展大璆，明珠炫轉玉音浮。", "酬君十首三更坐，減卻常時半夜愁。"]'),
('yuding-11','和樂天招錢蔚章看山絕句','元稹','唐','御定全唐诗','yuding','','[]','碧落招邀閑曠望，黃金城外玉方壺。',32,'御定全唐詩/json/413.json','["碧落招邀閑曠望，黃金城外玉方壺。", "人間還有大江海，萬里煙波天上無。"]'),
('yuding-12','折枝花贈行','元稹','唐','御定全唐诗','yuding','','[]','櫻桃花下送君時，一寸春心逐折枝。',32,'御定全唐詩/json/413.json','["櫻桃花下送君時，一寸春心逐折枝。", "別後相思最多處，千株萬片繞林垂。"]'),
('yuding-13','寄劉頗二首','元稹','唐','御定全唐诗','yuding','','[]','平生嗜酒顛狂甚，不許諸公占丈夫。',64,'御定全唐詩/json/413.json','["平生嗜酒顛狂甚，不許諸公占丈夫。", "唯愛劉君一片膽，近來還敢似人無。", "前年碣石煙塵起，共看官軍過洛城。", "無限公卿因戰得，與君依舊綠衫行。"]'),
('yuding-14','晨起送使，病不行，因過王十一館居二首','元稹','唐','御定全唐诗','yuding','','[]','自笑今朝誤夙興，逢他禦史瘧相仍。',64,'御定全唐詩/json/413.json','["自笑今朝誤夙興，逢他禦史瘧相仍。", "過君未起房門掩，深映寒窗一盞燈。", "密宇深房小火爐，飯香魚熟近中廚。", "野人愛靜仍耽寢，自問黃昏肯去無。"]'),
('yuding-15','送孫勝','元稹','唐','御定全唐诗','yuding','','[]','桐花暗澹柳惺憁，池帶輕波柳帶風。',32,'御定全唐詩/json/413.json','["桐花暗澹柳惺憁，池帶輕波柳帶風。", "今日與君臨水別，可憐春盡宋亭中。"]'),
('yuding-16','遊三寺回呈上府主嚴司空時因尋寺道出當陽縣奉命覆視縣囚牽於游行不暇詳究故以詩自誚爾','元稹','唐','御定全唐诗','yuding','','[]','謝公恣縱顛狂掾，觸處閑行許自由。舉板支頤對山色，',40,'御定全唐詩/json/413.json','["謝公恣縱顛狂掾，觸處閑行許自由。舉板支頤對山色，", "莫責尋常吐茵吏，書囊赤白報君侯。"]'),
('yuding-17','遠望','元稹','唐','御定全唐诗','yuding','','[]','滿眼傷心冬景和，一山紅樹寺邊多。',32,'御定全唐詩/json/413.json','["滿眼傷心冬景和，一山紅樹寺邊多。", "仲宣無限思鄉淚，漳水東流碧玉波。"]'),
('yuding-18','早春尋李校書','元稹','唐','御定全唐诗','yuding','','[]','款款春風澹澹雲，柳枝低作翠櫳裙。梅含雞舌兼紅氣，',40,'御定全唐詩/json/413.json','["款款春風澹澹雲，柳枝低作翠櫳裙。梅含雞舌兼紅氣，", "今朝何事偏相覓，撩亂芳情最是君。"]'),
('yuding-19','過襄陽樓呈上府主嚴司空樓在江陵節度使宅北隅','元稹','唐','御定全唐诗','yuding','','[]','襄陽樓下樹陰成，荷葉如錢水面平。拂水柳花千萬點，',40,'御定全唐詩/json/413.json','["襄陽樓下樹陰成，荷葉如錢水面平。拂水柳花千萬點，", "早晚暫教王粲上，庾公應待月分明。"]'),
('yuding-20','八月六日與僧如展前松滋主簿韋戴同遊碧澗寺賦得扉字韻寺臨蜀江內有碧澗穿注兩廊又有龍女洞能興雲雨詩中噴字以平聲韻','元稹','唐','御定全唐诗','yuding','','[]','空闊長江礙鐵圍，高低行樹倚岩扉。穿廊玉澗噴紅旭，',40,'御定全唐詩/json/413.json','["空闊長江礙鐵圍，高低行樹倚岩扉。穿廊玉澗噴紅旭，", "他生莫忘靈山別，滿壁人名後會稀。"]'),
('yuding-21','奉和竇容州','元稹','唐','御定全唐诗','yuding','','[]','明公莫訝容州遠，一路瀟湘景氣濃。斑竹初成二妃廟，',40,'御定全唐詩/json/413.json','["明公莫訝容州遠，一路瀟湘景氣濃。斑竹初成二妃廟，", "自歎風波去無極，不知何日又相逢。"]'),
('yuding-22','盧頭陀詩','元稹','唐','御定全唐诗','yuding','','[]','盧師深話出家由，剃盡心花始剃頭。馬哭青山別車匿，',40,'御定全唐詩/json/413.json','["盧師深話出家由，剃盡心花始剃頭。馬哭青山別車匿，", "為向八龍兄弟說，他生緣會此生休。"]'),
('yuding-23','醉別盧頭陀','元稹','唐','御定全唐诗','yuding','','[]','醉迷狂象別吾師，夢覺觀空始自悲。盡日笙歌人散後，',40,'御定全唐詩/json/413.json','["醉迷狂象別吾師，夢覺觀空始自悲。盡日笙歌人散後，", "頓見佛光身上出，已蒙衣內綴摩尼。"]'),
('yuding-0','陪張湖南宴望岳樓，稹為監察禦史張中丞知雜事','元稹','唐','御定全唐诗','yuding','','[]','觀象樓前奉末班，絳峰只似殿庭間。',32,'御定全唐詩/json/414.json','["觀象樓前奉末班，絳峰只似殿庭間。", "今日高樓重陪宴，雨籠衡岳是南山。"]'),
('yuding-1','岳陽樓','元稹','唐','御定全唐诗','yuding','','[]','岳陽樓上日銜窗，影到深潭赤玉幢。',32,'御定全唐詩/json/414.json','["岳陽樓上日銜窗，影到深潭赤玉幢。", "悵望殘春萬般意，滿欞湖水入西江。"]'),
('yuding-2','寄庾敬休','元稹','唐','御定全唐诗','yuding','','[]','小來同在曲江頭，不省春時不共遊。',32,'御定全唐詩/json/414.json','["小來同在曲江頭，不省春時不共遊。", "今日江風好暄暖，可憐春盡古湘州。"]'),
('yuding-3','花栽二首','元稹','唐','御定全唐诗','yuding','','[]','買得山花一兩栽，離鄉別土易摧頹。',64,'御定全唐詩/json/414.json','["買得山花一兩栽，離鄉別土易摧頹。", "欲知北客居南意，看取南花北地來。", "南花北地種應難，且向船中盡日看。", "縱使將來眼前死，猶勝拋擲在空欄。"]'),
('yuding-4','宿石磯','元稹','唐','御定全唐诗','yuding','','[]','石磯江水夜潺湲，半夜江風引杜鵑。',32,'御定全唐詩/json/414.json','["石磯江水夜潺湲，半夜江風引杜鵑。", "燈暗酒醒顛倒枕，五更斜月入空船。"]'),
('yuding-5','遭風二十韻','元稹','唐','御定全唐诗','yuding','','[]','洞庭彌漫接天回，一點君山似措杯。暝色已籠秋竹樹，',169,'御定全唐詩/json/414.json','["洞庭彌漫接天回，一點君山似措杯。暝色已籠秋竹樹，", "後侶逢灘方拽zB，前宗到浦已眠桅。俄驚四面雲屏合，", "勝淩豈但河宮溢，坱軋渾憂地軸摧。疑是陰兵致昏黑，", "水客暗遊燒野火，楓人夜長吼春雷。浸淫沙市兒童亂，", "檣烏鬥折頭倉掉，水狗斜傾尾纜開。在昔詎慚橫海志，", "閉目唯愁滿空電，冥心真類不然灰。那知否極休征至，", "紫衣將校臨船問，白馬君侯傍柳來。喚上驛亭還酩酊，"]'),
('yuding-6','贈崔元儒','元稹','唐','御定全唐诗','yuding','','[]','殷勤夏口阮元瑜，二十年前舊飲徒。最愛輕欺杏園客，',40,'御定全唐詩/json/414.json','["殷勤夏口阮元瑜，二十年前舊飲徒。最愛輕欺杏園客，", "今日頭盤三兩擲，翠娥潛笑白髭須。"]'),
('yuding-7','鄂州寓館嚴澗宅','元稹','唐','御定全唐诗','yuding','','[]','鳳有高梧鶴有松，偶來江外寄行蹤。花枝滿院空啼鳥，',40,'御定全唐詩/json/414.json','["鳳有高梧鶴有松，偶來江外寄行蹤。花枝滿院空啼鳥，", "何時最是思君處，月入斜窗曉寺鐘。"]'),
('yuding-8','送杜元穎','元稹','唐','御定全唐诗','yuding','','[]','江上五年同送客，與君長羨北歸人。',32,'御定全唐詩/json/414.json','["江上五年同送客，與君長羨北歸人。", "今朝又送君先去，千里洛陽城裏塵。"]'),
('yuding-9','貽蜀五首：病馬詩寄上李尚書','元稹','唐','御定全唐诗','yuding','','[]','萬里長鳴望蜀門，病身猶帶舊瘡痕。遙看雲路心空在，',40,'御定全唐詩/json/414.json','["萬里長鳴望蜀門，病身猶帶舊瘡痕。遙看雲路心空在，", "唯應夜識深山道，忽遇君侯一報恩。"]'),
('yuding-10','貽蜀五首：李中丞表臣','元稹','唐','御定全唐诗','yuding','','[]','韋門同是舊親賓，獨恨潘床簟有塵。十裏花溪錦城麗，',40,'御定全唐詩/json/414.json','["韋門同是舊親賓，獨恨潘床簟有塵。十裏花溪錦城麗，", "卻待文星上天去，少分光影照沉淪。"]'),
('yuding-11','貽蜀五首：盧評事子蒙','元稹','唐','御定全唐诗','yuding','','[]','為我殷勤盧子蒙，近來無複昔時同。懶成積疹推難動，',40,'御定全唐詩/json/414.json','["為我殷勤盧子蒙，近來無複昔時同。懶成積疹推難動，", "唯公兩弟閑相訪，往往潸然一望公。"]'),
('yuding-12','貽蜀五首：張校書元夫','元稹','唐','御定全唐诗','yuding','','[]','未面西川張校書，書來稠疊頗相於。我聞聲價金應敵，',40,'御定全唐詩/json/414.json','["未面西川張校書，書來稠疊頗相於。我聞聲價金應敵，", "勸君便是酬君愛，莫比尋常贈鯉魚。"]'),
('yuding-13','貽蜀五首：韋兵曹臧文','元稹','唐','御定全唐诗','yuding','','[]','處處侯門可曳裾，人人爭事蜀尚書。摩天氣直山曾拔，',40,'御定全唐詩/json/414.json','["處處侯門可曳裾，人人爭事蜀尚書。摩天氣直山曾拔，", "殷勤為話深相感，不學馮諼待食魚。"]'),
('yuding-14','贈嚴童子','元稹','唐','御定全唐诗','yuding','','[]','衛瓘諸孫衛玠珍，可憐雛鳳好青春。解拈玉葉排新句，',40,'御定全唐詩/json/414.json','["衛瓘諸孫衛玠珍，可憐雛鳳好青春。解拈玉葉排新句，", "楊公莫訝清無業，家有驪珠不復貧。"]'),
('yuding-15','桐孫詩','元稹','唐','御定全唐诗','yuding','','[]','去日桐花半桐葉，別來桐樹老桐孫。',32,'御定全唐詩/json/414.json','["去日桐花半桐葉，別來桐樹老桐孫。", "城中過盡無窮事，白髮滿頭歸故園。"]'),
('yuding-16','西歸絕句十二首','元稹','唐','御定全唐诗','yuding','','[]','雙堠頻頻減去程，漸知身得近京城。',384,'御定全唐詩/json/414.json','["雙堠頻頻減去程，漸知身得近京城。", "春來愛有歸鄉夢，一半猶疑夢裏行。", "五年江上損容顏，今日春風到武關。", "兩紙京書臨水讀，小桃花樹滿商山。", "同歸諫院韋丞相，共貶河南亞大夫。", "今日還鄉獨憔悴，幾人憐見白髭須。", "只去長安六日期，多應及得杏花時。", "春明門外誰相待，不夢閒人夢酒卮。", "白頭歸舍意如何，賀處無窮吊亦多。", "左降去時裴相宅，舊來車馬幾人過。", "還鄉何用淚沾襟，一半雲霄一半沉。", "世事漸多饒悵望，舊曾行處便傷心。", "閒遊寺觀從容到，遍問親知次第尋。", "腸斷裴家光德宅，無人掃地戟門深。", "一世營營死是休，生前無事定無由。", "不知山下東流水，何事長須日夜流。", "今朝西渡丹河水，心寄丹河無限愁。", "若到莊前竹園下，殷勤為繞故山流。", "寒窗風雪擁深爐，彼此相傷指白須。", "一夜思量十年事，幾人強健幾人無。", "雲覆藍橋雪滿溪，須臾便與碧峰齊。", "風回面市連天合，凍壓花枝著水低。", "寒花帶雪滿山腰，著柳冰珠滿碧條。", "天色漸明回一望，玉塵隨馬度藍橋。"]'),
('yuding-17','留呈夢得、子厚、致用','元稹','唐','御定全唐诗','yuding','','[]','泉溜才通疑夜磬，燒煙餘暖有春泥。千層玉帳鋪松蓋，',40,'御定全唐詩/json/414.json','["泉溜才通疑夜磬，燒煙餘暖有春泥。千層玉帳鋪松蓋，", "心知魏闕無多地，十二瓊樓百里西。"]'),
('yuding-18','小碎','元稹','唐','御定全唐诗','yuding','','[]','小碎詩篇取次書，等閒題柱意何如。',32,'御定全唐詩/json/414.json','["小碎詩篇取次書，等閒題柱意何如。", "諸郎到處應相問，留取三行代鯉魚。"]'),
('yuding-19','和樂天高相宅','元稹','唐','御定全唐诗','yuding','','[]','莫愁已去無窮事，漫苦如今有限身。',32,'御定全唐詩/json/414.json','["莫愁已去無窮事，漫苦如今有限身。", "二百年來城裏宅，一家知換幾多人。"]'),
('yuding-20','和樂天仇家酒','元稹','唐','御定全唐诗','yuding','','[]','病嗟酒戶年年減，老覺塵機漸漸深。',32,'御定全唐詩/json/414.json','["病嗟酒戶年年減，老覺塵機漸漸深。", "飲罷醒餘更惆悵，不如閒事不經心。"]'),
('yuding-21','和樂天贈雲寂僧','元稹','唐','御定全唐诗','yuding','','[]','欲離煩惱三千界，不在禪門八萬條。',32,'御定全唐詩/json/414.json','["欲離煩惱三千界，不在禪門八萬條。", "心火自生還自滅，雲師無路與君銷。"]'),
('yuding-22','澧西別樂天博載樊宗憲李景信兩秀才姪谷三月三十日相餞送','元稹','唐','御定全唐诗','yuding','','[]','今朝相送自同遊，酒語詩情替別愁。',32,'御定全唐詩/json/414.json','["今朝相送自同遊，酒語詩情替別愁。", "忽到灃西總回去，一身騎馬向通州。"]'),
('yuding-23','寄曇、嵩、寂三上人','元稹','唐','御定全唐诗','yuding','','[]','長學對治思苦處，偏將死苦教人間。',32,'御定全唐詩/json/414.json','["長學對治思苦處，偏將死苦教人間。", "今因為說無生死，無可對治心更閑。"]'),
('yuding-24','題漫天嶺智藏師蘭若僧雲住此二十八年','元稹','唐','御定全唐诗','yuding','','[]','僧臨大道閱浮生，來往憧憧利與名。',32,'御定全唐詩/json/414.json','["僧臨大道閱浮生，來往憧憧利與名。", "二十八年何限客，不曾閑見一人行。"]'),
('yuding-25','蒼溪縣寄揚州兄弟','元稹','唐','御定全唐诗','yuding','','[]','蒼溪縣下嘉陵水，入峽穿江到海流。',32,'御定全唐詩/json/414.json','["蒼溪縣下嘉陵水，入峽穿江到海流。", "憑仗鯉魚將遠信，雁回時節到揚州。"]'),
('yuding-26','贈吳渠州從姨兄士則','元稹','唐','御定全唐诗','yuding','','[]','憶昔分襟童子郎，白頭拋擲又他鄉。三千裏外巴南恨，',40,'御定全唐詩/json/414.json','["憶昔分襟童子郎，白頭拋擲又他鄉。三千裏外巴南恨，", "淚因生別兼懷舊，回首江山欲萬行。"]'),
('yuding-27','長灘夢李紳','元稹','唐','御定全唐诗','yuding','','[]','孤吟獨寢意千般，合眼逢君一夜歡。',32,'御定全唐詩/json/414.json','["孤吟獨寢意千般，合眼逢君一夜歡。", "慚愧夢魂無遠近，不辭風雨到長灘。"]'),
('yuding-0','新政縣','元稹','唐','御定全唐诗','yuding','','[]','新政縣前逢月夜，嘉陵江底看星辰。已聞城上三更鼓，',40,'御定全唐詩/json/415.json','["新政縣前逢月夜，嘉陵江底看星辰。已聞城上三更鼓，", "曾沾幾許名兼利，勞動生涯涉苦辛。"]'),
('yuding-1','南昌灘','元稹','唐','御定全唐诗','yuding','','[]','渠江明淨峽逶迤，船到明灘拽zB遲。櫓窡動搖妨作夢，',41,'御定全唐詩/json/415.json','["渠江明淨峽逶迤，船到明灘拽zB遲。櫓窡動搖妨作夢，", "物色可憐心莫恨，此行都是獨行時。"]'),
('yuding-2','見樂天詩','元稹','唐','御定全唐诗','yuding','','[]','通州到日日平西，江館無人虎印泥。',32,'御定全唐詩/json/415.json','["通州到日日平西，江館無人虎印泥。", "忽向破簷殘漏處，見君詩在柱心題。"]'),
('yuding-3','夜坐','元稹','唐','御定全唐诗','yuding','','[]','雨滯更愁南瘴毒，月明兼喜北風涼。古城樓影橫空館，',40,'御定全唐詩/json/415.json','["雨滯更愁南瘴毒，月明兼喜北風涼。古城樓影橫空館，", "孩提萬里何時見，狼藉家書滿臥床。"]'),
('yuding-4','聞樂天授江州司馬','元稹','唐','御定全唐诗','yuding','','[]','殘燈無焰影幢幢，此夕聞君謫九江。',32,'御定全唐詩/json/415.json','["殘燈無焰影幢幢，此夕聞君謫九江。", "垂死病中驚坐起，暗風吹雨入寒窗。"]'),
('yuding-5','歲日贈拒非','元稹','唐','御定全唐诗','yuding','','[]','君思曲水嗟身老，我望通州感道窮。',32,'御定全唐詩/json/415.json','["君思曲水嗟身老，我望通州感道窮。", "同入新年兩行淚，白頭翁坐說城中。"]'),
('yuding-6','送盧戡','元稹','唐','御定全唐诗','yuding','','[]','紅樹蟬聲滿夕陽，白頭相送倍相傷。老嗟去日光陰促，',40,'御定全唐詩/json/415.json','["紅樹蟬聲滿夕陽，白頭相送倍相傷。老嗟去日光陰促，", "紅旗滿眼襄州路，此別淚流千萬行。"]'),
('yuding-7','雨聲','元稹','唐','御定全唐诗','yuding','','[]','風吹竹葉休還動，雨點荷心暗複明。',32,'御定全唐詩/json/415.json','["風吹竹葉休還動，雨點荷心暗複明。", "曾向西江船上宿，慣聞寒夜滴篷聲。"]'),
('yuding-8','奉和滎陽公離筵作','元稹','唐','御定全唐诗','yuding','','[]','南郡生徒辭絳帳，東山妓樂擁油旌。',32,'御定全唐詩/json/415.json','["南郡生徒辭絳帳，東山妓樂擁油旌。", "鈞天排比簫韶待，猶顧人間有別情。"]'),
('yuding-9','嘉陵水','元稹','唐','御定全唐诗','yuding','','[]','古時應是山頭水，自古流來江路深。',32,'御定全唐詩/json/415.json','["古時應是山頭水，自古流來江路深。", "若使江流會人意，也應知我遠來心。"]'),
('yuding-10','閬州開元寺壁題樂天詩','元稹','唐','御定全唐诗','yuding','','[]','憶君無計寫君詩，寫盡千行說向誰。',32,'御定全唐詩/json/415.json','["憶君無計寫君詩，寫盡千行說向誰。", "題在閬州東寺壁，幾時知是見君時。"]'),
('yuding-11','憑李忠州寄書樂天','元稹','唐','御定全唐诗','yuding','','[]','萬里寄書將出峽，卻憑巫峽寄江州。',32,'御定全唐詩/json/415.json','["萬里寄書將出峽，卻憑巫峽寄江州。", "傷心最是江頭月，莫把書將上庾樓。"]'),
('yuding-12','得樂天書','元稹','唐','御定全唐诗','yuding','','[]','遠信入門先有淚，妻驚女哭問何如。',32,'御定全唐詩/json/415.json','["遠信入門先有淚，妻驚女哭問何如。", "尋常不省曾如此，應是江州司馬書。"]'),
('yuding-13','寄樂天','元稹','唐','御定全唐诗','yuding','','[]','無身尚擬魂相就，身在那無夢往還。',32,'御定全唐詩/json/415.json','["無身尚擬魂相就，身在那無夢往還。", "直到他生亦相覓，不能空記樹中環。"]'),
('yuding-14','酬知退','元稹','唐','御定全唐诗','yuding','','[]','終須修到無修處，聞盡聲聞始不聞。',32,'御定全唐詩/json/415.json','["終須修到無修處，聞盡聲聞始不聞。", "莫著妄心銷彼我，我心無我亦無君。"]'),
('yuding-15','通州','元稹','唐','御定全唐诗','yuding','','[]','平生欲得山中住，天與通州繞郡山。',32,'御定全唐詩/json/415.json','["平生欲得山中住，天與通州繞郡山。", "睡到日西無一事，月儲三萬買教閑。"]'),
('yuding-16','酬樂天書後三韻','元稹','唐','御定全唐诗','yuding','','[]','今日廬峰霞繞寺，昔時鸞殿鳳回書。兩封相去八年後，',24,'御定全唐詩/json/415.json','["今日廬峰霞繞寺，昔時鸞殿鳳回書。兩封相去八年後，"]'),
('yuding-17','相憶淚','元稹','唐','御定全唐诗','yuding','','[]','西江流水到江州，聞道分成九道流。我滴兩行相憶淚，',40,'御定全唐詩/json/415.json','["西江流水到江州，聞道分成九道流。我滴兩行相憶淚，", "會向伍員潮上見，氣充頑石報心仇。"]'),
('yuding-18','喜李十一景信到','元稹','唐','御定全唐诗','yuding','','[]','何事相逢翻有淚，念君緣我到通州。',32,'御定全唐詩/json/415.json','["何事相逢翻有淚，念君緣我到通州。", "留君剩住君須住，我不自由君自由。"]'),
('yuding-19','與李十一夜飲','元稹','唐','御定全唐诗','yuding','','[]','寒夜燈前賴酒壺，與君相對興猶孤。',32,'御定全唐詩/json/415.json','["寒夜燈前賴酒壺，與君相對興猶孤。", "忠州刺史應閑臥，江水猿聲睡得無。"]'),
('yuding-20','贈李十一','元稹','唐','御定全唐诗','yuding','','[]','淮水連年起戰塵，油旌三換一何頻。',32,'御定全唐詩/json/415.json','["淮水連年起戰塵，油旌三換一何頻。", "共君前後俱從事，羞見功名與別人。"]'),
('yuding-21','寒食日','元稹','唐','御定全唐诗','yuding','','[]','今年寒食好風流，此日一家同出遊。',32,'御定全唐詩/json/415.json','["今年寒食好風流，此日一家同出遊。", "碧水青山無限思，莫將心道是涪州。"]'),
('yuding-22','三兄以白角巾寄遺，發不勝冠，因有感歎','元稹','唐','御定全唐诗','yuding','','[]','病瘴年深渾禿盡，那能勝置角頭巾。暗梳蓬發羞臨鏡，',40,'御定全唐詩/json/415.json','["病瘴年深渾禿盡，那能勝置角頭巾。暗梳蓬發羞臨鏡，", "我身四十猶如此，何況吾兄六十身。"]'),
('yuding-23','別李十一五絕','元稹','唐','御定全唐诗','yuding','','[]','巴南分與親情別，不料與君床並頭。',160,'御定全唐詩/json/415.json','["巴南分與親情別，不料與君床並頭。", "為我遠來休悵望，折君災難是通州。", "京城每與閒人別，猶自傷心與白頭。", "今日別君心更苦，別君緣是在通州。", "萬里尚能來遠道，一程那忍便分頭。", "鳥籠猿檻君應會，十步向前非我州。", "來時見我江南岸，今日送君江上頭。", "別後料添新夢寐，虎驚蛇伏是通州。", "聞君欲去潛銷骨，一夜暗添新白頭。", "明朝別後應腸斷，獨棹破船歸到州。"]'),
('yuding-24','酬樂天醉別','元稹','唐','御定全唐诗','yuding','','[]','前回一去五年別，此別又知何日回。',32,'御定全唐詩/json/415.json','["前回一去五年別，此別又知何日回。", "好住樂天休悵望，匹如元不到京來。"]'),
('yuding-25','酬樂天雨後見憶','元稹','唐','御定全唐诗','yuding','','[]','雨滑危梁性命愁，差池一步一生休。',32,'御定全唐詩/json/415.json','["雨滑危梁性命愁，差池一步一生休。", "黃泉便是通州郡，漸入深泥漸到州。"]'),
('yuding-26','和樂天過秘閣書省舊廳','元稹','唐','御定全唐诗','yuding','','[]','聞君西省重徘徊，秘閣書房次第開。壁記欲題三漏合，',40,'御定全唐詩/json/415.json','["聞君西省重徘徊，秘閣書房次第開。壁記欲題三漏合，", "司馬見詩心最苦，滿身蚊蚋哭煙埃。"]'),
('yuding-27','和樂天贈楊秘書','元稹','唐','御定全唐诗','yuding','','[]','舊與楊郎在帝城，搜天斡地覓詩情。曾因並句甘稱小，',40,'御定全唐詩/json/415.json','["舊與楊郎在帝城，搜天斡地覓詩情。曾因並句甘稱小，", "因君投贈還相和，老去那能競底名。"]'),
('yuding-28','和樂天題王家亭子','元稹','唐','御定全唐诗','yuding','','[]','風吹筍籜飄紅砌，雨打桐花盡綠莎。',32,'御定全唐詩/json/415.json','["風吹筍籜飄紅砌，雨打桐花盡綠莎。", "都大資人無暇日，泛池全少買池多。"]'),
('yuding-29','酬樂天頻夢微之','元稹','唐','御定全唐诗','yuding','','[]','山水萬重書斷絕，念君憐我夢相聞。',32,'御定全唐詩/json/415.json','["山水萬重書斷絕，念君憐我夢相聞。", "我今因病魂顛倒，唯夢閒人不夢君。"]'),
('yuding-30','琵琶','元稹','唐','御定全唐诗','yuding','','[]','學語胡兒撼玉玲，甘州破裏最星星。',32,'御定全唐詩/json/415.json','["學語胡兒撼玉玲，甘州破裏最星星。", "使君自恨常多事，不得工夫夜夜聽。"]'),
('yuding-31','春詞','元稹','唐','御定全唐诗','yuding','','[]','山翠湖光似欲流，蜂聲鳥思卻堪愁。',32,'御定全唐詩/json/415.json','["山翠湖光似欲流，蜂聲鳥思卻堪愁。", "西施顏色今何在，但看春風百草頭。"]'),
('yuding-0','酬樂天春寄微之','元稹','唐','御定全唐诗','yuding','','[]','鸚心明黠雀幽蒙，何事相將盡入籠。君避海鯨驚浪裏，',40,'御定全唐詩/json/416.json','["鸚心明黠雀幽蒙，何事相將盡入籠。君避海鯨驚浪裏，", "一樹梅花數升酒，醉尋江岸哭東風。"]'),
('yuding-1','酬樂天舟泊夜讀微之詩','元稹','唐','御定全唐诗','yuding','','[]','知君暗泊西江岸，讀我閑詩欲到明。',32,'御定全唐詩/json/416.json','["知君暗泊西江岸，讀我閑詩欲到明。", "今夜通州還不睡，滿山風雨杜鵑聲。"]'),
('yuding-2','酬樂天武關南見微之題山石榴花詩','元稹','唐','御定全唐诗','yuding','','[]','比因酬贈為花時，不為君行不復知。',32,'御定全唐詩/json/416.json','["比因酬贈為花時，不為君行不復知。", "又更幾年還共到，滿牆塵土兩篇詩。"]'),
('yuding-3','酬樂天見寄','元稹','唐','御定全唐诗','yuding','','[]','三千裏外巴蛇穴，四十年來司馬官。瘴色滿身治不盡，',40,'御定全唐詩/json/416.json','["三千裏外巴蛇穴，四十年來司馬官。瘴色滿身治不盡，", "前日詩中高蓋字，至今唇舌遍長安。"]'),
('yuding-4','酬樂天得稹所寄紵絲布白輕庸製成衣服以詩報之','元稹','唐','御定全唐诗','yuding','','[]','湓城萬里隔巴庸，紵薄綈輕共一封。腰帶定知今瘦小，',40,'御定全唐詩/json/416.json','["湓城萬里隔巴庸，紵薄綈輕共一封。腰帶定知今瘦小，", "春草綠茸雲色白，想君騎馬好儀容。"]'),
('yuding-5','和樂天尋郭道士不遇','元稹','唐','御定全唐诗','yuding','','[]','昔年我見杯中渡，今日人言鶴上逢。兩虎定隨千歲鹿，',48,'御定全唐詩/json/416.json','["昔年我見杯中渡，今日人言鶴上逢。兩虎定隨千歲鹿，", "為僧時先有腳疾。欲請僧繇遠相畫，苦愁頻變本形容。"]'),
('yuding-6','酬樂天寄生衣','元稹','唐','御定全唐诗','yuding','','[]','秋茅處處流痎瘧，夜鳥聲聲哭瘴雲。',32,'御定全唐詩/json/416.json','["秋茅處處流痎瘧，夜鳥聲聲哭瘴雲。", "羸骨不勝纖細物，欲將文服卻還君。"]'),
('yuding-7','酬樂天得微之詩知通州事因成四首','元稹','唐','御定全唐诗','yuding','','[]','茅簷屋舍竹籬州，虎怕偏蹄蛇兩頭。暗蠱有時迷酒影，',160,'御定全唐詩/json/416.json','["茅簷屋舍竹籬州，虎怕偏蹄蛇兩頭。暗蠱有時迷酒影，", "知得共君相見否，近來魂夢轉悠悠。", "平地才應一頃餘，閣欄都大似巢居。入衙官吏聲疑鳥，", "此中愁殺須甘分，惟惜平生舊著書。", "哭鳥晝飛人少見，倀魂夜嘯虎行多。滿身沙虱無防處，", "南歌未有東西分，敢唱淪浪一字歌。", "荒蕪滿院不能鋤，甑有塵埃圃乏蔬。定覺身將囚一種，", "苦境萬般君莫問，自憐方寸本來虛。"]'),
('yuding-8','酬樂天聞李尚書拜相以詩見賀','元稹','唐','御定全唐诗','yuding','','[]','初因彈劾死東川，又為親情弄化權。百口共經三峽水，',40,'御定全唐詩/json/416.json','["初因彈劾死東川，又為親情弄化權。百口共經三峽水，", "若待更遭秋瘴後，便愁平地有重泉。"]'),
('yuding-9','酬樂天歎窮愁見寄','元稹','唐','御定全唐诗','yuding','','[]','病煎愁緒轉紛紛，百里何由說向君。老去心情隨日減，',40,'御定全唐詩/json/416.json','["病煎愁緒轉紛紛，百里何由說向君。老去心情隨日減，", "並與巴南終歲熱，四時誰道各平分。"]'),
('yuding-10','酬樂天三月三日見寄','元稹','唐','御定全唐诗','yuding','','[]','當年此日花前醉，今日花前病裏銷。',32,'御定全唐詩/json/416.json','["當年此日花前醉，今日花前病裏銷。", "獨倚破簾閑悵望，可憐虛度好春朝。"]'),
('yuding-11','酬樂天歎損傷見寄','元稹','唐','御定全唐诗','yuding','','[]','前途何在轉茫茫，漸老那能不自傷。病為怕風多睡月，',40,'御定全唐詩/json/416.json','["前途何在轉茫茫，漸老那能不自傷。病為怕風多睡月，", "唯有秋來兩行淚，對君新贈遠詩章。"]'),
('yuding-12','瘴塞','元稹','唐','御定全唐诗','yuding','','[]','瘴塞巴山哭鳥悲，紅妝少婦斂啼眉。',32,'御定全唐詩/json/416.json','["瘴塞巴山哭鳥悲，紅妝少婦斂啼眉。", "殷勤奉藥來相勸，雲是前年欲病時。"]'),
('yuding-13','紅荊','元稹','唐','御定全唐诗','yuding','','[]','庭中栽得紅荊樹，十月花開不待春。',32,'御定全唐詩/json/416.json','["庭中栽得紅荊樹，十月花開不待春。", "直到孩提盡驚怪，一家同是北來人。"]'),
('yuding-14','黃草峽聽柔之琴二首','元稹','唐','御定全唐诗','yuding','','[]','胡笳夜奏塞聲寒，是我鄉音聽漸難。',64,'御定全唐詩/json/416.json','["胡笳夜奏塞聲寒，是我鄉音聽漸難。", "料得小來辛苦學，又因知向峽中彈。", "別鶴淒清覺露寒，離聲漸咽命雛難。", "憐君伴我涪州宿，猶有心情徹夜彈。"]'),
('yuding-15','書劍','元稹','唐','御定全唐诗','yuding','','[]','渝工劍刃皆歐冶，巴吏書蹤盡子雲。',32,'御定全唐詩/json/416.json','["渝工劍刃皆歐冶，巴吏書蹤盡子雲。", "唯我心知有來處，泊船黃草夜思君。"]'),
('yuding-16','內狀詩寄楊、白二員外','元稹','唐','御定全唐诗','yuding','','[]','天門暗辟玉琤鍧，晝送中樞曉禁清。彤管內人書細膩，',40,'御定全唐詩/json/416.json','["天門暗辟玉琤鍧，晝送中樞曉禁清。彤管內人書細膩，", "南省郎官誰待詔，與君將向世間行。"]'),
('yuding-17','別毅郎','元稹','唐','御定全唐诗','yuding','','[]','爾爺只為一杯酒，此別那知死與生。',64,'御定全唐詩/json/416.json','["爾爺只為一杯酒，此別那知死與生。", "兒有何辜才七歲，亦教兒作瘴江行。", "愛惜爾爺唯有我，我今憔悴望何人。", "傷心自比籠中鶴，翦盡翅翎愁到身。"]'),
('yuding-18','自責','元稹','唐','御定全唐诗','yuding','','[]','犀帶金魚束紫袍，不能將命報分毫。',32,'御定全唐詩/json/416.json','["犀帶金魚束紫袍，不能將命報分毫。", "他時得見牛常侍，為爾君前捧佩刀。"]'),
('yuding-19','送公度之福建','元稹','唐','御定全唐诗','yuding','','[]','棠陰猶在建溪磯，此去那論是與非。',32,'御定全唐詩/json/416.json','["棠陰猶在建溪磯，此去那論是與非。", "若見白頭須盡敬，恐曾江岸識胡威。"]'),
('yuding-20','喜五兄自泗州至','元稹','唐','御定全唐诗','yuding','','[]','眼中三十年來淚，一望南雲一度垂。',32,'御定全唐詩/json/416.json','["眼中三十年來淚，一望南雲一度垂。", "慚愧臨淮李常侍，遠教形影暫相隨。"]'),
('yuding-21','杏花','元稹','唐','御定全唐诗','yuding','','[]','常年出入右銀台，每怪春光例早回。',32,'御定全唐詩/json/416.json','["常年出入右銀台，每怪春光例早回。", "慚愧杏園行在景，同州園裏也先開。"]'),
('yuding-22','第三歲日詠春風，憑楊員外寄長安柳','元稹','唐','御定全唐诗','yuding','','[]','三日春風已有情，拂人頭面稍憐輕。',32,'御定全唐詩/json/416.json','["三日春風已有情，拂人頭面稍憐輕。", "殷勤為報長安柳，莫惜枝條動軟聲。"]'),
('yuding-23','贈別楊員外巨源','元稹','唐','御定全唐诗','yuding','','[]','憶昔西河縣下時，青山憔悴宦名卑。揄揚陶令緣求酒，',40,'御定全唐詩/json/416.json','["憶昔西河縣下時，青山憔悴宦名卑。揄揚陶令緣求酒，", "白頭後會知何日，一盞煩君不用辭。"]'),
('yuding-24','寄樂天二首','元稹','唐','御定全唐诗','yuding','','[]','榮辱升沉影與身，世情誰是舊雷陳。唯應鮑叔猶憐我，',80,'御定全唐詩/json/416.json','["榮辱升沉影與身，世情誰是舊雷陳。唯應鮑叔猶憐我，", "老逢佳景唯惆悵，兩地各傷何限神。", "論才賦命不相干，鳳有文章雉有冠。羸骨欲銷猶被刻，", "休學州前羅刹石，一生身敵海波瀾。"]'),
('yuding-25','聽妻彈別鶴操','元稹','唐','御定全唐诗','yuding','','[]','別鶴聲聲怨夜弦，聞君此奏欲潸然。',32,'御定全唐詩/json/416.json','["別鶴聲聲怨夜弦，聞君此奏欲潸然。", "商瞿五十知無子，更付琴書與仲宣。"]'),
('yuding-26','和王侍郎酬廣宣上人觀放榜後相賀','元稹','唐','御定全唐诗','yuding','','[]','渥窪徒自有權奇，伯樂書名世始知。競走牆前希得俊，',40,'御定全唐詩/json/416.json','["渥窪徒自有權奇，伯樂書名世始知。競走牆前希得俊，", "珍重劉繇因首薦，為君送和碧雲詩。"]'),
('yuding-0','酬樂天喜鄰郡','元稹','唐','御定全唐诗','yuding','','[]','蹇驢瘦馬塵中伴，紫綬朱衣夢裏身。符竹偶因成對岸，',40,'御定全唐詩/json/417.json','["蹇驢瘦馬塵中伴，紫綬朱衣夢裏身。符竹偶因成對岸，", "老大那能更爭競，任君投募醉鄉人。"]'),
('yuding-1','再酬複言和前篇','元稹','唐','御定全唐诗','yuding','','[]','經過二郡逢賢牧，聚集諸郎宴老身。清夜漫勞紅燭會，',40,'御定全唐詩/json/417.json','["經過二郡逢賢牧，聚集諸郎宴老身。清夜漫勞紅燭會，", "潦倒微之從不占，未知公議道何人。"]'),
('yuding-2','贈樂天','元稹','唐','御定全唐诗','yuding','','[]','莫言鄰境易經過，彼此分符欲奈何。',32,'御定全唐詩/json/417.json','["莫言鄰境易經過，彼此分符欲奈何。", "垂老相逢漸難別，白頭期限各無多。"]'),
('yuding-3','重贈','元稹','唐','御定全唐诗','yuding','','[]','休遣玲瓏唱我詩，我詩多是別君詞。',32,'御定全唐詩/json/417.json','["休遣玲瓏唱我詩，我詩多是別君詞。", "明朝又向江頭別，月落潮平是去時。"]'),
('yuding-4','別後西陵晚眺','元稹','唐','御定全唐诗','yuding','','[]','晚日未拋詩筆硯，夕陽空望郡樓臺。',32,'御定全唐詩/json/417.json','["晚日未拋詩筆硯，夕陽空望郡樓臺。", "與君後會知何日，不似潮頭暮卻回。"]'),
('yuding-5','以州宅誇于樂天','元稹','唐','御定全唐诗','yuding','','[]','州城迥繞拂雲堆，鏡水稽山滿眼來。四面常時對屏障，',40,'御定全唐詩/json/417.json','["州城迥繞拂雲堆，鏡水稽山滿眼來。四面常時對屏障，", "我是玉皇香案吏，謫居猶得住蓬萊。"]'),
('yuding-6','重誇州宅旦暮景色，兼酬前篇末句','元稹','唐','御定全唐诗','yuding','','[]','仙都難畫亦難書，暫合登臨不合居。繞郭煙嵐新雨後，',40,'御定全唐詩/json/417.json','["仙都難畫亦難書，暫合登臨不合居。繞郭煙嵐新雨後，", "為問西州羅刹岸，濤頭衝突近何如。"]'),
('yuding-7','酬樂天吟張員外詩見寄因思上京每與樂天於居敬兄升平里詠張新詩','元稹','唐','御定全唐诗','yuding','','[]','樂天書內重封到，居敬堂前共讀時。四友一為泉路客，',40,'御定全唐詩/json/417.json','["樂天書內重封到，居敬堂前共讀時。四友一為泉路客，", "杯酒與他年少隔，不相酬贈欲何之。"]'),
('yuding-8','寄樂天','元稹','唐','御定全唐诗','yuding','','[]','閑夜思君坐到明，追尋往事倍傷情。同登科後心相合，',40,'御定全唐詩/json/417.json','["閑夜思君坐到明，追尋往事倍傷情。同登科後心相合，", "猶應更有前途在，知向人間何處行。"]'),
('yuding-9','戲贈樂天、複言','元稹','唐','御定全唐诗','yuding','','[]','樂事難逢歲易徂，白頭光景莫令孤。弄濤船更曾觀否，',40,'御定全唐詩/json/417.json','["樂事難逢歲易徂，白頭光景莫令孤。弄濤船更曾觀否，", "孫園虎寺隨宜看，不必遙遙羨鏡湖。"]'),
('yuding-10','重酬樂天','元稹','唐','御定全唐诗','yuding','','[]','紅塵擾擾日西徂，我興雲心兩共孤。暫出已遭千騎擁，',40,'御定全唐詩/json/417.json','["紅塵擾擾日西徂，我興雲心兩共孤。暫出已遭千騎擁，", "最笑近來黃叔度，自投名刺占陂湖。"]'),
('yuding-11','再酬複言','元稹','唐','御定全唐诗','yuding','','[]','繞郭笙歌夜景徂，稽山迥帶月輪孤。休文欲詠心應破，',40,'御定全唐詩/json/417.json','["繞郭笙歌夜景徂，稽山迥帶月輪孤。休文欲詠心應破，", "不然豈有姑蘇郡，擬著陂塘比鏡湖。"]'),
('yuding-12','郡務稍簡因得整比舊詩并連綴焚削封章繁委篋笥僅逾百軸偶成自歎因寄樂天','元稹','唐','御定全唐诗','yuding','','[]','近來章奏小年詩，一種成空盡可悲。書得眼昏朱似碧，',40,'御定全唐詩/json/417.json','["近來章奏小年詩，一種成空盡可悲。書得眼昏朱似碧，", "天遣兩家無嗣子，欲將文集與它誰。"]'),
('yuding-13','酬樂天餘思不盡加為六韻之作','元稹','唐','御定全唐诗','yuding','','[]','律呂同聲我爾身，文章君是一伶倫。眾推賈誼為才子，',48,'御定全唐詩/json/417.json','["律呂同聲我爾身，文章君是一伶倫。眾推賈誼為才子，", "元詩駁雜真難辨，白樸流傳用轉新。蔡女圖書雖在口，"]'),
('yuding-14','寄樂天','元稹','唐','御定全唐诗','yuding','','[]','莫嗟虛老海壖西，天下風光數會稽。靈泛橋前百里鏡，',40,'御定全唐詩/json/417.json','["莫嗟虛老海壖西，天下風光數會稽。靈泛橋前百里鏡，", "安得故人生羽翼，飛來相伴醉如泥。"]'),
('yuding-15','酬樂天雪中見寄','元稹','唐','御定全唐诗','yuding','','[]','知君夜聽風蕭索，曉望林亭雪半糊。撼落不教封柳眼，',88,'御定全唐詩/json/417.json','["知君夜聽風蕭索，曉望林亭雪半糊。撼落不教封柳眼，", "坐覺湖聲迷遠浪，回驚雲路在長途。錢塘湖上蘋先合，", "滿空飛舞應為瑞，寡和高歌只自娛。莫遣擁簾傷思婦，", "鏡水繞山山盡白，琉璃雲母世間無。"]'),
('yuding-16','和樂天早春見寄','元稹','唐','御定全唐诗','yuding','','[]','雨香雲澹覺微和，誰送春聲入棹歌。萱近北堂穿土早，',40,'御定全唐詩/json/417.json','["雨香雲澹覺微和，誰送春聲入棹歌。萱近北堂穿土早，", "同受新年不同賞，無由縮地欲如何。"]'),
('yuding-17','酬複言長慶四年元日郡齋感懷見寄','元稹','唐','御定全唐诗','yuding','','[]','臘盡殘銷春又歸，逢新別故欲沾衣。自驚身上添年紀，',72,'御定全唐詩/json/417.json','["臘盡殘銷春又歸，逢新別故欲沾衣。自驚身上添年紀，", "羞看稚子先拈酒，悵望平生舊采薇。去日漸加餘日少，", "苦思正旦酬白雪，閑觀風色動青旗。千官仗下爐煙裏，"]'),
('yuding-18','代郡齋神答樂天','元稹','唐','御定全唐诗','yuding','','[]','虛白堂神傳好語，二年長伴獨吟時。夜憐星月多離燭，',24,'御定全唐詩/json/417.json','["虛白堂神傳好語，二年長伴獨吟時。夜憐星月多離燭，"]'),
('yuding-19','酬樂天重寄別','元稹','唐','御定全唐诗','yuding','','[]','卻報君侯聽苦辭，老頭拋我欲何之。',32,'御定全唐詩/json/417.json','["卻報君侯聽苦辭，老頭拋我欲何之。", "武牢關外雖分手，不似如今衰白時。"]'),
('yuding-20','和樂天重題別東樓','元稹','唐','御定全唐诗','yuding','','[]','山容水態使君知，樓上從容萬狀移。日映文章霞細麗，',48,'御定全唐詩/json/417.json','["山容水態使君知，樓上從容萬狀移。日映文章霞細麗，", "喚客潛揮遠紅袖，賣壚高掛小青旗。剩鋪床席春眠處，"]'),
('yuding-21','餘杭周從事以十章見寄詞調清婉難於遍酬聊和詩首篇以答來貺','元稹','唐','御定全唐诗','yuding','','[]','擾擾紛紛旦暮間，經營閒事不曾閑。多緣老病推辭酒，',40,'御定全唐詩/json/417.json','["擾擾紛紛旦暮間，經營閒事不曾閑。多緣老病推辭酒，", "何由得似周從事，醉入人家醒始還。"]'),
('yuding-22','寄浙西李大夫四首','元稹','唐','御定全唐诗','yuding','','[]','柳眼梅心漸欲春，白頭西望憶何人。',128,'御定全唐詩/json/417.json','["柳眼梅心漸欲春，白頭西望憶何人。", "金陵太守曾相伴，共蹋銀台一路塵。", "蕊珠深處少人知，網索西臨太液池。", "浴殿曉聞天語後，步廊騎馬笑相隨。", "禁林同直話交情，無夜無曾不到明。", "最憶西樓人靜夜，玉晨鐘磬兩三聲。", "由來鵬化便圖南，浙右雖雄我未甘。", "早渡西江好歸去，莫拋舟楫滯春潭。"]'),
('yuding-23','初除浙東，妻有阻色，因以四韻曉之','元稹','唐','御定全唐诗','yuding','','[]','嫁時五月歸巴地，今日雙旌上越州。興慶首行千命婦，',40,'御定全唐詩/json/417.json','["嫁時五月歸巴地，今日雙旌上越州。興慶首行千命婦，", "我有主恩羞未報，君于此外更何求。"]'),
('yuding-24','為樂天自勘詩集，因思頃年城南醉歸，馬上遞，唱豔曲，十餘里不絕，長慶初俱以制誥侍宿南郊齋宮，夜後偶，吟數十篇，兩掖諸公洎翰林學士三十餘人驚起就聽，逮至卒吏，莫不眾觀，群公直至侍從行禮之時，不復聚寐，予與樂天吟哦竟亦不絕，因書於樂天卷後，越中冬夜風雨，不覺將曉，諸門互啟關鎖，即事成篇','元稹','唐','御定全唐诗','yuding','','[]','春野醉吟十里程，齋宮潛詠萬人驚。',32,'御定全唐詩/json/417.json','["春野醉吟十里程，齋宮潛詠萬人驚。", "今宵不寐到明讀，風雨曉聞開鎖聲。"]'),
('yuding-25','題長慶四年曆日尾','元稹','唐','御定全唐诗','yuding','','[]','殘曆半張餘十四，灰心雪鬢兩淒然。',32,'御定全唐詩/json/417.json','["殘曆半張餘十四，灰心雪鬢兩淒然。", "定知新歲禦樓後，從此不名長慶年。"]'),
('yuding-0','夢上天','元稹','唐','御定全唐诗','yuding','','[]','夢上高高天，高高蒼蒼高不極。下視五嶽塊累累，',86,'御定全唐詩/json/418.json','["夢上高高天，高高蒼蒼高不極。下視五嶽塊累累，", "西瞻若水兔輪低，東望蟠桃海波黑。日月之光不到此，", "來時畏有他人上，截斷龍胡斬鵬翼。茫茫漫漫方自悲，", "千慚萬謝喚厭人，向使無君終不寤。"]'),
('yuding-1','冬白紵','元稹','唐','御定全唐诗','yuding','','[]','吳宮夜長宮漏款，簾幕四垂燈焰暖。西施自舞王自管，',48,'御定全唐詩/json/418.json','["吳宮夜長宮漏款，簾幕四垂燈焰暖。西施自舞王自管，", "寢醒閽報門無事，子胥死後言為諱。近王之臣論王意，"]'),
('yuding-2','將進酒','元稹','唐','御定全唐诗','yuding','','[]','將進酒，將進酒。酒中有毒鴆主父，言之主父傷主母。',92,'御定全唐詩/json/418.json','["將進酒，將進酒。酒中有毒鴆主父，言之主父傷主母。", "母為妾地父妾天，仰天俯地不忍言。陽為僵踣主父前，", "推椎主母牽下堂，扶妾遣升堂上床。將進酒，", "妾為此事人偶知，自慚不密方自悲。主今顛倒安置妾，"]'),
('yuding-3','采珠行','元稹','唐','御定全唐诗','yuding','','[]','海波無底珠沉海，采珠之人判死采。萬人判死一得珠，',48,'御定全唐詩/json/418.json','["海波無底珠沉海，采珠之人判死采。萬人判死一得珠，", "海神采珠珠盡死，死盡明珠空海水。珠為海物海屬神，"]'),
('yuding-4','董逃行','元稹','唐','御定全唐诗','yuding','','[]','董逃董逃董卓逃，揩鏗戈甲聲勞嘈。剜剜深臍脂焰焰，',90,'御定全唐詩/json/418.json','["董逃董逃董卓逃，揩鏗戈甲聲勞嘈。剜剜深臍脂焰焰，", "膏銷骨盡煙火死，長安城中賊毛起。城門四走公卿士，", "董逃董逃人莫喜，勝負相環相枕倚，縫綴難成裁破易。", "何況曲針不能伸巧指，欲學裁縫須准擬。"]'),
('yuding-5','憶遠曲','元稹','唐','御定全唐诗','yuding','','[]','憶遠曲，郎身不遠郎心遠。沙隨郎飯俱在匙，',83,'御定全唐詩/json/418.json','["憶遠曲，郎身不遠郎心遠。沙隨郎飯俱在匙，", "況妾事姑姑進止，身去門前同萬里。一家儘是郎腹心，", "君今夜夜醉何處，姑來伴妾自閉門。嫁夫恨不早，", "妾不忍見姑郎忍見，為郎忍耐看姑面。"]'),
('yuding-6','夫遠征','元稹','唐','御定全唐诗','yuding','','[]','趙卒四十萬，盡為坑中鬼。趙王未信趙母言，',66,'御定全唐詩/json/418.json','["趙卒四十萬，盡為坑中鬼。趙王未信趙母言，", "括雖專命起尚輕，何況牽肘之人牽不已。坑中之鬼妻在營，", "夫遠征，遠征不必戍長城，出門便不知死生。"]'),
('yuding-7','織婦詞','元稹','唐','御定全唐诗','yuding','','[]','織夫何太忙，蠶經三臥行欲老。蠶神女聖早成絲，',70,'御定全唐詩/json/418.json','["織夫何太忙，蠶經三臥行欲老。蠶神女聖早成絲，", "征人戰苦束刀瘡，主將勳高換羅幕。繅絲織帛猶努力，", "簷前嫋嫋遊絲上，上有蜘蛛巧來往。羨他蟲豸解緣天，"]'),
('yuding-8','田家詞','元稹','唐','御定全唐诗','yuding','','[]','牛吒吒，田確確。旱塊敲牛蹄趵趵，種得官倉珠顆穀。',89,'御定全唐詩/json/418.json','["牛吒吒，田確確。旱塊敲牛蹄趵趵，種得官倉珠顆穀。", "六十年來兵蔟蔟，月月食糧車轆轆。一日官軍收海服，", "姑舂婦擔去輸官，輸官不足歸賣屋，願官早勝讎早覆。", "農死有兒牛有犢，誓不遣官軍糧不足。"]'),
('yuding-9','俠客行','元稹','唐','御定全唐诗','yuding','','[]','俠客不怕死，怕在事不成，事成不肯藏姓名。',67,'御定全唐詩/json/418.json','["俠客不怕死，怕在事不成，事成不肯藏姓名。", "我非竊賊誰夜行，白日堂堂殺袁盎。九衢草草人面青，", "分海減海力，俠客有謀，人不識測三尺鐵蛇延二國。"]'),
('yuding-10','君莫非','元稹','唐','御定全唐诗','yuding','','[]','鳥不解走，獸不解飛。兩不相解，那得相譏。犬不飲露，',50,'御定全唐詩/json/418.json','["鳥不解走，獸不解飛。兩不相解，那得相譏。犬不飲露，", "各自窠窟，人不能移。婦好針縷，夫讀書詩。男翁女嫁，"]'),
('yuding-11','田野狐兔行','元稹','唐','御定全唐诗','yuding','','[]','種豆耘鋤，種禾溝甽。禾苗豆甲，狐榾兔翦。割鵠喂鷹，',45,'御定全唐詩/json/418.json','["種豆耘鋤，種禾溝甽。禾苗豆甲，狐榾兔翦。割鵠喂鷹，", "日暗天寒，禾稀豆損。鷹犬就烹，狐兔俱哂。"]'),
('yuding-12','當來日大難行','元稹','唐','御定全唐诗','yuding','','[]','當來日大難行。前有阪，後有坑。大樑側，小梁傾。',71,'御定全唐詩/json/418.json','["當來日大難行。前有阪，後有坑。大樑側，小梁傾。", "兩軸相絞，兩輪相撐。大牛豎，小牛橫。烏啄牛背，", "輪軸自撓，牽制不停。泥潦漸久，荊棘旋生。行必不得，"]'),
('yuding-13','人道短','元稹','唐','御定全唐诗','yuding','','[]','古道天道長人道短，我道天道短人道長。',177,'御定全唐詩/json/418.json','["古道天道長人道短，我道天道短人道長。", "天道晝夜回轉不曾住，春秋冬夏忙。顛風暴雨電雷狂，", "泥金刻玉，與秦始皇。周公傅說，何不長宰相。老聃仲尼，", "堯舜留得神聖事，百代天子有典章。仲尼留得孝順語，", "諡作玄元帝，魂魄坐天堂。周公周禮二十卷，", "天能夭人命，人使道無窮。若此神聖事，誰道人道短，", "人能揀得丁沈蘭蕙，料理百和香。天解養禽獸，", "蚊蚋與利觜，枳棘與鋒鋩。賴得人道有揀別，"]'),
('yuding-14','苦樂相倚曲','元稹','唐','御定全唐诗','yuding','','[]','古來苦樂之相倚，近於掌上之十指。君心半夜猜恨生，',96,'御定全唐詩/json/418.json','["古來苦樂之相倚，近於掌上之十指。君心半夜猜恨生，", "未有因由相決絕，猶得半年佯暖熱。轉將深意諭旁人，", "呼天撫地將自明，不悟尋時暗銷骨。白首宮人前再拜，", "主今被奪心應苦，妾奪深恩初為主。欲知妾意恨主時，"]'),
('yuding-15','出門行','元稹','唐','御定全唐诗','yuding','','[]','兄弟同出門，同行不同志。淒淒分歧路，各各營所為。',409,'御定全唐詩/json/418.json','["兄弟同出門，同行不同志。淒淒分歧路，各各營所為。", "兄上荊山巔，翻石辨虹氣。弟沉滄海底，偷珠待龍睡。", "出門不數年，同歸亦同遂。俱用私所珍，升沉自茲異。", "獻珠龍王宮，值龍覓珠次。但喜複得珠，不求珠所自。", "酬客雙龍女，授客六龍轡。遣充行雨神，雨澤隨客意。", "雩夏鐘鼓繁，uG秋玉帛積。彩色畫廊廟，奴僮被珠翠。", "驥騄千萬雙，鴛鴦七十二。言者未搖舌，無人敢輕議。", "其兄因獻璞，再刖不履地。門戶親戚疏，匡床妻妾棄。", "銘心有所待，視足無所愧。持璞自枕頭，淚痕雙血漬。", "一朝龍醒寤，本問偷珠事。因知行雨偏，妻子五刑備。", "仁兄捧屍哭，勢友掉頭諱。喪車黔首葬，吊客青蠅至。", "楚有望氣人，王前忽長跪。賀王得貴寶，不遠王所蒞。", "求之果如言，剖出浮筠膩。白珩無顏色，垂棘有瑕累。", "在楚裂地封，入趙連城貴。秦遣李斯書，書為傳國瑞。", "秦亡漢魏傳，傳者得神器。卞和名永永，與寶不相墜。", "勸爾出門行，行難莫行易。易得還易失，難同亦難離。", "善賈識貪廉，良田無稙穉。磨劍莫磨錐，磨錐成小利。"]'),
('yuding-16','捉捕歌','元稹','唐','御定全唐诗','yuding','','[]','捉捕複捉捕，莫捉狐與兔。狐兔藏窟穴，豺狼妨道路。',289,'御定全唐詩/json/418.json','["捉捕複捉捕，莫捉狐與兔。狐兔藏窟穴，豺狼妨道路。", "道路非不妨，最憂螻蟻聚。豺狼不陷阱，螻蟻潛幽蠹。", "切切主人窗，主人輕細故。延緣蝕dw櫨，漸入棟樑柱。", "梁棟盡空虛，攻穿痕不露。主人坦然意，晝夜安寢寤。", "網羅布參差，鷹犬走回互。盡力窮窟穴，無心自還顧。", "客來歌捉捕，歌竟淚如雨。豈是惜狐兔，畏君先後誤。", "願君掃梁棟，莫遣螻蟻附。次及清道塗，盡滅豺狼步。", "主人堂上坐，行客門前度。然後巡野田，遍張畋獵具。", "外無梟獍援，內有熊羆驅。狡兔掘荒榛，妖狐熏古墓。", "用力不足多，得禽自無數。畏君聽未詳，聽客有明喻。", "蟣虱誰不輕，鯨鯢誰不惡。在海尚幽遐，在懷交穢汙。", "歌此勸主人，主人那不悟。不悟還更歌，誰能恐違忤。"]'),
('yuding-17','古築城曲五解','元稹','唐','御定全唐诗','yuding','','[]','年年塞下丁，長作出塞兵。自從冒頓強，官築遮虜城。',120,'御定全唐詩/json/418.json','["年年塞下丁，長作出塞兵。自從冒頓強，官築遮虜城。", "築城須努力，城高遮得賊。但恐賊路多，有城遮不得。", "丁口傳父言，莫問城堅不。平城被虜圍，漢劚城牆走。", "因茲請休和，虜往騎來過。半疑兼半信，築城猶嵯峨。", "築城安敢煩，願聽丁一言。請築鴻臚寺，兼愁虜出關。"]'),
('yuding-18','估客樂','元稹','唐','御定全唐诗','yuding','','[]','估客無住著，有利身則行。出門求火伴，入戶辭父兄。',408,'御定全唐詩/json/418.json','["估客無住著，有利身則行。出門求火伴，入戶辭父兄。", "父兄相教示，求利莫求名。求名有所避，求利無不營。", "火伴相勒縛，賣假莫賣誠。交關但交假，本生得失輕。", "自茲相將去，誓死意不更。亦解市頭語，便無鄰里情。", "鍮石打臂釧，糯米吹項瓔。歸來村中賣，敲作金石聲。", "村中田舍娘，貴賤不敢爭。所費百錢本，已得十倍贏。", "顏色轉光淨，飲食亦甘馨。子本頻蕃息，貨販日兼併。", "求珠駕滄海，采玉上荊衡。北買黨項馬，西擒吐蕃鸚。", "炎洲布火浣，蜀地錦織成。越婢脂肉滑，奚僮眉眼明。", "通算衣食費，不計遠近程。經遊天下遍，卻到長安城。", "城中東西市，聞客次第迎。迎客兼說客，多財為勢傾。", "客心本明黠，聞語心已驚。先問十常侍，次求百公卿。", "侯家與主第，點綴無不精。歸來始安坐，富與王者勍。", "市卒酒肉臭，縣胥家舍成。豈唯絕言語，奔走極使令。", "大兒販材木，巧識梁棟形。小兒販鹽鹵，不入州縣征。", "一身偃市利，突若截海鯨。鉤距不敢下，下則牙齒橫。", "生為估客樂，判爾樂一生。爾又生兩子，錢刀何歲平。"]'),
('yuding-0','連昌宮詞','元稹','唐','御定全唐诗','yuding','','[]','連昌宮中滿宮竹，歲久無人森似束。又有牆頭千葉桃，',360,'御定全唐詩/json/419.json','["連昌宮中滿宮竹，歲久無人森似束。又有牆頭千葉桃，", "上皇正在望仙樓，太真同憑闌幹立。樓上樓前盡珠翠，", "初過寒食一百六，店舍無煙宮樹綠。夜半月高弦索鳴，", "須臾覓得又連催，特敕街中許然燭。春嬌滿眼睡紅綃，", "逡巡大遍涼州徹，色色龜茲轟錄續。李謨擫笛傍宮牆，", "百官隊仗避岐薛，楊氏諸姨車鬥風。明年十月東都破，", "兩京定後六七年，卻尋家舍行宮前。莊園燒盡有枯井，", "往來年少說長安，玄武樓成花萼廢。去年敕使因斫竹，", "舞榭欹傾基尚在，文窗窈窕紗猶綠。塵埋粉壁舊花鈿，", "蛇出燕巢盤鬥栱，菌生香案正當衙。寢殿相連端正樓，", "指似傍人因慟哭，卻出宮門淚相續。自從此後還閉門，", "翁言野父何分別，耳聞眼見為君說。姚崇宋璟作相公，", "長官清平太守好，揀選皆言由相公。開元之末姚宋死，", "弄權宰相不記名，依稀憶得楊與李。廟謨顛倒四海搖，", "官軍又取淮西賊，此賊亦除天下寧。年年耕種宮前道，"]'),
('yuding-1','望雲騅馬歌','元稹','唐','御定全唐诗','yuding','','[]','憶昔先皇幸蜀時，八馬入谷七馬疲。肉綻筋攣四蹄脫，',346,'御定全唐詩/json/419.json','["憶昔先皇幸蜀時，八馬入谷七馬疲。肉綻筋攣四蹄脫，", "崢嶸白草眇難期，謥洞黃泉安可入。朱泚圍兵抽未盡，", "圉人初進望雲騅，彩色憔悴眾馬欺。上前噴吼如有意，", "蹄懸四局腦顆方，胯聳三山尾株直。圉人畏誚仍相惑，", "色沮聲悲仰天訴，天不遣言君未識。亞身受取白玉羈，", "龍騰魚鱉啅然驚，驥肦驢騾少顏色。七聖心迷運方厄，", "五六百里真符縣，八十四盤青山驛。掣開流電有輝光，", "齊映前導引騅頭，嚴震迎號抱騅足。路旁垂白天寶民，", "雄雄猛將李令公，收城殺賊豺狼空。天旋地轉日再中，", "禦馬齊登擬用槽，君王自試宣徽殿。圉人還進望雲騅，", "人人共惡難回跋，潛遣飛龍減芻秣。銀鞍繡韂不復施，", "登山縱似望雲騅，平地須饒紅叱撥。長安三月花垂草，", "望雲騅，爾之種類世世奇。當時項王乘爾祖，", "功成事遂身退天之道，何必隨群逐隊到死蹋紅塵。", "望雲騅，用與不用各有時，爾勿悲。"]'),
('yuding-2','和李校書新題樂府十二首：上陽白髮人','元稹','唐','御定全唐诗','yuding','','[]','天寶年中花鳥使，撩花狎鳥含春思。滿懷墨詔求嬪禦，',112,'御定全唐詩/json/419.json','["天寶年中花鳥使，撩花狎鳥含春思。滿懷墨詔求嬪禦，", "宮門一閉不復開，上陽花草青苔地。月夜閑聞洛水聲，", "近年又送數人來，自言興慶南宮至。我悲此曲將徹骨，", "諸王在合四十年，七宅六宮門戶閟。隋煬枝條襲封邑，", "何如決雍順眾流，女遣從夫男作吏。"]'),
('yuding-3','和李校書新題樂府十二首：華原磬','元稹','唐','御定全唐诗','yuding','','[]','泗濱浮石裁為磬，古樂疏音少人聽。工師小賤牙曠稀，',96,'御定全唐詩/json/419.json','["泗濱浮石裁為磬，古樂疏音少人聽。工師小賤牙曠稀，", "鏗金戛瑟徒相雜，投玉敲冰杳然零。華原軟石易追琢，", "玄宗愛樂愛新樂，梨園弟子承恩橫。霓裳才徹胡騎來，", "伯夔曾撫野獸馴，仲尼暫叩春雷盛。何時得向筍簴懸，"]'),
('yuding-4','和李校書新題樂府十二首：五弦彈','元稹','唐','御定全唐诗','yuding','','[]','趙璧五弦彈徵調，征聲巉絕何清峭。辭雄皓鶴警露啼，',120,'御定全唐詩/json/419.json','["趙璧五弦彈徵調，征聲巉絕何清峭。辭雄皓鶴警露啼，", "嗚嗚暗溜咽冰泉，殺殺霜刀澀寒鞘。促節頻催漸繁撥，", "眾樂雖同第一部，德宗皇帝常偏召。旬休節假暫歸來，", "水精簾外教貴嬪，玳瑁筵心伴中要。臣有五賢非此弦，", "三賢事漢滅暴強，四賢鎮岳甯邊徼。五賢並用調五常，"]'),
('yuding-5','和李校書新題樂府十二首：西涼伎','元稹','唐','御定全唐诗','yuding','','[]','吾聞昔日西涼州，人煙撲地桑柘稠。蒲萄酒熟恣行樂，',98,'御定全唐詩/json/419.json','["吾聞昔日西涼州，人煙撲地桑柘稠。蒲萄酒熟恣行樂，", "鄉人不識離別苦，更卒多為沉滯遊。哥舒開府設高宴，", "獅子搖光毛彩豎，胡騰醉舞筋骨柔。大宛來獻赤汗馬，", "開遠門前萬里堠，今來蹙到行原州。去京五百而近何其逼，"]'),
('yuding-6','和李校書新題樂府十二首：法曲','元稹','唐','御定全唐诗','yuding','','[]','吾聞黃帝鼓清角，弭伏熊羆舞玄鶴。舜持幹羽苗革心，',96,'御定全唐詩/json/419.json','["吾聞黃帝鼓清角，弭伏熊羆舞玄鶴。舜持幹羽苗革心，", "漢祖過沛亦有歌，秦王破陣非無作。作之宗廟見艱難，", "赤白桃李取花名，霓裳羽衣號天落。雅弄雖雲已變亂，", "女為胡婦學胡妝，伎進胡音務胡樂。火鳳聲沉多咽絕，"]'),
('yuding-7','和李校書新題樂府十二首：馴犀','元稹','唐','御定全唐诗','yuding','','[]','建中之初放馴象，遠歸林邑近交廣。獸返深山鳥構巢，',96,'御定全唐詩/json/419.json','["建中之初放馴象，遠歸林邑近交廣。獸返深山鳥構巢，", "玉盆金棧非不珍，虎啖狴牢魚食網。渡江之橘逾汶貉，", "行地無疆費傳驛，通天異物罹幽枉。乃知養獸如養人，", "脫衣推食衣食之，不若男耕女令紡。堯民不自知有堯，"]'),
('yuding-8','和李校書新題樂府十二首：立部伎','元稹','唐','御定全唐诗','yuding','','[]','胡部新聲錦筵坐，中庭漢振高音播。太宗廟樂傳子孫，',136,'御定全唐詩/json/419.json','["胡部新聲錦筵坐，中庭漢振高音播。太宗廟樂傳子孫，", "初疑遇敵身啟行，終象由文士憲左。昔日高宗常立聽，", "宋晉鄭女歌聲發，滿堂會客齊喧呵。珊珊佩玉動腰身，", "太常雅樂備宮懸，九奏未終百寮惰。惉滯難令季劄辨，", "宋沇嘗傳天寶季，法曲胡音忽相和。明年十月燕寇來，", "奸聲入耳佞入心，侏儒飽飯夷齊餓。"]'),
('yuding-9','和李校書新題樂府十二首：驃國樂','元稹','唐','御定全唐诗','yuding','','[]','驃之樂器頭象駝，音聲不合十二和。促舞跳趫筋節硬，',136,'御定全唐詩/json/419.json','["驃之樂器頭象駝，音聲不合十二和。促舞跳趫筋節硬，", "俯地呼天終不會，曲成調變當如何。德宗深意在柔遠，", "古時陶堯作天子，遜遁親聽康衢歌。又遣遒人持木鐸，", "盡令區中擊壤塊，燕及海外覃恩波。秦霸周衰古官廢，", "傳稱魚鱉亦咸若，苟能效此誠足多。借如牛馬未蒙澤，", "是非倒置自古有，驃兮驃兮誰爾訶。"]'),
('yuding-10','和李校書新題樂府十二首：胡旋女','元稹','唐','御定全唐诗','yuding','','[]','天寶欲末胡欲亂，胡人獻女能胡旋。旋得明王不覺迷，',112,'御定全唐詩/json/419.json','["天寶欲末胡欲亂，胡人獻女能胡旋。旋得明王不覺迷，", "蓬斷霜根羊角疾，竿戴朱盤火輪炫。驪珠迸珥逐飛星，", "萬過其誰辨終始，四座安能分背面。才人觀者相為言，", "巧隨清影觸處行，妙學春鶯百般囀。傾天側地用君力，", "寄言旋目與旋心，有國有家當共譴。"]'),
('yuding-11','和李校書新題樂府十二首：蠻子朝','元稹','唐','御定全唐诗','yuding','','[]','西南六詔有遺種，僻在荒陬路尋壅。部落支離君長賤，',121,'御定全唐詩/json/419.json','["西南六詔有遺種，僻在荒陬路尋壅。部落支離君長賤，", "夜防抄盜保深山，朝望煙塵上高塚。鳥道繩橋來款附，", "益州大將韋令公，頃實遭時定汧隴。自居劇鎮無他績，", "天子臨軒四方賀，朝廷無事唯端拱。漏天走馬春雨寒，", "匈奴互市歲不供，雲蠻通好轡長em。戎王養馬漸多年，"]'),
('yuding-12','和李校書新題樂府十二首：縛戎人','元稹','唐','御定全唐诗','yuding','','[]','邊頭大將差健卒，入抄禽生快於鶻。但逢赬面即捉來，',240,'御定全唐詩/json/419.json','["邊頭大將差健卒，入抄禽生快於鶻。但逢赬面即捉來，", "聖朝不殺諧至仁，遠送炎方示微罰。萬里虛勞肉食費，", "中有一人能漢語，自言家本長城窟。少年隨父戍安西，", "中原禍作邊防危，果有豺狼四來伐。蕃馬膘成正翹健，", "半夜城摧鵝雁鳴，妻啼子叫曾不歇。陰森神廟未敢依，", "平明蕃騎四面走，古墓深林盡株榾。少壯為俘頭被髡，", "暗水濺濺入舊池，平沙漫漫鋪明月。戎王遣將來安慰，", "五六十年消息絕，中間盟會又猖獗。眼穿東日望堯雲，", "常教孫子學鄉音，猶話平時好城闕。老者儻盡少者壯，", "緣邊飽喂十萬眾，何不齊驅一時發。年年但捉兩三人，"]'),
('yuding-13','和李校書新題樂府十二首：陰山道','元稹','唐','御定全唐诗','yuding','','[]','年年買馬陰山道，馬死陰山帛空耗。元和天子念女工，',139,'御定全唐詩/json/419.json','["年年買馬陰山道，馬死陰山帛空耗。元和天子念女工，", "費財為馬不獨生，耗帛傷工有他盜。臣聞平時七十萬匹馬，", "如今坰野十無一，盡在飛龍相踐暴。萬束芻茭供旦暮，", "稅戶逋逃例攤配，官司折納仍貪冒。挑紋變di力倍費，", "豪家富賈逾常制，令族清班無雅操。從騎愛奴絲布衫，", "綽立花磚鵷鳳行，雨露恩波幾時報。"]'),
('yuding-0','有鳥二十章','元稹','唐','御定全唐诗','yuding','','[]','有鳥有鳥名老鴟，鴟張貪很老不衰。似鷹指爪唯攫肉，',497,'御定全唐詩/json/420.json','["有鳥有鳥名老鴟，鴟張貪很老不衰。似鷹指爪唯攫肉，", "珠丸彈射死不去，意在護巢兼護兒。", "有鳥有鳥毛似鶴，行步雖遲性靈惡。主人但見閑慢容，", "千年不死伴靈龜，梟心鶴貌何人覺。", "有鳥有鳥如鸛雀，食蛇抱xB天姿惡。行經水滸為毒流，", "嗚呼為有白色毛，亦得乘軒謬稱鶴。", "有鳥有鳥名為鳩，毛衣軟毳心性柔。鶻緣暖足憐不吃，", "佳人許伴鵷雛食，望爾化為張氏鉤。", "有鳥有鳥名野雞，天姿耿介行步齊。主人偏養憐整頓，", "秋鷹迸逐霜鶻遠，鵩鳥護巢當晝啼。主人頻問遣妖術，", "有鳥有鳥群翠碧，毛羽短長心並窄。皆曾偷食淥池魚，", "飛飛競占嘉樹林，百鳥不爭緣鳳惜。", "有鳥有鳥群紙鳶，因風假勢童子牽。去地漸高人眼亂，", "愁爾一朝還到地，落在深泥誰複憐。", "有鳥有鳥名啄木，木中求食常不足。偏啄鄧林求一蟲，", "可憐樹上百鳥兒，有時飛向新林宿。", "有鳥有鳥眾蝙蝠，長伴佳人占華屋。妖鼠多年羽翮生，", "大廈雖存柱石傾，暗齧棟樑成蠹木。", "有鳥有鳥名為鴞，深藏孔穴難動搖。鷹鸇繞樹探不得，", "當時幸有燎原火，何不鼓風連夜燒。", "有鳥有鳥名燕子，口中未省無泥滓。春風吹送廊廡間，", "驅去驅來長信風，暫托棟樑何用喜。", "有鳥有鳥名老烏，貪癡突悖天下無。田中攫肉吞不足，", "山鴉野鵲閑受肉，鳳凰不得聞罪辜。秋鷹掣斷架上索，"]'),
('yuding-1','有酒十章','元稹','唐','御定全唐诗','yuding','','[]','有酒有酒雞初鳴，夜長睡足神慮清。悄然危坐心不平，',556,'御定全唐詩/json/420.json','["有酒有酒雞初鳴，夜長睡足神慮清。悄然危坐心不平，", "胡為沉濁以升清，矗然分畫高下程。天蒸地鬱群動萌，", "有酒有酒東方明，一杯既進吞元精。尚思天地之始名，", "胡山高屹崒海泓澄，胡不日車杲杲晝夜行，", "有酒有酒兮湛淥波，飲將愉兮氣彌和。念萬古之紛羅，", "炎始暴耶，蚩尤熾耶，軒轅戰耶，不得已耶。仁耶，", "禹功大耶，人戴之耶。益不逮耶，啟能德耶。家天下耶，", "嗚呼遠堯舜之日耶，何棄舜之速耶。辛癸虐耶，湯武革耶。", "順天意耶，公天下耶。踵夏榮嗣，私其公耶。並建萬國，", "二代而隕，守不仁耶。漢魏而降，乘其機耶。短長理亂，", "我可奈何兮一杯又進歌且歌。", "有酒有酒兮黯兮溟，仰天大呼兮，天漫漫兮高兮青。", "高兮漫兮吾孰知天否與靈。取人之仰者，", "蛇噴雲而出穴，虎嘯風兮屢鳴。汙高巢而鳳去兮，", "人懼愁兮戴榮，天寂默兮無聲。嗚呼，天在雲之上兮，", "有酒有酒香滿尊，君寧不飲開君顏。豈不知君飲此心恨，", "筋疲力竭波更大，鰭燋甲裂身已幹。有翼勸爾升九天，", "螗蜋雖怒誰爾懼，鶡旦雖啼誰爾憐。摶空意遠風來壯，", "有酒有酒歌且哀，江春例早多早梅。櫻桃桃李相續開，", "四月清和豔殘卉，芍藥翻紅蒲映水。夏龍痡毒雷雨多，", "筍牙成竹冒霜雪，榴花落地還銷歇。萬古盈虧相逐行，", "霜霰過兮複奈何，靈芝夐絕荊棘多。荊棘多兮可奈何，", "有酒有酒方爛漫，飲酣拔劍心眼亂。聲若雷砰目流電，", "嗚呼，風後力牧得親見，我可奈何兮又進一杯除健羨。"]'),
('yuding-2','華之巫','元稹','唐','御定全唐诗','yuding','','[]','有一人兮神之側，廟森森兮神默默。神默默兮可奈何，',112,'御定全唐詩/json/420.json','["有一人兮神之側，廟森森兮神默默。神默默兮可奈何，", "我能進若神之前，神不自言寄予口。爾欲見神安爾身，", "此盤不進行路難，陸有摧車舟有瀾。我聞此語長太息，", "假神力兮神未悟，行道之人不得度。我欲見神誅爾巫，", "爾巫爾巫且相保，吾民自有丘之禱。"]'),
('yuding-3','廟之神','元稹','唐','御定全唐诗','yuding','','[]','我馬煩兮釋我車，神之廟兮山之阿。予一拜而一祝，',44,'御定全唐詩/json/420.json','["我馬煩兮釋我車，神之廟兮山之阿。予一拜而一祝，", "歌曰：今耶，古耶，有耶，無耶。福不自神耶，"]'),
('yuding-0','村花晚','元稹','唐','御定全唐诗','yuding','','[]','三春已暮桃李傷，棠梨花白蔓菁黃。村中女兒爭摘將，',58,'御定全唐詩/json/421.json','["三春已暮桃李傷，棠梨花白蔓菁黃。村中女兒爭摘將，", "非無後秀與孤芳，奈爾千株萬頃之茫茫。", "天公此意何可量，長教爾輩時節長。"]'),
('yuding-1','紫躑躅','元稹','唐','御定全唐诗','yuding','','[]','紫躑躅，滅紫攏裙倚山腹。文君新寡乍歸來，',80,'御定全唐詩/json/421.json','["紫躑躅，滅紫攏裙倚山腹。文君新寡乍歸來，", "去年春別湘水頭，今年夏見青山曲。迢迢遠在青山上，", "樂躑躅，我向通州爾幽獨。可憐今夜宿青山，", "山空月午夜無人，何處知我顏如玉。"]'),
('yuding-2','山枇杷','元稹','唐','御定全唐诗','yuding','','[]','山枇杷，花似牡丹殷潑血。往年乘傳過青山，',128,'御定全唐詩/json/421.json','["山枇杷，花似牡丹殷潑血。往年乘傳過青山，", "緊搏紅袖欲支頤，慢解絳囊初破結。金線叢飄繁蕊亂，", "亞水依岩半傾側，籠雲隱霧多愁絕。綠珠語盡身欲投，", "說向閒人人不聽，曾向樂天時一說。昨來穀口先相問，", "山枇杷，爾托深山何太拙。天高萬里看不精，", "因爾幽芳喻昔賢，磻溪冷坐權門咽。"]'),
('yuding-3','樹上烏','元稹','唐','御定全唐诗','yuding','','[]','樹上烏，洲中有樹巢若鋪。百巢一樹知幾烏，',55,'御定全唐詩/json/421.json','["樹上烏，洲中有樹巢若鋪。百巢一樹知幾烏，", "靈蛇萬古唯一珠，豈可抨彈千萬億。", "吾不會天教爾輩多子孫，告訴天公天不言。"]'),
('yuding-4','琵琶歌','元稹','唐','御定全唐诗','yuding','','[]','琵琶宮調八十一，旋宮三調彈不出。玄宗偏許賀懷智，',336,'御定全唐詩/json/421.json','["琵琶宮調八十一，旋宮三調彈不出。玄宗偏許賀懷智，", "澒聲少得似雷吼，纏弦不敢彈羊皮。人間奇事會相續，", "管兒不作供奉兒，拋在東都雙鬢絲。逢人便請送杯盞，", "著作曾邀連夜宿，中碾春溪華新綠。平明船載管兒行，", "涼州大遍最豪嘈，六么散序多籠撚。我聞此曲深賞奇，", "淚垂捍撥朱弦濕，冰泉嗚咽流鶯澀。因茲彈作雨霖鈴，", "低回慢弄關山思，坐對燕然秋月寒。月寒一聲深殿磬，", "自茲聽後六七年，管兒在洛我朝天。遊想慈恩杏園裏，", "今春制獄正撩亂，晝夜推囚心似灰。暫輟歸時尋著作，", "是夕青春值三五，花枝向月雲含吐。著作施樽命管兒，", "猿鳴雪岫來三峽，鶴唳晴空聞九霄。逡巡彈得六么徹，", "我為含淒歎奇絕，許作長歌始終說。藝奇思寡塵事多，", "歌此歌，寄管兒。管兒管兒憂爾衰，爾衰之後繼者誰。", "繼之無乃在鐵山，鐵山已近曹穆間。性靈甚好功猶淺，"]'),
('yuding-5','小胡笳引','元稹','唐','御定全唐诗','yuding','','[]','雷氏金徽琴，王君寶重輕千金。三峽流中將得來，',94,'御定全唐詩/json/421.json','["雷氏金徽琴，王君寶重輕千金。三峽流中將得來，", "哀笳慢指董家本，薑生得之妙思忖。泛徽胡雁咽蕭蕭，", "潺湲疑是雁鸊鵜，砉騞如聞發鳴鏑。流宮變征漸幽咽，", "哀弦已罷春恨長，恨長何恨懷我鄉。我鄉安在長城窟，"]'),
('yuding-6','去杭州','元稹','唐','御定全唐诗','yuding','','[]','房杜王魏之子孫，雖及百代為清門。駿骨鳳毛真可貴，',232,'御定全唐詩/json/421.json','["房杜王魏之子孫，雖及百代為清門。駿骨鳳毛真可貴，", "與君言語見君性，靈府坦蕩消塵煩。自茲心洽跡亦洽，", "每出新詩共聯綴，閑因醉舞相牽援。時尋沙尾楓林夕，", "簡書五府已再至，波濤萬里酬一言。為君再拜贈君語，", "永寧昔在掄鑒表，沙汰沉濁澄浚源。君今取友由取士，", "今君佐藩如佐主，得不陳露酬所恩。昔公為善日不足，", "昔公令子尚貴主，公執舅禮婦執笲。返拜之儀自此絕，", "斯言皆為書佩帶，然後別袂乃可捫。別袂可捫不可解，", "翻風駕浪拍何處，直指杭州由上元。上元蕭寺基址在，", "得得為題羅刹石，古來非獨伍員冤。"]'),
('yuding-7','南家桃','元稹','唐','御定全唐诗','yuding','','[]','南家桃樹深紅色，日照露光看不得。樹小花狂風易吹，',40,'御定全唐詩/json/421.json','["南家桃樹深紅色，日照露光看不得。樹小花狂風易吹，", "更待明年花滿枝，一年迢遞空相憶。"]'),
('yuding-8','志堅師','元稹','唐','御定全唐诗','yuding','','[]','嵩山老僧披破衲，七十八年三十臘。靈武朝天遼海征，',40,'御定全唐詩/json/421.json','["嵩山老僧披破衲，七十八年三十臘。靈武朝天遼海征，", "淮西未返半年前，已見淮西陣雲合。"]'),
('yuding-9','答子蒙','元稹','唐','御定全唐诗','yuding','','[]','報盧君，門外雪紛紛。紛紛門外雪，城中鼓聲絕。',38,'御定全唐詩/json/421.json','["報盧君，門外雪紛紛。紛紛門外雪，城中鼓聲絕。", "強梁禦史人覷步，安得夜開沽酒戶。"]'),
('yuding-10','辛夷花','元稹','唐','御定全唐诗','yuding','','[]','問君辛夷花，君言已斑駁。不畏辛夷不爛開，',44,'御定全唐詩/json/421.json','["問君辛夷花，君言已斑駁。不畏辛夷不爛開，", "明日不推緣國忌，依前不得花前醉。韓員外家好辛夷，"]'),
('yuding-11','廳前柏','元稹','唐','御定全唐诗','yuding','','[]','廳前柏，知君曾對羅希奭。我本癲狂耽酒人，',20,'御定全唐詩/json/421.json','["廳前柏，知君曾對羅希奭。我本癲狂耽酒人，"]'),
('yuding-12','夜別筵','元稹','唐','御定全唐诗','yuding','','[]','夜長酒闌燈花長，燈花落地複落床。似我別淚三四行，',24,'御定全唐詩/json/421.json','["夜長酒闌燈花長，燈花落地複落床。似我別淚三四行，"]'),
('yuding-13','三泉驛','元稹','唐','御定全唐诗','yuding','','[]','三泉驛內逢上巳，新葉趨塵花落地。勸君滿盞君莫辭，',24,'御定全唐詩/json/421.json','["三泉驛內逢上巳，新葉趨塵花落地。勸君滿盞君莫辭，"]'),
('yuding-14','何滿子歌','元稹','唐','御定全唐诗','yuding','','[]','何滿能歌能宛轉，天寶年中世稱罕。嬰刑系在囹圄間，',168,'御定全唐詩/json/421.json','["何滿能歌能宛轉，天寶年中世稱罕。嬰刑系在囹圄間，", "便將何滿為曲名，禦譜親題樂府纂。魚家入內本領絕，", "我來湖外拜君侯，正值灰飛仲春管。廣宴江亭為我開，", "翠蛾轉盼搖雀釵，碧袖歌垂翻鶴卵。定面凝眸一聲發，", "犯羽含商移調態，留情度意拋弦管。湘妃寶瑟水上來，", "冰含遠溜咽還通，鶯泥晚花啼漸懶。斂黛吞聲若自冤，", "古者諸侯饗外賓，鹿鳴三奏陳圭瓚。何如有態一曲終，"]'),
('yuding-15','通州丁溪館夜別李景信三首','元稹','唐','御定全唐诗','yuding','','[]','月濛濛兮山掩掩，束束別魂眉斂斂。蠡盞覆時天欲明，',72,'御定全唐詩/json/421.json','["月濛濛兮山掩掩，束束別魂眉斂斂。蠡盞覆時天欲明，", "水環環兮山簇簇，啼鳥聲聲婦人哭。離床別臉睡還開，", "雨瀟瀟兮鵑咽咽，傾冠倒枕燈臨滅。倦僮呼喚應複眠，"]'),
('yuding-16','酬鄭從事四年九月宴望海亭，次用舊韻','元稹','唐','御定全唐诗','yuding','','[]','海亭樹木何蘢蔥，寒光透坼秋玲瓏。湖山四面爭氣色，',144,'御定全唐詩/json/421.json','["海亭樹木何蘢蔥，寒光透坼秋玲瓏。湖山四面爭氣色，", "嵌空古墓失文種，突兀怪石疑防風。舟船駢比有宗侶，", "興餘望劇酒四坐，歌聲舞豔煙霞中。酒酣從事歌送我，", "我聞此曲深歎息，唧唧不異秋草蟲。憶年十五學構廈，", "妝梳伎女上樓榭，止欲歡樂微茫躬。雖無趣尚慕賢聖，", "君今勸我酒太醉，醉語不復能沖融。勸君莫學虛富貴，"]'),
('yuding-0','夢遊春七十韻','元稹','唐','御定全唐诗','yuding','','[]','昔歲夢遊春，夢游何所遇。夢入深洞中，果遂平生趣。',576,'御定全唐詩/json/422.json','["昔歲夢遊春，夢游何所遇。夢入深洞中，果遂平生趣。", "清泠淺漫流，畫舫蘭篙渡。過盡萬株桃，盤旋竹林路。", "長廊抱小樓，門牖相回互。樓下雜花叢，叢邊繞鴛鷺。", "池光漾霞影，曉日初明煦。未敢上階行，頻移曲池步。", "烏龍不作聲，碧玉曾相慕。漸到簾幕間，裴回意猶懼。", "閑窺東西合，奇玩參差布。隔子碧油糊，駝鉤紫金鍍。", "逡巡日漸高，影響人將寤。鸚鵡饑亂鳴，嬌娃睡猶怒。", "簾開侍兒起，見我遙相諭。鋪設繡紅茵，施張鈿妝具。", "潛褰翡翠帷，瞥見珊瑚樹。不辨花貌人，空驚香若霧。", "身回夜合偏，態斂晨霞聚。睡臉桃破風，汗妝蓮委露。", "叢梳百葉髻，金蹙重台屨。紕軟鈿頭裙，玲瓏合歡袴。", "鮮妍脂粉薄，暗淡衣裳故。最似紅牡丹，雨來春欲暮。", "夢魂良易驚，靈境難久寓。夜夜望天河，無由重沿溯。", "結念心所期，返如禪頓悟。覺來八九年，不向花回顧。", "雜合兩京春，喧闐眾禽護。我到看花時，但作懷仙句。", "浮生轉經歷，道性尤堅固。近作夢仙詩，亦知勞肺腑。", "一夢何足雲，良時事婚娶。當年二紀初，嘉節三星度。", "朝蕣玉佩迎，高松女蘿附。韋門正全盛，出入多歡裕。", "甲第漲清池，鳴騶引朱輅。廣榭舞萎蕤，長筵賓雜厝。", "青春詎幾日，華實潛幽蠹。秋月照潘郎，空山懷謝傅。", "紅樓嗟壞壁，金穀迷荒戍。石壓破闌幹，門摧舊梐枑。", "雖雲覺夢殊，同是終難駐。悰緒竟何如，棼絲不成絇。", "卓女白頭吟，阿嬌金屋賦。重璧盛姬台，青塚明妃墓。", "盡委窮塵骨，皆隨流波注。幸有古如今，何勞縑比素。"]'),
('yuding-1','桐花落','元稹','唐','御定全唐诗','yuding','','[]','莎草遍桐陰，桐花滿莎落。蓋覆相團圓，可憐無厚薄。',144,'御定全唐詩/json/422.json','["莎草遍桐陰，桐花滿莎落。蓋覆相團圓，可憐無厚薄。", "昔歲幽院中，深堂下簾幕。同在後門前，因論花好惡。", "君誇沉檀樣，雲是指撝作。暗澹滅紫花，句連蹙金萼。", "都繡六七枝，鬥成雙孔雀。尾上稠疊花，又將金解絡。", "我愛看不已，君煩睡先著。我作繡桐詩，系君裙帶著。", "別來苦修道，此意都蕭索。今日竟相牽，思量偶然錯。"]'),
('yuding-2','夢昔時','元稹','唐','御定全唐诗','yuding','','[]','閑窗結幽夢，此夢誰人知。夜半初得處，天明臨去時。',48,'御定全唐詩/json/422.json','["閑窗結幽夢，此夢誰人知。夜半初得處，天明臨去時。", "山川已久隔，雲雨兩無期。何事來相感，又成新別離。"]'),
('yuding-3','恨妝成','元稹','唐','御定全唐诗','yuding','','[]','曉日穿隙明，開帷理妝點。傅粉貴重重，施朱憐冉冉。',72,'御定全唐詩/json/422.json','["曉日穿隙明，開帷理妝點。傅粉貴重重，施朱憐冉冉。", "柔鬟背額垂，叢鬢隨釵斂。凝翠暈蛾眉，輕紅拂花臉。", "滿頭行小梳，當面施圓靨。最恨落花時，妝成獨披掩。"]'),
('yuding-4','古決絕詞','元稹','唐','御定全唐诗','yuding','','[]','乍可為天上牽牛織女星，不願為庭前紅槿枝。',243,'御定全唐詩/json/422.json','["乍可為天上牽牛織女星，不願為庭前紅槿枝。", "七月七日一相見，相見故心終不移。那能朝開暮飛去，", "握手苦相問，竟不言後期。君情既決絕，妾意已參差。", "借如死生別，安得長苦悲。", "噫春冰之將泮，何予懷之獨結。有美一人，於焉曠絕。", "一日不見，比一日於三年，況三年之曠別。", "水得風兮小而已波，筍在苞兮高不見節。矧桃李之當春，", "幸他人之既不我先，又安能使他人之終不我奪。已焉哉，", "夜夜相抱眠，幽懷尚沉結。那堪一年事，長遣一宵說。", "但感久相思，何暇暫相悅。虹橋薄夜成，龍駕侵晨列。", "生憎野鶴性遲回，死恨天雞識時節。曙色漸曈曈，"]'),
('yuding-5','櫻桃花','元稹','唐','御定全唐诗','yuding','','[]','櫻桃花，一枝兩枝千萬朵。花磚曾立摘花人，',20,'御定全唐詩/json/422.json','["櫻桃花，一枝兩枝千萬朵。花磚曾立摘花人，"]'),
('yuding-6','曹十九舞綠鈿','元稹','唐','御定全唐诗','yuding','','[]','急管清弄頻，舞衣才攬結。含情獨搖手，雙袖參差列。',48,'御定全唐詩/json/422.json','["急管清弄頻，舞衣才攬結。含情獨搖手，雙袖參差列。", "騕褭柳牽絲，炫轉風回雪。凝眄嬌不移，往往度繁節。"]'),
('yuding-7','閨晚','元稹','唐','御定全唐诗','yuding','','[]','紅裙委磚階，玉爪kO朱橘。素臆光如砑，明瞳豔凝溢。',49,'御定全唐詩/json/422.json','["紅裙委磚階，玉爪kO朱橘。素臆光如砑，明瞳豔凝溢。", "調弦不成曲，學書徒弄筆。夜色侵洞房，春煙透簾出。"]'),
('yuding-8','曉將別','元稹','唐','御定全唐诗','yuding','','[]','風露曉淒淒，月下西牆西。行人帳中起，思婦枕前啼。',48,'御定全唐詩/json/422.json','["風露曉淒淒，月下西牆西。行人帳中起，思婦枕前啼。", "屑屑命僮禦，晨裝儼已齊。將去複攜手，日高方解攜。"]'),
('yuding-9','薔薇架','元稹','唐','御定全唐诗','yuding','','[]','五色階前架，一張籠上被。殷紅稠疊花，半綠鮮明地。',48,'御定全唐詩/json/422.json','["五色階前架，一張籠上被。殷紅稠疊花，半綠鮮明地。", "風蔓羅裙帶，露英蓮臉淚。多逢走馬郎，可惜簾邊思。"]'),
('yuding-10','月暗','元稹','唐','御定全唐诗','yuding','','[]','月暗燈殘面牆泣，羅纓鬥重知啼濕。真珠簾斷蝙蝠飛，',40,'御定全唐詩/json/422.json','["月暗燈殘面牆泣，羅纓鬥重知啼濕。真珠簾斷蝙蝠飛，", "君王掌上容一人，更有輕身何處立。"]'),
('yuding-11','新秋','元稹','唐','御定全唐诗','yuding','','[]','旦暮已淒涼，離人遠思忙。夏衣臨曉薄，秋影入簷長。',48,'御定全唐詩/json/422.json','["旦暮已淒涼，離人遠思忙。夏衣臨曉薄，秋影入簷長。", "前事風隨扇，歸心燕在梁。殷勤寄牛女，河漢正相望。"]'),
('yuding-12','贈雙文','元稹','唐','御定全唐诗','yuding','','[]','豔極翻含怨，憐多轉自嬌。有時還暫笑，閑坐愛無憀。',48,'御定全唐詩/json/422.json','["豔極翻含怨，憐多轉自嬌。有時還暫笑，閑坐愛無憀。", "曉月行看墮，春酥見欲消。何因肯垂手，不敢望回腰。"]'),
('yuding-13','春別','元稹','唐','御定全唐诗','yuding','','[]','幽芳本未闌，君去蕙花殘。河漢秋期遠，關山世路難。',48,'御定全唐詩/json/422.json','["幽芳本未闌，君去蕙花殘。河漢秋期遠，關山世路難。", "雲屏留粉絮，風幌引香蘭。腸斷回文錦，春深獨自看。"]'),
('yuding-14','和樂天示楊瓊','元稹','唐','御定全唐诗','yuding','','[]','我在江陵少年日，知有楊瓊初喚出。腰身瘦小歌圓緊，',88,'御定全唐詩/json/422.json','["我在江陵少年日，知有楊瓊初喚出。腰身瘦小歌圓緊，", "青衫玉貌何處去，安得紅旗遮頭白。我語楊瓊瓊莫語，", "楊瓊為我歌送酒，爾憶江陵縣中否。江陵王令骨為灰，", "我今賀爾亦自多，爾得老成余白首。"]'),
('yuding-15','魚中素','元稹','唐','御定全唐诗','yuding','','[]','重疊魚中素，幽緘手自開。斜紅餘淚跡，知著臉邊來。',24,'御定全唐詩/json/422.json','["重疊魚中素，幽緘手自開。斜紅餘淚跡，知著臉邊來。"]'),
('yuding-16','代九九','元稹','唐','御定全唐诗','yuding','','[]','昔年桃李月，顏色共花宜。回臉蓮初破，低蛾柳並垂。',240,'御定全唐詩/json/422.json','["昔年桃李月，顏色共花宜。回臉蓮初破，低蛾柳並垂。", "望山多倚樹，弄水愛臨池。遠被登樓識，潛因倒影窺。", "隔林徒想像，上砌轉逶迤。謾擲庭中果，虛攀牆外枝。", "強持文玉佩，求結麝香縭。阿母憐金重，親兄要馬騎。", "把將嬌小女，嫁與冶游兒。自隱勤勤索，相要事事隨。", "每常同坐臥，不省暫參差。才學羞兼妒，何言寵便移。", "青春來易皎，白日誓先虧。僻性嗔來見，邪行醉後知。", "別床鋪枕席，當面指瑕疵。妾貌應猶在，君情遽若斯。", "的成終世恨，焉用此宵為。鸞鏡燈前撲，鴛衾手下隳。", "參商半夜起，琴瑟一聲離。努力新叢豔，狂風次第吹。"]'),
('yuding-17','盧十九子蒙吟盧七員外洛川懷古六韻，命餘和','元稹','唐','御定全唐诗','yuding','','[]','聞道盧明府，閑行詠洛神。浪圓疑靨笑，波鬥憶眉顰。',72,'御定全唐詩/json/422.json','["聞道盧明府，閑行詠洛神。浪圓疑靨笑，波鬥憶眉顰。", "蹀躞橋頭馬，空蒙水上塵。草芽猶犯雪，冰岸欲消春。", "寓目終無限，通辭未有因。子蒙將此曲，吟似獨眠人。"]'),
('yuding-18','劉、阮妻二首','元稹','唐','御定全唐诗','yuding','','[]','仙洞千年一度閑，等閒偷入又偷回。',64,'御定全唐詩/json/422.json','["仙洞千年一度閑，等閒偷入又偷回。", "桃花飛盡東風起，何處消沉去不來。", "芙蓉脂肉綠雲鬟，罨畫樓臺青黛山。", "千樹桃花萬年藥，不知何事憶人間。"]'),
('yuding-19','桃花','元稹','唐','御定全唐诗','yuding','','[]','桃花淺深處，似勻深淺妝。春風助腸斷，吹落白衣裳。',24,'御定全唐詩/json/422.json','["桃花淺深處，似勻深淺妝。春風助腸斷，吹落白衣裳。"]'),
('yuding-20','暮秋','元稹','唐','御定全唐诗','yuding','','[]','看著牆西日又沉，步廊回合戟門深。',32,'御定全唐詩/json/422.json','["看著牆西日又沉，步廊回合戟門深。", "棲烏滿樹聲聲絕，小玉上床鋪夜衾。"]'),
('yuding-21','壓牆花','元稹','唐','御定全唐诗','yuding','','[]','野性大都迷裏巷，愛將高樹記人家。',32,'御定全唐詩/json/422.json','["野性大都迷裏巷，愛將高樹記人家。", "春來偏認平陽宅，為見牆頭拂面花。"]'),
('yuding-22','舞腰','元稹','唐','御定全唐诗','yuding','','[]','裙裾旋旋手迢迢，不趁音聲自趁嬌。',32,'御定全唐詩/json/422.json','["裙裾旋旋手迢迢，不趁音聲自趁嬌。", "未必諸郎知曲誤，一時偷眼為回腰。"]'),
('yuding-23','白衣裳二首','元稹','唐','御定全唐诗','yuding','','[]','雨濕輕塵隔院香，玉人初著白衣裳。',64,'御定全唐詩/json/422.json','["雨濕輕塵隔院香，玉人初著白衣裳。", "半含惆悵閑看繡，一朵梨花壓象床。", "藕絲衫子柳花裙，空著沈香慢火熏。", "閑倚屏風笑周昉，枉拋心力畫朝雲。"]'),
('yuding-24','憶事','元稹','唐','御定全唐诗','yuding','','[]','夜深閑到戟門邊，卻繞行廊又獨眠。',32,'御定全唐詩/json/422.json','["夜深閑到戟門邊，卻繞行廊又獨眠。", "明月滿庭池水淥，桐花垂在翠簾前。"]'),
('yuding-25','寄舊詩與薛濤，因成長句','元稹','唐','御定全唐诗','yuding','','[]','詩篇調態人皆有，細膩風光我獨知。月夜詠花憐暗澹，',40,'御定全唐詩/json/422.json','["詩篇調態人皆有，細膩風光我獨知。月夜詠花憐暗澹，", "老大不能收拾得，與君閑似好男兒。"]'),
('yuding-26','友封體','元稹','唐','御定全唐诗','yuding','','[]','雨送浮涼夏簟清，小樓腰褥怕單輕。微風暗度香囊轉，',40,'御定全唐詩/json/422.json','["雨送浮涼夏簟清，小樓腰褥怕單輕。微風暗度香囊轉，", "頻頻聞動中門鎖，桃葉知嗔未敢迎。"]'),
('yuding-27','看花','元稹','唐','御定全唐诗','yuding','','[]','努力少年求好官，好花須是少年看。',32,'御定全唐詩/json/422.json','["努力少年求好官，好花須是少年看。", "君看老大逢花樹，未折一枝心已闌。"]'),
('yuding-28','斑竹','元稹','唐','御定全唐诗','yuding','','[]','一枝斑竹渡湘沅，萬里行人感別魂。',32,'御定全唐詩/json/422.json','["一枝斑竹渡湘沅，萬里行人感別魂。", "知是娥皇廟前物，遠隨風雨送啼痕。"]'),
('yuding-29','箏','元稹','唐','御定全唐诗','yuding','','[]','莫愁私地愛王昌，夜夜箏聲怨隔牆。火鳳有凰求不得，',40,'御定全唐詩/json/422.json','["莫愁私地愛王昌，夜夜箏聲怨隔牆。火鳳有凰求不得，", "死恨相如新索婦，枉將心力為他狂。"]'),
('yuding-30','春曉','元稹','唐','御定全唐诗','yuding','','[]','半欲天明半未明，醉聞花氣睡聞鶯。',32,'御定全唐詩/json/422.json','["半欲天明半未明，醉聞花氣睡聞鶯。", "𤞇兒撼起鐘聲動，二十年前曉寺情。"]'),
('yuding-31','所思二首','元稹','唐','御定全唐诗','yuding','','[]','庾亮樓中初見時，武昌春柳似腰肢。',64,'御定全唐詩/json/422.json','["庾亮樓中初見時，武昌春柳似腰肢。", "相逢相失還如夢，為雨為雲今不知。", "鄂渚濛濛煙雨微，女郎魂逐暮雲歸。", "只應長在漢陽渡，化作鴛鴦一隻飛。"]'),
('yuding-32','鶯鶯詩','元稹','唐','御定全唐诗','yuding','','[]','殷紅淺碧舊衣裳，取次梳頭暗淡妝。夜合帶煙籠曉日，',40,'御定全唐詩/json/422.json','["殷紅淺碧舊衣裳，取次梳頭暗淡妝。夜合帶煙籠曉日，", "頻動橫波嗔阿母，等閒教見小兒郎。"]'),
('yuding-33','離思五首','元稹','唐','御定全唐诗','yuding','','[]','自愛殘妝曉鏡中，環釵謾篸綠絲叢。',160,'御定全唐詩/json/422.json','["自愛殘妝曉鏡中，環釵謾篸綠絲叢。", "須臾日射燕脂頰，一朵紅蘇旋欲融。", "山泉散漫繞階流，萬樹桃花映小樓。", "閑讀道書慵未起，水晶簾下看梳頭。", "紅羅著壓逐時新，吉了花紗嫩麹塵。", "第一莫嫌材地弱，些些紕縵最宜人。", "曾經滄海難為水，除卻巫山不是雲。", "取次花叢懶回顧，半緣修道半緣君。", "尋常百種花齊發，偏摘梨花與白人。", "今日江頭兩三樹，可憐和葉度殘春。"]'),
('yuding-34','雜憶五首','元稹','唐','御定全唐诗','yuding','','[]','今年寒食月無光，夜色才侵已上床。',160,'御定全唐詩/json/422.json','["今年寒食月無光，夜色才侵已上床。", "憶得雙文通內裏，玉櫳深處暗聞香。", "花籠微月竹籠煙，百尺絲繩拂地懸。", "憶得雙文人靜後，潛教桃葉送秋千。", "寒輕夜淺繞回廊，不辨花叢暗辨香。", "憶得雙文朧月下，小樓前後捉迷藏。", "山榴似火葉相兼，亞拂磚階半拂簷。", "憶得雙文獨披掩，滿頭花草倚新簾。", "春冰消盡碧波湖，漾影殘霞似有無。", "憶得雙文衫子薄，鈿頭雲映褪紅酥。"]'),
('yuding-35','有所教','元稹','唐','御定全唐诗','yuding','','[]','莫畫長眉畫短眉，斜紅傷豎莫傷垂。',32,'御定全唐詩/json/422.json','["莫畫長眉畫短眉，斜紅傷豎莫傷垂。", "人人總解爭時勢，都大須看各自宜。"]'),
('yuding-36','襄陽為盧竇紀事','元稹','唐','御定全唐诗','yuding','','[]','帝下真符召玉真，偶逢遊女暫相親。',160,'御定全唐詩/json/422.json','["帝下真符召玉真，偶逢遊女暫相親。", "素書三卷留為贈，從向人間說向人。", "風弄花枝月照階，醉和春睡倚香懷。", "依稀似覺雙環動，潛被蕭郎卸玉釵。", "鶯聲撩亂曙燈殘，暗覓金釵動曉寒。", "猶帶春酲懶相送，櫻桃花下隔簾看。", "琉璃波面月籠煙，暫逐蕭郎走上天。", "今日歸時最腸斷，回江還是夜來船。", "花枝臨水複臨堤，閑照江流亦照泥。", "千萬春風好抬舉，夜來曾有鳳凰棲。"]'),
('yuding-37','會真詩三十韻','元稹','唐','御定全唐诗','yuding','','[]','微月透簾櫳，螢光度碧空。遙天初縹緲，低樹漸蔥蘢。',360,'御定全唐詩/json/422.json','["微月透簾櫳，螢光度碧空。遙天初縹緲，低樹漸蔥蘢。", "龍吹過庭竹，鸞歌拂井桐。羅綃垂薄霧，環佩響輕風。", "絳節隨金母，雲心捧玉童。更深人悄悄，晨會雨濛濛。", "珠瑩光文履，花明隱繡櫳。寶釵行彩鳳，羅帔掩丹虹。", "言自瑤華浦，將朝碧帝宮。因游李城北，偶向宋家東。", "戲調初微拒，柔情已暗通。低鬟蟬影動，回步玉塵蒙。", "轉面流花雪，登床抱綺叢。鴛鴦交頸舞，翡翠合歡籠。", "眉黛羞頻聚，朱唇暖更融。氣清蘭蕊馥，膚潤玉肌豐。", "無力慵移腕，多嬌愛斂躬。汗光珠點點，發亂綠松松。", "方喜千年會，俄聞五夜窮。留連時有限，繾綣意難終。", "慢臉含愁態，芳詞誓素衷。贈環明運合，留結表心同。", "啼粉流清鏡，殘燈繞暗蟲。華光猶冉冉，旭日漸曈曈。", "警乘還歸洛，吹簫亦上嵩。衣香猶染麝，枕膩尚殘紅。", "冪冪臨塘草，飄飄思渚蓬。素琴鳴怨鶴，清漢望歸鴻。", "海闊誠難度，天高不易沖。行雲無處所，蕭史在樓中。"]'),
('yuding-38','古豔詩二首','元稹','唐','御定全唐诗','yuding','','[]','春來頻到宋家東，垂袖開懷待好風。',64,'御定全唐詩/json/422.json','["春來頻到宋家東，垂袖開懷待好風。", "鶯藏柳暗無人語，惟有牆花滿樹紅。", "深院無人草樹光，嬌鶯不語趁陰藏。", "等閒弄水浮花片，流出門前賺阮郎。"]'),
('yuding-0','奉和浙西大夫李德裕述夢四十韻大夫本題言贈於夢中詩賦以寄一二僚友故今所和者亦止述翰苑舊遊而已次本韻','元稹','唐','御定全唐诗','yuding','','[]','聞有池塘什，還因夢寐遭。攀禾工類蔡，詠豆敏過曹。',480,'御定全唐詩/json/423.json','["聞有池塘什，還因夢寐遭。攀禾工類蔡，詠豆敏過曹。", "莊蝶玄言秘，羅禽藻思高。戈矛排筆陣，貔虎讓文韜。", "彩繢鸞凰頸，權奇驥騄髦。神樞千里應，華袞一言褒。", "李廣留飛箭，王祥得佩刀。傳乘司隸馬，繼染翰林毫。", "辨穎□超脫，詞鋒豈足櫜。金剛錐透玉，鑌鐵劍吹毛。", "顧我曾陪附，思君正郁陶。近酬新樂錄，仍寄續離騷。", "阿閣偏隨鳳，方壺共跨鼇。借騎銀杏葉，橫賜錦垂萄。", "冰井分珍果，金瓶貯禦醪。獨辭珠有戒，廉取玉非叨。", "麥紙侵紅點，蘭燈焰碧高。代予言不易，承聖旨偏勞。", "繞月同棲鵲，驚風比夜獒。吏傳開鎖契，神撼引鈴絛。", "渥澤深難報，危心過自操。犯顏誠懇懇，騰口懼忉忉。", "佩寵雖緺綬，安貧尚葛袍。賓親多謝絕，延薦必英豪。", "分阻杯盤會，閑隨寺觀遨。祇園一林杏，仙洞萬株桃。", "澥海滄波減，昆明劫火熬。未陪登鶴駕，已訃墮烏號。", "痛淚過江浪，冤聲出海濤。尚看恩詔濕，已夢壽宮牢。", "再造承天寶，新持濟巨篙。猶憐弊簪履，重委舊旌旄。", "北望心彌苦，西回首屢搔。九霄難就日，兩浙僅容舠。", "暮竹寒窗影，衰楊古郡濠。魚蝦集橘市，鶴鸛起亭皋。", "朽刃休沖鬥，良弓枉在弢。早彎摧虎兕，便鑄墾蓬蒿。", "漁艇宜孤棹，樓船稱萬艘。量材分用處，終不學滔滔。"]'),
('yuding-1','自述','元稹','唐','御定全唐诗','yuding','','[]','延英引對碧衣郎，江硯宣毫各別床。',32,'御定全唐詩/json/423.json','["延英引對碧衣郎，江硯宣毫各別床。", "天子下簾親考試，宮人手裏過茶湯。"]'),
('yuding-2','春分投簡陽明洞天作','元稹','唐','御定全唐诗','yuding','','[]','中分春一半，今日半春徂。老惜光陰甚，慵牽興緒孤。',576,'御定全唐詩/json/423.json','["中分春一半，今日半春徂。老惜光陰甚，慵牽興緒孤。", "偶成投秘簡，聊得泛平湖。郡邑移仙界，山川展畫圖。", "旌旗遮嶼浦，士女滿闉闍。似木吳兒勁，如花越女姝。", "牛儂驚力直，蠶妾笑睢盱。怪我攜章甫，嘲人托鷓鴣。", "閭閻隨地勝，風俗與華殊。跣足沿流婦，丫頭避役奴。", "雕題雖少有，雞卜尚多巫。鄉味尤珍蛤，家神愛事烏。", "舟船通海嶠，田種繞城隅。櫛比千艘合，袈裟萬頃鋪。", "亥茶闐小市，漁父隔深蘆。日腳斜穿浪，雲根遠曳蒲。", "凝風花氣度，新雨草芽蘇。粉壞梅辭萼，紅含杏綴珠。", "薅餘秧漸長，燒後葑猶枯。綠綟高懸柳，青錢密辮榆。", "馴鷗眠淺瀨，驚雉迸平蕪。水靜王餘見，山空謝豹呼。", "燕狂捎蛺蝶，螟掛集蒲盧。淺碧鶴新卵，深黃鵝嫩雛。", "村扉以白板，寺壁耀赬糊。禹廟才離郭，陳莊恰半途。", "石帆何峭嶢，龍瑞本縈紆。穴為探符坼，潭因失箭刳。", "堤形彎熨斗，峰勢踴香爐。幢蓋迎三洞，煙霞貯一壺。", "桃枝蟠複直，桑樹亞還扶。鱉解稱從事，松堪作大夫。", "榮光飄殿閣，虛籟合笙竽。庭狎仙翁鹿，池游縣令鳧。", "君心除健羨，扣寂入虛無。岡蹋翻星紀，章飛動帝樞。", "東皇提白日，北斗下玄都。騎吏裙皆紫，科車幰盡朱。", "地侯鞭社伯，海若跨天吳。霧噴雷公怒，煙揚灶鬼趨。", "投壺憐玉女，噀飯笑麻姑。果實經千歲，衣裳重六銖。", "瓊杯傳素液，金匕進雕胡。掌裏承來露，柈中釣得鱸。", "菌生悲局促，柯爛覺須臾。稊米休言聖，醯雞益伏愚。", "鼓鼙催暝色，簪組縛微軀。遂別真徒侶，還來世路衢。"]'),
('yuding-3','春遊','元稹','唐','御定全唐诗','yuding','','[]','酒戶年年減，山行漸漸難。欲終心懶慢，轉恐興闌散。',72,'御定全唐詩/json/423.json','["酒戶年年減，山行漸漸難。欲終心懶慢，轉恐興闌散。", "鏡水波猶冷，稽峰雪尚殘。不能辜物色，乍可怯春寒。", "遠目傷千里，新年思萬端。無人知此意，閑憑小欄幹。"]'),
('yuding-4','除夜酬樂天','元稹','唐','御定全唐诗','yuding','','[]','引儺綏旆亂毿毿，戲罷人歸思不堪。虛漲火塵龜浦北，',40,'御定全唐詩/json/423.json','["引儺綏旆亂毿毿，戲罷人歸思不堪。虛漲火塵龜浦北，", "莫道明朝始添歲，今年春在歲前三。"]'),
('yuding-5','酬樂天初冬早寒見寄','元稹','唐','御定全唐诗','yuding','','[]','乍起衣猶冷，微吟帽半欹。霜凝南屋瓦，雞唱後園枝。',48,'御定全唐詩/json/423.json','["乍起衣猶冷，微吟帽半欹。霜凝南屋瓦，雞唱後園枝。", "洛水碧雲曉，吳宮黃葉時。兩傳千里意，書劄不如詩。"]'),
('yuding-6','酬白樂天杏花園','元稹','唐','御定全唐诗','yuding','','[]','劉郎不用閑惆悵，且作花間共醉人。',32,'御定全唐詩/json/423.json','["劉郎不用閑惆悵，且作花間共醉人。", "算得貞元舊朝士，幾人同見太和春。"]'),
('yuding-7','過東都別樂天二首','元稹','唐','御定全唐诗','yuding','','[]','君應怪我留連久，我欲與君辭別難。',64,'御定全唐詩/json/423.json','["君應怪我留連久，我欲與君辭別難。", "白頭徒侶漸稀少，明日恐君無此歡。", "自識君來三度別，這回白盡老髭須。", "戀君不去君須會，知得後回相見無。"]'),
('yuding-8','逢白公','元稹','唐','御定全唐诗','yuding','','[]','遠路事無限，相逢唯一言。月色照榮辱，長安千萬門。',24,'御定全唐詩/json/423.json','["遠路事無限，相逢唯一言。月色照榮辱，長安千萬門。"]'),
('yuding-9','酬白太傅','元稹','唐','御定全唐诗','yuding','','[]','太空秋色涼，獨鳥下微陽。三徑池塘靜，六街車馬忙。',48,'御定全唐詩/json/423.json','["太空秋色涼，獨鳥下微陽。三徑池塘靜，六街車馬忙。", "漸能高酒戶，始是入詩狂。官冷且無事，追陪慎莫忘。"]'),
('yuding-10','和嚴給事聞唐昌觀玉蕊花下有遊仙','元稹','唐','御定全唐诗','yuding','','[]','弄玉潛過玉樹時，不教青鳥出花枝。',32,'御定全唐詩/json/423.json','["弄玉潛過玉樹時，不教青鳥出花枝。", "的應未有諸人覺，只是嚴郎不得知。"]'),
('yuding-11','贈毛仙翁','元稹','唐','御定全唐诗','yuding','','[]','仙駕初從蓬海來，相逢又說向天臺。一言親授希微訣，',40,'御定全唐詩/json/423.json','["仙駕初從蓬海來，相逢又說向天臺。一言親授希微訣，", "花前揮手迢遙去，目斷霓旌不可陪。"]'),
('yuding-12','八月十四日夜玩月','元稹','唐','御定全唐诗','yuding','','[]','猶欠一宵輪未滿，紫霞紅襯碧雲端。',32,'御定全唐詩/json/423.json','["猶欠一宵輪未滿，紫霞紅襯碧雲端。", "誰能喚得姮娥下，引向堂前子細看。"]'),
('yuding-13','寒食夜','元稹','唐','御定全唐诗','yuding','','[]','紅染桃花雪壓梨，玲瓏雞子鬥贏時。',32,'御定全唐詩/json/423.json','["紅染桃花雪壓梨，玲瓏雞子鬥贏時。", "今年不是明寒食，暗地秋千別有期。"]'),
('yuding-14','三月三十日程氏館餞杜十四歸京','元稹','唐','御定全唐诗','yuding','','[]','江春今日盡，程館祖筵開。我正南冠縶，君尋北路回。',121,'御定全唐詩/json/423.json','["江春今日盡，程館祖筵開。我正南冠縶，君尋北路回。", "謀身誠太拙，從宦苦無媒。處困方明命，遭時不在才。", "逾年長倚玉，連夜共銜杯。涸溜沾濡沫，餘光照死灰。", "行看鴻欲翥，敢憚酒相催。拍逐飛觥絕，香隨舞袖來。", "消梨拋五遍，娑葛fg三台。已許尊前倒，臨風淚莫頹。"]'),
('yuding-15','酬張秘書因寄馬贈詩','元稹','唐','御定全唐诗','yuding','','[]','丞相功高厭武名，牽將戰馬寄儒生。四蹄荀距藏雖盡，',40,'御定全唐詩/json/423.json','["丞相功高厭武名，牽將戰馬寄儒生。四蹄荀距藏雖盡，", "勸君還卻司空著，莫遣衙參傍子城。"]'),
('yuding-16','戲酬副使中丞見示四韻','元稹','唐','御定全唐诗','yuding','','[]','莫恨暫櫜鞬，交遊幾個全。眼明相見日，肺病欲秋天。',48,'御定全唐詩/json/423.json','["莫恨暫櫜鞬，交遊幾個全。眼明相見日，肺病欲秋天。", "五馬虛盈櫪，雙蛾浪滿船。可憐俱老大，無處用閒錢。"]'),
('yuding-17','贈柔之','元稹','唐','御定全唐诗','yuding','','[]','窮冬到鄉國，正歲別京華。自恨風塵眼，常看遠地花。',48,'御定全唐詩/json/423.json','["窮冬到鄉國，正歲別京華。自恨風塵眼，常看遠地花。", "碧幢還照曜，紅粉莫咨嗟。嫁得浮雲婿，相隨即是家。"]'),
('yuding-18','修龜山魚池示眾僧','元稹','唐','御定全唐诗','yuding','','[]','勸爾諸僧好護持，不須垂釣引青絲。',32,'御定全唐詩/json/423.json','["勸爾諸僧好護持，不須垂釣引青絲。", "雲山莫厭看經坐，便是浮生得道時。"]'),
('yuding-19','寄贈薛濤','元稹','唐','御定全唐诗','yuding','','[]','錦江滑膩蛾眉秀，幻出文君與薛濤。言語巧偷鸚鵡舌，',40,'御定全唐詩/json/423.json','["錦江滑膩蛾眉秀，幻出文君與薛濤。言語巧偷鸚鵡舌，", "別後相思隔煙水，菖蒲花發五雲高。"]'),
('yuding-20','贈劉采春','元稹','唐','御定全唐诗','yuding','','[]','新妝巧樣畫雙蛾，謾裏常州透額羅。正面偷勻光滑笏，',40,'御定全唐詩/json/423.json','["新妝巧樣畫雙蛾，謾裏常州透額羅。正面偷勻光滑笏，", "更有惱人腸斷處，選詞能唱望夫歌。"]'),
('yuding-21','醉題東武','元稹','唐','御定全唐诗','yuding','','[]','役役行人事，紛紛碎簿書。功夫兩衙盡，留滯七年餘。',48,'御定全唐詩/json/423.json','["役役行人事，紛紛碎簿書。功夫兩衙盡，留滯七年餘。", "病痛梅天發，親情海岸疏。因循未歸得，不是憶鱸魚。"]'),
('yuding-22','崔徽歌','元稹','唐','御定全唐诗','yuding','','[]','崔徽本不是娼家，教歌按舞娼家長。使君知有不自由，',40,'御定全唐詩/json/423.json','["崔徽本不是娼家，教歌按舞娼家長。使君知有不自由，", "為徽持此謝敬中，以死報郎為□□。"]'),
('yuding-23','一字至七字詩：茶','元稹','唐','御定全唐诗','yuding','','[]','茶，香葉，嫩芽。慕詩客，愛僧家。碾雕白玉，',21,'御定全唐詩/json/423.json','["茶，香葉，嫩芽。慕詩客，愛僧家。碾雕白玉，"]'),
('yuding-24','句','元稹','唐','御定全唐诗','yuding','','[]','兒歌楊柳葉，妾拂石榴花。',139,'御定全唐詩/json/423.json','["兒歌楊柳葉，妾拂石榴花。", "松門待制應全遠，藥樹監搜可得知。（《文昌雜錄》", "雲：唐宣政殿為正衙，殿庭東西有四松，松下待制官", "立班之地，舊圖猶存。殿門外有藥樹，監察禦史監搜", "之位在焉。唐制：百官入宮殿門，必搜，監察所掌也。", "至太和元年，監搜始停）", "髻鬟峨峨高一尺，門前立地看春風。（《李娃行》，"]'),
('yuding-0','賀雨','白居易','唐','御定全唐诗','yuding','','[]','皇帝嗣寶曆，元和三年冬。自冬及春暮，不雨旱爞爞。',384,'御定全唐詩/json/424.json','["皇帝嗣寶曆，元和三年冬。自冬及春暮，不雨旱爞爞。", "上心念下民，懼歲成災凶。遂下罪己詔，殷勤告萬邦。", "帝曰予一人，繼天承祖宗。憂勤不遑寧，夙夜心忡忡。", "元年誅劉辟，一舉靖巴邛。二年戮李錡，不戰安江東。", "顧惟眇眇德，遽有巍巍功。或者天降沴，無乃儆予躬。", "上思答天戒，下思致時邕。莫如率其身，慈和與儉恭。", "乃命罷進獻，乃命賑饑窮。宥死降五刑，責己寬三農。", "宮女出宣徽，廄馬減飛龍。庶政靡不舉，皆出自宸衷。", "奔騰道路人，傴僂田野翁。歡呼相告報，感泣涕沾胸。", "順人人心悅，先天天意從。詔下才七日，和氣生沖融。", "凝為油油雲，散作習習風。晝夜三日雨，淒淒複濛濛。", "萬心春熙熙，百穀青芃芃。人變愁為喜，歲易儉為豐。", "乃知王者心，憂樂與眾同。皇天與後土，所感無不通。", "冠佩何鏘鏘，將相及王公。蹈舞呼萬歲，列賀明庭中。", "小臣誠愚陋，職忝金鑾宮。稽首再三拜，一言獻天聰。", "君以明為聖，臣以直為忠。敢賀有其始，亦願有其終。"]'),
('yuding-1','讀張籍古樂府','白居易','唐','御定全唐诗','yuding','','[]','張君何為者，業文三十春。尤工樂府詩，舉代少其倫。',240,'御定全唐詩/json/424.json','["張君何為者，業文三十春。尤工樂府詩，舉代少其倫。", "為詩意如何，六義互鋪陳。風雅比興外，未嘗著空文。", "讀君學仙詩，可諷放佚君。讀君董公詩，可誨貪暴臣。", "讀君商女詩，可感悍婦仁。讀君勤齊詩，可勸薄夫敦。", "上可裨教化，舒之濟萬民。下可理情性，卷之善一身。", "始從青衿歲，迨此白髮新。日夜秉筆吟，心苦力亦勤。", "時無采詩官，委棄如泥塵。恐君百歲後，滅沒人不聞。", "願藏中秘書，百代不湮淪。願播內樂府，時得聞至尊。", "言者志之苗，行者文之根。所以讀君詩，亦知君為人。", "如何欲五十，官小身賤貧。病眼街西住，無人行到門。"]'),
('yuding-2','哭孔戡','白居易','唐','御定全唐诗','yuding','','[]','洛陽誰不死，戡死聞長安。我是知戡者，聞之涕泫然。',192,'御定全唐詩/json/424.json','["洛陽誰不死，戡死聞長安。我是知戡者，聞之涕泫然。", "戡佐山東軍，非義不可幹。拂衣向西來，其道直如弦。", "從事得如此，人人以為難。人言明明代，合置在朝端。", "或望居諫司，有事戡必言。或望居憲府，有邪戡必彈。", "惜哉兩不諧，沒齒為閑官。竟不得一日，謇謇立君前。", "形骸隨眾人，斂葬北邙山。平生剛腸內，直氣歸其間。", "賢者為生民，生死懸在天。謂天不愛人，胡為生其賢。", "謂天果愛民，胡為奪其年。茫茫元化中，誰執如此權。"]'),
('yuding-3','凶宅','白居易','唐','御定全唐诗','yuding','','[]','長安多大宅，列在街西東。往往朱門內，房廊相對空。',264,'御定全唐詩/json/424.json','["長安多大宅，列在街西東。往往朱門內，房廊相對空。", "梟鳴松桂樹，狐藏蘭菊叢。蒼苔黃葉地，日暮多旋風。", "前主為將相，得罪竄巴庸。後主為公卿，寢疾歿其中。", "連延四五主，殃禍繼相鍾。自從十年來，不利主人翁。", "風雨壞簷隙，蛇鼠穿牆墉。人疑不敢買，日毀土木功。", "嗟嗟俗人心，甚矣其愚蒙。但恐災將至，不思禍所從。", "我今題此詩，欲悟迷者胸。凡為大官人，年祿多高崇。", "權重持難久，位高勢易窮。驕者物之盈，老者數之終。", "四者如寇盜，日夜來相攻。假使居吉土，孰能保其躬。", "因小以明大，借家可喻邦。周秦宅殽函，其宅非不同。", "一興八百年，一死望夷宮。寄語家與國，人凶非宅凶。"]'),
('yuding-4','夢仙','白居易','唐','御定全唐诗','yuding','','[]','人有夢仙者，夢身升上清。坐乘一白鶴，前引雙紅旌。',288,'御定全唐詩/json/424.json','["人有夢仙者，夢身升上清。坐乘一白鶴，前引雙紅旌。", "羽衣忽飄飄，玉鸞俄錚錚。半空直下視，人世塵冥冥。", "漸失鄉國處，才分山水形。東海一片白，列嶽五點青。", "須臾群仙來，相引朝玉京。安期羨門輩，列侍如公卿。", "仰謁玉皇帝，稽首前致誠。帝言汝仙才，努力勿自輕。", "卻後十五年，期汝不死庭。再拜受斯言，既寤喜且驚。", "秘之不敢泄，誓志居岩扃。恩愛舍骨肉，飲食斷膻腥。", "朝餐雲母散，夜吸沆瀣精。空山三十載，日望輜輧迎。", "前期過已久，鸞鶴無來聲。齒發日衰白，耳目減聰明。", "一朝同物化，身與糞壤並。神仙信有之，俗力非可營。", "苟無金骨相，不列丹台名。徒傳辟穀法，虛受燒丹經。", "只自取勤苦，百年終不成。悲哉夢仙人，一夢誤一生。"]'),
('yuding-5','觀刈麥','白居易','唐','御定全唐诗','yuding','','[]','田家少閑月，五月人倍忙。夜來南風起，小麥覆隴黃。',156,'御定全唐詩/json/424.json','["田家少閑月，五月人倍忙。夜來南風起，小麥覆隴黃。", "婦姑荷簟食，童稚攜壺漿。相隨餉田去，丁壯在南岡。", "足蒸暑土氣，背灼炎天光。力盡不知熱，但惜夏日長。", "複有貧婦人，抱子在其傍。右手秉遺穗，左臂懸敝筐。", "聽其相顧言，聞者為悲傷。家田輸稅盡，拾此充饑腸。", "今我何功德，曾不事農桑。吏祿三百石，歲晏有餘糧。", "念此私自愧，盡日不能忘。"]'),
('yuding-6','題海圖屏風','白居易','唐','御定全唐诗','yuding','','[]','海水無風時，波濤安悠悠。鱗介無小大，遂性各沉浮。',156,'御定全唐詩/json/424.json','["海水無風時，波濤安悠悠。鱗介無小大，遂性各沉浮。", "突兀海底鼇，首冠三神丘。釣網不能制，其來非一秋。", "或者不量力，謂茲鼇可求。贔屭牽不動，綸絕沉其鉤。", "一鼇既頓頷，諸鼇齊掉頭。白濤與黑浪，呼吸繞咽喉。", "噴風激飛廉，鼓波怒陽侯。鯨鯢得其便，張口欲吞舟。", "萬里無活鱗，百川多倒流。遂使江漢水，朝宗意亦休。", "蒼然屏風上，此畫良有由。"]'),
('yuding-7','羸駿','白居易','唐','御定全唐诗','yuding','','[]','驊騮失其主，羸餓無人牧。向風嘶一聲，莽蒼黃河曲。',96,'御定全唐詩/json/424.json','["驊騮失其主，羸餓無人牧。向風嘶一聲，莽蒼黃河曲。", "蹋冰水畔立，臥雪塚間宿。歲暮田野空，寒草不滿腹。", "豈無市駿者，儘是凡人目。相馬失於瘦，遂遺千里足。", "村中何擾擾，有吏征芻粟。輸彼軍廄中，化作駑駘肉。"]'),
('yuding-8','廢琴','白居易','唐','御定全唐诗','yuding','','[]','絲桐合為琴，中有太古聲。古聲澹無味，不稱今人情。',72,'御定全唐詩/json/424.json','["絲桐合為琴，中有太古聲。古聲澹無味，不稱今人情。", "玉徽光彩滅，朱弦塵土生。廢棄來已久，遺音尚泠泠。", "不辭為君彈，縱彈人不聽。何物使之然，羌笛與秦箏。"]'),
('yuding-9','李都尉古劍','白居易','唐','御定全唐诗','yuding','','[]','古劍寒黯黯，鑄來幾千秋。白光納日月，紫氣排鬥牛。',108,'御定全唐詩/json/424.json','["古劍寒黯黯，鑄來幾千秋。白光納日月，紫氣排鬥牛。", "有客借一觀，愛之不敢求。湛然玉匣中，秋水澄不流。", "至寶有本性，精剛無與儔。可使寸寸折，不能繞指柔。", "願快直士心，將斷佞臣頭。不願報小怨，夜半刺私仇。", "勸君慎所用，無作神兵羞。"]'),
('yuding-10','雲居寺孤桐','白居易','唐','御定全唐诗','yuding','','[]','一株青玉立，千葉綠雲委。亭亭五丈餘，高意猶未已。',84,'御定全唐詩/json/424.json','["一株青玉立，千葉綠雲委。亭亭五丈餘，高意猶未已。", "山僧年九十，清淨老不死。自雲手種時，一顆青桐子。", "直從萌芽拔，高自毫末始。四面無附枝，中心有通理。", "寄言立身者，孤直當如此。"]'),
('yuding-11','京兆府新栽蓮','白居易','唐','御定全唐诗','yuding','','[]','汙溝貯濁水，水上葉田田。我來一長歎，知是東溪蓮。',96,'御定全唐詩/json/424.json','["汙溝貯濁水，水上葉田田。我來一長歎，知是東溪蓮。", "下有青泥汙，馨香無複全。上有紅塵撲，顏色不得鮮。", "物性猶如此，人事亦宜然。托根非其所，不如遭棄捐。", "昔在溪中日，花葉媚清漣。今來不得地，憔悴府門前。"]'),
('yuding-12','月夜登閣避暑','白居易','唐','御定全唐诗','yuding','','[]','旱久炎氣盛，中人若燔燒。清風隱何處，草樹不動搖。',96,'御定全唐詩/json/424.json','["旱久炎氣盛，中人若燔燒。清風隱何處，草樹不動搖。", "何以避暑氣，無如出塵囂。行行都門外，佛閣正岧嶢。", "清涼近高生，煩熱委靜銷。開襟當軒坐，意泰神飄飄。", "回看歸路傍，禾黍盡枯焦。獨善誠有計，將何救旱苗。"]'),
('yuding-13','初授拾遺','白居易','唐','御定全唐诗','yuding','','[]','奉詔登左掖，束帶參朝議。何言初命卑，且脫風塵吏。',120,'御定全唐詩/json/424.json','["奉詔登左掖，束帶參朝議。何言初命卑，且脫風塵吏。", "杜甫陳子昂，才名括天地。當時非不遇，尚無過斯位。", "況余蹇薄者，寵至不自意。驚近白日光，慚非青雲器。", "天子方從諫，朝廷無忌諱。豈不思匪躬，適遇時無事。", "受命已旬月，飽食隨班次。諫紙忽盈箱，對之終自愧。"]'),
('yuding-14','贈元稹','白居易','唐','御定全唐诗','yuding','','[]','自我從宦遊，七年在長安。所得惟元君，乃知定交難。',144,'御定全唐詩/json/424.json','["自我從宦遊，七年在長安。所得惟元君，乃知定交難。", "豈無山上苗，徑寸無歲寒。豈無要津水，咫尺有波瀾。", "之子異於是，久處誓不諼。無波古井水，有節秋竹竿。", "一為同心友，三及芳歲闌。花下鞍馬遊，雪中杯酒歡。", "衡門相逢迎，不具帶與冠。春風日高睡，秋月夜深看。", "不為同登科，不為同署官。所合在方寸，心源無異端。"]'),
('yuding-15','哭劉敦質','白居易','唐','御定全唐诗','yuding','','[]','小樹兩株柏，新土三尺墳。蒼蒼白露草，此地哭劉君。',84,'御定全唐詩/json/424.json','["小樹兩株柏，新土三尺墳。蒼蒼白露草，此地哭劉君。", "哭君豈無辭，辭雲君子人。如何天不吊，窮悴至終身。", "愚者多貴壽，賢者獨賤迍。龍亢彼無悔，蠖屈此不伸。", "哭罷持此辭，吾將詰羲文。"]'),
('yuding-16','答友問','白居易','唐','御定全唐诗','yuding','','[]','大圭廉不割，利劍用不缺。當其斬馬時，良玉不如鐵。',60,'御定全唐詩/json/424.json','["大圭廉不割，利劍用不缺。當其斬馬時，良玉不如鐵。", "置鐵在洪爐，鐵消易如雪。良玉同其中，三日燒不熱。", "君疑才與德，詠此知優劣。"]'),
('yuding-17','雜興三首','白居易','唐','御定全唐诗','yuding','','[]','楚王多內寵，傾國選嬪妃。又愛從禽樂，馳騁每相隨。',396,'御定全唐詩/json/424.json','["楚王多內寵，傾國選嬪妃。又愛從禽樂，馳騁每相隨。", "錦鞲臂花隼，羅袂控金羈。遂習宮中女，皆如馬上兒。", "色禽合為荒，刑政兩已衰。雲夢春仍獵，章華夜不歸。", "東風二月天，春雁正離離。美人挾銀鏑，一發疊雙飛。", "飛鴻驚斷行，斂翅避蛾眉。君王顧之笑，弓箭生光輝。", "回眸語君曰，昔聞莊王時。有一愚夫人，其名曰樊姬。", "不有此遊樂，三載斷鮮肥。", "越國政初荒，越天旱不已。風日燥水田，水涸塵飛起。", "國中新下令，官渠禁流水。流水不入田，壅入王宮裏。", "餘波養魚鳥，倒影浮樓雉。澹灩九折池，縈回十餘裏。", "四月芰荷發，越王日遊嬉。左右好風來，香動芙蓉蕊。", "但愛芙蓉香，又種芙蓉子。不念閶門外，千里稻苗死。", "吳王心日侈，服玩盡奇瑰。身臥翠羽帳，手持紅玉杯。", "冠垂明月珠，帶束通天犀。行動自矜顧，數步一裴回。", "小人知所好，懷寶四方來。奸邪得藉手，從此幸門開。", "古稱國之寶，谷米與賢才。今看君王眼，視之如塵灰。", "伍員諫已死，浮屍去不回。姑蘇台下草，麋鹿暗生麑。"]'),
('yuding-18','宿紫閣山北村','白居易','唐','御定全唐诗','yuding','','[]','晨遊紫閣峰，暮宿山下村。村老見餘喜，為餘開一尊。',120,'御定全唐詩/json/424.json','["晨遊紫閣峰，暮宿山下村。村老見餘喜，為餘開一尊。", "舉杯未及飲，暴卒來入門。紫衣挾刀斧，草草十餘人。", "奪我席上酒，掣我盤中飧。主人退後立，斂手反如賓。", "中庭有奇樹，種來三十春。主人惜不得，持斧斷其根。", "口稱采造家，身屬神策軍。主人慎勿語，中尉正承恩。"]'),
('yuding-19','讀漢書','白居易','唐','御定全唐诗','yuding','','[]','禾黍與稂莠，雨來同日滋。桃李與荊棘，霜降同夜萎。',156,'御定全唐詩/json/424.json','["禾黍與稂莠，雨來同日滋。桃李與荊棘，霜降同夜萎。", "草木既區別，榮枯那等夷。茫茫天地意，無乃太無私。", "小人與君子，用置各有宜。奈何西漢末，忠邪並信之。", "不然盡信忠，早絕邪臣窺。不然盡信邪，早使忠臣知。", "優遊兩不斷，盛業日已衰。痛矣蕭京輩，終令陷禍機。", "每讀元成紀，憤憤令人悲。寄言為國者，不得學天時。", "寄言為臣者，可以鑒於斯。"]'),
('yuding-20','贈樊著作','白居易','唐','御定全唐诗','yuding','','[]','陽城為諫議，以正事其君。其手如屈軼，舉必指佞臣。',216,'御定全唐詩/json/424.json','["陽城為諫議，以正事其君。其手如屈軼，舉必指佞臣。", "卒使不仁者，不得秉國鈞。元稹為禦史，以直立其身。", "其心如肺石，動必達窮民。東川八十家，冤憤一言伸。", "劉辟肆亂心，殺人正紛紛。其嫂曰庾氏，棄絕不為親。", "從史萌逆節，隱心潛負恩。其佐曰孔戡，舍去不為賓。", "凡此士與女，其道天下聞。常恐國史上，但記鳳與麟。", "賢者不為名，名彰教乃敦。每惜若人輩，身死名亦淪。", "君為著作郎，職廢志空存。雖有良史才，直筆無所申。", "何不自著書，實錄彼善人。編為一家言，以備史闕文。"]'),
('yuding-21','蜀路石婦','白居易','唐','御定全唐诗','yuding','','[]','道傍一石婦，無記複無銘。傳是此鄉女，為婦孝且貞。',168,'御定全唐詩/json/424.json','["道傍一石婦，無記複無銘。傳是此鄉女，為婦孝且貞。", "十五嫁邑人，十六夫征行。夫行二十載，婦獨守孤煢。", "其夫有父母，老病不安寧。其婦執婦道，一一如禮經。", "晨昏問起居，恭順發心誠。藥餌自調節，膳羞必甘馨。", "夫行竟不歸，婦德轉光明。後人高其節，刻石像婦形。", "儼然整衣巾，若立在閨庭。似見舅姑禮，如聞環佩聲。", "至今為婦者，見此孝心生。不比山頭石，空有望夫名。"]'),
('yuding-22','折劍頭','白居易','唐','御定全唐诗','yuding','','[]','拾得折劍頭，不知折之由。一握青蛇尾，數寸碧峰頭。',72,'御定全唐詩/json/424.json','["拾得折劍頭，不知折之由。一握青蛇尾，數寸碧峰頭。", "疑是斬鯨鯢，不然刺蛟虯。缺落泥土中，委棄無人收。", "我有鄙介性，好剛不好柔。勿輕直折劍，猶勝曲全鉤。"]'),
('yuding-23','登樂遊園望','白居易','唐','御定全唐诗','yuding','','[]','獨上樂遊園，四望天日曛。東北何靄靄，宮闕入煙雲。',96,'御定全唐詩/json/424.json','["獨上樂遊園，四望天日曛。東北何靄靄，宮闕入煙雲。", "愛此高處立，忽如遺垢氛。耳目暫清曠，懷抱鬱不伸。", "下視十二街，綠樹間紅塵。車馬徒滿眼，不見心所親。", "孔生死洛陽，元九謫荊門。可憐南北路，高蓋者何人。"]'),
('yuding-24','酬元九對新栽竹有懷見寄','白居易','唐','御定全唐诗','yuding','','[]','昔我十年前，與君始相識。曾將秋竹竿，比君孤且直。',120,'御定全唐詩/json/424.json','["昔我十年前，與君始相識。曾將秋竹竿，比君孤且直。", "中心一以合，外事紛無極。共保秋竹心，風霜侵不得。", "始嫌梧桐樹，秋至先改色。不愛楊柳枝，春來軟無力。", "憐君別我後，見竹長相憶。長欲在眼前，故栽庭戶側。", "分首今何處，君南我在北。吟我贈君詩，對之心惻惻。"]'),
('yuding-25','感鶴','白居易','唐','御定全唐诗','yuding','','[]','鶴有不群者，飛飛在野田。饑不啄腐鼠，渴不飲盜泉。',120,'御定全唐詩/json/424.json','["鶴有不群者，飛飛在野田。饑不啄腐鼠，渴不飲盜泉。", "貞姿自耿介，雜鳥何翩翾。同游不同志，如此十餘年。", "一興嗜欲念，遂為矰繳牽。委質小池內，爭食群雞前。", "不惟懷稻粱，兼亦競腥膻。不惟戀主人，兼亦狎烏鳶。", "物心不可知，天性有時遷。一飽尚如此，況乘大夫軒。"]'),
('yuding-26','春雪','白居易','唐','御定全唐诗','yuding','','[]','元和歲在卯，六年春二月。月晦寒食天，天陰夜飛雪。',168,'御定全唐詩/json/424.json','["元和歲在卯，六年春二月。月晦寒食天，天陰夜飛雪。", "連宵複竟日，浩浩殊未歇。大似落鵝毛，密如飄玉屑。", "寒銷春茫蒼，氣變風凜冽。上林草盡沒，曲江水複結。", "紅幹杏花死，綠凍楊枝折。所憐物性傷，非惜年芳絕。", "上天有時令，四序平分別。寒燠苟反常，物生皆夭閼。", "我觀聖人意，魯史有其說。或記水不冰，或書霜不殺。", "上將儆政教，下以防災孽。茲雪今如何，信美非時節。"]'),
('yuding-27','高僕射','白居易','唐','御定全唐诗','yuding','','[]','富貴人所愛，聖人去其泰。所以致仕年，著在禮經內。',144,'御定全唐詩/json/424.json','["富貴人所愛，聖人去其泰。所以致仕年，著在禮經內。", "玄元亦有訓，知止則不殆。二疏獨能行，遺跡東門外。", "清風久銷歇，迨此向千載。斯人古亦稀，何況今之代。", "遑遑名利客，白首千百輩。惟有高僕射，七十懸車蓋。", "我年雖未老，歲月亦雲邁。預恐耄及時，貪榮不能退。", "中心私自儆，何以為我戒。故作僕射詩，書之於大帶。"]'),
('yuding-28','白牡丹','白居易','唐','御定全唐诗','yuding','','[]','城中看花客，旦暮走營營。素華人不顧，亦占牡丹名。',168,'御定全唐詩/json/424.json','["城中看花客，旦暮走營營。素華人不顧，亦占牡丹名。", "閉在深寺中，車馬無來聲。唯有錢學士，盡日繞叢行。", "憐此皓然質，無人自芳馨。眾嫌我獨賞，移植在中庭。", "留景夜不暝，迎光曙先明。對之心亦靜，虛白相向生。", "唐昌玉蕊花，攀玩眾所爭。折來比顏色，一種如瑤瓊。", "彼因稀見貴，此以多為輕。始知無正色，愛惡隨人情。", "豈惟花獨爾，理與人事並。君看入時者，紫豔與紅英。"]'),
('yuding-29','贈內','白居易','唐','御定全唐诗','yuding','','[]','生為同室親，死為同穴塵。他人尚相勉，而況我與君。',180,'御定全唐詩/json/424.json','["生為同室親，死為同穴塵。他人尚相勉，而況我與君。", "黔婁固窮士，妻賢忘其貧。冀缺一農夫，妻敬儼如賓。", "陶潛不營生，翟氏自爨薪。梁鴻不肯仕，孟光甘布裙。", "君雖不讀書，此事耳亦聞。至此千載後，傳是何如人。", "人生未死間，不能忘其身。所須者衣食，不過飽與溫。", "蔬食足充饑，何必膏粱珍。繒絮足禦寒，何必錦繡文。", "君家有貽訓，清白遺子孫。我亦貞苦士，與君新結婚。", "庶保貧與素，偕老同欣欣。"]'),
('yuding-30','寄唐生','白居易','唐','御定全唐诗','yuding','','[]','賈誼哭時事，阮籍哭路岐。唐生今亦哭，異代同其悲。',288,'御定全唐詩/json/424.json','["賈誼哭時事，阮籍哭路岐。唐生今亦哭，異代同其悲。", "唐生者何人，五十寒且饑。不悲口無食，不悲身無衣。", "所悲忠與義，悲甚則哭之。太尉擊賊日，尚書叱盜時。", "大夫死凶寇，諫議謫蠻夷。每見如此事，聲發涕輒隨。", "往往聞其風，俗士猶或非。憐君頭半白，其志竟不衰。", "我亦君之徒，鬱鬱何所為。不能發聲哭，轉作樂府詩。", "篇篇無空文，句句必盡規。功高虞人箴，痛甚騷人辭。", "非求宮律高，不務文字奇。惟歌生民病，願得天子知。", "未得天子知，甘受時人嗤。藥良氣味苦，琴澹音聲稀。", "不懼權豪怒，亦任親朋譏。人竟無奈何，呼作狂男兒。", "每逢群盜息，或遇雲霧披。但自高聲歌，庶幾天聽卑。", "歌哭雖異名，所感則同歸。寄君三十章，與君為哭詞。"]'),
('yuding-31','傷唐衢二首','白居易','唐','御定全唐诗','yuding','','[]','自我心存道，外物少能逼。常排傷心事，不為長歎息。',336,'御定全唐詩/json/424.json','["自我心存道，外物少能逼。常排傷心事，不為長歎息。", "忽聞唐衢死，不覺動顏色。悲端從東來，觸我心惻惻。", "伊昔未相知，偶遊滑台側。同宿李翱家，一言如舊識。", "酒酣出送我，風雪黃河北。日西並馬頭，語別至昏黑。", "君歸向東鄭，我來游上國。交心不交面，從此重相憶。", "憐君儒家子，不得詩書力。五十著青衫，試官無祿食。", "遺文僅千首，六義無差忒。散在京洛間，何人為收拾。", "憶昨元和初，忝備諫官位。是時兵革後，生民正憔悴。", "但傷民病痛，不識時忌諱。遂作秦中吟，一吟悲一事。", "貴人皆怪怒，閒人亦非訾。天高未及聞，荊棘生滿地。", "惟有唐衢見，知我平生志。一讀興歎嗟，再吟垂涕泗。", "因和三十韻，手題遠緘寄。致吾陳杜間，賞愛非常意。", "此人無複見，此詩猶可貴。今日開篋看，蠹魚損文字。", "不知何處葬，欲問先歔欷。終去哭墳前，還君一掬淚。"]'),
('yuding-32','問友','白居易','唐','御定全唐诗','yuding','','[]','種蘭不種艾，蘭生艾亦生。根荄相交長，莖葉相附榮。',72,'御定全唐詩/json/424.json','["種蘭不種艾，蘭生艾亦生。根荄相交長，莖葉相附榮。", "香莖與臭葉，日夜俱長大。鋤艾恐傷蘭，溉蘭恐滋艾。", "蘭亦未能溉，艾亦未能除。沉吟意不決，問君合何如。"]'),
('yuding-33','悲哉行','白居易','唐','御定全唐诗','yuding','','[]','悲哉為儒者，力學不知疲。讀書眼欲暗，秉筆手生胝。',192,'御定全唐詩/json/424.json','["悲哉為儒者，力學不知疲。讀書眼欲暗，秉筆手生胝。", "十上方一第，成名常苦遲。縱有宦達者，兩鬢已成絲。", "可憐少壯日，適在窮賤時。丈夫老且病，焉用富貴為。", "沉沉朱門宅，中有乳臭兒。狀貌如婦人，光明膏粱肌。", "手不把書卷，身不擐戎衣。二十襲封爵，門承勳戚資。", "春來日日出，服禦何輕肥。朝從博徒飲，暮有倡樓期。", "平封還酒債，堆金選蛾眉。聲色狗馬外，其餘一無知。", "山苗與澗松，地勢隨高卑。古來無奈何，非君獨傷悲。"]'),
('yuding-34','紫藤','白居易','唐','御定全唐诗','yuding','','[]','藤花紫蒙茸，藤葉青扶疏。誰謂好顏色，而為害有餘。',156,'御定全唐詩/json/424.json','["藤花紫蒙茸，藤葉青扶疏。誰謂好顏色，而為害有餘。", "下如蛇屈盤，上若繩縈紆。可憐中間樹，束縛成枯株。", "柔蔓不自勝，嫋嫋掛空虛。豈知纏樹木，千夫力不如。", "先柔後為害，有似諛佞徒。附著君權勢，君迷不肯誅。", "又如妖婦人，綢繆蠱其夫。奇邪壞人室，夫惑不能除。", "寄言邦與家，所慎在其初。毫末不早辨，滋蔓信難圖。", "願以藤為戒，銘之於座隅。"]'),
('yuding-35','放鷹','白居易','唐','御定全唐诗','yuding','','[]','十月鷹出籠，草枯雉兔肥。下鞲隨指顧，百擲無一遺。',144,'御定全唐詩/json/424.json','["十月鷹出籠，草枯雉兔肥。下鞲隨指顧，百擲無一遺。", "鷹翅疾如風，鷹爪利如錐。本為鳥所設，今為人所資。", "孰能使之然，有術甚易知。取其向背性，制在饑飽時。", "不可使長飽，不可使長饑。饑則力不足，飽則背人飛。", "乘饑縱搏擊，未飽須縶維。所以爪翅功，而人坐收之。", "聖明馭英雄，其術亦如斯。鄙語不可棄，吾聞諸獵師。"]'),
('yuding-36','慈烏夜啼','白居易','唐','御定全唐诗','yuding','','[]','慈烏失其母，啞啞吐哀音。晝夜不飛去，經年守故林。',108,'御定全唐詩/json/424.json','["慈烏失其母，啞啞吐哀音。晝夜不飛去，經年守故林。", "夜夜夜半啼，聞者為沾襟。聲中如告訴，未盡反哺心。", "百鳥豈無母，爾獨哀怨深。應是母慈重，使爾悲不任。", "昔有吳起者，母歿喪不臨。嗟哉斯徒輩，其心不如禽。", "慈烏複慈烏，鳥中之曾參。"]'),
('yuding-37','燕詩示劉叟','白居易','唐','御定全唐诗','yuding','','[]','梁上有雙燕，翩翩雄與雌。銜泥兩椽間，一巢生四兒。',180,'御定全唐詩/json/424.json','["梁上有雙燕，翩翩雄與雌。銜泥兩椽間，一巢生四兒。", "四兒日夜長，索食聲孜孜。青蟲不易捕，黃口無飽期。", "觜爪雖欲敝，心力不知疲。須臾十來往，猶恐巢中饑。", "辛勤三十日，母瘦雛漸肥。喃喃教言語，一一刷毛衣。", "一旦羽翼成，引上庭樹枝。舉翅不回顧，隨風四散飛。", "雌雄空中鳴，聲盡呼不歸。卻入空巢裏，啁啾終夜悲。", "燕燕爾勿悲，爾當返自思。思爾為雛日，高飛背母時。", "當時父母念，今日爾應知。"]'),
('yuding-38','埰地黃者','白居易','唐','御定全唐诗','yuding','','[]','麥死春不雨，禾損秋早霜。歲晏無口食，田中埰地黃。',84,'御定全唐詩/json/424.json','["麥死春不雨，禾損秋早霜。歲晏無口食，田中埰地黃。", "采之將何用，持以易餱糧。淩晨荷鋤去，薄暮不盈筐。", "攜來朱門家，賣與白麵郎。與君啖肥馬，可使照地光。", "願易馬殘粟，救此苦饑腸。"]'),
('yuding-39','初入太行路','白居易','唐','御定全唐诗','yuding','','[]','天冷日不光，太行峰蒼莽。嘗聞此中險，今我方獨往。',48,'御定全唐詩/json/424.json','["天冷日不光，太行峰蒼莽。嘗聞此中險，今我方獨往。", "馬蹄凍且滑，羊腸不可上。若比世路難，猶自平於掌。"]'),
('yuding-40','鄧魴、張徹落第','白居易','唐','御定全唐诗','yuding','','[]','古琴無俗韻，奏罷無人聽。寒松無妖花，枝下無人行。',84,'御定全唐詩/json/424.json','["古琴無俗韻，奏罷無人聽。寒松無妖花，枝下無人行。", "春風十二街，軒騎不暫停。奔車看牡丹，走馬聽秦箏。", "眾目悅芳豔，松獨守其貞。眾耳喜鄭衛，琴亦不改聲。", "懷哉二夫子，念此無自輕。"]'),
('yuding-41','送王處士','白居易','唐','御定全唐诗','yuding','','[]','王門豈無酒，侯門豈無肉。主人貴且驕，待客禮不足。',96,'御定全唐詩/json/424.json','["王門豈無酒，侯門豈無肉。主人貴且驕，待客禮不足。", "望塵而拜者，朝夕走碌碌。王生獨拂衣，遐舉如雲鵠。", "甯歸白雲外，飲水臥空穀。不能隨眾人，斂手低眉目。", "扣門與我別，酤酒留君宿。好去采薇人，終南山正綠。"]'),
('yuding-42','村居苦寒','白居易','唐','御定全唐诗','yuding','','[]','八年十二月，五日雪紛紛。竹柏皆凍死，況彼無衣民。',120,'御定全唐詩/json/424.json','["八年十二月，五日雪紛紛。竹柏皆凍死，況彼無衣民。", "回觀村閭間，十室八九貧。北風利如劍，布絮不蔽身。", "唯燒蒿棘火，愁坐夜待晨。乃知大寒歲，農者尤苦辛。", "顧我當此日，草堂深掩門。褐裘覆紖被，坐臥有餘溫。", "倖免饑凍苦，又無壟畝勤。念彼深可愧，自問是何人。"]'),
('yuding-43','納粟','白居易','唐','御定全唐诗','yuding','','[]','有吏夜叩門，高聲催納粟。家人不待曉，場上張燈燭。',96,'御定全唐詩/json/424.json','["有吏夜叩門，高聲催納粟。家人不待曉，場上張燈燭。", "揚簸淨如珠，一車三十斛。猶憂納不中，鞭責及僮僕。", "昔餘謬從事，內愧才不足。連授四命官，坐屍十年祿。", "常聞古人語，損益周必複。今日諒甘心，還他太倉穀。"]'),
('yuding-44','薛中丞','白居易','唐','御定全唐诗','yuding','','[]','百人無一直，百直無一遇。借問遇者誰，正人行得路。',192,'御定全唐詩/json/424.json','["百人無一直，百直無一遇。借問遇者誰，正人行得路。", "中丞薛存誠，守直心甚固。皇明燭如日，再使秉王度。", "奸豪與佞巧，非不憎且懼。直道漸光明，邪謀難蓋覆。", "每因匪躬節，知有匡時具。張為墜網綱，倚作頹簷柱。", "悠哉上天意，報施紛回互。自古已冥茫，從今尤不諭。", "豈與小人意，昏然同好惡。不然君子人，何反如朝露。", "裴相昨已夭，薛君今又去。以我惜賢心，五年如旦暮。", "況聞善人命，長短系運數。今我一涕零，豈為中丞故。"]'),
('yuding-45','秋池二首','白居易','唐','御定全唐诗','yuding','','[]','前池秋始半，卉物多摧壞。欲暮槿先萎，未霜荷已敗。',96,'御定全唐詩/json/424.json','["前池秋始半，卉物多摧壞。欲暮槿先萎，未霜荷已敗。", "默然有所感，可以從茲誡。本不種松筠，早凋何足怪。", "鑿池貯秋水，中有蘋與芰。天旱水暗消，塌然委空地。", "有似泛泛者，附離權與貴。一旦恩勢移，相隨共憔悴。"]'),
('yuding-46','夏旱','白居易','唐','御定全唐诗','yuding','','[]','太陰不離畢，太歲仍在午。旱日與炎風，枯焦我田畝。',96,'御定全唐詩/json/424.json','["太陰不離畢，太歲仍在午。旱日與炎風，枯焦我田畝。", "金石欲銷鑠，況茲禾與黍。嗷嗷萬族中，唯農最辛苦。", "憫然望歲者，出門何所睹。但見棘與茨，羅生遍場圃。", "惡苗承沴氣，欣然得其所。感此因問天，可能長不雨。"]'),
('yuding-47','諭友','白居易','唐','御定全唐诗','yuding','','[]','昨夜霜一降，殺君庭中槐。幹葉不待黃，索索飛下來。',156,'御定全唐詩/json/424.json','["昨夜霜一降，殺君庭中槐。幹葉不待黃，索索飛下來。", "憐君感節物，晨起步前階。臨風蹋葉立，半日顏色哀。", "西望長安城，歌鐘十二街。何人不歡樂，君獨心悠哉。", "白日頭上走，朱顏鏡中頹。平生青雲心，銷化成死灰。", "我今贈一言，勝飲酒千杯。其言雖甚鄙，可破悒悒懷。", "朱門有勳貴，陋巷有顏回。窮通各問命，不系才不才。", "推此自豁豁，不必待安排。"]'),
('yuding-48','丘中有一士二首','白居易','唐','御定全唐诗','yuding','','[]','丘中有一士，不知其姓名。面色不憂苦，血氣常和平。',192,'御定全唐詩/json/424.json','["丘中有一士，不知其姓名。面色不憂苦，血氣常和平。", "每選隙地居，不蹋要路行。舉動無尤悔，物莫與之爭。", "藜藿不充腸，布褐不蔽形。終歲守窮餓，而無嗟歎聲。", "豈是愛貧賤，深知時俗情。勿矜羅弋巧，鸞鶴在冥冥。", "丘中有一士，守道歲月深。行披帶索衣，坐拍無弦琴。", "不飲濁泉水，不息曲木陰。所逢苟非義，糞土千黃金。", "鄉人化其風，熏如蘭在林。智愚與強弱，不忍相欺侵。", "我欲訪其人，將行複沉吟。何必見其面，但在學其心。"]'),
('yuding-49','新制布裘','白居易','唐','御定全唐诗','yuding','','[]','桂布白似雪，吳綿軟於雲。布重綿且厚，為裘有餘溫。',96,'御定全唐詩/json/424.json','["桂布白似雪，吳綿軟於雲。布重綿且厚，為裘有餘溫。", "朝擁坐至暮，夜覆眠達晨。誰知嚴冬月，支體暖如春。", "中夕忽有念，撫裘起逡巡。丈夫貴兼濟，豈獨善一身。", "安得萬里裘，蓋裹週四垠。穩暖皆如我，天下無寒人。"]'),
('yuding-50','杏園中棗樹','白居易','唐','御定全唐诗','yuding','','[]','人言百果中，唯棗凡且鄙。皮皴似龜手，葉小如鼠耳。',144,'御定全唐詩/json/424.json','["人言百果中，唯棗凡且鄙。皮皴似龜手，葉小如鼠耳。", "胡為不自知，生花此園裏。豈宜遇攀玩，倖免遭傷毀。", "二月曲江頭，雜英紅旖旎。棗亦在其間，如嫫對西子。", "東風不擇木，吹喣長未已。眼看欲合抱，得盡生生理。", "寄言遊春客，乞君一回視。君愛繞指柔，從君憐柳杞。", "君求悅目豔，不敢爭桃李。君若作大車，輪軸材須此。"]'),
('yuding-51','蝦蟆','白居易','唐','御定全唐诗','yuding','','[]','嘉魚薦宗廟，靈龜貢邦家。應龍能致雨，潤我百穀芽。',144,'御定全唐詩/json/424.json','["嘉魚薦宗廟，靈龜貢邦家。應龍能致雨，潤我百穀芽。", "蠢蠢水族中，無用者蝦蟆。形穢肌肉腥，出沒於泥沙。", "六月七月交，時雨正滂沱。蝦蟆得其志，快樂無以加。", "地既蕃其生，使之族類多。天又與其聲，得以相喧嘩。", "豈惟玉池上，汙君清冷波。可獨瑤瑟前，亂君鹿鳴歌。", "常恐飛上天，跳躍隨姮娥。往往蝕明月，遣君無奈何。"]'),
('yuding-52','寄隱者','白居易','唐','御定全唐诗','yuding','','[]','賣藥向都城，行憩青門樹。道逢馳驛者，色有非常懼。',120,'御定全唐詩/json/424.json','["賣藥向都城，行憩青門樹。道逢馳驛者，色有非常懼。", "親族走相送，欲別不敢住。私怪問道旁，何人複何故。", "雲是右丞相，當國握樞務。祿厚食萬錢，恩深日三顧。", "昨日延英對，今日崖州去。由來君臣間，寵辱在朝暮。", "青青東郊草，中有歸山路。歸去臥雲人，謀身計非誤。"]'),
('yuding-53','放魚','白居易','唐','御定全唐诗','yuding','','[]','曉日提竹籃，家僮買春蔬。青青芹蕨下，疊臥雙白魚。',156,'御定全唐詩/json/424.json','["曉日提竹籃，家僮買春蔬。青青芹蕨下，疊臥雙白魚。", "無聲但呀呀，以氣相喣濡。傾籃寫地上，撥剌長尺餘。", "豈唯刀機憂，坐見螻蟻圖。脫泉雖已久，得水猶可蘇。", "放之小池中，且用救乾枯。水小池窄狹，動尾觸四隅。", "一時幸苟活，久遠將何如。憐其不得所，移放于南湖。", "南湖連西江，好去勿踟躕。施恩即望報，吾非斯人徒。", "不須泥沙底，辛苦覓明珠。"]'),
('yuding-54','文柏床','白居易','唐','御定全唐诗','yuding','','[]','陵上有老柏，柯葉寒蒼蒼。朝為風煙樹，暮為宴寢床。',96,'御定全唐詩/json/424.json','["陵上有老柏，柯葉寒蒼蒼。朝為風煙樹，暮為宴寢床。", "以其多奇文，宜升君子堂。刮削露節目，拂拭生輝光。", "玄斑狀狸首，素質如截肪。雖充悅目玩，終乏周身防。", "華彩誠可愛，生理苦已傷。方知自殘者，為有好文章。"]'),
('yuding-55','潯陽三題：廬山桂','白居易','唐','御定全唐诗','yuding','','[]','偃蹇月中桂，結根依青天。天風繞月起，吹子下人間。',108,'御定全唐詩/json/424.json','["偃蹇月中桂，結根依青天。天風繞月起，吹子下人間。", "飄零委何處，乃落匡廬山。生為石上桂，葉如翦碧鮮。", "枝幹日長大，根荄日牢堅。不歸天上月，空老山中年。", "廬山去咸陽，道裏三四千。無人為移植，得入上林園。", "不及紅花樹，長栽溫室前。"]'),
('yuding-56','潯陽三題：湓浦竹','白居易','唐','御定全唐诗','yuding','','[]','潯陽十月天，天氣仍溫燠。有霜不殺草，有風不落木。',96,'御定全唐詩/json/424.json','["潯陽十月天，天氣仍溫燠。有霜不殺草，有風不落木。", "玄冥氣力薄，草木冬猶綠。誰肯湓浦頭，回眼看修竹。", "其有顧盼者，持刀斬且束。剖劈青琅玕，家家蓋牆屋。", "吾聞汾晉間，竹少重如玉。胡為取輕賤，生此西江曲。"]'),
('yuding-57','潯陽三題：東林寺白蓮','白居易','唐','御定全唐诗','yuding','','[]','東林北塘水，湛湛見底清。中生白芙蓉，菡萏三百莖。',120,'御定全唐詩/json/424.json','["東林北塘水，湛湛見底清。中生白芙蓉，菡萏三百莖。", "白日發光彩，清飆散芳馨。泄香銀囊破，瀉露玉盤傾。", "我慚塵垢眼，見此瓊瑤英。乃知紅蓮花，虛得清淨名。", "夏萼敷未歇，秋房結才成。夜深眾僧寢，獨起繞池行。", "欲收一顆子，寄向長安城。但恐出山去，人間種不生。"]'),
('yuding-58','大水','白居易','唐','御定全唐诗','yuding','','[]','潯陽郊郭間，大水歲一至。閭閻半飄蕩，城堞多傾墜。',120,'御定全唐詩/json/424.json','["潯陽郊郭間，大水歲一至。閭閻半飄蕩，城堞多傾墜。", "蒼茫生海色，渺漫連空翠。風卷白波翻，日煎紅浪沸。", "工商徹屋去，牛馬登山避。況當率稅時，頗害農桑事。", "獨有傭舟子，鼓枻生意氣。不知萬人災，自覓錐刀利。", "吾無奈爾何，爾非久得志。九月霜降後，水涸為平地。"]'),
('yuding-0','續古詩十首','白居易','唐','御定全唐诗','yuding','','[]','戚戚複戚戚，送君遠行役。行役非中原，海外黃沙磧。',528,'御定全唐詩/json/425.json','["戚戚複戚戚，送君遠行役。行役非中原，海外黃沙磧。", "伶俜獨居妾，迢遞長征客。君望功名歸，妾憂生死隔。", "誰家無夫婦，何人不離坼。所恨薄命身，嫁遲別日迫。", "妾身有存歿，妾心無改易。生作閨中婦，死作山頭石。", "掩淚別鄉里，飄颻將遠行。茫茫綠野中，春盡孤客情。", "驅馬上丘隴，高低路不平。風吹棠梨花，啼鳥時一聲。", "古墓何代人，不知姓與名。化作路傍土，年年春草生。", "感彼忽自悟，今我何營營。", "朝采山上薇，暮采山上薇。歲晏薇亦盡，饑來何所為。", "坐飲白石水，手把青松枝。擊節獨長歌，其聲清且悲。", "櫪馬非不肥，所苦常縶維。豢豕非不飽，所憂竟為犧。", "行行歌此曲，以慰常苦饑。", "雨露長纖草，山苗高入雲。風雪折勁木，澗松摧為薪。", "風摧此何意，雨長彼何因。百丈澗底死，寸莖山上春。", "可憐苦節士，感此涕盈巾。", "窈窕雙鬟女，容德俱如玉。晝居不逾閾，夜行常秉燭。", "氣如含露蘭，心如貫霜竹。宜當備嬪禦，胡為守幽獨。", "無媒不得選，年忽過三六。歲暮望漢宮，誰在黃金屋。", "邯鄲進倡女，能唱黃花曲。一曲稱君心，恩榮連九族。", "棲棲遠方士，讀書三十年。業成無知己，徒步來入關。", "長安多王侯，英俊競攀援。幸隨眾賓末，得廁門館間。", "東閣有旨酒，中堂有管弦。何為向隅客，對此不開顏。", "富貴無是非，主人終日歡。貧賤多悔尤，客子中夜歎。", "歸去複歸去，故鄉貧亦安。"]'),
('yuding-1','秦中吟十首：議婚','白居易','唐','御定全唐诗','yuding','','[]','天下無正聲，悅耳即為娛。人間無正色，悅目即為姝。',180,'御定全唐詩/json/425.json','["天下無正聲，悅耳即為娛。人間無正色，悅目即為姝。", "顏色非相遠，貧富則有殊。貧為時所棄，富為時所趨。", "紅樓富家女，金縷繡羅襦。見人不斂手，嬌癡二八初。", "母兄未開口，已嫁不須臾。綠窗貧家女，寂寞二十餘。", "荊釵不直錢，衣上無真珠。幾回人欲聘，臨日又踟躕。", "主人會良媒，置酒滿玉壺。四座且勿飲，聽我歌兩途。", "富家女易嫁，嫁早輕其夫。貧家女難嫁，嫁晚孝于姑。", "聞君欲娶婦，娶婦意何如。"]'),
('yuding-2','秦中吟十首：重賦','白居易','唐','御定全唐诗','yuding','','[]','厚地植桑麻，所要濟生民。生民理布帛，所求活一身。',228,'御定全唐詩/json/425.json','["厚地植桑麻，所要濟生民。生民理布帛，所求活一身。", "身外充征賦，上以奉君親。國家定兩稅，本意在愛人。", "厥初防其淫，明敕內外臣。稅外加一物，皆以枉法論。", "奈何歲月久，貪吏得因循。浚我以求寵，斂索無冬春。", "織絹未成匹，繰絲未盈斤。裏胥迫我納，不許暫逡巡。", "歲暮天地閉，陰風生破村。夜深煙火盡，霰雪白紛紛。", "幼者形不蔽，老者體無溫。悲喘與寒氣，併入鼻中辛。", "昨日輸殘稅，因窺官庫門。繒帛如山積，絲絮如雲屯。", "號為羨餘物，隨月獻至尊。奪我身上暖，買爾眼前恩。", "進入瓊林庫，歲久化為塵。"]'),
('yuding-3','秦中吟十首：傷宅','白居易','唐','御定全唐诗','yuding','','[]','誰家起甲第，朱門大道邊。豐屋中櫛比，高牆外回環。',168,'御定全唐詩/json/425.json','["誰家起甲第，朱門大道邊。豐屋中櫛比，高牆外回環。", "累累六七堂，棟宇相連延。一堂費百萬，鬱鬱起青煙。", "洞房溫且清，寒暑不能幹。高堂虛且迥，坐臥見南山。", "繞廊紫藤架，夾砌紅藥欄。攀枝摘櫻桃，帶花移牡丹。", "主人此中坐，十載為大官。廚有臭敗肉，庫有貫朽錢。", "誰能將我語，問爾骨肉間。豈無窮賤者，忍不救饑寒。", "如何奉一身，直欲保千年。不見馬家宅，今作奉誠園。"]'),
('yuding-4','秦中吟十首：傷友','白居易','唐','御定全唐诗','yuding','','[]','陋巷孤寒士，出門苦恓恓。雖雲志氣高，豈免顏色低。',144,'御定全唐詩/json/425.json','["陋巷孤寒士，出門苦恓恓。雖雲志氣高，豈免顏色低。", "平生同門友，通籍在金閨。曩者膠漆契，邇來雲雨睽。", "正逢下朝歸，軒騎五門西。是時天久陰，三日雨淒淒。", "蹇驢避路立，肥馬當風嘶。回頭忘相識，占道上沙堤。", "昔年洛陽社，貧賤相提攜。今日長安道，對面隔雲泥。", "近日多如此，非君獨慘淒。死生不變者，唯聞任與黎。"]'),
('yuding-5','秦中吟十首：不致仕','白居易','唐','御定全唐诗','yuding','','[]','七十而致仕，禮法有明文。何乃貪榮者，斯言如不聞。',132,'御定全唐詩/json/425.json','["七十而致仕，禮法有明文。何乃貪榮者，斯言如不聞。", "可憐八九十，齒墮雙眸昏。朝露貪名利，夕陽憂子孫。", "掛冠顧翠緌，懸車惜朱輪。金章腰不勝，傴僂入君門。", "誰不愛富貴，誰不戀君恩。年高須告老，名遂合退身。", "少時共嗤誚，晚歲多因循。賢哉漢二疏，彼獨是何人。", "寂寞東門路，無人繼去塵。"]'),
('yuding-6','秦中吟十首：立碑','白居易','唐','御定全唐诗','yuding','','[]','勳德既下衰，文章亦陵夷。但見山中石，立作路旁碑。',168,'御定全唐詩/json/425.json','["勳德既下衰，文章亦陵夷。但見山中石，立作路旁碑。", "銘勳悉太公，敘德皆仲尼。複以多為貴，千言直萬貲。", "為文彼何人，想見下筆時。但欲愚者悅，不思賢者嗤。", "豈獨賢者嗤，仍傳後代疑。古石蒼苔字，安知是愧詞。", "我聞望江縣，麹令撫煢嫠。在官有仁政，名不聞京師。", "身歿欲歸葬，百姓遮路岐。攀轅不得歸，留葬此江湄。", "至今道其名，男女涕皆垂。無人立碑碣，唯有邑人知。"]'),
('yuding-7','秦中吟十首：輕肥','白居易','唐','御定全唐诗','yuding','','[]','意氣驕滿路，鞍馬光照塵。借問何為者，人稱是內臣。',96,'御定全唐詩/json/425.json','["意氣驕滿路，鞍馬光照塵。借問何為者，人稱是內臣。", "朱紱皆大夫，紫綬或將軍。誇赴軍中宴，走馬去如雲。", "尊罍溢九醞，水陸羅八珍。果擘洞庭橘，膾切天池鱗。", "食飽心自若，酒酣氣益振。是歲江南旱，衢州人食人。"]'),
('yuding-8','秦中吟十首：五弦','白居易','唐','御定全唐诗','yuding','','[]','清歌且罷唱，紅袂亦停舞。趙叟抱五弦，宛轉當胸撫。',120,'御定全唐詩/json/425.json','["清歌且罷唱，紅袂亦停舞。趙叟抱五弦，宛轉當胸撫。", "大聲粗若散，颯颯風和雨。小聲細欲絕，切切鬼神語。", "又如鵲報喜，轉作猿啼苦。十指無定音，顛倒宮征羽。", "坐客聞此聲，形神若無主。行客聞此聲，駐足不能舉。", "嗟嗟俗人耳，好今不好古。所以綠窗琴，日日生塵土。"]'),
('yuding-9','秦中吟十首：歌舞','白居易','唐','御定全唐诗','yuding','','[]','秦中歲雲暮，大雪滿皇州。雪中退朝者，朱紫盡公侯。',108,'御定全唐詩/json/425.json','["秦中歲雲暮，大雪滿皇州。雪中退朝者，朱紫盡公侯。", "貴有風雪興，富無饑寒憂。所營唯第宅，所務在追遊。", "朱門車馬客，紅燭歌舞樓。歡酣促密坐，醉暖脫重裘。", "秋官為主人，廷尉居上頭。日中為一樂，夜半不能休。", "豈知閿鄉獄，中有凍死囚。"]'),
('yuding-10','秦中吟十首：買花','白居易','唐','御定全唐诗','yuding','','[]','帝城春欲暮，喧喧車馬度。共道牡丹時，相隨買花去。',120,'御定全唐詩/json/425.json','["帝城春欲暮，喧喧車馬度。共道牡丹時，相隨買花去。", "貴賤無常價，酬直看花數。灼灼百朵紅，戔戔五束素。", "上張幄幕庇，旁織巴籬護。水灑複泥封，移來色如故。", "家家習為俗，人人迷不悟。有一田舍翁，偶來買花處。", "低頭獨長歎，此歎無人喻。一叢深色花，十戶中人賦。"]'),
('yuding-11','贈友五首','白居易','唐','御定全唐诗','yuding','','[]','一年十二月，每月有常令。君出臣奉行，謂之握金鏡。',564,'御定全唐詩/json/425.json','["一年十二月，每月有常令。君出臣奉行，謂之握金鏡。", "由茲六氣順，以遂萬物性。時令一反常，生靈受其病。", "周漢德下衰，王風始不競。又從斬晁錯，諸侯益強盛。", "百里不同禁，四時自為政。盛夏興土功，方春剿人命。", "誰能救其失，待君佐邦柄。峨峨象魏門，懸法彝倫正。", "銀生楚山曲，金生鄱溪濱。南人棄農業，求之多苦辛。", "披砂複鑿石，矻矻無冬春。手足盡皴胝，愛利不愛身。", "畬田既慵斫，稻田亦懶耘。相攜作遊手，皆道求金銀。", "畢竟金與銀，何殊泥與塵。且非衣食物，不濟饑寒人。", "棄本以趨末，日富而歲貧。所以先聖王，棄藏不為珍。", "誰能反古風，待君秉國鈞。捐金複抵璧，勿使勞生民。", "私家無錢爐，平地無銅山。胡為秋夏稅，歲歲輸銅錢。", "錢力日已重，農力日已殫。賤糶粟與麥，賤貿絲與綿。", "歲暮衣食盡，焉得無饑寒。吾聞國之初，有制垂不刊。", "庸必算丁口，租必計桑田。不求土所無，不強人所難。", "量入以為出，上足下亦安。兵興一變法，兵息遂不還。", "使我農桑人，憔悴畎畝間。誰能革此弊，待君秉利權。", "複彼租庸法，令如貞觀年。", "京師四方則，王化之本根。長吏久於政，然後風教敦。", "如何尹京者，遷次不逡巡。請君屈指數，十年十五人。", "科條日相矯，吏力亦已勤。寬猛政不一，民心安得淳。", "九州雍為首，群牧之所遵。天下率如此，何以安吾民。", "誰能變此法，待君贊彌綸。慎擇循良吏，令其長子孫。", "三十男有室，二十女有歸。近代多離亂，婚姻多過期。"]'),
('yuding-12','寓意詩五首','白居易','唐','御定全唐诗','yuding','','[]','豫樟生深山，七年而後知。挺高二百尺，本末皆十圍。',564,'御定全唐詩/json/425.json','["豫樟生深山，七年而後知。挺高二百尺，本末皆十圍。", "天子建明堂，此材獨中規。匠人執斤墨，采度將有期。", "孟冬草木枯，烈火燎山陂。疾風吹猛焰，從根燒到枝。", "養材三十年，方成棟樑姿。一朝為灰燼，柯葉無孑遺。", "地雖生爾材，天不與爾時。不如糞土英，猶有人掇之。", "已矣勿重陳，重陳令人悲。不悲焚燒苦，但悲採用遲。", "赫赫京內史，炎炎中書郎。昨傳征拜日，恩賜頗殊常。", "貂冠水蒼玉，紫綬黃金章。佩服身未暖，已聞竄遐荒。", "親戚不得別，吞聲泣路旁。賓客亦已散，門前雀羅張。", "富貴來不久，倏如瓦溝霜。權勢去尤速，瞥若石火光。", "不如守貧賤，貧賤可久長。傳語宦遊子，且來歸故鄉。", "促織不成章，提壺但聞聲。嗟哉蟲與鳥，無實有虛名。", "與君定交日，久要如弟兄。何以示誠信，白水指為盟。", "雲雨一為別，飛沉兩難並。君為得風鵬，我為失水鯨。", "音信日已疏，恩分日已輕。窮通尚如此，何況死與生。", "乃知擇交難，須有知人明。莫將山上松，結托水上萍。", "翩翩兩玄鳥，本是同巢燕。分飛來幾時，秋夏炎涼變。", "一宿蓬蓽廬，一棲明光殿。偶因銜泥處，複得重相見。", "彼矜杏梁貴，此嗟茅棟賤。眼看秋社至，兩處俱難戀。", "所托各暫時，胡為相嘆羨。", "婆娑園中樹，根株大合圍。蠢爾樹間蟲，形質一何微。", "孰謂蟲之微，蟲蠹已無期。孰謂樹之大，花葉有衰時。", "花衰夏未實，葉病秋先萎。樹心半為土，觀者安得知。", "借問蟲何在，在身不在枝。借問蟲何食，食心不食皮。"]'),
('yuding-13','讀史五首','白居易','唐','御定全唐诗','yuding','','[]','楚懷放靈均，國政亦荒淫。彷徨未忍決，繞澤行悲吟。',468,'御定全唐詩/json/425.json','["楚懷放靈均，國政亦荒淫。彷徨未忍決，繞澤行悲吟。", "漢文疑賈生，謫置湘之陰。是時刑方措，此去難為心。", "士生一代間，誰不有浮沉。良時真可惜，亂世何足欽。", "乃知汨羅恨，未抵長沙深。", "禍患如棼絲，其來無端緒。馬遷下蠶室，嵇康就囹圄。", "抱冤志氣屈，忍恥形神沮。當彼戮辱時，奮飛無翅羽。", "商山有黃綺，潁川有巢許。何不從之游，超然離網罟。", "山林少羈鞅，世路多艱阻。寄謝伐檀人，慎勿嗟窮處。", "漢日大將軍，少為乞食子。秦時故列侯，老作鋤瓜士。", "春華何暐曄，園中發桃李。秋風忽蕭條，堂上生荊杞。", "深谷變為岸，桑田成海水。勢去未須悲，時來何足喜。", "寄言榮枯者，反復殊未已。", "含沙射人影，雖病人不知。巧言構人罪，至死人不疑。", "掇蜂殺愛子，掩鼻戮寵姬。弘恭陷蕭望，趙高謀李斯。", "陰德既必報，陰禍豈虛施。人事雖可罔，天道終難欺。", "明則有刑辟，幽則有神祇。苟免勿私喜，鬼得而誅之。", "季子憔悴時，婦見不下機。買臣負薪日，妻亦棄如遺。", "一朝黃金多，佩印衣錦歸。去妻不敢視，婦嫂強依依。", "富貴家人重，貧賤妻子欺。奈何貧富間，可移親愛志。", "遂使中人心，汲汲求富貴。又令下人力，各競錐刀利。", "隨分歸舍來，一取妻孥意。"]'),
('yuding-14','和答詩十首：和思歸樂','白居易','唐','御定全唐诗','yuding','','[]','山中不棲鳥，夜半聲嚶嚶。似道思歸樂，行人掩泣聽。',456,'御定全唐詩/json/425.json','["山中不棲鳥，夜半聲嚶嚶。似道思歸樂，行人掩泣聽。", "皆疑此山路，遷客多南征。憂憤氣不散，結化為精靈。", "我謂此山鳥，本不因人生。人心自懷土，想作思歸鳴。", "孟嘗平居時，娛耳琴泠泠。雍門一言感，未奏淚沾纓。", "魏武銅雀妓，日與歡樂並。一旦西陵望，欲歌先涕零。", "峽猿亦何意，隴水複何情。為入愁人耳，皆為腸斷聲。", "請看元侍禦，亦宿此郵亭。因聽思歸鳥，神氣獨安寧。", "問君何以然，道勝心自平。雖為南遷客，如在長安城。", "雲得此道來，何慮複何營。窮達有前定，憂喜無交爭。", "所以事君日，持憲立大庭。雖有回天力，撓之終不傾。", "況始三十餘，年少有直名。心中志氣大，眼前爵祿輕。", "君恩若雨露，君威若雷霆。退不苟免難，進不曲求榮。", "在火辨玉性，經霜識松貞。展禽任三黜，靈均長獨醒。", "獲戾自東洛，貶官向南荊。再拜辭闕下，長揖別公卿。", "荊州又非遠，驛路半月程。漢水照天碧，楚山插雲青。", "江陵橘似珠，宜城酒如餳。誰謂譴謫去，未妨遊賞行。", "人生百歲內，天地暫寓形。太倉一稊米，大海一浮萍。", "身委逍遙篇，心付頭陀經。尚達死生觀，寧為寵辱驚。", "中懷苟有主，外物安能縈。任意思歸樂，聲聲啼到明。"]'),
('yuding-15','和答詩十首：和陽城驛','白居易','唐','御定全唐诗','yuding','','[]','商山陽城驛，中有歎者誰。雲是元監察，江陵謫去時。',456,'御定全唐詩/json/425.json','["商山陽城驛，中有歎者誰。雲是元監察，江陵謫去時。", "忽見此驛名，良久涕欲垂。何故陽道州，名姓同於斯。", "憐君一寸心，寵辱誓不移。疾惡若巷伯，好賢如緇衣。", "沉吟不能去，意者欲改為。改為避賢驛，大署於門楣。", "荊人愛羊祜，戶曹改為辭。一字不忍道，況兼姓呼之。", "因題八百言，言直文甚奇。詩成寄與我，鏘若金和絲。", "上言陽公行，友悌無等夷。骨肉同衾裯，至死不相離。", "次言陽公跡，夏邑始棲遲。鄉人化其風，少長皆孝慈。", "次言陽公道，終日對酒卮。兄弟笑相顧，醉貌紅怡怡。", "次言陽公節，謇謇居諫司。誓心除國蠹，決死犯天威。", "終言陽公命，左遷天一涯。道州炎瘴地，身不得生歸。", "一一皆實錄，事事無孑遺。凡是為善者，聞之惻然悲。", "道州既已矣，往者不可追。何世無其人，來者亦可思。", "願以君子文，告彼大樂師。附於雅歌末，奏之白玉墀。", "天子聞此章，教化如法施。直諫從如流，佞臣惡如疵。", "宰相聞此章，政柄端正持。進賢不知倦，去邪勿複疑。", "憲臣聞此章，不敢懷依違。諫官聞此章，不忍縱詭隨。", "然後告史氏，舊史有前規。若作陽公傳，欲令後世知。", "不勞敘世家，不用費文辭。但于國史上，全錄元稹詩。"]'),
('yuding-16','和答詩十首：答桐花','白居易','唐','御定全唐诗','yuding','','[]','山木多蓊鬱，茲桐獨亭亭。葉重碧雲片，花簇紫霞英。',432,'御定全唐詩/json/425.json','["山木多蓊鬱，茲桐獨亭亭。葉重碧雲片，花簇紫霞英。", "是時三月天，春暖山雨晴。夜色向月淺，暗香隨風輕。", "行者多商賈，居者悉黎氓。無人解賞愛，有客獨屏營。", "手攀花枝立，足蹋花影行。生憐不得所，死欲揚其聲。", "截為天子琴，刻作古人形。雲待我成器，薦之于穆清。", "誠是君子心，恐非草木情。胡為愛其華，而反傷其生。", "老龜被刳腸，不如無神靈。雄雞自斷尾，不願為犧牲。", "況此好顏色，花紫葉青青。宜遂天地性，忍加刀斧刑。", "我思五丁力，拔入九重城。當君正殿栽，花葉生光晶。", "上對月中桂，下覆階前蓂。泛拂香爐煙，隱映斧藻屏。", "為君布綠陰，當暑蔭軒楹。沉沉綠滿地，桃李不敢爭。", "為君發清韻，風來如叩瓊。泠泠聲滿耳，鄭衛不足聽。", "受君封植力，不獨吐芬馨。助君行春令，開花應晴明。", "受君雨露恩，不獨含芳榮。戒君無戲言，翦葉封弟兄。", "受君歲月功，不獨資生成。為君長高枝，鳳凰上頭鳴。", "一鳴君萬歲，壽如山不傾。再鳴萬人泰，泰階為之平。", "如何有此用，幽滯在岩坰。歲月不爾駐，孤芳坐凋零。", "請向桐枝上，為餘題姓名。待餘有勢力，移爾獻丹庭。"]'),
('yuding-17','和答詩十首：和大觜烏','白居易','唐','御定全唐诗','yuding','','[]','烏者種有二，名同性不同。觜小者慈孝，觜大者貪庸。',480,'御定全唐詩/json/425.json','["烏者種有二，名同性不同。觜小者慈孝，觜大者貪庸。", "觜大命又長，生來十餘冬。物老顏色變，頭毛白茸茸。", "飛來庭樹上，初但驚兒童。老巫生奸計，與烏意潛通。", "雲此非凡鳥，遙見起敬恭。千歲乃一出，喜賀主人翁。", "祥瑞來白日，神聖占知風。陰作北斗使，能為人吉凶。", "此烏所止家，家產日夜豐。上以致壽考，下可宜田農。", "主人富家子，身老心童蒙。隨巫拜複祝，婦姑亦相從。", "殺雞薦其肉，敬若禋六宗。烏喜張大觜，飛接在虛空。", "烏既飽膻腥，巫亦饗甘濃。烏巫互相利，不復兩西東。", "日日營巢窟，稍稍近房櫳。雖生八九子，誰辨其雌雄。", "群雛又成長，眾觜逞殘凶。探巢吞燕卵，入蔟啄蠶蟲。", "豈無乘秋隼，羈絆委高墉。但食烏殘肉，無施搏擊功。", "亦有能言鸚，翅碧觜距紅。暫曾說烏罪，囚閉在深籠。", "青青窗前柳，鬱鬱井上桐。貪烏占棲息，慈烏獨不容。", "慈烏爾奚為，來往何憧憧。曉去先晨鼓，暮歸後昏鐘。", "辛苦塵土間，飛啄禾黍叢。得食將哺母，饑腸不自充。", "主人憎慈烏，命子削彈弓。弦續會稽竹，丸鑄荊山銅。", "慈烏求母食，飛下爾庭中。數粒未入口，一丸已中胸。", "仰天號一聲，似欲訴蒼穹。反哺日未足，非是惜微躬。", "誰能持此冤，一為問化工。胡然大觜烏，竟得天年終。"]'),
('yuding-18','和答詩十首：答四皓廟','白居易','唐','御定全唐诗','yuding','','[]','天下有道見，無道卷懷之。此乃聖人語，吾聞諸仲尼。',456,'御定全唐詩/json/425.json','["天下有道見，無道卷懷之。此乃聖人語，吾聞諸仲尼。", "矯矯四先生，同稟希世資。隨時有顯晦，秉道無磷緇。", "秦皇肆暴虐，二世遘亂離。先生相隨去，商嶺采紫芝。", "君看秦獄中，戮辱者李斯。劉項爭天下，謀臣竟悅隨。", "先生如鸞鶴，去入冥冥飛。君看齊鼎中，焦爛者酈其。", "子房得沛公，自謂相遇遲。八難掉舌樞，三略役心機。", "辛苦十數年，晝夜形神疲。竟雜霸者道，徒稱帝者師。", "子房爾則能，此非吾所宜。漢高之季年，嬖寵鐘所私。", "塚嫡欲廢奪，骨肉相憂疑。豈無子房口，口舌無所施。", "亦有陳平心，心計將何為。皤皤四先生，高冠危映眉。", "從容下南山，顧盼入東闈。前瞻惠太子，左右生羽儀。", "卻顧戚夫人，楚舞無光輝。心不畫一計，口不吐一詞。", "闇定天下本，遂安劉氏危。子房吾則能，此非爾所知。", "先生道既光，太子禮甚卑。安車留不住，功成棄如遺。", "如彼旱天雲，一雨百穀滋。澤則在天下，雲複歸希夷。", "勿高巢與由，勿尚呂與伊。巢由往不返，伊呂去不歸。", "豈如四先生，出處兩逶迤。何必長隱逸，何必長濟時。", "由來聖人道，無朕不可窺。卷之不盈握，舒之亙八陲。", "先生道甚明，夫子猶或非。願子辨其惑，為予吟此詩。"]'),
('yuding-19','和答詩十首：和雉媒','白居易','唐','御定全唐诗','yuding','','[]','吟君雉媒什，一哂複一歎。和之一何晚，今日乃成篇。',180,'御定全唐詩/json/425.json','["吟君雉媒什，一哂複一歎。和之一何晚，今日乃成篇。", "豈唯鳥有之，抑亦人複然。張陳刎頸交，竟以勢不完。", "至今不平氣，塞絕泜水源。趙襄骨肉親，亦以利相殘。", "至今不善名，高於磨笄山。況此籠中雉，志在飲啄間。", "稻粱暫入口，性已隨人遷。身苦亦自忘，同族何足言。", "但恨為媒拙，不足以自全。勸君今日後，養鳥養青鸞。", "青鸞一失侶，至死守孤單。勸君今日後，結客結任安。", "主人賓客去，獨住在門闌。"]'),
('yuding-20','和答詩十首：和松樹','白居易','唐','御定全唐诗','yuding','','[]','亭亭山上松，一一生朝陽。森聳上參天，柯條百尺長。',168,'御定全唐詩/json/425.json','["亭亭山上松，一一生朝陽。森聳上參天，柯條百尺長。", "漠漠塵中槐，兩兩夾康莊。婆娑低覆地，枝幹亦尋常。", "八月白露降，槐葉次第黃。歲暮滿山雪，松色鬱青蒼。", "彼如君子心，秉操貫冰霜。此如小人面，變態隨炎涼。", "共知松勝槐，誠欲栽道傍。糞土種瑤草，瑤草終不芳。", "尚可以斧斤，伐之為棟樑。殺身獲其所，為君構明堂。", "不然終天年，老死在南岡。不願亞枝葉，低隨槐樹行。"]'),
('yuding-21','和答詩十首：答箭鏃','白居易','唐','御定全唐诗','yuding','','[]','矢人職司憂，為箭恐不精。精在利其鏃，錯磨鋒鏑成。',204,'御定全唐詩/json/425.json','["矢人職司憂，為箭恐不精。精在利其鏃，錯磨鋒鏑成。", "插以青竹簳，羽之赤雁翎。勿言分寸鐵，為用乃長兵。", "聞有狗盜者，晝伏夜潛行。摩弓拭箭鏃，夜射不待明。", "一盜既流血，百犬同吠聲。狺狺嗥不已，主人為之驚。", "盜心憎主人，主人不知情。反責鏃太利，矢人獲罪名。", "寄言控弦者，願君少留聽。何不向西射，西天有狼星。", "何不向東射，東海有長鯨。不然學仁貴，三矢平虜庭。", "不然學仲連，一發下燕城。胡為射小盜，此用無乃輕。", "徒沾一點血，虛汙箭頭腥。"]'),
('yuding-22','和答詩十首：和古社','白居易','唐','御定全唐诗','yuding','','[]','廢村多年樹，生在古社隈。為作妖狐窟，心空身未摧。',180,'御定全唐詩/json/425.json','["廢村多年樹，生在古社隈。為作妖狐窟，心空身未摧。", "妖狐變美女，社樹成樓臺。黃昏行人過，見者心裴回。", "饑雕竟不捉，老犬反為媒。歲媚少年客，十去九不回。", "昨夜雲雨合，烈風驅迅雷。風拔樹根出，雷劈社壇開。", "飛電化為火，妖狐燒作灰。天明至其所，清曠無氛埃。", "舊地葺村落，新田辟荒萊。始知天降火，不必常為災。", "勿謂神默默，勿謂天恢恢。勿喜犬不捕，勿誇雕不猜。", "寄言狐媚者，天火有時來。"]'),
('yuding-23','和答詩十首：和分水嶺','白居易','唐','御定全唐诗','yuding','','[]','高嶺峻棱棱，細泉流亹亹。勢分合不得，東西隨所委。',168,'御定全唐詩/json/425.json','["高嶺峻棱棱，細泉流亹亹。勢分合不得，東西隨所委。", "悠悠草蔓底，濺濺石罅裏。分流來幾年，晝夜兩如此。", "朝宗遠不及，去海三千里。浸潤小無功，山苗長旱死。", "縈紆用無所，奔迫流不已。唯作嗚咽聲，夜入行人耳。", "有源殊不竭，無坎終難止。同出而異流，君看何所似。", "有似骨肉親，派別從茲始。又似勢利交，波瀾相背起。", "所以贈君詩，將君何所比。不比山上泉，比君井中水。"]'),
('yuding-24','有木詩八首','白居易','唐','御定全唐诗','yuding','','[]','有木名弱柳，結根近清池。風煙借顏色，雨露助華滋。',576,'御定全唐詩/json/425.json','["有木名弱柳，結根近清池。風煙借顏色，雨露助華滋。", "峨峨白雪花，嫋嫋青絲枝。漸密陰自庇，轉高梢四垂。", "截枝扶為杖，軟弱不自持。折條用樊圃，柔脆非其宜。", "為樹信可玩，論材何所施。可惜金堤地，栽之徒爾為。", "有木名櫻桃，得地早滋茂。葉密獨承日，花繁偏受露。", "迎風闇搖動，引鳥潛來去。鳥啄子難成，風來枝莫住。", "低軟易攀玩，佳人屢回顧。色求桃李饒，心向松筠妒。", "好是映牆花，本非當軒樹。所以姓蕭人，曾為伐櫻賦。", "有木秋不凋，青青在江北。謂為洞庭橘，美人自移植。", "上受顧盼恩，下勤澆溉力。實成乃是枳，臭苦不堪食。", "物有似是者，真偽何由識。美人默無言，對之長歎息。", "中含害物意，外矯淩霜色。仍向枝葉間，潛生刺如棘。", "有木名杜梨，陰森覆丘壑。心蠹已空朽，根深尚盤薄。", "狐媚言語巧，鳥妖聲音惡。憑此為巢穴，往來互棲托。", "四傍五六本，葉枝相交錯。借問因何生，秋風吹子落。", "為長社壇下，無人敢芟斫。幾度野火來，風回燒不著。", "有木香苒苒，山頭生一蕟。主人不知名，移種近軒闥。", "愛其有芳味，因以調麹糵。前後曾飲者，十人無一活。", "豈徒悔封植，兼亦誤采掇。試問識藥人，始知名野葛。", "年深已滋蔓，刀斧不可伐。何時猛風來，為我連根拔。", "有木名水檉，遠望青童童。根株非勁挺，柯葉多蒙籠。", "彩翠色如柏，鱗皴皮似松。為同松柏類，得列嘉樹中。", "枝弱不勝雪，勢高常懼風。雪壓低還舉，風吹西複東。", "柔芳甚楊柳，早落先梧桐。惟有一堪賞，中心無蠹蟲。"]'),
('yuding-25','歎魯二首','白居易','唐','御定全唐诗','yuding','','[]','季桓心豈忠，其富過周公。陽貨道豈正，其權執國命。',144,'御定全唐詩/json/425.json','["季桓心豈忠，其富過周公。陽貨道豈正，其權執國命。", "由來富與權，不系才與賢。所托得其地，雖愚亦獲安。", "彘肥因糞壤，鼠穩依社壇。蟲獸尚如是，豈謂無因緣。", "展禽胡為者，直道竟三黜。顏子何如人，屢空聊過日。", "皆懷王佐道，不踐陪臣秩。自古無奈何，命為時所屈。", "有如草木分，天各與其一。荔枝非名花，牡丹無甘實。"]'),
('yuding-26','反鮑明遠白頭吟','白居易','唐','御定全唐诗','yuding','','[]','炎炎者烈火，營營者小蠅。火不熱貞玉，蠅不點清冰。',120,'御定全唐詩/json/425.json','["炎炎者烈火，營營者小蠅。火不熱貞玉，蠅不點清冰。", "此苟無所受，彼莫能相仍。乃知物性中，各有能不能。", "古稱怨恨死，則人有所懲。懲淫或應可，在道未為弘。", "譬如蜩鷃徒，啾啾啅龍鵬。宜當委之去，寥廓高飛騰。", "豈能泥塵下，區區酬怨憎。胡為坐自苦，吞悲仍撫膺。"]'),
('yuding-27','青塚','白居易','唐','御定全唐诗','yuding','','[]','上有饑鷹號，下有枯蓬走。茫茫邊雪裏，一掬沙培塿。',192,'御定全唐詩/json/425.json','["上有饑鷹號，下有枯蓬走。茫茫邊雪裏，一掬沙培塿。", "傳是昭君墓，埋閉蛾眉久。凝脂化為泥，鉛黛複何有。", "唯有陰怨氣，時生墳左右。鬱鬱如苦霧，不隨骨銷朽。", "婦人無他才，榮枯系妍否。何乃明妃命，獨懸畫工手。", "丹青一詿誤，白黑相紛糾。遂使君眼中，西施作嫫母。", "同儕傾寵倖，異類為配偶。禍福安可知，美顏不如醜。", "何言一時事，可戒千年後。特報後來姝，不須倚眉首。", "無辭插荊釵，嫁作貧家婦。不見青塚上，行人為澆酒。"]'),
('yuding-28','雜感','白居易','唐','御定全唐诗','yuding','','[]','君子防悔尤，賢人戒行藏。嫌疑遠瓜李，言動慎毫芒。',180,'御定全唐詩/json/425.json','["君子防悔尤，賢人戒行藏。嫌疑遠瓜李，言動慎毫芒。", "立教固如此，撫事有非常。為君持所感，仰面問蒼蒼。", "犬齧桃樹根，李樹反見傷。老龜烹不爛，延禍及枯桑。", "城門自焚爇，池魚罹其殃。陽貨肆兇暴，仲尼畏于匡。", "魯酒薄如水，邯鄲開戰場。伯禽鞭見血，過失由成王。", "都尉身降虜，宮刑加子長。呂安兄不道，都市殺嵇康。", "斯人死已久，其事甚昭彰。是非不由己，禍患安可防。", "使我千載後，涕泗滿衣裳。"]'),
('yuding-0','七德舞－美撥亂，陳王業也','白居易','唐','御定全唐诗','yuding','','[]','七德舞，七德歌，傳自武德至元和。元和小臣白居易，',120,'御定全唐詩/json/426.json','["七德舞，七德歌，傳自武德至元和。元和小臣白居易，", "二十有九即帝位，三十有五致太平。功成理定何神速，", "魏征夢見子夜泣，張謹哀聞辰日哭。怨女三千放出宮，", "含血吮創撫戰士，思摩奮呼乞效死。則知不獨善戰善乘時，", "歌七德，舞七德，聖人有作垂無極。豈徒耀神武，"]'),
('yuding-1','法曲－美列聖，正華聲也','白居易','唐','御定全唐诗','yuding','','[]','法曲法曲歌大定，積德重熙有餘慶。永徽之人舞而詠，',88,'御定全唐詩/json/426.json','["法曲法曲歌大定，積德重熙有餘慶。永徽之人舞而詠，", "法曲法曲歌堂堂，堂堂之慶垂無疆。中宗肅宗複鴻業，", "以亂幹和天寶末，明年胡塵犯宮闕。乃知法曲本華風，", "願求牙曠正華音，不令夷夏相交侵。"]'),
('yuding-2','二王后－明祖宗之意也','白居易','唐','御定全唐诗','yuding','','[]','二王后，彼何人，介公酅公為國賓，周武隋文之子孫。',88,'御定全唐詩/json/426.json','["二王后，彼何人，介公酅公為國賓，周武隋文之子孫。", "古人有言天下者，非是一人之天下。周亡天下傳于隋，", "明堂太廟朝享時，引居賓位備威儀。備威儀，助郊祭，", "欲令嗣位守文君，亡國子孫取為戒。"]'),
('yuding-3','海漫漫－戒求仙也','白居易','唐','御定全唐诗','yuding','','[]','海漫漫，直下無底傍無邊。雲濤煙浪最深處，',94,'御定全唐詩/json/426.json','["海漫漫，直下無底傍無邊。雲濤煙浪最深處，", "秦皇漢武信此語，方士年年采藥去。蓬萊今古但聞名，", "不見蓬萊不敢歸，童男丱女舟中老。徐福文成多誑誕，", "何況玄元聖祖五千言，不言藥，不言仙，不言白日升青天。"]'),
('yuding-4','立部伎－刺雅樂之替也','白居易','唐','御定全唐诗','yuding','','[]','立部伎，鼓笛喧。舞雙劍，跳七丸。嫋巨索，掉長竿。',120,'御定全唐詩/json/426.json','["立部伎，鼓笛喧。舞雙劍，跳七丸。嫋巨索，掉長竿。", "太常部伎有等級，堂上者坐堂下立。堂上坐部笙歌清，", "立部賤，坐部貴，坐部退為立部伎，擊鼓吹笙和雜戲。", "立部又退何所任，始就樂懸操雅音。雅音替壞一至此，", "欲望鳳來百獸舞，何異北轅將適楚。工師愚賤安足雲，"]'),
('yuding-5','華原磬－刺樂工非其人也','白居易','唐','御定全唐诗','yuding','','[]','華原磬，華原磬，古人不聽今人聽。泗濱石，泗濱石，',96,'御定全唐詩/json/426.json','["華原磬，華原磬，古人不聽今人聽。泗濱石，泗濱石，", "樂工雖在耳如壁，不分清濁即為聾。梨園弟子調律呂，", "宮懸一聽華原石，君心遂忘封疆臣。果然胡寇從燕起，", "磬襄入海去不歸，長安市兒為樂師。華原磬與泗濱石，"]'),
('yuding-6','上陽白髮人－湣怨曠也','白居易','唐','御定全唐诗','yuding','','[]','上陽人，紅顏闇老白髮新。綠衣監使守宮門，',136,'御定全唐詩/json/426.json','["上陽人，紅顏闇老白髮新。綠衣監使守宮門，", "同時采擇百餘人，零落年深殘此身。憶昔吞悲別親族，", "未容君王得見面，已被楊妃遙側目。妒令潛配上陽宮，", "耿耿殘燈背壁影，蕭蕭暗雨打窗聲。春日遲，", "鶯歸燕去長悄然，春往秋來不記年。唯向深宮望明月，", "小頭鞋履窄衣裳，青黛點眉眉細長。外人不見見應笑，"]'),
('yuding-7','胡旋女－戒近習也','白居易','唐','御定全唐诗','yuding','','[]','胡旋女，胡旋女。心應弦，手應鼓。弦鼓一聲雙袖舉，',120,'御定全唐詩/json/426.json','["胡旋女，胡旋女。心應弦，手應鼓。弦鼓一聲雙袖舉，", "人間物類無可比，奔車輪緩旋風遲。曲終再拜謝天子，", "中原自有胡旋者，鬥妙爭能爾不如。天寶季年時欲變，", "梨花園中冊作妃，金雞障下養為兒。祿山胡旋迷君眼，", "從茲地軸天維轉，五十年來制不禁。胡旋女，莫空舞，"]'),
('yuding-8','新豐折臂翁－戒邊功也','白居易','唐','御定全唐诗','yuding','','[]','新豐老翁八十八，頭鬢眉須皆似雪。玄孫扶向店前行，',222,'御定全唐詩/json/426.json','["新豐老翁八十八，頭鬢眉須皆似雪。玄孫扶向店前行，", "翁雲貫屬新豐縣，生逢聖代無征戰。慣聽梨園歌管聲，", "點得驅將何處去，五月萬里雲南行。聞道雲南有瀘水，", "村南村北哭聲哀，兒別爺娘夫別妻。皆雲前後征蠻者，", "夜深不敢使人知，偷將大石捶折臂。張弓簸旗俱不堪，", "此臂折來六十年，一肢雖廢一身全。至今風雨陰寒夜，", "不然當時瀘水頭，身死魂孤骨不收。應作雲南望鄉鬼，", "君不聞開元宰相宋開府，不賞邊功防黷武。", "又不聞天寶宰相楊國忠，欲求恩幸立邊功。", "邊功未立生人怨，請問新豐折臂翁。"]'),
('yuding-9','太行路－借夫婦以諷君臣之不終也','白居易','唐','御定全唐诗','yuding','','[]','太行之路能摧車，若比人心是坦途。巫峽之水能覆舟，',91,'御定全唐詩/json/426.json','["太行之路能摧車，若比人心是坦途。巫峽之水能覆舟，", "與君結髮未五載，豈期牛女為參商。古稱色衰相棄背，", "為君熏衣裳，君聞蘭麝不馨香。為君盛容飾，", "不獨人間夫與妻，近代君臣亦如此。君不見左納言，"]'),
('yuding-10','司天臺－引古以儆今也','白居易','唐','御定全唐诗','yuding','','[]','司天臺，仰觀俯察天人際。羲和死來職事廢，',68,'御定全唐詩/json/426.json','["司天臺，仰觀俯察天人際。羲和死來職事廢，", "北辰微闇少光色，四星煌煌如火赤。耀芒動角射三台，", "明朝趨入明光殿，唯奏慶雲壽星見。天文時變兩如斯，"]'),
('yuding-11','捕蝗－刺長吏也','白居易','唐','御定全唐诗','yuding','','[]','捕蝗捕蝗誰家子，天熱日長饑欲死。興元兵後傷陰陽，',106,'御定全唐詩/json/426.json','["捕蝗捕蝗誰家子，天熱日長饑欲死。興元兵後傷陰陽，", "雨飛蠶食千里間，不見青苗空赤土。河南長吏言憂農，", "捕蝗捕蝗竟何利，徒使饑人重勞費。一蟲雖死百蟲來，", "又聞貞觀之初道欲昌，文皇仰天吞一蝗。", "一人有慶兆民賴，是歲雖蝗不為害。"]'),
('yuding-12','昆明春－思王澤之廣被也','白居易','唐','御定全唐诗','yuding','','[]','昆明春，昆明春，春池岸古春流新。影浸南山青滉漾，',112,'御定全唐詩/json/426.json','["昆明春，昆明春，春池岸古春流新。影浸南山青滉漾，", "詔開八水注恩波，千介萬鱗同日活。今來淨綠水照天，", "動植飛沉皆遂性，皇澤如春無不被。漁者仍豐網罟資，", "菰蒲無租魚無稅，近水之人感君惠。感君惠，獨何人，", "天涯地角無禁利，熙熙同似昆明春。"]'),
('yuding-13','城鹽州－美聖謨而誚邊將也','白居易','唐','御定全唐诗','yuding','','[]','城鹽州，城鹽州，城在五原原上頭。蕃東節度缽闡布，',140,'御定全唐詩/json/426.json','["城鹽州，城鹽州，城在五原原上頭。蕃東節度缽闡布，", "君臣赬面有憂色，皆言勿謂唐無人。自築鹽州十餘載，", "諸邊急警勞戍人，唯此一道無煙塵。靈夏潛安誰複辨，", "城鹽州，鹽州未城天子憂。德宗按圖自定計，", "韓公創築受降城，三城鼎峙屯漢兵。東西亙絕數千里，", "相看養寇為身謀，各握強兵固恩澤。願分今日邊將恩，"]'),
('yuding-14','道州民－美臣遇明主也','白居易','唐','御定全唐诗','yuding','','[]','道州民，多侏儒，長者不過三尺餘。市作矮奴年進送，',68,'御定全唐詩/json/426.json','["道州民，多侏儒，長者不過三尺餘。市作矮奴年進送，", "城雲臣按六典書，任土貢有不貢無。道州水土所生者，", "道州民，老者幼者何欣欣。父兄子弟始相保，"]'),
('yuding-15','馴犀－感為政之難終也','白居易','唐','御定全唐诗','yuding','','[]','馴犀馴犀通天犀，軀貌駭人角駭雞。海蠻聞有明天子，',118,'御定全唐詩/json/426.json','["馴犀馴犀通天犀，軀貌駭人角駭雞。海蠻聞有明天子，", "五年馴養始堪獻，六譯語言方得通。上嘉人獸俱來遠，", "海鳥不知鐘鼓樂，池魚空結江湖心。馴犀生處南方熱，", "飲冰臥霰苦蜷局，角骨凍傷鱗甲蹜。馴犀死，蠻兒啼，", "君不見建中初，馴象生還放林邑。君不見貞元末，"]'),
('yuding-16','五弦彈－惡鄭之奪雅也','白居易','唐','御定全唐诗','yuding','','[]','五弦彈，五弦彈，聽者傾耳心寥寥。趙璧知君入骨愛，',160,'御定全唐詩/json/426.json','["五弦彈，五弦彈，聽者傾耳心寥寥。趙璧知君入骨愛，", "第三第四弦泠泠，夜鶴憶子籠中鳴。第五弦聲最掩抑，", "鐵擊珊瑚一兩曲，冰瀉玉盤千萬聲。鐵聲殺，冰聲寒。", "殺聲入耳膚血憯，寒氣中人肌骨酸。曲終聲盡欲半日，", "自歎今朝初得聞，始知孤負平生耳。唯憂趙璧白髮生，", "一彈一唱再三歎，曲澹節稀聲不多。融融曳曳召元氣，", "更從趙璧藝成來，二十五弦不如五。"]'),
('yuding-17','蠻子朝－刺將驕而相備位也','白居易','唐','御定全唐诗','yuding','','[]','蠻子朝，泛皮船兮渡繩橋，來自巂州道路遙。',182,'御定全唐詩/json/426.json','["蠻子朝，泛皮船兮渡繩橋，來自巂州道路遙。", "入界先經蜀川過，蜀將收功先表賀。臣聞雲南六詔蠻，", "開元皇帝雖聖神，唯蠻倔強不來賓。鮮于仲通六萬卒，", "誰知今日慕華風，不勞一人蠻自通。誠由陛下休明德，", "蠻子導從者誰何，摩挲俗羽雙隈伽。清平官持赤藤杖，", "上心貴在懷遠蠻，引臨玉座近天顏。冕旒不垂親勞俫。", "賜衣賜食移時對。移時對，不可得，大臣相看有羨色。", "可憐宰相拖紫佩金章，朝日唯聞對一刻。"]'),
('yuding-18','驃國樂－欲王化之先邇後遠也','白居易','唐','御定全唐诗','yuding','','[]','驃國樂，驃國樂，出自大海西南角。雍羌之子舒難陀，',144,'御定全唐詩/json/426.json','["驃國樂，驃國樂，出自大海西南角。雍羌之子舒難陀，", "玉螺一吹椎髻聳，銅鼓一擊文身踴。珠纓炫轉星宿搖，", "左右歡呼何翕習，至尊德廣之所及。須臾百辟詣閣門，", "時有擊壤老農父，暗測君心閑獨語。聞君政化甚聖明，", "觀身理國國可濟，君如心兮民如體。體生疾苦心憯淒，", "貞元之民苟無病，驃樂不來君亦聖。驃樂驃樂徒喧喧，"]'),
('yuding-19','縛戎人－達窮民之情也','白居易','唐','御定全唐诗','yuding','','[]','縛戎人，縛戎人，耳穿面破驅入秦。天子矜憐不忍殺，',208,'御定全唐詩/json/426.json','["縛戎人，縛戎人，耳穿面破驅入秦。天子矜憐不忍殺，", "身被金創面多瘠，扶病徒行日一驛。朝餐饑渴費杯盤，", "其中一虜語諸虜，爾苦非多我苦多。同伴行人因借問，", "一落蕃中四十載，遣著皮裘系毛帶。唯許正朝服漢儀，", "暗思幸有殘筋力，更恐年衰歸不得。蕃候嚴兵鳥不飛，", "驚藏青塚寒草疏，偷渡黃河夜冰薄。忽聞漢軍鼙鼓聲，", "配向東南卑濕地，定無存恤空防備。念此吞聲仰訴天，", "沒蕃被囚思漢土，歸漢被劫為蕃虜。早知如此悔歸來，", "自古此冤應未有，漢心漢語吐蕃身。"]'),
('yuding-0','驪宮高－美天子重惜人之財力也','白居易','唐','御定全唐诗','yuding','','[]','高高驪山上有宮，朱樓紫殿三四重。遲遲兮春日，',94,'御定全唐詩/json/427.json','["高高驪山上有宮，朱樓紫殿三四重。遲遲兮春日，", "翠華不來歲月久，牆有衣兮瓦有松。吾君在位已五載，", "一人出兮不容易，六宮從兮百司備。八十一車千萬騎，", "吾君修己人不知，不自逸兮不自嬉。吾君愛人人不識，"]'),
('yuding-1','百煉鏡－辨皇王鑒也','白居易','唐','御定全唐诗','yuding','','[]','百煉鏡，鎔範非常規，日辰處所靈且祇。江心波上舟中鑄，',74,'御定全唐詩/json/427.json','["百煉鏡，鎔範非常規，日辰處所靈且祇。江心波上舟中鑄，", "鏡成將獻蓬萊宮，揚州長吏手自封。人間臣妾不合照，", "太宗常以人為鏡，鑒古鑒今不鑒容。四海安危居掌內，"]'),
('yuding-2','青石－激忠烈也','白居易','唐','御定全唐诗','yuding','','[]','青石出自藍田山，兼車運載來長安。工人磨琢欲何用，',80,'御定全唐詩/json/427.json','["青石出自藍田山，兼車運載來長安。工人磨琢欲何用，", "刻此兩片堅貞質，狀彼二人忠烈姿。義心如石屹不轉，", "各於其上題名諡，一置高山一沉水。陵穀雖遷碑獨存，", "慕為人，勸事君。"]'),
('yuding-3','兩朱閣－刺佛寺浸多也','白居易','唐','御定全唐诗','yuding','','[]','兩朱閣，南北相對起。借問何人家，貞元雙帝子。',94,'御定全唐詩/json/427.json','["兩朱閣，南北相對起。借問何人家，貞元雙帝子。", "帝子吹簫雙得仙，五雲飄颻飛上天。第宅亭台不將去，", "花落黃昏悄悄時，不聞歌吹聞鐘磬。寺門敕榜金字書，", "憶昨平陽宅初置，吞併平人幾家地。仙去雙雙作梵宮，"]'),
('yuding-4','西涼伎－刺封疆之臣也','白居易','唐','御定全唐诗','yuding','','[]','西涼伎，假面胡人假獅子。刻木為頭絲作尾，',164,'御定全唐詩/json/427.json','["西涼伎，假面胡人假獅子。刻木為頭絲作尾，", "紫髯深目兩胡兒，鼓舞跳樑前致辭。應似涼州未陷日，", "泣向獅子涕雙垂，涼州陷沒知不知。獅子回頭向西望，", "娛賓犒士宴監軍，獅子胡兒長在目。有一征夫年七十，", "自從天寶兵戈起，犬戎日夜吞西鄙。涼州陷來四十年，", "緣邊空屯十萬卒，飽食溫衣閑過日。遺民腸斷在涼州，", "奈何仍看西涼伎，取笑資歡無所愧。縱無智力未能收，"]'),
('yuding-5','八駿圖－戒奇物、懲佚遊也','白居易','唐','御定全唐诗','yuding','','[]','穆王八駿天馬駒，後人愛之寫為圖。背如龍兮頸如象，',120,'御定全唐詩/json/427.json','["穆王八駿天馬駒，後人愛之寫為圖。背如龍兮頸如象，", "四荒八極蹋欲遍，三十二蹄無歇時。屬車軸折趁不及，", "璧台南與盛姬遊，明堂不復朝諸侯。白雲黃竹歌聲動，", "豈知才及四代孫，心輕王業如灰土。由來尤物不在大，", "穆王得之不為戒，八駿駒來周室壞。至今此物尚稱珍，"]'),
('yuding-6','澗底松－念寒俊也','白居易','唐','御定全唐诗','yuding','','[]','有松百尺大十圍，生在澗底寒且卑。澗深山險人路絕，',48,'御定全唐詩/json/427.json','["有松百尺大十圍，生在澗底寒且卑。澗深山險人路絕，", "誰喻蒼蒼造物意，但與之材不與地。金張世祿原憲貧，"]'),
('yuding-7','牡丹芳－美天子憂農也','白居易','唐','御定全唐诗','yuding','','[]','牡丹芳，牡丹芳，黃金蕊綻紅玉房。千片赤英霞爛爛，',208,'御定全唐詩/json/427.json','["牡丹芳，牡丹芳，黃金蕊綻紅玉房。千片赤英霞爛爛，", "仙人琪樹白無色，王母桃花小不香。宿露輕盈泛紫豔，", "映葉多情隱羞面，臥叢無力含醉妝。低嬌笑容疑掩口，", "石竹金錢何細碎，芙蓉芍藥苦尋常。遂使王公與卿士，", "衛公宅靜閉東院，西明寺深開北廊。戲蝶雙舞看人久，", "花開花落二十日，一城之人皆若狂。三代以還文勝質，", "元和天子憂農桑，恤下動天天降祥。去歲嘉禾生九穗，", "無人知，可歎息。我願暫求造化力，減卻牡丹妖豔色。", "少回卿士愛花心，同似吾君憂稼穡。"]'),
('yuding-8','紅線毯－憂蠶桑之費也','白居易','唐','御定全唐诗','yuding','','[]','紅線毯，擇繭繰絲清水煮，揀絲練線紅藍染。',108,'御定全唐詩/json/427.json','["紅線毯，擇繭繰絲清水煮，揀絲練線紅藍染。", "染為紅線紅于藍，織作披香殿上毯。披香殿廣十丈餘，", "美人蹋上歌舞來，羅襪繡鞋隨步沒。太原毯澀毳縷硬，", "宣城太守加樣織，自謂為臣能竭力。百夫同擔進宮中，", "地不知寒人要暖，少奪人衣作地衣。"]'),
('yuding-9','杜陵叟－傷農夫之困也','白居易','唐','御定全唐诗','yuding','','[]','杜陵叟，杜陵居，歲種薄田一頃餘。三月無雨旱風起，',98,'御定全唐詩/json/427.json','["杜陵叟，杜陵居，歲種薄田一頃餘。三月無雨旱風起，", "長吏明知不申破，急斂暴徵求考課。典桑賣地納官租，", "虐人害物即豺狼，何必鉤爪鋸牙食人肉。不知何人奏皇帝，", "昨日裏胥方到門，手持尺牒榜鄉村。十家租稅九家畢，"]'),
('yuding-10','繚綾－念女工之勞也','白居易','唐','御定全唐诗','yuding','','[]','繚綾繚綾何所似，不似羅綃與紈綺。應似天臺山上月明前，',114,'御定全唐詩/json/427.json','["繚綾繚綾何所似，不似羅綃與紈綺。應似天臺山上月明前，", "織者何人衣者誰，越溪寒女漢宮姬。去年中使宣口敕，", "廣裁衫袖長制裙，金鬥熨波刀翦紋。異彩奇文相隱映，", "汗沾粉汙不再著，曳土蹋泥無惜心。繚綾織成費功績，", "昭陽殿裏歌舞人。若見織時應也惜。"]'),
('yuding-11','賣炭翁－苦官市也','白居易','唐','御定全唐诗','yuding','','[]','賣炭翁，伐薪燒炭南山中。滿面塵灰煙火色，',84,'御定全唐詩/json/427.json','["賣炭翁，伐薪燒炭南山中。滿面塵灰煙火色，", "可憐身上衣正單，心憂炭賤願天寒。夜來城上一尺雪，", "翩翩兩騎來是誰，黃衣使者白衫兒。手把文書口稱敕，", "半匹紅紗一丈綾，系向牛頭充炭直。"]'),
('yuding-12','母別子－刺新間舊也','白居易','唐','御定全唐诗','yuding','','[]','母別子，子別母，白日無光哭聲苦。關西驃騎大將軍，',96,'御定全唐詩/json/427.json','["母別子，子別母，白日無光哭聲苦。關西驃騎大將軍，", "新人迎來舊人棄，掌上蓮花眼中刺。迎新棄舊未足悲，", "以汝夫婦新燕婉，使我母子生別離。不如林中烏與鵲，", "新人新人聽我語，洛陽無限紅樓女。但願將軍重立功，"]'),
('yuding-13','陰山道－疾貪虜也','白居易','唐','御定全唐诗','yuding','','[]','陰山道，陰山道，紇邏敦肥水泉好。每至戎人送馬時，',112,'御定全唐詩/json/427.json','["陰山道，陰山道，紇邏敦肥水泉好。每至戎人送馬時，", "五十匹縑易一匹，縑去馬來無了日。養無所用去非宜，", "藕絲蛛網三丈餘，回紇訴稱無用處。咸安公主號可敦，", "仍詔江淮馬價縑，從此不令疏短織。合羅將軍呼萬歲，", "縑漸好，馬漸多。陰山虜，奈爾何。"]'),
('yuding-14','時世妝－儆戎也','白居易','唐','御定全唐诗','yuding','','[]','時世妝，時世妝，出自城中傳四方。時世流行無遠近，',64,'御定全唐詩/json/427.json','["時世妝，時世妝，出自城中傳四方。時世流行無遠近，", "妍媸黑白失本態，妝成盡似含悲啼。圓鬟無鬢堆髻樣，", "元和妝梳君記取，髻堆面赭非華風。"]'),
('yuding-15','李夫人－鑒嬖惑也','白居易','唐','御定全唐诗','yuding','','[]','漢武帝，初喪李夫人。夫人病時不肯別，死後留得生前恩。',189,'御定全唐詩/json/427.json','["漢武帝，初喪李夫人。夫人病時不肯別，死後留得生前恩。", "君恩不盡念未已，甘泉殿裏令寫真。丹青畫出竟何益，", "九華帳深夜悄悄，反魂香降夫人魂。夫人之魂在何許，", "去何速兮來何遲，是耶非耶兩不知。翠蛾仿佛平生貌，", "背燈隔帳不得語，安用暫來還見違。傷心不獨漢武帝，", "又不見泰陵一掬淚，馬嵬坡下念楊妃。", "縱令妍姿豔質化為土，此恨長在無銷期。", "生亦惑，死亦惑，尤物惑人忘不得。", "人非木石皆有情，不如不遇傾城色。"]'),
('yuding-16','陵園妾－憐幽閉也','白居易','唐','御定全唐诗','yuding','','[]','陵園妾，顏色如花命如葉。命如葉薄將奈何，',132,'御定全唐詩/json/427.json','["陵園妾，顏色如花命如葉。命如葉薄將奈何，", "青絲發落叢鬢疏，紅玉膚銷系裙慢。憶昔宮中被妒猜，", "山宮一閉無開日，未死此身不令出。松門到曉月裴回，", "眼看菊蕊重陽淚，手把梨花寒食心。把花掩淚無人見，", "遙想六宮奉至尊，宣徽雪夜浴堂春。雨露之恩不及者，", "願令輪轉直陵園，三歲一來均苦樂。"]'),
('yuding-17','鹽商婦－惡幸人也','白居易','唐','御定全唐诗','yuding','','[]','鹽商婦，多金帛，不事田農與蠶績。南北東西不失家，',118,'御定全唐詩/json/427.json','["鹽商婦，多金帛，不事田農與蠶績。南北東西不失家，", "綠鬟富去金釵多，皓腕肥來銀釧窄。前呼蒼頭後叱婢，", "每年鹽利入官時，少入官家多入私。官家利薄私家厚，", "飽食濃妝倚柁樓，兩朵紅腮花欲綻。鹽商婦，有幸嫁鹽商。", "終朝美飯食，終歲好衣裳。好衣美食來何處，"]'),
('yuding-18','杏為梁－刺居處僭也','白居易','唐','御定全唐诗','yuding','','[]','右為梁，桂為柱，何人堂室李開府。碧砌紅軒色未幹，',98,'御定全唐詩/json/427.json','["右為梁，桂為柱，何人堂室李開府。碧砌紅軒色未幹，", "素泥朱版光未滅，今日官收別賜人。開府之堂將軍宅，", "更有愚夫念身後，心雖甚長計非久。窮奢極麗越規模，", "君不見馬家宅，尚猶存，宅門題作奉誠園。君不見魏家宅，"]'),
('yuding-19','井底引銀瓶－止淫奔也','白居易','唐','御定全唐诗','yuding','','[]','井底引銀瓶，銀瓶欲上絲繩絕。石上磨玉簪，',136,'御定全唐詩/json/427.json','["井底引銀瓶，銀瓶欲上絲繩絕。石上磨玉簪，", "憶昔在家為女時，人言舉動有殊姿。嬋娟兩鬢秋蟬翼，", "妾弄青梅憑短牆，君騎白馬傍垂楊。牆頭馬上遙相顧，", "感君松柏化為心，闇合雙鬟逐君去。到君家舍五六年，", "終知君家不可住，其奈出門無去處。豈無父母在高堂，", "為君一日恩，誤妾百年身。寄言癡小人家女，"]'),
('yuding-20','官牛－諷執政也','白居易','唐','御定全唐诗','yuding','','[]','官牛官牛駕官車，滻水岸邊般載沙。一石沙，幾斤重，',44,'御定全唐詩/json/427.json','["官牛官牛駕官車，滻水岸邊般載沙。一石沙，幾斤重，", "昨來新拜右丞相，恐怕泥塗汙馬蹄。右丞相，"]'),
('yuding-21','紫毫筆－譏失職也','白居易','唐','御定全唐诗','yuding','','[]','紫毫筆，尖如錐兮利如刀。江南石上有老兔，',116,'御定全唐詩/json/427.json','["紫毫筆，尖如錐兮利如刀。江南石上有老兔，", "毫雖輕，功甚重。管勒工名充歲貢，君兮臣兮勿輕用。", "勿輕用，將何如，願賜東西府禦史，願頒左右台起居。", "搦管趨入黃金闕，抽毫立在白玉除。臣有奸邪正衙奏，", "每歲宣城進筆時，紫毫之價如金貴。慎勿空將彈失儀，"]'),
('yuding-22','隋堤柳－憫亡國也','白居易','唐','御定全唐诗','yuding','','[]','隋堤柳，歲久年深盡衰朽。風飄飄兮雨蕭蕭，',112,'御定全唐詩/json/427.json','["隋堤柳，歲久年深盡衰朽。風飄飄兮雨蕭蕭，", "大業年中煬天子，種柳成行夾流水。西自黃河東至淮，", "南幸江都恣佚游，應將此柳系龍舟。紫髯郎將護錦纜，", "上荒下困勢不久，宗社之危如綴旒。煬天子，", "土墳數尺何處葬，吳公台下多悲風。二百年來汴河路，"]'),
('yuding-23','草茫茫－懲厚葬也','白居易','唐','御定全唐诗','yuding','','[]','草茫茫，土蒼蒼。蒼蒼茫茫在何處，驪山腳下秦皇墓。',88,'御定全唐詩/json/427.json','["草茫茫，土蒼蒼。蒼蒼茫茫在何處，驪山腳下秦皇墓。", "墓中下涸二重泉，當時自以為深固。下流水銀象江海，", "一朝盜掘墳陵破，龍槨神堂三月火。可憐寶玉歸人間，", "憑君回首向南望，漢文葬在霸陵原。"]'),
('yuding-24','古塚狐－戒豔色也','白居易','唐','御定全唐诗','yuding','','[]','古塚狐，妖且老，化為婦人顏色好。頭變雲鬟面變妝，',106,'御定全唐詩/json/427.json','["古塚狐，妖且老，化為婦人顏色好。頭變雲鬟面變妝，", "或歌或舞或悲啼，翠眉不舉花顏低。忽然一笑千萬態，", "彼真此假俱迷人，人心惡假貴重真。狐假女妖害猶淺，", "何況褒妲之色善蠱惑，能喪人家覆人國。", "君看為害淺深間，豈將假色同真色。"]'),
('yuding-25','黑潭龍－疾貪吏也','白居易','唐','御定全唐诗','yuding','','[]','黑潭水深黑如墨，傳有神龍人不識。潭上架屋官立祠，',84,'御定全唐詩/json/427.json','["黑潭水深黑如墨，傳有神龍人不識。潭上架屋官立祠，", "家家養豚漉清酒，朝祈暮賽依巫口。神之來兮風飄飄，", "肉堆潭岸石，酒潑廟前草。不知龍神享幾多，", "狐假龍神食豚盡，九重泉底龍知無。"]'),
('yuding-26','天可度－惡詐人也','白居易','唐','御定全唐诗','yuding','','[]','天可度，地可量，唯有人心不可防。但見丹誠赤如血，',84,'御定全唐詩/json/427.json','["天可度，地可量，唯有人心不可防。但見丹誠赤如血，", "勸君掇蜂君莫掇，使君父子成豺狼。海底魚兮天上鳥，", "君不見李義府之輩笑欣欣，笑中有刀潛殺人。", "陰陽神變皆可測，不測人間笑是瞋。"]'),
('yuding-27','秦吉了－哀冤民也','白居易','唐','御定全唐诗','yuding','','[]','秦吉了，出南中，彩毛青黑花頸紅。耳聰心慧舌端巧，',74,'御定全唐詩/json/427.json','["秦吉了，出南中，彩毛青黑花頸紅。耳聰心慧舌端巧，", "鳶捎乳燕一窠覆，烏啄母雞雙眼枯。雞號墮地燕驚去，", "亦有鸞鶴群，閑立高颺如不聞。秦吉了，人云爾是能言鳥，"]'),
('yuding-28','鴉九劍－思決壅也','白居易','唐','御定全唐诗','yuding','','[]','歐冶子死千年後，精靈闇授張鴉九。鴉九鑄劍吳山中，',72,'御定全唐詩/json/427.json','["歐冶子死千年後，精靈闇授張鴉九。鴉九鑄劍吳山中，", "劍成未試十餘年，有客持金買一觀。誰知閉匣長思用，", "君勿矜我玉可切，君勿誇我鐘可刜。不如持我決浮雲，"]'),
('yuding-29','采詩官－監前王亂亡之由也','白居易','唐','御定全唐诗','yuding','','[]','采詩官，采詩聽歌導人言。言者無罪聞者誡，',135,'御定全唐詩/json/427.json','["采詩官，采詩聽歌導人言。言者無罪聞者誡，", "郊廟登歌贊君美，樂府豔詞悅君意。若求興諭規刺言，", "諍臣杜口為冗員，諫鼓高懸作虛器。一人負扆常端默，", "君之堂兮千里遠，君之門兮九重閟。君耳唯聞堂上言，", "君不見厲王胡亥之末年，群臣有利君無利。", "君兮君兮願聽此，欲開壅蔽達人情，先向歌詩求諷刺。"]'),
('yuding-0','常樂里閒居偶題十六韻兼寄劉十五公輿王十一起呂二炅呂四熲崔十八玄亮元九稹劉三十二敦質張十五仲元時為校書郎','白居易','唐','御定全唐诗','yuding','','[]','帝都名利場，雞鳴無安居。獨有懶慢者，日高頭未梳。',192,'御定全唐詩/json/428.json','["帝都名利場，雞鳴無安居。獨有懶慢者，日高頭未梳。", "工拙性不同，進退跡遂殊。幸逢太平代，天子好文儒。", "小才難大用，典校在秘書。三旬兩入省，因得養頑疏。", "茅屋四五間，一馬二僕夫。俸錢萬六千，月給亦有餘。", "既無衣食牽，亦少人事拘。遂使少年心，日日常晏如。", "勿言無知己，躁靜各有徒。蘭台七八人，出處與之俱。", "旬時阻談笑，旦夕望軒車。誰能讎校閑，解帶臥吾廬。", "窗前有竹玩，門處有酒酤。何以待君子，數竿對一壺。"]'),
('yuding-1','答元八宗簡同遊曲江後明日見贈','白居易','唐','御定全唐诗','yuding','','[]','長安千萬人，出門各有營。唯我與夫子，信馬悠悠行。',120,'御定全唐詩/json/428.json','["長安千萬人，出門各有營。唯我與夫子，信馬悠悠行。", "行到曲江頭，反照草樹明。南山好顏色，病客有心情。", "水禽翻白羽，風荷嫋翠莖。何必滄浪去，即此可濯纓。", "時景不重來，賞心難再並。坐愁紅塵裏，夕鼓咚咚聲。", "歸來經一宿，世慮稍複生。賴聞瑤華唱，再得塵襟清。"]'),
('yuding-2','感時','白居易','唐','御定全唐诗','yuding','','[]','朝見日上天，暮見日入地。不覺明鏡中，忽年三十四。',156,'御定全唐詩/json/428.json','["朝見日上天，暮見日入地。不覺明鏡中，忽年三十四。", "勿言身未老，冉冉行將至。白髮雖未生，朱顏已先悴。", "人生詎幾何，在世猶如寄。雖有七十期，十人無一二。", "今我猶未悟，往往不適意。胡為方寸間，不貯浩然氣。", "貧賤非不惡，道在何足避。富貴非不愛，時來當自致。", "所以達人心，外物不能累。唯當飲美酒，終日陶陶醉。", "斯言勝金玉，佩服無失墜。"]'),
('yuding-3','首夏同諸校正遊開元觀，因宿玩月','白居易','唐','御定全唐诗','yuding','','[]','我與二三子，策名在京師。官小無職事，閑于為客時。',144,'御定全唐詩/json/428.json','["我與二三子，策名在京師。官小無職事，閑于為客時。", "沉沉道觀中，心賞期在茲。到門車馬回，入院巾杖隨。", "清和四月初，樹木正華滋。風清新葉影，鳥戀殘花枝。", "向夕天又晴，東南餘霞披。置酒西廊下，待月杯行遲。", "須臾金魄生，若與吾徒期。光華一照耀，殿角相參差。", "終夜清景前，笑歌不知疲。長安名利地，此興幾人知。"]'),
('yuding-4','永崇裏觀居','白居易','唐','御定全唐诗','yuding','','[]','季夏中氣候，煩暑自此收。蕭颯風雨天，蟬聲暮啾啾。',144,'御定全唐詩/json/428.json','["季夏中氣候，煩暑自此收。蕭颯風雨天，蟬聲暮啾啾。", "永崇裏巷靜，華陽觀院幽。軒車不到處，滿地槐花秋。", "年光忽冉冉，世事本悠悠。何必待衰老，然後悟浮休。", "真隱豈長遠，至道在冥搜。身雖世界住，心與虛無遊。", "朝饑有蔬食，夜寒有布裘。倖免凍與餒，此外複何求。", "寡欲雖少病，樂天心不憂。何以明吾志，周易在床頭。"]'),
('yuding-5','早送舉人入試','白居易','唐','御定全唐诗','yuding','','[]','夙駕送舉人，東方猶未明。自謂出太早，已有車馬行。',96,'御定全唐詩/json/428.json','["夙駕送舉人，東方猶未明。自謂出太早，已有車馬行。", "騎火高低影，街鼓參差聲。可憐早朝者，相看意氣生。", "日出塵埃飛，群動互營營。營營各何求，無非利與名。", "而我常晏起，虛住長安城。春深官又滿，日有歸山情。"]'),
('yuding-6','招王質夫','白居易','唐','御定全唐诗','yuding','','[]','濯足雲水客，折腰簪笏身。喧閑跡相背，十裏別經旬。',48,'御定全唐詩/json/428.json','["濯足雲水客，折腰簪笏身。喧閑跡相背，十裏別經旬。", "忽因乘逸興，莫惜訪囂塵。窗前故栽竹，與君為主人。"]'),
('yuding-7','祗役駱口，因與王質夫同遊秋山，偶題三韻','白居易','唐','御定全唐诗','yuding','','[]','石擁百泉合，雲破千峰開。平生煙霞侶，此地重裴回。',36,'御定全唐詩/json/428.json','["石擁百泉合，雲破千峰開。平生煙霞侶，此地重裴回。", "今日勤王意，一半為山來。"]'),
('yuding-8','見蕭侍禦憶舊山草堂詩，因以繼和','白居易','唐','御定全唐诗','yuding','','[]','琢玉以為架，綴珠以為籠。玉架絆野鶴，珠籠鎖冥鴻。',144,'御定全唐詩/json/428.json','["琢玉以為架，綴珠以為籠。玉架絆野鶴，珠籠鎖冥鴻。", "鴻思雲外天，鶴憶松上風。珠玉信為美，鳥不戀其中。", "台中蕭侍禦，心與鴻鶴同。晚起慵冠豸，閑行厭避驄。", "昨見憶山詩，詩思浩無窮。歸夢杳何處，舊居茫水東。", "秋閑杉桂林，春老芝朮叢。自雲別山后，離抱常忡忡。", "衣繡非不榮，持憲非不雄。所樂不在此，悵望草堂空。"]'),
('yuding-9','病假中南亭閑望','白居易','唐','御定全唐诗','yuding','','[]','欹枕不視事，兩日門掩關。始知吏役身，不病不得閒。',60,'御定全唐詩/json/428.json','["欹枕不視事，兩日門掩關。始知吏役身，不病不得閒。", "閑意不在遠，小亭方丈間。西簷竹梢上，坐見太白山。", "遙愧峰上雲，對此塵中顏。"]'),
('yuding-10','仙遊寺獨宿','白居易','唐','御定全唐诗','yuding','','[]','沙鶴上階立，潭月當戶開。此中留我宿，兩夜不能回。',48,'御定全唐詩/json/428.json','["沙鶴上階立，潭月當戶開。此中留我宿，兩夜不能回。", "幸與靜境遇，喜無歸侶催。從今獨遊後，不擬共人來。"]'),
('yuding-11','前庭涼夜','白居易','唐','御定全唐诗','yuding','','[]','露簟色似玉，風幌影如波。坐愁樹葉落，中庭明月多。',24,'御定全唐詩/json/428.json','["露簟色似玉，風幌影如波。坐愁樹葉落，中庭明月多。"]'),
('yuding-12','官舍小亭閑望','白居易','唐','御定全唐诗','yuding','','[]','風竹散清韻，煙槐凝綠姿。日高人吏去，閑坐在茅茨。',96,'御定全唐詩/json/428.json','["風竹散清韻，煙槐凝綠姿。日高人吏去，閑坐在茅茨。", "葛衣禦時暑，蔬飯療朝饑。持此聊自足，心力少營為。", "亭上獨吟罷，眼前無事時。數峰太白雪，一卷陶潛詩。", "人心各自是，我是良在茲。回謝爭名客，甘從君所嗤。"]'),
('yuding-13','早秋獨夜','白居易','唐','御定全唐诗','yuding','','[]','井梧涼葉動，鄰杵秋聲發。獨向簷下眠，覺來半床月。',24,'御定全唐詩/json/428.json','["井梧涼葉動，鄰杵秋聲發。獨向簷下眠，覺來半床月。"]'),
('yuding-14','聽彈古淥水','白居易','唐','御定全唐诗','yuding','','[]','聞君古淥水，使我心和平。欲識慢流意，為聽疏泛聲。',36,'御定全唐詩/json/428.json','["聞君古淥水，使我心和平。欲識慢流意，為聽疏泛聲。", "西窗竹陰下，竟日有餘清。"]'),
('yuding-15','松齋自題','白居易','唐','御定全唐诗','yuding','','[]','非老亦非少，年過三紀餘。非賤亦非貴，朝登一命初。',120,'御定全唐詩/json/428.json','["非老亦非少，年過三紀餘。非賤亦非貴，朝登一命初。", "才小分易足，心寬體長舒。充腸皆美食，容膝即安居。", "況此松齋下，一琴數帙書。書不求甚解，琴聊以自娛。", "夜直入君門，晚歸臥吾廬。形骸委順動，方寸付空虛。", "持此將過日，自然多晏如。昏昏複默默，非智亦非愚。"]'),
('yuding-16','冬夜與錢員外同直禁中','白居易','唐','御定全唐诗','yuding','','[]','夜深草詔罷，霜月淒凜凜。欲臥暖殘杯，燈前相對飲。',48,'御定全唐詩/json/428.json','["夜深草詔罷，霜月淒凜凜。欲臥暖殘杯，燈前相對飲。", "連鋪青縑被，封置通中枕。仿佛百餘宵，與君同此寢。"]'),
('yuding-17','和錢員外禁中夙興見示','白居易','唐','御定全唐诗','yuding','','[]','窗白星漢曙，窗暖燈火餘。坐卷朱裏幕，看封紫泥書。',72,'御定全唐詩/json/428.json','["窗白星漢曙，窗暖燈火餘。坐卷朱裏幕，看封紫泥書。", "窅窅鐘漏盡，曈曈霞景初。樓臺紅照曜，松竹青扶疏。", "君愛此時好，回頭特謂餘。不知上清界，曉景複何如。"]'),
('yuding-18','夏日獨直，寄蕭侍禦','白居易','唐','御定全唐诗','yuding','','[]','憲台文法地，翰林清切司。鷹猜課野鶴，驥德責山麋。',144,'御定全唐詩/json/428.json','["憲台文法地，翰林清切司。鷹猜課野鶴，驥德責山麋。", "課責雖不同，同歸非所宜。是以方寸內，忽忽暗相思。", "夏日獨上直，日長何所為。澹然無他念，虛靜是吾師。", "形委有事牽，心與無事期。中臆一以曠，外累都若遺。", "地貴身不覺，意閑境來隨。但對松與竹，如在山中時。", "情性聊自適，吟詠偶成詩。此意非夫子，餘人多不知。"]'),
('yuding-19','松聲','白居易','唐','御定全唐诗','yuding','','[]','月好好獨坐，雙松在前軒。西南微風來，潛入枝葉間。',96,'御定全唐詩/json/428.json','["月好好獨坐，雙松在前軒。西南微風來，潛入枝葉間。", "蕭寥發為聲，半夜明月前。寒山颯颯雨，秋琴泠泠弦。", "一聞滌炎暑，再聽破昏煩。竟夕遂不寐，心體俱翛然。", "南陌車馬動，西鄰歌吹繁。誰知茲簷下，滿耳不為喧。"]'),
('yuding-20','禁中','白居易','唐','御定全唐诗','yuding','','[]','門嚴九重靜，窗幽一室閑。好是修心處，何必在深山。',24,'御定全唐詩/json/428.json','["門嚴九重靜，窗幽一室閑。好是修心處，何必在深山。"]'),
('yuding-21','贈吳丹','白居易','唐','御定全唐诗','yuding','','[]','巧者力苦勞，智者心苦憂。愛君無巧智，終歲閑悠悠。',192,'御定全唐詩/json/428.json','["巧者力苦勞，智者心苦憂。愛君無巧智，終歲閑悠悠。", "嘗登禦史府，亦佐東諸侯。手操糾謬簡，心運決勝籌。", "宦途似風水，君心如虛舟。泛然而不有，進退得自由。", "今來脫豸冠，時往侍龍樓。官曹稱心靜，居處隨跡幽。", "冬負南榮日，支體甚溫柔。夏臥北窗風，枕席如涼秋。", "南山入捨下，酒甕在床頭。人間有閑地，何必隱林丘。", "顧我愚且昧，勞生殊未休。一入金門直，星霜三四周。", "主恩信難報，近地徒久留。終當乞閑官，退與夫子游。"]'),
('yuding-22','初除戶曹，喜而言志','白居易','唐','御定全唐诗','yuding','','[]','詔授戶曹掾，捧詔感君恩。感恩非為己，祿養及吾親。',192,'御定全唐詩/json/428.json','["詔授戶曹掾，捧詔感君恩。感恩非為己，祿養及吾親。", "弟兄俱簪笏，新婦儼衣巾。羅列高堂下，拜慶正紛紛。", "俸錢四五萬，月可奉晨昏。廩祿二百石，歲可盈倉囷。", "喧喧車馬來，賀客滿我門。不以我為貪，知我家內貧。", "置酒延賀客，客容亦歡欣。笑雲今日後，不復憂空尊。", "答雲如君言，願君少逡巡。我有平生志，醉後為君陳。", "人生百歲期，七十有幾人。浮榮及虛位，皆是身之賓。", "唯有衣與食，此事粗關身。苟免饑寒外，餘物盡浮雲。"]'),
('yuding-23','秋居書懷','白居易','唐','御定全唐诗','yuding','','[]','門前少賓客，階下多松竹。秋景下西牆，涼風入東屋。',120,'御定全唐詩/json/428.json','["門前少賓客，階下多松竹。秋景下西牆，涼風入東屋。", "有琴慵不弄，有書閑不讀。盡日方寸中，澹然無所欲。", "何須廣居處，不用多積蓄。丈室可容身，鬥儲可充腹。", "況無治道術，坐受官家祿。不種一株桑，不鋤一壟穀。", "終朝飽飯餐，卒歲豐衣服。持此知愧心，自然易為足。"]'),
('yuding-24','禁中曉臥，因懷王起居','白居易','唐','御定全唐诗','yuding','','[]','遲遲禁漏盡，悄悄暝鴉喧。夜雨槐花落，微涼臥北軒。',48,'御定全唐詩/json/428.json','["遲遲禁漏盡，悄悄暝鴉喧。夜雨槐花落，微涼臥北軒。", "曙燈殘未滅，風簾閑自翻。每一得靜境，思與故人言。"]'),
('yuding-25','養拙','白居易','唐','御定全唐诗','yuding','','[]','鐵柔不為劍，木曲不為轅。今我亦如此，愚蒙不及門。',96,'御定全唐詩/json/428.json','["鐵柔不為劍，木曲不為轅。今我亦如此，愚蒙不及門。", "甘心謝名利，滅跡歸丘園。坐臥茅茨中，但對琴與尊。", "身去韁鎖累，耳辭朝市喧。逍遙無所為，時窺五千言。", "無憂樂性場，寡欲清心源。始知不才者，可以探道根。"]'),
('yuding-26','寄李十一建','白居易','唐','御定全唐诗','yuding','','[]','外事牽我形，外物誘我情。李君別來久，褊吝從中生。',204,'御定全唐詩/json/428.json','["外事牽我形，外物誘我情。李君別來久，褊吝從中生。", "憶昨訪君時，立馬扣柴荊。有時君未起，稚子喜先迎。", "連步笑出門，衣翻冠或傾。掃階苔紋綠，拂榻藤陰清。", "家醞及春熟，園葵乘露烹。看山東亭坐，待月南原行。", "門靜唯鳥語，坊遠少鼓聲。相對盡日言，不及利與名。", "分手來幾時，明月三四盈。別時殘花落，及此新蟬鳴。", "芳歲忽已晚，離抱悵未平。豈不思命駕，吏職坐相縈。", "前時君有期，訪我來山城。心賞久雲阻，言約無自輕。", "相去幸非遠，走馬一日程。"]'),
('yuding-27','旅次華州，贈袁右丞','白居易','唐','御定全唐诗','yuding','','[]','渭水綠溶溶，華山青崇崇。山水一何麗，君子在其中。',120,'御定全唐詩/json/428.json','["渭水綠溶溶，華山青崇崇。山水一何麗，君子在其中。", "才與世會合，物隨誠感通。德星降人福，時雨助歲功。", "化行人無訟，囹圄千日空。政順氣亦和，黍稷三年豐。", "客自帝城來，驅馬出關東。愛此一郡人，如見太古風。", "方今天子心，憂人正忡忡。安得天下守，盡得如袁公。"]'),
('yuding-28','酬楊九弘貞長安病中見寄','白居易','唐','御定全唐诗','yuding','','[]','伏枕君寂寂，折腰我營營。所嗟經時別，相去一宿程。',120,'御定全唐詩/json/428.json','["伏枕君寂寂，折腰我營營。所嗟經時別，相去一宿程。", "攜手昨何時，昆明春水準。離郡來幾日，太白夏雲生。", "之子未得意，貧病客帝城。貧堅志士節，病長高人情。", "隱幾自恬澹，閉門無送迎。龍臥心有待，鶴瘦貌彌清。", "清機發為文，投我如振瓊。何以慰饑渴，捧之吟一聲。"]'),
('yuding-29','禁中寓直夢游仙遊寺','白居易','唐','御定全唐诗','yuding','','[]','西軒草詔暇，松竹深寂寂。月出清風來，忽似山中夕。',48,'御定全唐詩/json/428.json','["西軒草詔暇，松竹深寂寂。月出清風來，忽似山中夕。", "因成西南夢，夢作遊仙客。覺聞宮漏聲，猶謂山泉滴。"]'),
('yuding-30','贈王山人','白居易','唐','御定全唐诗','yuding','','[]','聞君減寢食，日聽神仙說。暗待非常人，潛求長生訣。',96,'御定全唐詩/json/428.json','["聞君減寢食，日聽神仙說。暗待非常人，潛求長生訣。", "言長本對短，未離生死轍。假使得長生，才能勝夭折。", "松樹千年朽，槿花一日歇。畢竟共虛空，何須誇歲月。", "彭殤徒自異，生死終無別。不如學無生，無生即無滅。"]'),
('yuding-31','秋山','白居易','唐','御定全唐诗','yuding','','[]','久病曠心賞，今朝一登山。山秋雲物冷，稱我清羸顏。',84,'御定全唐詩/json/428.json','["久病曠心賞，今朝一登山。山秋雲物冷，稱我清羸顏。", "白石臥可枕，青蘿行可攀。意中如有得，盡日不欲還。", "人生無幾何，如寄天地間。心有千載憂，身無一日閑。", "何時解塵網，此地來掩關。"]'),
('yuding-32','贈能七倫','白居易','唐','御定全唐诗','yuding','','[]','澗松高百尋，四時寒森森。臨風有清韻，向日無曲陰。',96,'御定全唐詩/json/428.json','["澗松高百尋，四時寒森森。臨風有清韻，向日無曲陰。", "如何時俗人，但賞桃李林。豈不知堅貞，芳馨誘其心。", "能生學為文，氣高功亦深。手中一百篇，句句披沙金。", "苦節二十年，無人振陸沉。今我尚貧賤，徒為爾知音。"]'),
('yuding-33','題楊穎士西亭','白居易','唐','御定全唐诗','yuding','','[]','靜得亭上境，遠諧塵外蹤。憑軒東南望，鳥滅山重重。',60,'御定全唐詩/json/428.json','["靜得亭上境，遠諧塵外蹤。憑軒東南望，鳥滅山重重。", "竹露冷煩襟，杉風清病容。曠然宜真趣，道與心相逢。", "即此可遺世，何必蓬壺峰。"]'),
('yuding-34','題贈鄭秘書征君石溝溪隱居','白居易','唐','御定全唐诗','yuding','','[]','鄭君得自然，虛白生心胸。吸彼沆瀣精，凝為冰雪容。',180,'御定全唐詩/json/428.json','["鄭君得自然，虛白生心胸。吸彼沆瀣精，凝為冰雪容。", "大君貞元初，求賢致時雍。蒲輪入翠微，迎下天臺峰。", "赤城別松喬，黃閣交夔龍。俯仰受三命，從容辭九重。", "出籠鶴翩翩，歸林鳳雍雍。在火辨良玉，經霜識貞松。", "新居寄楚山，山碧溪溶溶。丹灶燒煙煴，黃精花豐茸。", "蕙帳夜琴澹，桂尊春酒濃。時人不到處，苔石無塵蹤。", "我今何為者，趨世身龍鍾。不向林壑訪，無由朝市逢。", "終當解塵纓，蔔築來相從。"]'),
('yuding-35','及第後歸覲，留別諸同年','白居易','唐','御定全唐诗','yuding','','[]','十年常苦學，一上謬成名。擢第未為貴，賀親方始榮。',72,'御定全唐詩/json/428.json','["十年常苦學，一上謬成名。擢第未為貴，賀親方始榮。", "時輩六七人，送我出帝城。軒車動行色，絲管舉離聲。", "得意減別恨，半酣輕遠程。翩翩馬蹄疾，春日歸鄉情。"]'),
('yuding-36','清夜琴興','白居易','唐','御定全唐诗','yuding','','[]','月出鳥棲盡，寂然坐空林。是時心境閑，可以彈素琴。',72,'御定全唐詩/json/428.json','["月出鳥棲盡，寂然坐空林。是時心境閑，可以彈素琴。", "清泠由木性，恬澹隨人心。心積和平氣，木應正始音。", "響餘群動息，曲罷秋夜深。正聲感元化，天地清沉沉。"]'),
('yuding-37','郊陶潛體詩十六首','白居易','唐','御定全唐诗','yuding','','[]','不動者厚地，不息者高天。無窮者日月，長在者山川。',552,'御定全唐詩/json/428.json','["不動者厚地，不息者高天。無窮者日月，長在者山川。", "松柏與龜鶴，其壽皆千年。嗟嗟群物中，而人獨不然。", "早出向朝市，暮已歸下泉。形質及壽命，危脆若浮煙。", "堯舜與周孔，古來稱聖賢。借問今何在，一去亦不還。", "我無不死藥，萬萬隨化遷。所未定知者，修短遲速間。", "幸及身健日，當歌一尊前。何必待人勸，持此自為歡。", "翳翳逾月陰，沉沉連日雨。開簾望天色，黃雲暗如土。", "行潦毀我墉，疾風壞我宇。蓬莠生庭院，泥塗失場圃。", "村深絕賓客，窗晦無儔侶。盡日不下床，跳蛙時入戶。", "出門無所往，入室還獨處。不以酒自娛，塊然與誰語。", "朝飲一杯酒，冥心合元化。兀然無所思，日高尚閑臥。", "暮讀一卷書，會意如嘉話。欣然有所遇，夜深猶獨坐。", "又得琴上趣，安弦有餘暇。複多詩中狂，下筆不能罷。", "唯茲三四事，持用度晝夜。所以陰雨中，經旬不出舍。", "始悟獨往人，心安時亦過。", "東家采桑婦，雨來苦愁悲。蔟蠶北堂前，雨冷不成絲。", "西家荷鋤叟，雨來亦怨咨。種豆南山下，雨多落為萁。", "而我獨何幸，醞酒本無期。及此多雨日，正遇新熟時。", "開瓶瀉尊中，玉液黃金脂。持玩已可悅，歡嘗有餘滋。", "一酌發好容，再酌開愁眉。連延四五酌，酣暢入四肢。", "忽然遺我物，誰複分是非。是時連夕雨，酩酊無所知。", "人心苦顛倒，反為憂者嗤。", "朝亦獨醉歌，暮亦獨醉睡。未盡一壺酒，已成三獨醉。", "勿嫌飲太少，且喜歡易致。一杯複兩杯，多不過三四。"]'),
('yuding-0','自題寫真','白居易','唐','御定全唐诗','yuding','','[]','我貌不自識，李放寫我真。靜觀神與骨，合是山中人。',84,'御定全唐詩/json/429.json','["我貌不自識，李放寫我真。靜觀神與骨，合是山中人。", "蒲柳質易朽，麋鹿心難馴。何事赤墀上，五年為侍臣。", "況多剛狷性，難與世同塵。不惟非貴相，但恐生禍因。", "宜當早罷去，收取雲泉身。"]'),
('yuding-1','遣懷','白居易','唐','御定全唐诗','yuding','','[]','寓心身體中，寓性方寸內。此身是外物，何足苦憂愛。',96,'御定全唐詩/json/429.json','["寓心身體中，寓性方寸內。此身是外物，何足苦憂愛。", "況有假飾者，華簪及高蓋。此又疏於身，複在外物外。", "操之多惴栗，失之又悲悔。乃知名與器，得喪俱為害。", "頹然環堵客，蘿蕙為巾帶。自得此道來，身窮心甚泰。"]'),
('yuding-2','渭上偶釣','白居易','唐','御定全唐诗','yuding','','[]','渭水如鏡色，中有鯉與魴。偶持一竿竹，懸釣在其傍。',108,'御定全唐詩/json/429.json','["渭水如鏡色，中有鯉與魴。偶持一竿竹，懸釣在其傍。", "微風吹釣絲，嫋嫋十尺長。誰知對魚坐，心在無何鄉。", "昔有白頭人，亦釣此渭陽。釣人不釣魚，七十得文王。", "況我垂釣意，人魚又兼忘。無機兩不得，但弄秋水光。", "興盡釣亦罷，歸來飲我觴。"]'),
('yuding-3','隱幾','白居易','唐','御定全唐诗','yuding','','[]','身適忘四支，心適忘是非。既適又忘適，不知吾是誰。',84,'御定全唐詩/json/429.json','["身適忘四支，心適忘是非。既適又忘適，不知吾是誰。", "百體如槁木，兀然無所知。方寸如死灰，寂然無所思。", "今日複明日，身心忽兩遺。行年三十九，歲暮日斜時。", "四十心不動，吾今其庶幾。"]'),
('yuding-4','春眠','白居易','唐','御定全唐诗','yuding','','[]','新浴肢體暢，獨寢神魂安。況因夜深坐，遂成日高眠。',96,'御定全唐詩/json/429.json','["新浴肢體暢，獨寢神魂安。況因夜深坐，遂成日高眠。", "春被薄亦暖，朝窗深更閑。卻忘人間事，似得枕上仙。", "至適無夢想，大和難名言。全勝彭澤醉，欲敵曹溪禪。", "何物呼我覺，伯勞聲關關。起來妻子笑，生計春茫然。"]'),
('yuding-5','閒居','白居易','唐','御定全唐诗','yuding','','[]','空腹一盞粥，饑食有餘味。南簷半床日，暖臥因成睡。',108,'御定全唐詩/json/429.json','["空腹一盞粥，饑食有餘味。南簷半床日，暖臥因成睡。", "綿袍擁兩膝，竹幾支雙臂。從旦直至昏，身心一無事。", "心足即為富，身閑乃當貴。富貴在此中，何必居高位。", "君看裴相國，金紫光照地。心苦頭盡白，才年四十四。", "乃知高蓋車，乘者多憂畏。"]'),
('yuding-6','夏日','白居易','唐','御定全唐诗','yuding','','[]','東窗晚無熱，北戶涼有風。盡日坐複臥，不離一室中。',36,'御定全唐詩/json/429.json','["東窗晚無熱，北戶涼有風。盡日坐複臥，不離一室中。", "中心本無系，亦與出門同。"]'),
('yuding-7','適意二首','白居易','唐','御定全唐诗','yuding','','[]','十年為旅客，常有饑寒愁。三年作諫官，複多屍素羞。',228,'御定全唐詩/json/429.json','["十年為旅客，常有饑寒愁。三年作諫官，複多屍素羞。", "有酒不暇飲，有山不得遊。豈無平生志，拘牽不自由。", "一朝歸渭上，泛如不系舟。置心世事外，無喜亦無憂。", "終日一蔬食，終年一布裘。寒來彌懶放，數日一梳頭。", "朝睡足始起，夜酌醉即休。人心不過適，適外複何求。", "早歲從旅遊，頗諳時俗意。中年忝班列，備見朝廷事。", "作客誠已難，為臣尤不易。況余方且介，舉動多忤累。", "直道速我尤，詭遇非吾志。胸中十年內，消盡浩然氣。", "自從返田畝，頓覺無憂愧。蟠木用難施，浮雲心易遂。", "悠悠身與世，從此兩相棄。"]'),
('yuding-8','首夏病間','白居易','唐','御定全唐诗','yuding','','[]','我生來幾時，萬有四千日。自省於其間，非憂即有疾。',120,'御定全唐詩/json/429.json','["我生來幾時，萬有四千日。自省於其間，非憂即有疾。", "老去慮漸息，年來病初愈。忽喜身與心，泰然兩無苦。", "況茲孟夏月，清和好時節。微風吹袷衣，不寒複不熱。", "移榻樹陰下，竟日何所為。或飲一甌茗，或吟兩句詩。", "內無憂患迫，外無職役羈。此日不自適，何時是適時。"]'),
('yuding-9','晚春酤酒','白居易','唐','御定全唐诗','yuding','','[]','百花落如雪，兩鬢垂作絲。春去有來日，我老無少時。',96,'御定全唐詩/json/429.json','["百花落如雪，兩鬢垂作絲。春去有來日，我老無少時。", "人生待富貴，為樂常苦遲。不如貧賤日，隨分開愁眉。", "賣我所乘馬，典我舊朝衣。盡將酤酒飲，酩酊步行歸。", "名姓日隱晦，形骸日變衰。醉臥黃公肆，人知我是誰。"]'),
('yuding-10','蘭若寓居','白居易','唐','御定全唐诗','yuding','','[]','名宦老慵求，退身安草野。家園病懶歸，寄居在蘭若。',72,'御定全唐詩/json/429.json','["名宦老慵求，退身安草野。家園病懶歸，寄居在蘭若。", "薜衣換簪組，藜杖代車馬。行止輒自由，甚覺身瀟灑。", "晨游南塢上，夜息東庵下。人間千萬事，無有關心者。"]'),
('yuding-11','麹生訪宿','白居易','唐','御定全唐诗','yuding','','[]','西齋寂已暮，叩門聲樀樀。知是君宿來，自拂塵埃席。',72,'御定全唐詩/json/429.json','["西齋寂已暮，叩門聲樀樀。知是君宿來，自拂塵埃席。", "村家何所有，茶果迎來客。貧靜似僧居，竹林依四壁。", "廚燈斜影出，簷雨餘聲滴。不是愛閒人，肯來同此夕。"]'),
('yuding-12','聞庾七左降，因詠所懷','白居易','唐','御定全唐诗','yuding','','[]','我病臥渭北，君老謫巴東。相悲一長歎，薄命與君同。',120,'御定全唐詩/json/429.json','["我病臥渭北，君老謫巴東。相悲一長歎，薄命與君同。", "既歎還自哂，哂歎兩未終。後心誚前意，所見何迷蒙。", "人生大塊間，如鴻毛在風。或飄青雲上，或落泥塗中。", "袞服相天下，倘來非我通。布衣委草莽，偶去非吾窮。", "外物不可必，中懷須自空。無令怏怏氣，留滯在心胸。"]'),
('yuding-13','答蔔者','白居易','唐','御定全唐诗','yuding','','[]','病眼昏似夜，衰鬢颯如秋。除卻須衣食，平生百事休。',48,'御定全唐詩/json/429.json','["病眼昏似夜，衰鬢颯如秋。除卻須衣食，平生百事休。", "知君善易者，問我決疑不。不蔔非他故，人間無所求。"]'),
('yuding-14','歸田三首','白居易','唐','御定全唐诗','yuding','','[]','人生何所欲，所欲唯兩端。中人愛富貴，高士慕神仙。',348,'御定全唐詩/json/429.json','["人生何所欲，所欲唯兩端。中人愛富貴，高士慕神仙。", "神仙須有籍，富貴亦在天。莫戀長安道，莫尋方丈山。", "西京塵浩浩，東海浪漫漫。金門不可入，琪樹何由攀。", "不如歸山下，如法種春田。", "種田意已決，決意複何如。賣馬買犢使，徒步歸田廬。", "迎春治耒耜，候雨辟菑畬。策杖田頭立，躬親課僕夫。", "吾聞老農言，為稼慎在初。所施不鹵莽，其報必有餘。", "上求奉王稅，下望備家儲。安得放慵惰，拱手而曳裾。", "學農未為鄙，親友勿笑餘。更待明年後，自擬執犁鋤。", "三十為近臣，腰間鳴佩玉。四十為野夫，田中學鋤穀。", "何言十年內，變化如此速。此理固是常，窮通相倚伏。", "為魚有深水，為鳥有高木。何必守一方，窘然自牽束。", "化吾足為馬，吾因以行陸。化吾手為彈，吾因以求肉。", "形骸為異物，委順心猶足。幸得且歸農，安知不為福。", "況吾行欲老，瞥若風前燭。孰能俄頃間，將心系榮辱。"]'),
('yuding-15','秋游原上','白居易','唐','御定全唐诗','yuding','','[]','七月行已半，早涼天氣清。清晨起巾櫛，徐步出柴荊。',132,'御定全唐詩/json/429.json','["七月行已半，早涼天氣清。清晨起巾櫛，徐步出柴荊。", "露杖筇竹冷，風襟越蕉輕。閑攜弟侄輩，同上秋原行。", "新棗未全赤，晚瓜有餘馨。依依田家叟，設此相逢迎。", "自我到此村，往來白髮生。村中相識久，老幼皆有情。", "留連向暮歸，樹樹風蟬聲。是時新雨足，禾黍夾道青。", "見此令人飽，何必待西成。"]'),
('yuding-16','九日登西原宴望','白居易','唐','御定全唐诗','yuding','','[]','病愛枕席涼，日高眠未輟。弟兄呼我起，今日重陽節。',132,'御定全唐詩/json/429.json','["病愛枕席涼，日高眠未輟。弟兄呼我起，今日重陽節。", "起登西原望，懷抱同一豁。移座就菊叢，糕酒前羅列。", "雖無絲與管，歌笑隨情發。白日未及傾，顏酡耳已熱。", "酒酣四向望，六合何空闊。天地自久長，斯人幾時活。", "請看原下村，村人死不歇。一村四十家，哭葬無虛月。", "指此各相勉，良辰且歡悅。"]'),
('yuding-17','寄同病者','白居易','唐','御定全唐诗','yuding','','[]','三十生二毛，早衰為沉屙。四十官七品，拙宦非由他。',120,'御定全唐詩/json/429.json','["三十生二毛，早衰為沉屙。四十官七品，拙宦非由他。", "年顏日枯槁，時命日蹉跎。豈獨我如此，聖賢無奈何。", "回觀親舊中，舉目尤可嗟。或有終老者，沉賤如泥沙。", "或有始壯者，飄忽如風花。窮餓與夭促，不如我者多。", "以此反自慰，常得心平和。寄言同病者，回歎且為歌。"]'),
('yuding-18','游藍田山卜居','白居易','唐','御定全唐诗','yuding','','[]','脫置腰下組，擺落心中塵。行歌望山去，意似歸鄉人。',60,'御定全唐詩/json/429.json','["脫置腰下組，擺落心中塵。行歌望山去，意似歸鄉人。", "朝蹋玉峰下，暮尋藍水濱。擬求幽僻地，安置疏慵身。", "本性便山寺，應須旁悟真。"]'),
('yuding-19','村雪夜坐','白居易','唐','御定全唐诗','yuding','','[]','南窗背燈坐，風霰暗紛紛。寂寞深村夜，殘雁雪中聞。',24,'御定全唐詩/json/429.json','["南窗背燈坐，風霰暗紛紛。寂寞深村夜，殘雁雪中聞。"]'),
('yuding-20','東園玩菊','白居易','唐','御定全唐诗','yuding','','[]','少年昨已去，芳歲今又闌。如何寂寞意，複此荒涼園。',144,'御定全唐詩/json/429.json','["少年昨已去，芳歲今又闌。如何寂寞意，複此荒涼園。", "園中獨立久，日澹風露寒。秋蔬盡蕪沒，好樹亦凋殘。", "唯有數叢菊，新開籬落間。攜觴聊就酌，為爾一留連。", "憶我少小日，易為興所牽。見酒無時節，未飲已欣然。", "近從年長來，漸覺取樂難。常恐更衰老，強飲亦無歡。", "顧謂爾菊花，後時何獨鮮。誠知不為我，借爾暫開顏。"]'),
('yuding-21','觀稼','白居易','唐','御定全唐诗','yuding','','[]','世役不我牽，身心常自若。晚出看田畝，閑行旁村落。',144,'御定全唐詩/json/429.json','["世役不我牽，身心常自若。晚出看田畝，閑行旁村落。", "累累繞場稼，嘖嘖群飛雀。年豐豈獨人，禽鳥聲亦樂。", "田翁逢我喜，默起具尊杓。斂手笑相延，社酒有殘酌。", "愧茲勤且敬，藜杖為淹泊。言動任天真，未覺農人惡。", "停杯問生事，夫種妻兒獲。筋力苦疲勞，衣食常單薄。", "自慚祿仕者，曾不營農作。饑食無所勞，何殊衛人鶴。"]'),
('yuding-22','聞哭者','白居易','唐','御定全唐诗','yuding','','[]','昨日南鄰哭，哭聲一何苦。雲是妻哭夫，夫年二十五。',96,'御定全唐詩/json/429.json','["昨日南鄰哭，哭聲一何苦。雲是妻哭夫，夫年二十五。", "今朝北裏哭，哭聲又何切。雲是母哭兒，兒年十七八。", "四鄰尚如此，天下多夭折。乃知浮世人，少得垂白髮。", "餘今過四十，念彼聊自悅。從此明鏡中，不嫌頭似雪。"]'),
('yuding-23','新構亭台，示諸弟侄','白居易','唐','御定全唐诗','yuding','','[]','平臺高數尺，臺上結茅茨。東西疏二牖，南北開兩扉。',132,'御定全唐詩/json/429.json','["平臺高數尺，臺上結茅茨。東西疏二牖，南北開兩扉。", "蘆簾前後卷，竹簟當中施。清泠白石枕，疏涼黃葛衣。", "開襟向風坐，夏日如秋時。嘯傲頗有趣，窺臨不知疲。", "東窗對華山，三峰碧參差。南簷當渭水，臥見雲帆飛。", "仰摘枝上果，俯折畦中葵。足以充饑渴，何必慕甘肥。", "況有好群從，旦夕相追隨。"]'),
('yuding-24','自吟拙什，因有所懷','白居易','唐','御定全唐诗','yuding','','[]','懶病每多暇，暇來何所為。未能拋筆硯，時作一篇詩。',108,'御定全唐詩/json/429.json','["懶病每多暇，暇來何所為。未能拋筆硯，時作一篇詩。", "詩成淡無味，多被眾人嗤。上怪落聲韻，下嫌拙言詞。", "時時自吟詠，吟罷有所思。蘇州及彭澤，與我不同時。", "此外複誰愛，唯有元微之。謫向江陵府，三年作判司。", "相去二千里，詩成遠不知。"]'),
('yuding-25','東坡秋意，寄元八','白居易','唐','御定全唐诗','yuding','','[]','寥落野陂畔，獨行思有餘。秋荷病葉上，白露大如珠。',96,'御定全唐詩/json/429.json','["寥落野陂畔，獨行思有餘。秋荷病葉上，白露大如珠。", "忽憶同賞地，曲江東北隅。秋池少遊客，唯我與君俱。", "啼蛩隱紅蓼，瘦馬蹋青蕪。當時與今日，俱是暮秋初。", "節物苦相似，時景亦無餘。唯有人分散，經年不得書。"]'),
('yuding-26','閒居','白居易','唐','御定全唐诗','yuding','','[]','深閉竹間扉，靜掃松下地。獨嘯晚風前，何人知此意。',48,'御定全唐詩/json/429.json','["深閉竹間扉，靜掃松下地。獨嘯晚風前，何人知此意。", "看山盡日坐，枕帙移時睡。誰能從我遊，使君心無事。"]'),
('yuding-27','詠拙','白居易','唐','御定全唐诗','yuding','','[]','所稟有巧拙，不可改者性。所賦有厚薄，不可移者命。',192,'御定全唐詩/json/429.json','["所稟有巧拙，不可改者性。所賦有厚薄，不可移者命。", "我性愚且蠢，我命薄且屯。問我何以知，所知良有因。", "亦曾舉兩足，學人蹋紅塵。從茲知性拙，不解轉如輪。", "亦曾奮六翮，高飛到青雲。從茲知命薄，摧落不逡巡。", "慕貴而厭賤，樂富而惡貧。同此天地間，我豈異於人。", "性命苟如此，反則成苦辛。以此自安分，雖窮每欣欣。", "葺茅為我廬，編蓬為我門。縫布作袍被，種穀充盤飧。", "靜讀古人書，閑釣清渭濱。優哉複遊哉，聊以終吾身。"]'),
('yuding-28','詠慵','白居易','唐','御定全唐诗','yuding','','[]','有官慵不選，有田慵不農。屋穿慵不葺，衣裂慵不縫。',96,'御定全唐詩/json/429.json','["有官慵不選，有田慵不農。屋穿慵不葺，衣裂慵不縫。", "有酒慵不酌，無異尊常空。有琴慵不彈，亦與無弦同。", "家人告飯盡，欲炊慵不舂。親朋寄書至，欲讀慵開封。", "嘗聞嵇叔夜，一生在慵中。彈琴複鍛鐵，比我未為慵。"]'),
('yuding-29','冬夜','白居易','唐','御定全唐诗','yuding','','[]','家貧親愛散，身病交遊罷。眼前無一人，獨掩村齋臥。',96,'御定全唐詩/json/429.json','["家貧親愛散，身病交遊罷。眼前無一人，獨掩村齋臥。", "冷落燈火暗，離披簾幕破。策策窗戶前，又聞新雪下。", "長年漸省睡，夜半起端坐。不學坐忘心，寂莫安可過。", "兀然身寄世，浩然心委化。如此來四年，一千三百夜。"]'),
('yuding-30','村中留李三固言宿','白居易','唐','御定全唐诗','yuding','','[]','平生早遊宦，不道無親故。如我與君心，相知應有數。',108,'御定全唐詩/json/429.json','["平生早遊宦，不道無親故。如我與君心，相知應有數。", "春明門前別，金氏陂中遇。村酒兩三杯，相留寒日暮。", "勿嫌村酒薄，聊酌論心素。請君少踟躕，系馬門前樹。", "明年身若健，便擬江湖去。他日縱相思，知君無覓處。", "後會既茫茫，今宵君且住。"]'),
('yuding-31','友人夜訪','白居易','唐','御定全唐诗','yuding','','[]','簷間清風簟，松下明月杯。幽意正如此，況乃故人來。',24,'御定全唐詩/json/429.json','["簷間清風簟，松下明月杯。幽意正如此，況乃故人來。"]'),
('yuding-32','遊悟真寺詩','白居易','唐','御定全唐诗','yuding','','[]','元和九年秋，八月月上弦。我遊悟真寺，寺在王順山。',576,'御定全唐詩/json/429.json','["元和九年秋，八月月上弦。我遊悟真寺，寺在王順山。", "去山四五裏，先聞水潺湲。自茲舍車馬，始涉藍溪灣。", "手拄青竹杖，足蹋白石灘。漸怪耳目曠，不聞人世喧。", "山下望山上，初疑不可攀。誰知中有路，盤折通岩巔。", "一息幡竿下，再休石龕邊。龕間長丈餘，門戶無扃關。", "仰窺不見人，石發垂若鬟。驚出白蝙蝠，雙飛如雪翻。", "回首寺門望，青崖夾朱軒。如擘山腹開，置寺於其間。", "入門無平地，地窄虛空寬。房廊與台殿，高下隨峰巒。", "岩崿無撮土，樹木多瘦堅。根株抱石長，屈曲蟲蛇蟠。", "松桂亂無行，四時鬱芊芊。枝梢嫋青翠，韻若風中弦。", "日月光不透，綠陰相交延。幽鳥時一聲，聞之似寒蟬。", "首憩賓位亭，就坐未及安。須臾開北戶，萬里明豁然。", "拂簷虹霏微，繞棟雲迴旋。赤日間白雨，陰晴同一川。", "野綠簇草樹，眼界吞秦原。渭水細不見，漢陵小於拳。", "卻顧來時路，縈紆映朱欄。歷歷上山人，一一遙可觀。", "前對多寶塔，風鐸鳴四端。欒櫨與戶牖，恰恰金碧繁。", "雲昔迦葉佛，此地坐涅盤。至今鐵缽在，當底手跡穿。", "西開玉像殿，白佛森比肩。鬥藪塵埃衣，禮拜冰雪顏。", "疊霜為袈裟，貫雹為華鬘。逼觀疑鬼功，其跡非雕鐫。", "次登觀音堂，未到聞栴檀。上階脫雙履，斂足升淨筵。", "六楹排玉鏡，四座敷金鈿。黑夜自光明，不待燈燭燃。", "眾寶互低昂，碧佩珊瑚幡。風來似天樂，相觸聲珊珊。", "白珠垂露凝，赤珠滴血殷。點綴佛髻上，合為七寶冠。", "雙瓶白琉璃，色若秋水寒。隔瓶見舍利，圓轉如金丹。"]'),
('yuding-33','酬張十八訪宿見贈','白居易','唐','御定全唐诗','yuding','','[]','昔我為近臣，君常稀到門。今我官職冷，君君來往頻。',192,'御定全唐詩/json/429.json','["昔我為近臣，君常稀到門。今我官職冷，君君來往頻。", "我受狷介性，立為頑拙身。平生雖寡合，合即無緇磷。", "況君秉高義，富貴視如雲。五侯三相家，眼冷不見君。", "問其所與遊，獨言韓舍人。其次即及我，我愧非其倫。", "胡為謬相愛，歲晚逾勤勤。落然頹簷下，一話夜達晨。", "床單食味薄，亦不嫌我貧。日高上馬去，相顧猶逡巡。", "長安久無雨，日赤風昏昏。憐君將病眼，為我犯埃塵。", "遠從延康裏，來訪曲江濱。所重君子道，不獨愧相親。"]'),
('yuding-34','朝歸書寄元八','白居易','唐','御定全唐诗','yuding','','[]','進入閣前拜，退就廊下餐。歸來昭國裏，人臥馬歇鞍。',192,'御定全唐詩/json/429.json','["進入閣前拜，退就廊下餐。歸來昭國裏，人臥馬歇鞍。", "卻睡至日午，起坐心浩然。況當好時節，雨後清和天。", "柿樹綠陰合，王家庭院寬。瓶中鄠縣酒，牆上終南山。", "獨眠仍獨坐，開襟當風前。禪師與詩客，次第來相看。", "要語連夜語，須眠終日眠。除非奉朝謁，此外無別牽。", "年長身且健，官貧心甚安。幸無急病痛，不至苦饑寒。", "自此聊以適，外緣不能幹。唯應靜者信，難為動者言。", "台中元侍禦，早晚作郎官。未作郎官際，無人相伴閑。"]'),
('yuding-35','酬吳七見寄','白居易','唐','御定全唐诗','yuding','','[]','曲江有病客，尋常多掩關。又聞馬死來，不出身更閑。',192,'御定全唐詩/json/429.json','["曲江有病客，尋常多掩關。又聞馬死來，不出身更閑。", "聞有送書者，自起出門看。素緘署丹字，中有瓊瑤篇。", "口吟耳自聽，當暑忽翛然。似漱寒玉冰，如聞商風弦。", "首章歎時節，末句思笑言。懶慢不相訪，隔街如隔山。", "嘗聞陶潛語，心遠地自偏。君住安邑裏，左右車徒喧。", "竹藥閉深院，琴尊開小軒。誰知市南地，轉作壺中天。", "君本上清人，名在石堂間。不知有何過，謫作人間仙。", "常恐歲月滿，飄然歸紫煙。莫忘蜉蝣內，進士有同年。"]'),
('yuding-36','昭國閒居','白居易','唐','御定全唐诗','yuding','','[]','貧閑日高起，門巷晝寂寂。時暑放朝參，天陰少人客。',96,'御定全唐詩/json/429.json','["貧閑日高起，門巷晝寂寂。時暑放朝參，天陰少人客。", "槐花滿田地，僅絕人行跡。獨在一床眠，清涼風雨夕。", "勿嫌坊曲遠，近即多牽役。勿嫌祿俸薄，厚即多憂責。", "平生尚恬曠，老大宜安適。何以養吾真，官閒居處僻。"]'),
('yuding-37','喜陳兄至','白居易','唐','御定全唐诗','yuding','','[]','黃鳥啼欲歇，青梅結半成。坐憐春物盡，起入東園行。',72,'御定全唐詩/json/429.json','["黃鳥啼欲歇，青梅結半成。坐憐春物盡，起入東園行。", "攜觴懶獨酌，忽聞叩門聲。閒人猶喜至，何況是陳兄。", "從容盡日語，稠疊長年情。勿輕一盞酒，可以話平生。"]'),
('yuding-38','贈杓直','白居易','唐','御定全唐诗','yuding','','[]','世路重祿位，棲棲者孔宣。人情愛年壽，夭死者顏淵。',216,'御定全唐詩/json/429.json','["世路重祿位，棲棲者孔宣。人情愛年壽，夭死者顏淵。", "二人如何人，不奈命與天。我今信多幸，撫己愧前賢。", "已年四十四，又為五品官。況茲知足外，別有所安焉。", "早年以身代，直赴逍遙篇。近歲將心地，回向南宗禪。", "外順世間法，內脫區中緣。進不厭朝市，退不戀人寰。", "自吾得此心，投足無不安。體非導引適，意無江湖閑。", "有興或飲酒，無事多掩關。寂靜夜深坐，安穩日高眠。", "秋不苦長夜，春不惜流年。委形老小外，忘懷生死間。", "昨日共君語，與餘心膂然。此道不可道，因君聊強言。"]'),
('yuding-39','寄張十八','白居易','唐','御定全唐诗','yuding','','[]','饑止一簟食，渴止一壺漿。出入止一馬，寢興止一床。',132,'御定全唐詩/json/429.json','["饑止一簟食，渴止一壺漿。出入止一馬，寢興止一床。", "此外無長物，於我有若亡。胡然不知足，名利心遑遑。", "念茲彌懶放，積習遂為常。經旬不出門，竟日不下堂。", "同病者張生，貧僻住延康。慵中每相憶，此意未能忘。", "迢迢青槐街，相去八九坊。秋來未相見，應有新詩章。", "早晚來同宿，天氣轉清涼。"]'),
('yuding-40','題玉泉寺','白居易','唐','御定全唐诗','yuding','','[]','湛湛玉泉色，悠悠浮雲身。閒心對定水，清淨兩無塵。',48,'御定全唐詩/json/429.json','["湛湛玉泉色，悠悠浮雲身。閒心對定水，清淨兩無塵。", "手把青筇杖，頭戴白綸巾。興盡下山去，知我是誰人。"]'),
('yuding-41','朝回游城南','白居易','唐','御定全唐诗','yuding','','[]','朝退馬未困，秋初日猶長。回轡城南去，郊野正清涼。',108,'御定全唐詩/json/429.json','["朝退馬未困，秋初日猶長。回轡城南去，郊野正清涼。", "水竹夾小徑，縈回繞川岡。仰看晚山色，俯弄秋泉光。", "青松系我馬，白石為我床。常時簪組累，此日和身忘。", "旦隨鵷鷺末，暮遊鷗鶴旁。機心一以盡，兩處不亂行。", "誰辨心與跡，非行亦非藏。"]'),
('yuding-42','舟行','白居易','唐','御定全唐诗','yuding','','[]','帆影日漸高，閑眠猶未起。起問鼓枻人，已行三十裏。',72,'御定全唐詩/json/429.json','["帆影日漸高，閑眠猶未起。起問鼓枻人，已行三十裏。", "船頭有行灶，炊稻烹紅鯉。飽食起婆娑，盥漱秋江水。", "平生滄浪意，一旦來遊此。何況不失家，舟中載妻子。"]'),
('yuding-43','湓浦早冬','白居易','唐','御定全唐诗','yuding','','[]','潯陽孟冬月，草木未全衰。祇抵長安陌，涼風八月時。',60,'御定全唐詩/json/429.json','["潯陽孟冬月，草木未全衰。祇抵長安陌，涼風八月時。", "日西湓水曲，獨行吟舊詩。蓼花始零落，蒲葉稍離披。", "但作城中想，何異曲江池。"]'),
('yuding-44','江州雪','白居易','唐','御定全唐诗','yuding','','[]','新雪滿前山，初晴好天氣。日西騎馬出，忽有京都意。',72,'御定全唐詩/json/429.json','["新雪滿前山，初晴好天氣。日西騎馬出，忽有京都意。", "城柳方綴花，簷冰才結穗。須臾風日暖，處處皆飄墜。", "行吟賞未足，坐歎銷何易。猶勝嶺南看，雰雰不到地。"]'),
('yuding-0','題潯陽樓','白居易','唐','御定全唐诗','yuding','','[]','常愛陶彭澤，文思何高玄。又怪韋江州，詩情亦清閒。',96,'御定全唐詩/json/430.json','["常愛陶彭澤，文思何高玄。又怪韋江州，詩情亦清閒。", "今朝登此樓，有以知其然。大江寒見底，匡山青倚天。", "深夜湓浦月，平旦爐峰煙。清輝與靈氣，日夕供文篇。", "我無二人才，孰為來其間。因高偶成句，俯仰愧江山。"]'),
('yuding-1','訪陶公舊宅','白居易','唐','御定全唐诗','yuding','','[]','垢塵不汙玉，靈鳳不啄膻。嗚呼陶靖節，生彼晉宋間。',216,'御定全唐詩/json/430.json','["垢塵不汙玉，靈鳳不啄膻。嗚呼陶靖節，生彼晉宋間。", "心實有所守，口終不能言。永惟孤竹子，拂衣首陽山。", "夷齊各一身，窮餓未為難。先生有五男，與之同饑寒。", "腸中食不充，身上衣不完。連征竟不起，斯可謂真賢。", "我生君之後，相去五百年。每讀五柳傳，目想心拳拳。", "昔常詠遺風，著為十六篇。今來訪故宅，森若君在前。", "不慕尊有酒，不慕琴無弦。慕君遺榮利，老死此丘園。", "柴桑古村落，栗裏舊山川。不見籬下菊，但餘墟中煙。", "子孫雖無聞，族氏猶未遷。每逢姓陶人，使我心依然。"]'),
('yuding-2','北亭','白居易','唐','御定全唐诗','yuding','','[]','廬宮山下州，湓浦沙邊宅。宅北倚高岡，迢迢數千尺。',144,'御定全唐詩/json/430.json','["廬宮山下州，湓浦沙邊宅。宅北倚高岡，迢迢數千尺。", "上有青青竹，竹間多白石。茅亭居上頭，豁達門四辟。", "前楹捲簾箔，北牖施床席。江風萬里來，吹我涼淅淅。", "日高公府歸，巾笏隨手擲。脫衣恣搔首，坐臥任所適。", "時傾一杯酒，曠望湖天夕。口詠獨酌謠，目送歸飛翮。", "慚無出塵操，未免折腰役。偶獲此閒居，謬似高人跡。"]'),
('yuding-3','泛湓水','白居易','唐','御定全唐诗','yuding','','[]','四月未全熱，麥涼江氣秋。湖山處處好，最愛湓水頭。',180,'御定全唐詩/json/430.json','["四月未全熱，麥涼江氣秋。湖山處處好，最愛湓水頭。", "湓水從東來，一派入江流。可憐似縈帶，中有隨風舟。", "命酒一臨泛，舍鞍揚棹謳。放回岸傍馬，去逐波間鷗。", "煙浪始渺渺，風襟亦悠悠。初疑上河漢，中若尋瀛洲。", "汀樹綠拂地，沙草芳未休。青蘿與紫葛，枝蔓垂相樛。", "系纜步平岸，回頭望江州。城雉映水見，隱隱如蜃樓。", "日入意未盡，將歸複少留。到官行半歲，今日方一遊。", "此地來何暮，可以寫吾憂。"]'),
('yuding-4','答故人','白居易','唐','御定全唐诗','yuding','','[]','故人對酒歎，歎我在天涯。見我昔榮遇，念我今蹉跎。',132,'御定全唐詩/json/430.json','["故人對酒歎，歎我在天涯。見我昔榮遇，念我今蹉跎。", "問我為司馬，官意複如何。答雲且勿歎，聽我為君歌。", "我本蓬蓽人，鄙賤劇泥沙。讀書未百卷，信口嘲風花。", "自從筮仕來，六命三登科。顧慚虛劣姿，所得亦已多。", "散員足庇身，薄俸可資家。省分輒自愧，豈為不遇耶。", "煩君對杯酒，為我一咨蹉。"]'),
('yuding-5','官舍內新鑿小池','白居易','唐','御定全唐诗','yuding','','[]','簾下開小池，盈盈水方積。中底鋪白沙，四隅甃青石。',96,'御定全唐詩/json/430.json','["簾下開小池，盈盈水方積。中底鋪白沙，四隅甃青石。", "勿言不深廣，但取幽人適。泛灩微雨朝，泓澄明月夕。", "豈無大江水，波浪連天白。未如床席間，方丈深盈尺。", "清淺可狎弄，昏煩聊漱滌。最愛曉暝時，一片秋天碧。"]'),
('yuding-6','宿簡寂觀','白居易','唐','御定全唐诗','yuding','','[]','岩白雲尚屯，林紅葉初隕。秋光引閒步，不知身遠近。',72,'御定全唐詩/json/430.json','["岩白雲尚屯，林紅葉初隕。秋光引閒步，不知身遠近。", "夕投靈洞宿，臥覺塵機泯。名利心既忘，市朝夢亦盡。", "暫來尚如此，況乃終身隱。何以療夜饑，一匙雲母粉。"]'),
('yuding-7','讀謝靈運詩','白居易','唐','御定全唐诗','yuding','','[]','吾聞達士道，窮通順冥數。通乃朝廷來，窮即江湖去。',108,'御定全唐詩/json/430.json','["吾聞達士道，窮通順冥數。通乃朝廷來，窮即江湖去。", "謝公才廓落，與世不相遇。壯志鬱不用，須有所泄處。", "泄為山水詩，逸韻諧奇趣。大必籠天海，細不遺草樹。", "豈惟玩景物，亦欲攄心素。往往即事中，未能忘興諭。", "因知康樂作，不獨在章句。"]'),
('yuding-8','北亭獨宿','白居易','唐','御定全唐诗','yuding','','[]','悄悄壁下床，紗籠耿殘燭。夜半獨眠覺，疑在僧房宿。',24,'御定全唐詩/json/430.json','["悄悄壁下床，紗籠耿殘燭。夜半獨眠覺，疑在僧房宿。"]'),
('yuding-9','約心','白居易','唐','御定全唐诗','yuding','','[]','黑鬢絲雪侵，青袍塵土涴。兀兀複騰騰，江城一上佐。',60,'御定全唐詩/json/430.json','["黑鬢絲雪侵，青袍塵土涴。兀兀複騰騰，江城一上佐。", "朝就高齋上，熏然負暄臥。晚下小池前，澹然臨水坐。", "已約終身心，長如今日過。"]'),
('yuding-10','晚望','白居易','唐','御定全唐诗','yuding','','[]','江城寒角動，沙洲夕鳥還。獨在高亭上，西南望遠山。',24,'御定全唐詩/json/430.json','["江城寒角動，沙洲夕鳥還。獨在高亭上，西南望遠山。"]'),
('yuding-11','早春','白居易','唐','御定全唐诗','yuding','','[]','雪消冰又釋，景和風複暄。滿庭田地濕，薺葉生牆根。',48,'御定全唐詩/json/430.json','["雪消冰又釋，景和風複暄。滿庭田地濕，薺葉生牆根。", "官舍悄無事，日西斜掩門。不開莊老卷，欲與何人言。"]'),
('yuding-12','春寢','白居易','唐','御定全唐诗','yuding','','[]','何處春暄來，微和生血氣。氣熏肌骨暢，東窗一昏睡。',72,'御定全唐詩/json/430.json','["何處春暄來，微和生血氣。氣熏肌骨暢，東窗一昏睡。", "是時正月晦，假日無公事。爛熳不能休，自午將及未。", "緬思少健日，甘寢常自恣。一從衰疾來，枕上無此味。"]'),
('yuding-13','睡起晏坐','白居易','唐','御定全唐诗','yuding','','[]','後亭晝眠足，起坐春景暮。新覺眼猶昏，無思心正住。',72,'御定全唐詩/json/430.json','["後亭晝眠足，起坐春景暮。新覺眼猶昏，無思心正住。", "澹寂歸一性，虛閑遺萬慮。了然此時心，無物可譬喻。", "本是無有鄉，亦名不用處。行禪與坐忘，同歸無異路。"]'),
('yuding-14','詠懷','白居易','唐','御定全唐诗','yuding','','[]','盡日松下坐，有時池畔行。行立與坐臥，中懷澹無營。',48,'御定全唐詩/json/430.json','["盡日松下坐，有時池畔行。行立與坐臥，中懷澹無營。", "不覺流年過，亦任白髮生。不為世所薄，安得遂閒情。"]'),
('yuding-15','春遊二林寺','白居易','唐','御定全唐诗','yuding','','[]','下馬二林寺，翛然進輕策。朝為公府吏，暮作靈山客。',132,'御定全唐詩/json/430.json','["下馬二林寺，翛然進輕策。朝為公府吏，暮作靈山客。", "二月匡廬北，冰雪始消釋。陽叢抽茗芽，陰竇泄泉脈。", "熙熙風土暖，藹藹雲嵐積。散作萬壑春，凝為一氣碧。", "身閑易飄泊，官散無牽迫。緬彼十八人，古今同此適。", "是年淮寇起，處處興兵革。智士勞思謀，戎臣苦征役。", "獨有不才者，山中弄泉石。"]'),
('yuding-16','出山吟','白居易','唐','御定全唐诗','yuding','','[]','朝詠遊仙詩，暮歌采薇曲。臥雲坐白石，山中十五宿。',48,'御定全唐詩/json/430.json','["朝詠遊仙詩，暮歌采薇曲。臥雲坐白石，山中十五宿。", "行隨出洞水，回別緣岩竹。早晚重來遊，心期瑤草綠。"]'),
('yuding-17','歲暮','白居易','唐','御定全唐诗','yuding','','[]','已任時命去，亦從歲月除。中心一調伏，外累盡空虛。',48,'御定全唐詩/json/430.json','["已任時命去，亦從歲月除。中心一調伏，外累盡空虛。", "名宦意已矣，林泉計何如。擬近東林寺，溪邊結一廬。"]'),
('yuding-18','聞早鶯','白居易','唐','御定全唐诗','yuding','','[]','日出眠未起，屋頭聞早鶯。忽如上林曉，萬年枝上鳴。',84,'御定全唐詩/json/430.json','["日出眠未起，屋頭聞早鶯。忽如上林曉，萬年枝上鳴。", "憶為近臣時，秉筆直承明。春深視草暇，旦暮聞此聲。", "今聞在何處，寂寞潯陽城。鳥聲信如一，分別在人情。", "不作天涯意，豈殊禁中聽。"]'),
('yuding-19','栽杉','白居易','唐','御定全唐诗','yuding','','[]','勁葉森利劍，孤莖挺端標。才高四五尺，勢若干青霄。',96,'御定全唐詩/json/430.json','["勁葉森利劍，孤莖挺端標。才高四五尺，勢若干青霄。", "移栽東窗前，愛爾寒不凋。病夫臥相對，日夕閑蕭蕭。", "昨為山中樹，今為簷下條。雖然遇賞玩，無乃近塵囂。", "猶勝澗穀底，埋沒隨眾樵。不見鬱鬱松，委質山上苗。"]'),
('yuding-20','過李生','白居易','唐','御定全唐诗','yuding','','[]','蘋小蒲葉短，南湖春水生。子近湖邊住，靜境稱高情。',144,'御定全唐詩/json/430.json','["蘋小蒲葉短，南湖春水生。子近湖邊住，靜境稱高情。", "我為郡司馬，散拙無所營。使君知性野，衙退任閑行。", "行攜小榼出，逢花輒獨傾。半酣到子舍，下馬扣柴荊。", "何以引我步，繞籬竹萬莖。何以醒我酒，吳音吟一聲。", "須臾進野飯，飯稻茹芹英。白甌青竹箸，儉潔無膻腥。", "欲去複裴回，夕鴉已飛鳴。何當重遊此，待君湖水平。"]'),
('yuding-21','詠意','白居易','唐','御定全唐诗','yuding','','[]','常聞南華經，巧勞智憂愁。不如無能者，飽食但遨遊。',144,'御定全唐詩/json/430.json','["常聞南華經，巧勞智憂愁。不如無能者，飽食但遨遊。", "平生愛慕道，今日近此流。自來潯陽郡，四序忽已周。", "不分物黑白，但與時沉浮。朝餐夕安寢，用是為身謀。", "此外即閑放，時尋山水幽。春遊慧遠寺，秋上庾公樓。", "或吟詩一章，或飲茶一甌。身心一無系，浩浩如虛舟。", "富貴亦有苦，苦在心危憂。貧賤亦有樂，樂在身自由。"]'),
('yuding-22','食筍','白居易','唐','御定全唐诗','yuding','','[]','此州乃竹鄉，春筍滿山谷。山夫折盈抱，抱來早市鬻。',96,'御定全唐詩/json/430.json','["此州乃竹鄉，春筍滿山谷。山夫折盈抱，抱來早市鬻。", "物以多為賤，雙錢易一束。置之炊甑中，與飯同時熟。", "紫籜坼故錦，素肌擘新玉。每日遂加餐，經時不思肉。", "久為京洛客，此味常不足。且食勿踟躕，南風吹作竹。"]'),
('yuding-23','游石門澗','白居易','唐','御定全唐诗','yuding','','[]','石門無舊徑，披榛訪遺跡。時逢山水秋，清輝如古昔。',84,'御定全唐詩/json/430.json','["石門無舊徑，披榛訪遺跡。時逢山水秋，清輝如古昔。", "常聞慧遠輩，題詩此岩壁。雲覆莓苔封，蒼然無處覓。", "蕭疏野生竹，崩剝多年石。自從東晉後，無複人遊歷。", "獨有秋澗聲，潺湲空旦夕。"]'),
('yuding-24','招東鄰','白居易','唐','御定全唐诗','yuding','','[]','小榼二升酒，新簟六尺床。能來夜話否，池畔欲秋涼。',24,'御定全唐詩/json/430.json','["小榼二升酒，新簟六尺床。能來夜話否，池畔欲秋涼。"]'),
('yuding-25','題元十八溪亭','白居易','唐','御定全唐诗','yuding','','[]','怪君不喜仕，又不遊州裏。今日到幽居，了然知所以。',96,'御定全唐詩/json/430.json','["怪君不喜仕，又不遊州裏。今日到幽居，了然知所以。", "宿君石溪亭，潺湲聲滿耳。飲君螺杯酒，醉臥不能起。", "見君五老峰，益悔居城市。愛君三男兒，始歎身無子。", "余方爐峰下，結室為居士。山北與山東，往來從此始。"]'),
('yuding-26','香爐峰下新置草堂，即事詠懷，題于石上','白居易','唐','御定全唐诗','yuding','','[]','香爐峰北面，遺愛寺西偏。白石何鑿鑿，清流亦潺潺。',228,'御定全唐詩/json/430.json','["香爐峰北面，遺愛寺西偏。白石何鑿鑿，清流亦潺潺。", "有松數十株，有竹千餘竿。松張翠傘蓋，竹倚青琅玕。", "其下無人居，悠哉多歲年。有時聚猿鳥，終日空風煙。", "時有沉冥子，姓白字樂天。平生無所好，見此心依然。", "如獲終老地，忽乎不知還。架岩結茅宇，斫壑開茶園。", "何以洗我耳，屋頭飛落泉。何以淨我眼，砌下生白蓮。", "左手攜一壺，右手挈五弦。傲然意自足，箕踞於其間。", "興酣仰天歌，歌中聊寄言。言我本野夫，誤為世網牽。", "時來昔捧日，老去今歸山。倦鳥得茂樹，涸魚返清源。", "舍此欲焉往，人間多險艱。"]'),
('yuding-27','草堂前新開一池，養魚種荷，日有幽趣','白居易','唐','御定全唐诗','yuding','','[]','淙淙三峽水，浩浩萬頃陂。未如新塘上，微風動漣漪。',72,'御定全唐詩/json/430.json','["淙淙三峽水，浩浩萬頃陂。未如新塘上，微風動漣漪。", "小萍加泛泛，初蒲正離離。紅鯉二三寸，白蓮八九枝。", "繞水欲成徑，護堤方插籬。已被山中客，呼作白家池。"]'),
('yuding-28','白雲期','白居易','唐','御定全唐诗','yuding','','[]','三十氣太壯，胸中多是非。六十身太老，四體不支持。',72,'御定全唐詩/json/430.json','["三十氣太壯，胸中多是非。六十身太老，四體不支持。", "四十至五十，正是退閒時。年長識命分，心慵少營為。", "見酒興猶在，登山力未衰。吾年幸當此，且與白雲期。"]'),
('yuding-29','登香爐峰頂','白居易','唐','御定全唐诗','yuding','','[]','迢迢香爐峰，心存耳目想。終年牽物役，今日方一往。',120,'御定全唐詩/json/430.json','["迢迢香爐峰，心存耳目想。終年牽物役，今日方一往。", "攀蘿蹋危石，手足勞俯仰。同遊三四人，兩人不敢上。", "上到峰之頂，目眩神怳怳。高低有萬尋，闊狹無數丈。", "不窮視聽界，焉識宇宙廣。江水細如繩，湓城小於掌。", "紛吾何屑屑，未能脫塵鞅。歸去思自嗟，低頭入蟻壤。"]'),
('yuding-30','答崔侍郎、錢舍人書問，因繼以詩','白居易','唐','御定全唐诗','yuding','','[]','旦暮兩蔬食，日中一閑眠。便是了一日，如此已三年。',216,'御定全唐詩/json/430.json','["旦暮兩蔬食，日中一閑眠。便是了一日，如此已三年。", "心不擇時適，足不揀地安。窮通與遠近，一貫無兩端。", "常見今之人，其心或不然。在勞則念息，處靜已思喧。", "如是用身心，無乃自傷殘。坐輸憂惱便，安得形神全。", "吾有二道友，藹藹崔與錢。同飛青雲路，獨墮黃泥泉。", "歲暮物萬變，故情何不遷。應為平生心，與我同一源。", "帝鄉遠于日，美人高在天。誰謂萬里別，常若在目前。", "泥泉樂者魚，雲路遊者鸞。勿言雲泥異，同在逍遙間。", "因君問心地，書後偶成篇。慎勿說向人，人多笑此言。"]'),
('yuding-31','烹葵','白居易','唐','御定全唐诗','yuding','','[]','昨臥不夕食，今起乃朝饑。貧廚何所有，炊稻烹秋葵。',108,'御定全唐詩/json/430.json','["昨臥不夕食，今起乃朝饑。貧廚何所有，炊稻烹秋葵。", "紅粒香複軟，綠英滑且肥。饑來止於飽，飽後複何思。", "憶昔榮遇日，迨今窮退時。今亦不凍餒，昔亦無餘資。", "口既不減食，身又不減衣。撫心私自問，何者是榮衰。", "勿學常人意，其間分是非。"]'),
('yuding-32','小池二首','白居易','唐','御定全唐诗','yuding','','[]','晝倦前齋熱，晚愛小池清。映林餘景沒，近水微涼生。',72,'御定全唐詩/json/430.json','["晝倦前齋熱，晚愛小池清。映林餘景沒，近水微涼生。", "坐把蒲葵扇，閑吟三兩聲。", "有意不在大，湛湛方丈餘。荷側瀉清露，萍開見遊魚。", "每一臨此坐，憶歸青溪居。"]'),
('yuding-33','閉關','白居易','唐','御定全唐诗','yuding','','[]','我心忘世久，世亦不我幹。遂成一無事，因得長掩關。',84,'御定全唐詩/json/430.json','["我心忘世久，世亦不我幹。遂成一無事，因得長掩關。", "掩關來幾時，仿佛二三年。著書已盈帙，生子欲能言。", "始悟身向老，複悲世多艱。回顧趨時者，役役塵壤間。", "歲暮竟何得，不如且安閒。"]'),
('yuding-34','弄龜羅','白居易','唐','御定全唐诗','yuding','','[]','有侄始六歲，字之為阿龜。有女生三年，其名曰羅兒。',108,'御定全唐詩/json/430.json','["有侄始六歲，字之為阿龜。有女生三年，其名曰羅兒。", "一始學笑語，一能誦歌詩。朝戲抱我足，夜眠枕我衣。", "汝生何其晚，我年行已衰。物情小可念，人意老多慈。", "酒美竟須壞，月圓終有虧。亦如恩愛緣，乃是憂惱資。", "舉世同此累，吾安能去之。"]'),
('yuding-35','截樹','白居易','唐','御定全唐诗','yuding','','[]','種樹當前軒，樹高柯葉繁。惜哉遠山色，隱此蒙籠間。',120,'御定全唐詩/json/430.json','["種樹當前軒，樹高柯葉繁。惜哉遠山色，隱此蒙籠間。", "一朝持斧斤，手自截其端。萬葉落頭上，千峰來面前。", "忽似決雲霧，豁達睹青天。又如所念人，久別一款顏。", "始有清風至，稍見飛鳥還。開懷東南望，目遠心遼然。", "人各有偏好，物莫能兩全。豈不愛柔條，不如見青山。"]'),
('yuding-36','望江樓上作','白居易','唐','御定全唐诗','yuding','','[]','江畔百尺樓，樓前千里道。憑高望平遠，亦足舒懷抱。',72,'御定全唐詩/json/430.json','["江畔百尺樓，樓前千里道。憑高望平遠，亦足舒懷抱。", "驛路使憧憧，關防兵草草。及茲多事日，尤覺閒人好。", "我年過不惑，休退誠非早。從此拂塵衣，歸山未為老。"]'),
('yuding-37','題座隅','白居易','唐','御定全唐诗','yuding','','[]','手不任執殳，肩不能荷鋤。量力揆所用，曾不敵一夫。',156,'御定全唐詩/json/430.json','["手不任執殳，肩不能荷鋤。量力揆所用，曾不敵一夫。", "幸因筆硯功，得升仕進途。曆官凡五六，祿俸及妻孥。", "左右有兼僕，出入有單車。自奉雖不厚，亦不至饑劬。", "若有人及此，傍觀為何如。雖賢亦為幸，況我鄙且愚。", "伯夷古賢人，魯山亦其徒。時哉無奈何，俱化為餓殍。", "念彼益自愧，不敢忘斯須。平生榮利心，破滅無遺餘。", "猶恐塵妄起，題此於座隅。"]'),
('yuding-38','昔與微之在朝日同蓄休退之心迨今十年淪落老大追尋前約且結後期','白居易','唐','御定全唐诗','yuding','','[]','往子為禦史，伊餘忝拾遺。皆逢盛明代，俱登清近司。',156,'御定全唐詩/json/430.json','["往子為禦史，伊餘忝拾遺。皆逢盛明代，俱登清近司。", "予系玉為佩，子曳繡為衣。從容香煙下，同侍白玉墀。", "朝見寵者辱，暮見安者危。紛紛無退者，相顧令人悲。", "宦情君早厭，世事我深知。常于榮顯日，已約林泉期。", "況今各流落，身病齒發衰。不作臥雲計，攜手欲何之。", "待君女嫁後，及我官滿時。稍無骨肉累，粗有漁樵資。", "歲晚青山路，白首期同歸。"]'),
('yuding-39','垂釣','白居易','唐','御定全唐诗','yuding','','[]','臨水一長嘯，忽思十年初。三登甲乙第，一入承明廬。',48,'御定全唐詩/json/430.json','["臨水一長嘯，忽思十年初。三登甲乙第，一入承明廬。", "浮生多變化，外事有盈虛。今來伴江叟，沙頭坐釣魚。"]'),
('yuding-40','晚燕','白居易','唐','御定全唐诗','yuding','','[]','百鳥乳雛畢，秋燕獨蹉跎。去社日已近，銜泥意如何。',48,'御定全唐詩/json/430.json','["百鳥乳雛畢，秋燕獨蹉跎。去社日已近，銜泥意如何。", "不悟時節晚，徒施工用多。人間事亦爾，不獨燕營窠。"]'),
('yuding-41','贖雞','白居易','唐','御定全唐诗','yuding','','[]','清晨臨江望，水禽正喧繁。鳧雁與鷗鷺，遊颺戲朝暾。',156,'御定全唐詩/json/430.json','["清晨臨江望，水禽正喧繁。鳧雁與鷗鷺，遊颺戲朝暾。", "適有鬻雞者，挈之來遠村。飛鳴彼何樂，窘束此何冤。", "喔喔十四雛，罩縛同一樊。足傷金距縮，頭搶花冠翻。", "經宿廢飲啄，日高詣屠門。遲回未死間，饑渴欲相吞。", "常慕古人道，仁信及魚豚。見茲生惻隱，贖放雙林園。", "開籠解索時，雞雞聽我言。與爾鏹三百，小惠何足論。", "莫學銜環雀，崎嶇謾報恩。"]'),
('yuding-42','秋日懷杓直','白居易','唐','御定全唐诗','yuding','','[]','晚來天色好，獨出江邊步。憶與李舍人，曲江相近住。',144,'御定全唐詩/json/430.json','["晚來天色好，獨出江邊步。憶與李舍人，曲江相近住。", "常雲遇清景，必約同幽趣。若不訪我來，還須覓君去。", "開眉笑相見，把手期何處。西寺老胡僧，南園亂松樹。", "攜持小酒榼，吟詠新詩句。同出複同歸，從朝直至暮。", "風雨忽消散，江山眇回互。潯陽與涔陽，相望空雲霧。", "心期自乖曠，時景還如故。今日郡齋中，秋光誰共度。"]'),
('yuding-43','食後','白居易','唐','御定全唐诗','yuding','','[]','食罷一覺睡，起來兩甌茶。舉頭看日影，已複西南斜。',48,'御定全唐詩/json/430.json','["食罷一覺睡，起來兩甌茶。舉頭看日影，已複西南斜。", "樂人惜日促，憂人厭年賒。無憂無樂者，長短任生涯。"]'),
('yuding-44','齊物二首','白居易','唐','御定全唐诗','yuding','','[]','青松高百尺，綠蕙低數寸。同生大塊間，長短各有分。',96,'御定全唐詩/json/430.json','["青松高百尺，綠蕙低數寸。同生大塊間，長短各有分。", "長者不可退，短者不可進。若用此理推，窮通兩無悶。", "椿壽八千春，槿花不經宿。中間複何有，冉冉孤生竹。", "竹身三年老，竹色四時綠。雖謝椿有餘，猶勝槿不足。"]'),
('yuding-45','山下宿','白居易','唐','御定全唐诗','yuding','','[]','獨到山下宿，靜向月中行。何處水邊碓，夜舂雲母聲。',24,'御定全唐詩/json/430.json','["獨到山下宿，靜向月中行。何處水邊碓，夜舂雲母聲。"]'),
('yuding-46','題舊寫真圖','白居易','唐','御定全唐诗','yuding','','[]','我昔三十六，寫貌在丹青。我今四十六，衰悴臥江城。',108,'御定全唐詩/json/430.json','["我昔三十六，寫貌在丹青。我今四十六，衰悴臥江城。", "豈比十年老，曾與眾苦並。一照舊圖畫，無複昔儀形。", "形影默相顧，如弟對老兄。況使他人見，能不昧平生。", "羲和鞭日走，不為我少停。形骸屬日月，老去何足驚。", "所恨淩煙閣，不得畫功名。"]'),
('yuding-47','閒居','白居易','唐','御定全唐诗','yuding','','[]','肺病不飲酒，眼昏不讀書。端然無所作，身意閑有餘。',48,'御定全唐詩/json/430.json','["肺病不飲酒，眼昏不讀書。端然無所作，身意閑有餘。", "雞棲籬落晚，雪映林木疏。幽獨已雲極，何必山中居。"]'),
('yuding-48','對酒示行簡','白居易','唐','御定全唐诗','yuding','','[]','今旦一尊酒，歡暢何怡怡。此樂從中來，他人安得知。',156,'御定全唐詩/json/430.json','["今旦一尊酒，歡暢何怡怡。此樂從中來，他人安得知。", "兄弟唯二人，遠別恒苦悲。今春自巴峽，萬里平安歸。", "複有雙幼妹，笄年未結褵。昨日嫁娶畢，良人皆可依。", "憂念兩消釋，如刀斷羈縻。身輕心無系，忽欲淩空飛。", "人生苟有累，食肉常如饑。我心既無苦，飲水亦可肥。", "行簡勸爾酒，停杯聽我辭。不歎鄉國遠，不嫌官祿微。", "但願我與爾，終老不相離。"]'),
('yuding-49','詠懷','白居易','唐','御定全唐诗','yuding','','[]','冉牛與顏淵，卞和與馬遷。或罹天六極，或被人刑殘。',144,'御定全唐詩/json/430.json','["冉牛與顏淵，卞和與馬遷。或罹天六極，或被人刑殘。", "顧我信為幸，百骸且完全。五十不為夭，吾今欠數年。", "知分心自足，委順身常安。故雖窮退日，而無戚戚顏。", "昔有榮先生，從事于其間。今我不量力，舉心欲攀援。", "窮通不由己，歡戚不由天。命即無奈何，心可使泰然。", "且務由己者，省躬諒非難。勿問由天者，天高難與言。"]'),
('yuding-50','夜琴','白居易','唐','御定全唐诗','yuding','','[]','蜀桐木性實，楚絲音韻清。調慢彈且緩，夜深十數聲。',48,'御定全唐詩/json/430.json','["蜀桐木性實，楚絲音韻清。調慢彈且緩，夜深十數聲。", "入耳澹無味，愜心潛有情。自弄還自罷，亦不要人聽。"]'),
('yuding-51','山中獨吟','白居易','唐','御定全唐诗','yuding','','[]','人各有一癖，我癖在章句。萬緣皆已消，此病獨未去。',108,'御定全唐詩/json/430.json','["人各有一癖，我癖在章句。萬緣皆已消，此病獨未去。", "每逢美風景，或對好親故。高聲詠一篇，恍若與神遇。", "自為江上客，半在山中住。有時新詩成，獨上東岩路。", "身倚白石崖，手攀青桂樹。狂吟驚林壑，猿鳥皆窺覷。", "恐為世所嗤，故就無人處。"]'),
('yuding-52','達理二首','白居易','唐','御定全唐诗','yuding','','[]','何物壯不老，何時窮不通。如彼音與律，宛轉旋為宮。',192,'御定全唐詩/json/430.json','["何物壯不老，何時窮不通。如彼音與律，宛轉旋為宮。", "我命獨何薄，多悴而少豐。當壯已先衰，暫泰還長窮。", "我無奈命何，委順以待終。命無奈我何，方寸如虛空。", "懵然與化俱，混然與俗同。誰能坐自苦，齟齬於其中。", "舒姑化為泉，牛哀病作虎。或柳生肘間，或男變為女。", "鳥獸及水木，本不與民伍。胡然生變遷，不待死歸土。", "百骸是己物，尚不能為主。況彼時命間，倚伏何足數。", "時來不可遏，命去焉能取。唯當養浩然，吾聞達人語。"]'),
('yuding-53','湖亭晚望殘水','白居易','唐','御定全唐诗','yuding','','[]','湖上秋泬寥，湖邊晚蕭瑟。登亭望湖水，水縮湖底出。',108,'御定全唐詩/json/430.json','["湖上秋泬寥，湖邊晚蕭瑟。登亭望湖水，水縮湖底出。", "清渟得早霜，明滅浮殘日。流注隨地勢，窪坳無定質。", "泓澄白龍臥，宛轉青蛇屈。破鏡折劍頭，光芒又非一。", "久為山水客，見盡幽奇物。及來湖亭望，此狀難談悉。", "乃知天地間，勝事殊未畢。"]'),
('yuding-54','郭虛舟相訪','白居易','唐','御定全唐诗','yuding','','[]','朝暖就南軒，暮寒歸後屋。晚酒一兩杯，夜棋三數局。',48,'御定全唐詩/json/430.json','["朝暖就南軒，暮寒歸後屋。晚酒一兩杯，夜棋三數局。", "寒灰埋暗火，曉焰凝殘燭。不嫌貧冷人，時來同一宿。"]'),
('yuding-0','長慶二年七月自中書舍人出守杭州，路次藍溪作','白居易','唐','御定全唐诗','yuding','','[]','太原一男子，自顧庸且鄙。老逢不次恩，洗拔出泥滓。',240,'御定全唐詩/json/431.json','["太原一男子，自顧庸且鄙。老逢不次恩，洗拔出泥滓。", "既居可言地，願助朝廷理。伏閣三上章，戇愚不稱旨。", "聖人存大體，優貸容不死。鳳詔停舍人，魚書除刺史。", "冥懷齊寵辱，委順隨行止。我自得此心，於茲十年矣。", "餘杭乃名郡，郡郭臨江汜。已想海門山，潮聲來入耳。", "昔予貞元末，羈旅曾遊此。甚覺太守尊，亦諳魚酒美。", "因生江海興，每羨滄浪水。尚擬拂衣行，況今兼祿仕。", "青山峰巒接，白日煙塵起。東道既不通，改轅遂南指。", "自秦窮楚越，浩蕩五千里。聞有賢主人，而多好山水。", "是行頗為愜，所曆良可紀。策馬度藍溪，勝遊從此始。"]'),
('yuding-1','初出城留別','白居易','唐','御定全唐诗','yuding','','[]','朝從紫禁歸，暮出青門去。勿言城東陌，便是江南路。',48,'御定全唐詩/json/431.json','["朝從紫禁歸，暮出青門去。勿言城東陌，便是江南路。", "揚鞭簇車馬，揮手辭親故。我生本無鄉，心安是歸處。"]'),
('yuding-2','過駱山人野居小池','白居易','唐','御定全唐诗','yuding','','[]','茅覆環堵亭，泉添方丈沼。紅芳照水荷，白頸觀魚鳥。',96,'御定全唐詩/json/431.json','["茅覆環堵亭，泉添方丈沼。紅芳照水荷，白頸觀魚鳥。", "拳石苔蒼翠，尺波煙杳渺。但問有意無，勿論池大小。", "門前車馬路，奔走無昏曉。名利驅人心，賢愚同擾擾。", "善哉駱處士，安置身心了。何乃獨多君，丘園居者少。"]'),
('yuding-3','宿清源寺','白居易','唐','御定全唐诗','yuding','','[]','往謫潯陽去，夜憩輞溪曲。今為錢塘行，重經茲寺宿。',84,'御定全唐詩/json/431.json','["往謫潯陽去，夜憩輞溪曲。今為錢塘行，重經茲寺宿。", "爾來幾何歲，溪草二八綠。不見舊房僧，蒼然新樹木。", "虛空走日月，世界遷陵穀。我生寄其間，孰能逃倚伏。", "隨緣又南去，好住東廊竹。"]'),
('yuding-4','宿藍溪對月','白居易','唐','御定全唐诗','yuding','','[]','昨夜鳳池頭，今夜藍溪口。明月本無心，行人自回首。',48,'御定全唐詩/json/431.json','["昨夜鳳池頭，今夜藍溪口。明月本無心，行人自回首。", "新秋松影下，半夜鐘聲後。清影不宜昏，聊將茶代酒。"]'),
('yuding-5','自秦望赴五松驛，馬上偶睡，睡覺成吟','白居易','唐','御定全唐诗','yuding','','[]','長途發已久，前館行未至。體倦目已昏，瞌然遂成睡。',84,'御定全唐詩/json/431.json','["長途發已久，前館行未至。體倦目已昏，瞌然遂成睡。", "右袂尚垂鞭，左手暫委轡。忽覺問僕夫，才行百步地。", "形神分處所，遲速相乖異。馬上幾多時，夢中無限事。", "誠哉達人語，百齡同一寐。"]'),
('yuding-6','鄧州路中作','白居易','唐','御定全唐诗','yuding','','[]','蕭蕭誰家村，秋梨葉半坼。漠漠誰家園，秋韭花初白。',72,'御定全唐詩/json/431.json','["蕭蕭誰家村，秋梨葉半坼。漠漠誰家園，秋韭花初白。", "路逢故里物，使我嗟行役。不歸渭北村，又作江南客。", "去鄉徒自苦，濟世終無益。自問波上萍，何如澗中石。"]'),
('yuding-7','朱藤杖紫驄吟','白居易','唐','御定全唐诗','yuding','','[]','拄上山之上，騎下山之下。江州去日朱藤杖，',20,'御定全唐詩/json/431.json','["拄上山之上，騎下山之下。江州去日朱藤杖，"]'),
('yuding-8','桐樹館重題','白居易','唐','御定全唐诗','yuding','','[]','階前下馬時，梁上題詩處。慘澹病使君，蕭疏老松樹。',36,'御定全唐詩/json/431.json','["階前下馬時，梁上題詩處。慘澹病使君，蕭疏老松樹。", "自嗟還自哂，又向杭州去。"]'),
('yuding-9','過紫霞蘭若','白居易','唐','御定全唐诗','yuding','','[]','我愛此山頭，及此三登曆。紫霞舊精舍，寥落空泉石。',48,'御定全唐詩/json/431.json','["我愛此山頭，及此三登曆。紫霞舊精舍，寥落空泉石。", "朝市日喧隘，雲林長悄寂。猶存住寺僧，肯有歸山客。"]'),
('yuding-10','感舊紗帽','白居易','唐','御定全唐诗','yuding','','[]','昔君烏紗帽，贈我白頭翁。帽今在頂上，君已歸泉中。',48,'御定全唐詩/json/431.json','["昔君烏紗帽，贈我白頭翁。帽今在頂上，君已歸泉中。", "物故猶堪用，人亡不可逢。岐山今夜月，墳樹正秋風。"]'),
('yuding-11','思竹窗','白居易','唐','御定全唐诗','yuding','','[]','不憶西省松，不憶南宮菊。惟憶新昌堂，蕭蕭北窗竹。',36,'御定全唐詩/json/431.json','["不憶西省松，不憶南宮菊。惟憶新昌堂，蕭蕭北窗竹。", "窗間枕簟在，來後何人宿。"]'),
('yuding-12','馬上作','白居易','唐','御定全唐诗','yuding','','[]','處世非不遇，榮身頗有餘。勳為上柱國，爵乃朝大夫。',240,'御定全唐詩/json/431.json','["處世非不遇，榮身頗有餘。勳為上柱國，爵乃朝大夫。", "自問有何才，兩入承明廬。又問有何政，再駕朱輪車。", "矧予東山人，自惟樸且疏。彈琴複有酒，且慕嵇阮徒。", "暗被鄉里薦，誤上賢能書。一列朝士籍，遂為世網拘。", "高有罾繳憂，下有陷阱虞。每覺宇宙窄，未嘗心體舒。", "蹉跎二十年，頷下生白須。何言左遷去，尚獲專城居。", "杭州五千里，往若投淵魚。雖未脫簪組，且來泛江湖。", "吳中多詩人，亦不少酒酤。高聲詠篇什，大笑飛杯盂。", "五十未全老，尚可且歡娛。用茲送日月，君以為何如。", "秋風起江上，白日落路隅。回首語五馬，去矣勿踟躕。"]'),
('yuding-13','秋蝶','白居易','唐','御定全唐诗','yuding','','[]','秋花紫濛濛，秋蝶黃茸茸。花低蝶新小，飛戲叢西東。',72,'御定全唐詩/json/431.json','["秋花紫濛濛，秋蝶黃茸茸。花低蝶新小，飛戲叢西東。", "日暮涼風來，紛紛花落叢。夜深白露冷，蝶已死叢中。", "朝生夕俱死，氣類各相從。不見千年鶴，多棲百丈松。"]'),
('yuding-14','登商山最高頂','白居易','唐','御定全唐诗','yuding','','[]','高高此山頂，四望唯煙雲。下有一條路，通達楚與秦。',72,'御定全唐詩/json/431.json','["高高此山頂，四望唯煙雲。下有一條路，通達楚與秦。", "或名誘其心，或利牽其身。乘者及負者，來去何云云。", "我亦斯人徒，未能出囂塵。七年三往復，何得笑他人。"]'),
('yuding-15','枯桑','白居易','唐','御定全唐诗','yuding','','[]','道傍老枯樹，枯來非一朝。皮黃外尚活，心黑中先焦。',36,'御定全唐詩/json/431.json','["道傍老枯樹，枯來非一朝。皮黃外尚活，心黑中先焦。", "有似多憂者，非因外火燒。"]'),
('yuding-16','山路偶興','白居易','唐','御定全唐诗','yuding','','[]','筋力未全衰，僕馬不至弱。又多山水趣，心賞非寂寞。',96,'御定全唐詩/json/431.json','["筋力未全衰，僕馬不至弱。又多山水趣，心賞非寂寞。", "捫蘿上煙嶺，蹋石穿雲壑。穀鳥晚仍啼，洞花秋不落。", "提籠複攜榼，遇勝時停泊。泉憩茶數甌，嵐行酒一酌。", "獨吟還獨嘯，此興殊未惡。假使在城時，終年有何樂。"]'),
('yuding-17','山雉','白居易','唐','御定全唐诗','yuding','','[]','五步一啄草，十步一飲水。適性遂其生，時哉山梁雉。',72,'御定全唐詩/json/431.json','["五步一啄草，十步一飲水。適性遂其生，時哉山梁雉。", "梁上無罾繳，梁下無鷹鸇。雌雄與群雛，皆得終天年。", "嗟嗟籠下雞，及彼池中雁。既有稻粱恩，必有犧牲患。"]'),
('yuding-18','初下漢江舟中作，寄兩省給舍','白居易','唐','御定全唐诗','yuding','','[]','秋水淅紅粒，朝煙烹白鱗。一食飽至夜，一臥安達晨。',96,'御定全唐詩/json/431.json','["秋水淅紅粒，朝煙烹白鱗。一食飽至夜，一臥安達晨。", "晨無朝謁勞，夜無直宿勤。不知兩掖客，何似扁舟人。", "尚想到郡日，且稱守土臣。猶須副憂寄，恤隱安疲民。", "期年庶報政，三年當退身。終使滄浪水，濯吾纓上塵。"]'),
('yuding-19','自蜀江至洞庭湖口有感而作','白居易','唐','御定全唐诗','yuding','','[]','江從西南來，浩浩無旦夕。長波逐若瀉，連山鑿如劈。',264,'御定全唐詩/json/431.json','["江從西南來，浩浩無旦夕。長波逐若瀉，連山鑿如劈。", "千年不壅潰，萬姓無墊溺。不爾民為魚，大哉禹之績。", "導岷既艱遠，距海無咫尺。胡為不訖功，餘水斯委積。", "洞庭與青草，大小兩相敵。混合萬丈深，淼茫千里白。", "每歲秋夏時，浩大吞七澤。水族窟穴多，農人土地窄。", "我今尚嗟歎，禹豈不愛惜。邈未究其由，想古觀遺跡。", "疑此苗人頑，恃險不終役。帝亦無奈何，留患與今昔。", "水流天地內，如身有血脈。滯則為疽疣，治之在針石。", "安得禹複生，為唐水官伯。手提倚天劍，重來親指畫。", "疏河似翦紙，決壅同裂帛。滲作膏腴田，蹋平魚鱉宅。", "龍宮變閭裏，水府生禾麥。坐添百萬戶，書我司徒籍。"]'),
('yuding-20','初領郡政衙退登東樓作','白居易','唐','御定全唐诗','yuding','','[]','鰥煢心所念，簡牘手自操。何言符竹貴，未免州縣勞。',96,'御定全唐詩/json/431.json','["鰥煢心所念，簡牘手自操。何言符竹貴，未免州縣勞。", "賴是餘杭郡，台榭繞官曹。淩晨親政事，向晚恣遊遨。", "山冷微有雪，波平未生濤。水心如鏡面，千里無纖毫。", "直下江最闊，近東樓更高。煩襟與滯念，一望皆遁逃。"]'),
('yuding-21','清調吟','白居易','唐','御定全唐诗','yuding','','[]','索索風戒寒，沉沉日藏耀。勸君飲濁醪，聽我吟清調。',72,'御定全唐詩/json/431.json','["索索風戒寒，沉沉日藏耀。勸君飲濁醪，聽我吟清調。", "芳節變窮陰，朝光成夕照。與君生此世，不合長年少。", "今晨從此過，明日安能料。若不結跏禪，即須開口笑。"]'),
('yuding-22','狂歌詞','白居易','唐','御定全唐诗','yuding','','[]','明月照君席，白露沾我衣。勸君酒杯滿，聽我狂歌詞。',72,'御定全唐詩/json/431.json','["明月照君席，白露沾我衣。勸君酒杯滿，聽我狂歌詞。", "五十已後衰，二十已前癡。晝夜又分半，其間幾何時。", "生前不歡樂，死後有餘貲。焉用黃墟下，珠衾玉匣為。"]'),
('yuding-23','郡亭','白居易','唐','御定全唐诗','yuding','','[]','平旦起視事，亭午臥掩關。除親簿領外，多在琴書前。',96,'御定全唐詩/json/431.json','["平旦起視事，亭午臥掩關。除親簿領外，多在琴書前。", "況有虛白亭，坐見海門山。潮來一憑檻，賓至一開筵。", "終朝對雲水，有時聽管弦。持此聊過日，非忙亦非閑。", "山林太寂寞，朝闕空喧煩。唯茲郡閣內，囂靜得中間。"]'),
('yuding-24','詠懷','白居易','唐','御定全唐诗','yuding','','[]','昔為鳳閣郎，今為二千石。自覺不如今，人言不如昔。',120,'御定全唐詩/json/431.json','["昔為鳳閣郎，今為二千石。自覺不如今，人言不如昔。", "昔雖居近密，終日多憂惕。有詩不敢吟，有酒不敢吃。", "今雖在疏遠，竟歲無牽役。飽食坐終朝，長歌醉通夕。", "人生百年內，疾速如過隙。先務身安閒，次要心歡適。", "事有得而失，物有損而益。所以見道人，觀心不觀跡。"]'),
('yuding-25','立春後五日','白居易','唐','御定全唐诗','yuding','','[]','立春後五日，春態紛婀娜。白日斜漸長，碧雲低欲墮。',72,'御定全唐詩/json/431.json','["立春後五日，春態紛婀娜。白日斜漸長，碧雲低欲墮。", "殘冰坼玉片，新萼排紅顆。遇物盡欣欣，愛春非獨我。", "迎芳後園立，就暖前簷坐。還有惆悵心，欲別紅爐火。"]'),
('yuding-26','郡中即事','白居易','唐','御定全唐诗','yuding','','[]','漫漫潮初平，熙熙春日至。空闊遠江山，晴明好天氣。',120,'御定全唐詩/json/431.json','["漫漫潮初平，熙熙春日至。空闊遠江山，晴明好天氣。", "外有適意物，中無系心事。數篇對竹吟，一杯望雲醉。", "行攜杖扶力，臥讀書取睡。久養病形骸，深諳閒氣味。", "遙思九城陌，擾擾趨名利。今朝是雙日，朝謁多軒騎。", "寵者防悔尤，權者懷憂畏。為報高車蓋，恐非真富貴。"]'),
('yuding-27','郡齋暇日辱常州陳郎中使君早春晚坐水西館書事詩十六韻見寄亦以十六韻酬之','白居易','唐','御定全唐诗','yuding','','[]','新年多暇日，晏起褰簾坐。睡足心更慵，日高頭未裹。',192,'御定全唐詩/json/431.json','["新年多暇日，晏起褰簾坐。睡足心更慵，日高頭未裹。", "徐傾下藥酒，稍爇煎茶火。誰伴寂寥身，無弦琴在左。", "遙思毗陵館，春深物嫋娜。波拂黃柳梢，風搖白梅朵。", "衙門排曉戟，鈴閣開朝鎖。太守水西來，朱衣垂素舸。", "良辰不易得，佳會無由果。五馬正相望，雙魚忽前墮。", "魚中獲瑰寶，持玩何磊砢。一百六十言，字字靈珠顆。", "上申心款曲，下敘時坎坷。才富不如君，道孤還似我。", "敢辭官遠慢，且貴身安妥。忽複問榮枯，冥心無不可。"]'),
('yuding-28','官舍','白居易','唐','御定全唐诗','yuding','','[]','高樹換新葉，陰陰覆地隅。何言太守宅，有似幽人居。',108,'御定全唐詩/json/431.json','["高樹換新葉，陰陰覆地隅。何言太守宅，有似幽人居。", "太守臥其下，閑慵兩有餘。起嘗一甌茗，行讀一卷書。", "早梅結青實，殘櫻落紅珠。稚女弄庭果，嬉戲牽人裾。", "是日晚彌靜，巢禽下相呼。嘖嘖護兒鵲，啞啞母子烏。", "豈唯雲鳥爾，吾亦引吾雛。"]'),
('yuding-29','吾雛','白居易','唐','御定全唐诗','yuding','','[]','吾雛字阿羅，阿羅才七齡。嗟吾不才子，憐爾無弟兄。',120,'御定全唐詩/json/431.json','["吾雛字阿羅，阿羅才七齡。嗟吾不才子，憐爾無弟兄。", "撫養雖驕騃，性識頗聰明。學母畫眉樣，效吾詠詩聲。", "我齒今欲墮，汝齒昨始生。我頭髮盡落，汝頂髻初成。", "老幼不相待，父衰汝孩嬰。緬想古人心，慈愛亦不輕。", "蔡邕念文姬，於公歎緹縈。敢求得汝力，但未忘父情。"]'),
('yuding-30','題小橋前新竹招客','白居易','唐','御定全唐诗','yuding','','[]','雁齒小紅橋，垂簷低白屋。橋前何所有，苒苒新生竹。',96,'御定全唐詩/json/431.json','["雁齒小紅橋，垂簷低白屋。橋前何所有，苒苒新生竹。", "皮開坼褐錦，節露抽青玉。筠翠如可餐，粉霜不忍觸。", "閑吟聲未已，幽玩心難足。管領好風煙，輕欺凡草木。", "誰能有月夜，伴我林中宿。為君傾一杯，狂歌竹枝曲。"]'),
('yuding-31','病中逢秋，招客夜酌','白居易','唐','御定全唐诗','yuding','','[]','不見詩酒客，臥來半月餘。合和新藥草，尋檢舊方書。',72,'御定全唐詩/json/431.json','["不見詩酒客，臥來半月餘。合和新藥草，尋檢舊方書。", "晚霽煙景度，早涼窗戶虛。雪生衰鬢久，秋入病心初。", "臥簟蘄竹冷，風襟邛葛疏。夜來身校健，小飲複何如。"]'),
('yuding-32','食飽','白居易','唐','御定全唐诗','yuding','','[]','食飽拂枕臥，睡足起閑吟。淺酌一杯酒，緩彈數弄琴。',48,'御定全唐詩/json/431.json','["食飽拂枕臥，睡足起閑吟。淺酌一杯酒，緩彈數弄琴。", "既可暢情性，亦足傲光陰。誰知利名盡，無複長安心。"]'),
('yuding-33','嚴十八郎中在郡日改制東南樓因名清輝未立標榜徵歸郎署予既到郡性愛樓居宴遊其間頗有幽致聊成十韻兼戲寄嚴','白居易','唐','御定全唐诗','yuding','','[]','嚴郎置茲樓，立名曰清輝。未及署花榜，遽征還粉闈。',120,'御定全唐詩/json/431.json','["嚴郎置茲樓，立名曰清輝。未及署花榜，遽征還粉闈。", "去來三四年，塵土登者稀。今春新太守，灑掃施簾幃。", "院柳煙婀娜，簷花雪霏微。看山倚前戶，待月闡東扉。", "碧窗戛瑤瑟，朱欄飄舞衣。燒香卷幕坐，風燕雙雙飛。", "君作不得住，我來幸因依。始知天地間，靈境有所歸。"]'),
('yuding-34','南亭對酒送春','白居易','唐','御定全唐诗','yuding','','[]','含桃實已落，紅薇花尚熏。冉冉三月盡，晚鶯城上聞。',120,'御定全唐詩/json/431.json','["含桃實已落，紅薇花尚熏。冉冉三月盡，晚鶯城上聞。", "獨持一杯酒，南亭送殘春。半酣忽長歌，歌中何所雲。", "雲我五十餘，未是苦老人。刺史二千石，亦不為賤貧。", "天下三品官，多老於我身。同年登第者，零落無一分。", "親故半為鬼，僮僕多見孫。念此聊自解，逢酒且歡欣。"]'),
('yuding-35','玩新庭樹，因詠所懷','白居易','唐','御定全唐诗','yuding','','[]','靄靄四月初，新樹葉成陰。動搖風景麗，蓋覆庭院深。',96,'御定全唐詩/json/431.json','["靄靄四月初，新樹葉成陰。動搖風景麗，蓋覆庭院深。", "下有無事人，竟日此幽尋。豈惟玩時物，亦可開煩襟。", "時與道人語，或聽詩客吟。度春足芳色，入夜多鳴禽。", "偶得幽閒境，遂忘塵俗心。始知真隱者，不必在山林。"]'),
('yuding-36','仲夏齋戒月','白居易','唐','御定全唐诗','yuding','','[]','仲夏齋戒月，三旬斷腥膻。自覺心骨爽，行起身翩翩。',120,'御定全唐詩/json/431.json','["仲夏齋戒月，三旬斷腥膻。自覺心骨爽，行起身翩翩。", "始知絕粒人，四體更輕便。初能脫病患，久必成神仙。", "禦寇馭泠風，赤松遊紫煙。常疑此說謬，今乃知其然。", "我今過半百，氣衰神不全。已垂兩鬢絲，難補三丹田。", "但減葷血味，稍結清淨緣。脫巾且修養，聊以終天年。"]'),
('yuding-37','除官去未間','白居易','唐','御定全唐诗','yuding','','[]','除官去未間，半月恣遊討。朝尋霞外寺，暮宿波上島。',96,'御定全唐詩/json/431.json','["除官去未間，半月恣遊討。朝尋霞外寺，暮宿波上島。", "新樹少於松，平湖半連草。躋攀有次第，賞玩無昏早。", "有時騎馬醉，兀兀冥天造。窮通與生死，其奈吾懷抱。", "江山信為美，齒發行將老。在郡誠未厭，歸鄉去亦好。"]'),
('yuding-38','三年為刺史二首','白居易','唐','御定全唐诗','yuding','','[]','三年為刺史，無政在人口。唯向城郡中，題詩十餘首。',72,'御定全唐詩/json/431.json','["三年為刺史，無政在人口。唯向城郡中，題詩十餘首。", "慚非甘棠詠，豈有思人不。", "三年為刺史，飲冰複食檗。唯向天竺山，取得兩片石。", "此抵有千金，無乃傷清白。"]'),
('yuding-39','別萱桂','白居易','唐','御定全唐诗','yuding','','[]','使君竟不住，萱桂徒栽種。桂有留人名，萱無忘憂用。',36,'御定全唐詩/json/431.json','["使君竟不住，萱桂徒栽種。桂有留人名，萱無忘憂用。", "不如江畔月，步步來相送。"]'),
('yuding-40','自餘杭歸宿淮口作','白居易','唐','御定全唐诗','yuding','','[]','為郡已多暇，猶少勤吏職。罷郡更安閒，無所勞心力。',108,'御定全唐詩/json/431.json','["為郡已多暇，猶少勤吏職。罷郡更安閒，無所勞心力。", "舟行明月下，夜泊清淮北。豈止吾一身，舉家同燕息。", "三年請祿俸，頗有餘衣食。乃至僮僕間，皆無凍餒色。", "行行弄雲水，步步近鄉國。妻子在我前，琴書在我側。", "此外吾不知，於焉心自得。"]'),
('yuding-41','舟中李山人訪宿','白居易','唐','御定全唐诗','yuding','','[]','日暮舟悄悄，煙生水沉沉。何以延宿客，夜酒與秋琴。',72,'御定全唐詩/json/431.json','["日暮舟悄悄，煙生水沉沉。何以延宿客，夜酒與秋琴。", "來客道門子，來自嵩高岑。軒軒舉雲貌，豁豁開清襟。", "得意言語斷，入玄滋味深。默然相顧哂，心適而忘心。"]'),
('yuding-42','洛下卜居','白居易','唐','御定全唐诗','yuding','','[]','三年典郡歸，所得非金帛。天竺石兩片，華亭鶴一支。',144,'御定全唐詩/json/431.json','["三年典郡歸，所得非金帛。天竺石兩片，華亭鶴一支。", "飲啄供稻粱，包裹用茵席。誠知是勞費，其奈心愛惜。", "遠從餘杭郭，同到洛陽陌。下擔拂雲根，開籠展霜翮。", "貞姿不可雜，高性宜其適。遂就無塵坊，仍求有水宅。", "東南得幽境，樹老寒泉碧。池畔多竹陰，門前少人跡。", "未請中庶祿，且脫雙驂易。豈獨為身謀，安吾鶴與石。"]'),
('yuding-43','洛中偶作','白居易','唐','御定全唐诗','yuding','','[]','五年職翰林，四年蒞潯陽。一年巴郡守，半年南宮郎。',144,'御定全唐詩/json/431.json','["五年職翰林，四年蒞潯陽。一年巴郡守，半年南宮郎。", "二年直綸閣，三年刺史堂。凡此十五載，有詩千餘章。", "境興周萬象，土風備四方。獨無洛中作，能不心悢悢。", "今為青宮長，始來遊此鄉。裴回伊澗上，睥睨嵩少傍。", "遇物輒一詠，一詠傾一觴。筆下成釋憾，卷中同補亡。", "往往顧自哂，眼昏須鬢蒼。不知老將至，猶自放詩狂。"]'),
('yuding-44','贈蘇少府','白居易','唐','御定全唐诗','yuding','','[]','籍甚二十年，今日方款顏。相送嵩洛下，論心杯酒間。',72,'御定全唐詩/json/431.json','["籍甚二十年，今日方款顏。相送嵩洛下，論心杯酒間。", "河亞懶出入，府寮多閉關。蒼發彼此老，白日尋常閑。", "朝從攜手出，暮思聯騎還。何當挈一榼，同宿龍門山。"]'),
('yuding-45','移家入新宅','白居易','唐','御定全唐诗','yuding','','[]','移家入新宅，罷郡有餘貲。既可避燥濕，複免憂寒饑。',192,'御定全唐詩/json/431.json','["移家入新宅，罷郡有餘貲。既可避燥濕，複免憂寒饑。", "疾平未還假，官閑得分司。幸有俸祿在，而無職役羈。", "清旦盥漱畢，開軒捲簾幃。家人及雞犬，隨我亦熙熙。", "取興或寄酒，放情不過詩。何必苦修道，此即是無為。", "外累信已遣，中懷時有思。有思一何遠，默坐低雙眉。", "十載囚竄客，萬時征戍兒。春朝鎖籠鳥，冬夜支床龜。", "驛馬走四蹄，痛酸無歇期。磑牛封兩目，昏閉何人知。", "誰能脫放去，四散任所之。各得適其性，如吾今日時。"]'),
('yuding-46','琴','白居易','唐','御定全唐诗','yuding','','[]','置琴曲幾上，慵坐但含情。何煩故揮弄，風弦自有聲。',24,'御定全唐詩/json/431.json','["置琴曲幾上，慵坐但含情。何煩故揮弄，風弦自有聲。"]'),
('yuding-47','鶴','白居易','唐','御定全唐诗','yuding','','[]','人各有所好，物固無常宜。誰謂爾能舞，不如閑立時。',24,'御定全唐詩/json/431.json','["人各有所好，物固無常宜。誰謂爾能舞，不如閑立時。"]'),
('yuding-48','自詠','白居易','唐','御定全唐诗','yuding','','[]','夜鏡隱白髮，朝酒發紅顏。可憐假年少，自笑須臾間。',180,'御定全唐詩/json/431.json','["夜鏡隱白髮，朝酒發紅顏。可憐假年少，自笑須臾間。", "朱砂賤如土，不解燒為丹。玄鬢化為雪，未聞休得官。", "咄哉個丈夫，心性何墮頑。但遇詩與酒，便忘寢與餐。", "高聲發一吟，似得詩中仙。引滿飲一盞，盡忘身外緣。", "昔有醉先生，席地而幕天。於今居處在，許我當中眠。", "眠罷又一酌，酌罷又一篇。回面顧妻子，生計方落然。", "誠知此事非，又過知非年。豈不欲自改，改即心不安。", "且向安處去，其餘皆老閑。"]'),
('yuding-49','林下閒步，寄皇甫庶子','白居易','唐','御定全唐诗','yuding','','[]','扶杖起病初，策馬力未任。既懶出門去，亦無客來尋。',72,'御定全唐詩/json/431.json','["扶杖起病初，策馬力未任。既懶出門去，亦無客來尋。", "以此遂成閑，閒步繞園林。天曉煙景澹，樹寒鳥雀深。", "一酌池上酒，數聲竹間吟。寄言東曹長，當知幽獨心。"]'),
('yuding-50','晏起','白居易','唐','御定全唐诗','yuding','','[]','鳥鳴庭樹上，日照屋簷時。老去慵轉極，寒來起尤遲。',96,'御定全唐詩/json/431.json','["鳥鳴庭樹上，日照屋簷時。老去慵轉極，寒來起尤遲。", "厚薄被適性，高低枕得宜。神安體穩暖，此味何人知。", "睡足仰頭坐，兀然無所思。如未鑿七竅，若都遺四肢。", "緬想長安客，早朝霜滿衣。彼此各自適，不知誰是非。"]'),
('yuding-51','池畔二首','白居易','唐','御定全唐诗','yuding','','[]','結構池西廊，疏理池東樹。此意人不知，欲為待月處。',49,'御定全唐詩/json/431.json','["結構池西廊，疏理池東樹。此意人不知，欲為待月處。", "持刀gN密竹，竹少風來多。此意人不會，欲令池有波。"]'),
('yuding-52','春葺新居','白居易','唐','御定全唐诗','yuding','','[]','江州司馬日，忠州刺史時。栽松滿後院，種柳蔭前墀。',120,'御定全唐詩/json/431.json','["江州司馬日，忠州刺史時。栽松滿後院，種柳蔭前墀。", "彼皆非吾土，栽種尚忘疲。況茲是我宅，葺藝固其宜。", "平旦領僕使，乘春親指揮。移花夾暖室，徙竹覆寒池。", "池水變綠色，池芳動清輝。尋芳弄水坐，盡日心熙熙。", "一物苟可適，萬緣都若遺。設如宅門外，有事吾不知。"]'),
('yuding-53','贈言','白居易','唐','御定全唐诗','yuding','','[]','捧籝獻千金，彼金何足道。臨觴贈一言，此言真可寶。',84,'御定全唐詩/json/431.json','["捧籝獻千金，彼金何足道。臨觴贈一言，此言真可寶。", "流光我已晚，適意君不早。況君春風面，柔促如芳草。", "二十方長成，三十向衰老。鏡中桃李色，不得十年好。", "胡為坐脈脈，不肯傾懷抱。"]'),
('yuding-54','泛春池','白居易','唐','御定全唐诗','yuding','','[]','白蘋湘渚曲，綠筱剡溪口。各在天一涯，信美非吾有。',204,'御定全唐詩/json/431.json','["白蘋湘渚曲，綠筱剡溪口。各在天一涯，信美非吾有。", "何如此庭內，水竹交左右。霜竹百千竿，煙波六七畝。", "泓澄動階砌，澹濘映戶牖。蛇皮細有紋，鏡面清無垢。", "主人過橋來，雙童扶一叟。恐汙清泠波，塵纓先抖擻。", "波上一葉舟，舟中一尊酒。酒開舟不系，去去隨所偶。", "或繞蒲浦前，或泊桃島後。未撥落杯花，低沖拂面柳。", "半酣迷所在，倚榜兀回首。不知此何處，複是人寰否。", "誰知始疏鑿，幾主相傳受。楊家去雲遠，田氏將非久。", "天與愛水人，終焉落吾手。"]'),
('yuding-0','西明寺牡丹花時憶元九','白居易','唐','御定全唐诗','yuding','','[]','前年題名處，今日看花來。一作芸香吏，三見牡丹開。',60,'御定全唐詩/json/432.json','["前年題名處，今日看花來。一作芸香吏，三見牡丹開。", "豈獨花堪惜，方知老暗催。何況尋花伴，東都去未回。", "詎知紅芳側，春盡思悠哉。"]'),
('yuding-1','傷楊弘貞','白居易','唐','御定全唐诗','yuding','','[]','顏子昔短命，仲尼惜其賢。楊生亦好學，不幸複徒然。',36,'御定全唐詩/json/432.json','["顏子昔短命，仲尼惜其賢。楊生亦好學，不幸複徒然。", "誰識天地意，獨與龜鶴年。"]'),
('yuding-2','權攝昭應，早秋書事，寄元拾遺，兼呈李司錄','白居易','唐','御定全唐诗','yuding','','[]','夏閏秋候早，七月風騷騷。渭川煙景晚，驪山宮殿高。',96,'御定全唐詩/json/432.json','["夏閏秋候早，七月風騷騷。渭川煙景晚，驪山宮殿高。", "丹殿子司諫，赤縣我徒勞。相去半日程，不得同遊遨。", "到官來十日，覽鏡生二毛。可憐趨走吏，塵土滿青袍。", "郵傳擁兩驛，簿書堆六曹。為問綱紀掾，何必使鉛刀。"]'),
('yuding-3','新栽竹','白居易','唐','御定全唐诗','yuding','','[]','佐邑意不適，閉門秋草生。何以娛野性，種竹百餘莖。',84,'御定全唐詩/json/432.json','["佐邑意不適，閉門秋草生。何以娛野性，種竹百餘莖。", "見此溪上色，憶得山中情。有時公事暇，盡日繞欄行。", "勿言根未固，勿言陰未成。已覺庭宇內，稍稍有餘清。", "最愛近窗臥，秋風枝有聲。"]'),
('yuding-4','秋霖中過尹縱之仙游山居','白居易','唐','御定全唐诗','yuding','','[]','慘慘八月暮，連連三日霖。邑居尚愁寂，況乃在山林。',84,'御定全唐詩/json/432.json','["慘慘八月暮，連連三日霖。邑居尚愁寂，況乃在山林。", "林下有志士，苦學惜光陰。歲晚千萬慮，併入方寸心。", "岩鳥共旅宿，草蟲伴愁吟。秋天床席冷，夜雨燈火深。", "憐君寂寞意，攜酒一相尋。"]'),
('yuding-5','寄江南兄弟','白居易','唐','御定全唐诗','yuding','','[]','分散骨肉戀，趨馳名利牽。一奔塵埃馬，一泛風波船。',96,'御定全唐詩/json/432.json','["分散骨肉戀，趨馳名利牽。一奔塵埃馬，一泛風波船。", "忽憶分手時，憫默秋風前。別來朝複夕，積日成七年。", "花落城中池，春深江上天。登樓東南望，鳥滅煙蒼然。", "相去複幾許，道裏近三千。平地猶難見，況乃隔山川。"]'),
('yuding-6','曲江早秋','白居易','唐','御定全唐诗','yuding','','[]','秋波紅蓼水，夕照青蕪岸。獨信馬蹄行，曲江池四畔。',84,'御定全唐詩/json/432.json','["秋波紅蓼水，夕照青蕪岸。獨信馬蹄行，曲江池四畔。", "早涼晴後至，殘暑暝來散。方喜炎燠銷，複嗟時節換。", "我年三十六，冉冉昏復旦。人壽七十稀，七十新過半。", "且當對酒笑，勿起臨風歎。"]'),
('yuding-7','寄題盩厔廳前雙松','白居易','唐','御定全唐诗','yuding','','[]','憶昨為吏日，折腰多苦辛。歸家不自適，無計慰心神。',144,'御定全唐詩/json/432.json','["憶昨為吏日，折腰多苦辛。歸家不自適，無計慰心神。", "手栽兩樹松，聊以當嘉賓。乘春日一溉，生意漸欣欣。", "清韻度秋在，綠茸隨日新。始憐澗底色，不憶城中春。", "有時晝掩關，雙影對一身。盡日不寂寞，意中如三人。", "忽奉宣室詔，征為文苑臣。閑來一惆悵，恰似別交親。", "早知煙翠前，攀玩不逡巡。悔從白雲裏，移爾落囂塵。"]'),
('yuding-8','翰林院中感秋懷王質夫','白居易','唐','御定全唐诗','yuding','','[]','何處感時節，新蟬禁中聞。宮槐有秋意，風夕花紛紛。',60,'御定全唐詩/json/432.json','["何處感時節，新蟬禁中聞。宮槐有秋意，風夕花紛紛。", "寄跡鴛鷺行，歸心鷗鶴群。唯有王居士，知予憶白雲。", "何日仙遊寺，潭前秋見君。"]'),
('yuding-9','禁中月','白居易','唐','御定全唐诗','yuding','','[]','海水明月出，禁中清夜長。東南樓殿白，稍稍上宮牆。',48,'御定全唐詩/json/432.json','["海水明月出，禁中清夜長。東南樓殿白，稍稍上宮牆。", "淨落金塘水，明浮玉砌霜。不比人間見，塵土汙清光。"]'),
('yuding-10','贈賣松者','白居易','唐','御定全唐诗','yuding','','[]','一束蒼蒼色，知從澗底來。劚掘經幾日，枝葉滿塵埃。',36,'御定全唐詩/json/432.json','["一束蒼蒼色，知從澗底來。劚掘經幾日，枝葉滿塵埃。", "不買非他意，城中無地栽。"]'),
('yuding-11','初見白髮','白居易','唐','御定全唐诗','yuding','','[]','白髮生一莖，朝來明鏡裏。勿言一莖少，滿頭從此始。',48,'御定全唐詩/json/432.json','["白髮生一莖，朝來明鏡裏。勿言一莖少，滿頭從此始。", "青山方遠別，黃綬初從仕。未料容鬢間，蹉跎忽如此。"]'),
('yuding-12','別元九後詠所懷','白居易','唐','御定全唐诗','yuding','','[]','零落桐葉雨，蕭條槿花風。悠悠早秋意，生此幽閒中。',72,'御定全唐詩/json/432.json','["零落桐葉雨，蕭條槿花風。悠悠早秋意，生此幽閒中。", "況與故人別，中懷正無悰。勿雲不相送，心到青門東。", "相知豈在多，但問同不同。同心一人去，坐覺長安空。"]'),
('yuding-13','禁中秋宿','白居易','唐','御定全唐诗','yuding','','[]','風翻朱裏幕，雨冷通中枕。耿耿背斜燈，秋床一人寢。',24,'御定全唐詩/json/432.json','["風翻朱裏幕，雨冷通中枕。耿耿背斜燈，秋床一人寢。"]'),
('yuding-14','早秋曲江感懷','白居易','唐','御定全唐诗','yuding','','[]','離離暑雲散，嫋嫋涼風起。池上秋又來，荷花半成子。',72,'御定全唐詩/json/432.json','["離離暑雲散，嫋嫋涼風起。池上秋又來，荷花半成子。", "朱顏易銷歇，白日無窮已。人壽不如山，年光忽于水。", "青蕪與紅蓼，歲歲秋相似。去歲此悲秋，今秋複來此。"]'),
('yuding-15','寄元九','白居易','唐','御定全唐诗','yuding','','[]','身為近密拘，心為名檢縛。月夜與花時，少逢杯酒樂。',120,'御定全唐詩/json/432.json','["身為近密拘，心為名檢縛。月夜與花時，少逢杯酒樂。", "唯有元夫子，閑來同一酌。把手或酣歌，展眉時笑謔。", "今春除禦史，前月之東洛。別來未開顏，塵埃滿尊杓。", "蕙風晚香盡，槐雨餘花落。秋意一蕭條，離容兩寂寞。", "況隨白日老，共負青山約。誰識相念心，鞲鷹與籠鶴。"]'),
('yuding-16','暮春寄元九','白居易','唐','御定全唐诗','yuding','','[]','梨花結成實，燕卵化為雛。時物又若此，道情複何如。',72,'御定全唐詩/json/432.json','["梨花結成實，燕卵化為雛。時物又若此，道情複何如。", "但覺日月促，不嗟年歲徂。浮生都是夢，老小亦何殊。", "唯與故人別，江陵初謫居。時時一相見，此意未全除。"]'),
('yuding-17','早梳頭','白居易','唐','御定全唐诗','yuding','','[]','夜沐早梳頭，窗明秋鏡曉。颯然握中發，一沐知一少。',60,'御定全唐詩/json/432.json','["夜沐早梳頭，窗明秋鏡曉。颯然握中發，一沐知一少。", "年事漸蹉跎，世緣方繳繞。不學空門法，老病何由了。", "未得無生心，白頭亦為夭。"]'),
('yuding-18','出關路','白居易','唐','御定全唐诗','yuding','','[]','山川函谷路，塵土遊子顏。蕭條去國意，秋風生故關。',24,'御定全唐詩/json/432.json','["山川函谷路，塵土遊子顏。蕭條去國意，秋風生故關。"]'),
('yuding-19','別舍弟後月夜','白居易','唐','御定全唐诗','yuding','','[]','悄悄初別夜，去住兩盤桓。行子孤燈店，居人明月軒。',72,'御定全唐詩/json/432.json','["悄悄初別夜，去住兩盤桓。行子孤燈店，居人明月軒。", "平生共貧苦，未必日成歡。及此暫為別，懷抱已憂煩。", "況是庭葉盡，複思山路寒。如何為不念，馬瘦衣裳單。"]'),
('yuding-20','新豐路逢故人','白居易','唐','御定全唐诗','yuding','','[]','塵土長路晚，風煙廢宮秋。相逢立馬語，盡日此橋頭。',48,'御定全唐詩/json/432.json','["塵土長路晚，風煙廢宮秋。相逢立馬語，盡日此橋頭。", "知君不得意，鬱鬱來西遊。惆悵新豐店，何人識馬周。"]'),
('yuding-21','金鑾子晬日','白居易','唐','御定全唐诗','yuding','','[]','行年欲四十，有女曰金鑾。生來始周歲，學坐未能言。',72,'御定全唐詩/json/432.json','["行年欲四十，有女曰金鑾。生來始周歲，學坐未能言。", "慚非達者懷，未免俗情憐。從此累身外，徒雲慰目前。", "若無夭折患，則有婚嫁牽。使我歸山計，應遲十五年。"]'),
('yuding-22','青龍寺早夏','白居易','唐','御定全唐诗','yuding','','[]','塵埃經小雨，地高倚長坡。日西寺門外，景氣含清和。',96,'御定全唐詩/json/432.json','["塵埃經小雨，地高倚長坡。日西寺門外，景氣含清和。", "閑有老僧立，靜無凡客過。殘鶯意思盡，新葉陰涼多。", "春去來幾日，夏雲忽嵯峨。朝朝感時節，年鬢暗蹉跎。", "胡為戀朝市，不去歸煙蘿。青山寸步地，自問心如何。"]'),
('yuding-23','秋題牡丹叢','白居易','唐','御定全唐诗','yuding','','[]','晚叢白露夕，衰葉涼風朝。紅豔久已歇，碧芳今亦銷。',36,'御定全唐詩/json/432.json','["晚叢白露夕，衰葉涼風朝。紅豔久已歇，碧芳今亦銷。", "幽人坐相對，心事共蕭條。"]'),
('yuding-24','勸酒寄元九','白居易','唐','御定全唐诗','yuding','','[]','薤葉有朝露，槿枝無宿花。君今亦如此，促促生有涯。',156,'御定全唐詩/json/432.json','["薤葉有朝露，槿枝無宿花。君今亦如此，促促生有涯。", "既不逐禪僧，林下學楞伽。又不隨道士，山中煉丹砂。", "百年夜分半，一歲春無多。何不飲美酒，胡然自悲嗟。", "俗號銷愁藥，神速無以加。一杯驅世慮，兩杯反天和。", "三杯即酩酊，或笑任狂歌。陶陶複兀兀，吾孰知其他。", "況在名利途，平生有風波。深心藏陷阱，巧言織網羅。", "舉目非不見，不醉欲如何。"]'),
('yuding-25','曲江感秋','白居易','唐','御定全唐诗','yuding','','[]','沙草新雨地，岸柳涼風枝。三年感秋意，並在曲江池。',96,'御定全唐詩/json/432.json','["沙草新雨地，岸柳涼風枝。三年感秋意，並在曲江池。", "早蟬已嘹唳，晚荷複離披。前秋去秋思，一一生此時。", "昔人三十二，秋興已雲悲。我今欲四十，秋懷亦可知。", "歲月不虛設，此身隨日衰。暗老不自覺，直到鬢成絲。"]'),
('yuding-26','酬張太祝晚秋臥病見寄','白居易','唐','御定全唐诗','yuding','','[]','高才淹禮寺，短羽翔禁林。西街居處遠，北闕官曹深。',120,'御定全唐詩/json/432.json','["高才淹禮寺，短羽翔禁林。西街居處遠，北闕官曹深。", "君病不來訪，我忙難往尋。差池終日別，寥落經年心。", "露濕綠蕪地，月寒紅樹陰。況茲獨愁夕，聞彼相思吟。", "上歎言笑阻，下嗟時歲侵。容衰曉窗鏡，思苦秋弦琴。", "一章錦繡段，八韻瓊瑤音。何以報珍重，慚無雙南金。"]'),
('yuding-27','立秋日曲江憶元九','白居易','唐','御定全唐诗','yuding','','[]','下馬柳陰下，獨上堤上行。故人千萬里，新蟬三兩聲。',48,'御定全唐詩/json/432.json','["下馬柳陰下，獨上堤上行。故人千萬里，新蟬三兩聲。", "城中曲江水，江上江陵城。兩地新秋思，應同此日情。"]'),
('yuding-28','早朝賀雪寄陳山人','白居易','唐','御定全唐诗','yuding','','[]','長安盈尺雪，早朝賀君喜。將赴銀台門，始出新昌裏。',96,'御定全唐詩/json/432.json','["長安盈尺雪，早朝賀君喜。將赴銀台門，始出新昌裏。", "上堤馬蹄滑，中路蠟燭死。十裏向北行，寒風吹破耳。", "待漏午門外，候對三殿裏。須鬢凍生冰，衣裳冷如水。", "忽思仙游谷，暗謝陳居士。暖覆褐裘眠，日高應未起。"]'),
('yuding-29','初與元九別後忽夢見之及寤而書適至兼寄桐花詩悵然感懷因以此寄','白居易','唐','御定全唐诗','yuding','','[]','永壽寺中語，新昌坊北分。歸來數行淚，悲事不悲君。',288,'御定全唐詩/json/432.json','["永壽寺中語，新昌坊北分。歸來數行淚，悲事不悲君。", "悠悠藍田路，自去無消息。計君食宿程，已過商山北。", "昨夜雲四散，千里同月色。曉來夢見君，應是君相憶。", "夢中握君手，問君意何如。君言苦相憶，無人可寄書。", "覺來未及說，叩門聲冬冬。言是商州使，送君書一封。", "枕上忽驚起，顛倒著衣裳。開緘見手劄，一紙十三行。", "上論遷謫心，下說離別腸。心腸都未盡，不暇敘炎涼。", "雲作此書夜，夜宿商州東。獨對孤燈坐，陽城山館中。", "夜深作書畢，山月向西斜。月下何所有，一樹紫桐花。", "桐花半落時，複道正相思。殷勤書背後，兼寄桐花詩。", "桐花詩八韻，思緒一何深。以我今朝意，憶君此夜心。", "一章三遍讀，一句十回吟。珍重八十字，字字化為金。"]'),
('yuding-30','和元九悼往','白居易','唐','御定全唐诗','yuding','','[]','美人別君去，自去無處尋。舊物零落盡，此情安可任。',120,'御定全唐詩/json/432.json','["美人別君去，自去無處尋。舊物零落盡，此情安可任。", "唯有襭紗幌，塵埃日夜侵。馨香與顏色，不似舊時深。", "透影燈耿耿，籠光月沉沉。中有孤眠客，秋涼生夜衾。", "舊宅牡丹院，新墳松柏林。夢中咸陽淚，覺後江陵心。", "含此來年恨，發為中夜吟。無論君自感，聞者欲沾襟。"]'),
('yuding-31','重到渭上舊居','白居易','唐','御定全唐诗','yuding','','[]','舊居清渭曲，開門當蔡渡。十年方一還，幾欲迷歸路。',144,'御定全唐詩/json/432.json','["舊居清渭曲，開門當蔡渡。十年方一還，幾欲迷歸路。", "追思昔日行，感傷故遊處。插柳作高林，種桃成老樹。", "因驚成人者，儘是舊童孺。試問舊老人，半為繞村墓。", "浮生同過客，前後遞來去。白日如弄珠，出沒光不住。", "人物日改變，舉目悲所遇。回念念我身，安得不衰暮。", "朱顏銷不歇，白髮生無數。唯有山門外，三峰色如故。"]'),
('yuding-32','白髮','白居易','唐','御定全唐诗','yuding','','[]','白髮知時節，暗與我有期。今朝日陽裏，梳落數莖絲。',144,'御定全唐詩/json/432.json','["白髮知時節，暗與我有期。今朝日陽裏，梳落數莖絲。", "家人不慣見，憫默為我悲。我雲何足怪，此意爾不知。", "凡人年三十，外壯中已衰。但思寢食味，已減二十時。", "況我今四十，本來形貌羸。書魔昏兩眼，酒病沉四肢。", "親愛日零落，在者仍別離。身心久如此，白髮生已遲。", "由來生老死，三病長相隨。除卻念無生，人間無藥治。"]'),
('yuding-33','秋日','白居易','唐','御定全唐诗','yuding','','[]','池殘寥落水，窗下悠揚日。嫋嫋秋風多，槐花半成實。',36,'御定全唐詩/json/432.json','["池殘寥落水，窗下悠揚日。嫋嫋秋風多，槐花半成實。", "下有獨立人，年來四十一。"]'),
('yuding-34','將之饒州，江浦夜泊','白居易','唐','御定全唐诗','yuding','','[]','明月滿深浦，愁人臥孤舟。煩冤寢不得，夏夜長於秋。',108,'御定全唐詩/json/432.json','["明月滿深浦，愁人臥孤舟。煩冤寢不得，夏夜長於秋。", "苦乏衣食資，遠為江海遊。光陰坐遲暮，鄉國行阻修。", "身病向鄱陽，家貧寄徐州。前事與後事，豈堪心並憂。", "憂來起長望，但見江水流。雲樹靄蒼蒼，煙波澹悠悠。", "故園迷處所，一念堪白頭。"]'),
('yuding-35','思歸','白居易','唐','御定全唐诗','yuding','','[]','養無晨昏膳，隱無伏臘資。遂求及親祿，黽勉來京師。',96,'御定全唐詩/json/432.json','["養無晨昏膳，隱無伏臘資。遂求及親祿，黽勉來京師。", "薄俸未及親，別家已經時。冬積溫席戀，春違采蘭期。", "夏至一陰生，稍稍夕漏遲。塊然抱愁者，長夜獨先知。", "悠悠鄉關路，夢去身不隨。坐惜時節變，蟬鳴槐花枝。"]'),
('yuding-36','冀城北原作','白居易','唐','御定全唐诗','yuding','','[]','野色何莽蒼，秋聲亦蕭疏。風吹黃埃起，落日驅征車。',108,'御定全唐詩/json/432.json','["野色何莽蒼，秋聲亦蕭疏。風吹黃埃起，落日驅征車。", "何代此開國，封疆百里餘。古今不相待，朝市無常居。", "昔人城邑中，今變為丘墟。昔人墓田中，今化為裏閭。", "廢興相催迫，日月互居諸。世變無遺風，焉能知其初。", "行人千載後，懷古空躊躇。"]'),
('yuding-37','客路感秋，寄明准上人','白居易','唐','御定全唐诗','yuding','','[]','日暮天地冷，雨霽山河清。長風從西來，草木凝秋聲。',72,'御定全唐詩/json/432.json','["日暮天地冷，雨霽山河清。長風從西來，草木凝秋聲。", "已感歲倏忽，複傷物凋零。孰能不憯淒，天時牽人情。", "借問空門子，何法易修行。使我忘得心，不教煩惱生。"]'),
('yuding-38','游襄陽懷孟浩然','白居易','唐','御定全唐诗','yuding','','[]','楚山碧岩岩，漢水碧湯湯。秀氣結成象，孟氏之文章。',72,'御定全唐詩/json/432.json','["楚山碧岩岩，漢水碧湯湯。秀氣結成象，孟氏之文章。", "今我諷遺文，思人至其鄉。清風無人繼，日暮空襄陽。", "南望鹿門山，藹若有餘芳。舊隱不知處，雲深樹蒼蒼。"]'),
('yuding-39','秋暮西歸途中書情','白居易','唐','御定全唐诗','yuding','','[]','耿耿旅燈下，愁多常少眠。思鄉貴早發，發在雞鳴前。',96,'御定全唐詩/json/432.json','["耿耿旅燈下，愁多常少眠。思鄉貴早發，發在雞鳴前。", "九月草木落，平蕪連遠山。秋陰和曙色，萬木蒼蒼然。", "去秋偶東遊，今秋始西旋。馬瘦衣裳破，別家來二年。", "憶歸複愁歸，歸無一囊錢。心雖非蘭膏，安得不自然。"]'),
('yuding-40','秋懷','白居易','唐','御定全唐诗','yuding','','[]','月出照北堂，光華滿階墀。涼風從西至，草木日夜衰。',72,'御定全唐詩/json/432.json','["月出照北堂，光華滿階墀。涼風從西至，草木日夜衰。", "桐柳減綠陰，蕙蘭消碧滋。感物私自念，我心亦如之。", "安得長少壯，盛衰迫天時。人生如石火，為樂長苦遲。"]'),
('yuding-41','別楊穎士、盧克柔、殷堯藩','白居易','唐','御定全唐诗','yuding','','[]','倦鳥暮歸林，浮雲晴歸山。獨有行路子，悠悠不知還。',84,'御定全唐詩/json/432.json','["倦鳥暮歸林，浮雲晴歸山。獨有行路子，悠悠不知還。", "人生苦營營，終日群動間。所務雖不同，同歸於不閑。", "扁舟來楚鄉，匹馬往秦關。離憂繞心曲，宛轉如迴圈。", "且持一杯酒，聊以開愁顏。"]'),
('yuding-42','題贈定光上人','白居易','唐','御定全唐诗','yuding','','[]','二十身出家，四十心離塵。得徑入大道，乘此不退輪。',84,'御定全唐詩/json/432.json','["二十身出家，四十心離塵。得徑入大道，乘此不退輪。", "一坐十五年，林下秋複春。春花與秋氣，不感無情人。", "我來如有悟，潛以心照身。誤落聞見中，憂喜傷形神。", "安得遺耳目，冥然反天真。"]'),
('yuding-43','祇役駱口驛喜蕭侍禦書至兼睹新詩吟諷通宵因寄八韻','白居易','唐','御定全唐诗','yuding','','[]','日暮心無憀，吏役正營營。忽驚芳信至，複與新詩並。',96,'御定全唐詩/json/432.json','["日暮心無憀，吏役正營營。忽驚芳信至，複與新詩並。", "是時天無雲，山館有月明。月下讀數遍，風前吟一聲。", "一吟三四歎，聲盡有餘清。雅哉君子文，詠性不詠情。", "使我靈府中，鄙吝不得生。始知聽韶濩，可使心和平。"]'),
('yuding-44','酬李少府曹長官舍見贈','白居易','唐','御定全唐诗','yuding','','[]','低腰複斂手，心體不遑安。一落風塵下，方知為吏難。',120,'御定全唐詩/json/432.json','["低腰複斂手，心體不遑安。一落風塵下，方知為吏難。", "公事與日長，宦情隨歲闌。惆悵青袍袖，芸香無半殘。", "賴有李夫子，此懷聊自寬。兩心如止水，彼此無波瀾。", "往往簿書暇，相勸強為歡。白馬晚蹋雪，淥觴春暖寒。", "戀月夜同宿，愛山晴共看。野性自相近，不是為同官。"]'),
('yuding-45','留別','白居易','唐','御定全唐诗','yuding','','[]','秋涼卷朝簟，春暖撤夜衾。雖是無情物，欲別尚沉吟。',84,'御定全唐詩/json/432.json','["秋涼卷朝簟，春暖撤夜衾。雖是無情物，欲別尚沉吟。", "況與有情別，別隨情淺深。二年歡笑意，一旦東西心。", "獨留誠可念，同行力不任。前事詎能料，後期諒難尋。", "唯有潺湲淚，不惜共沾襟。"]'),
('yuding-46','曉別','白居易','唐','御定全唐诗','yuding','','[]','曉鼓聲已半，離筵坐難久。請君斷腸歌，送我和淚酒。',48,'御定全唐詩/json/432.json','["曉鼓聲已半，離筵坐難久。請君斷腸歌，送我和淚酒。", "月落欲明前，馬嘶初別後。浩浩暗塵中，何由見回首。"]'),
('yuding-47','北園','白居易','唐','御定全唐诗','yuding','','[]','北園東風起，雜花次第開。心知須臾落，一日三四來。',48,'御定全唐詩/json/432.json','["北園東風起，雜花次第開。心知須臾落，一日三四來。", "花下豈無酒，欲酌複遲回。所思眇千里，誰勸我一杯。"]'),
('yuding-48','惜栯李花','白居易','唐','御定全唐诗','yuding','','[]','樹小花鮮妍，香繁條軟弱。高低二三尺，重疊千萬萼。',72,'御定全唐詩/json/432.json','["樹小花鮮妍，香繁條軟弱。高低二三尺，重疊千萬萼。", "朝豔藹霏霏，夕凋紛漠漠。辭枝朱粉細，覆地紅綃薄。", "由來好顏色，常苦易銷鑠。不見莨蕩花，狂風吹不落。"]'),
('yuding-49','照鏡','白居易','唐','御定全唐诗','yuding','','[]','皎皎青銅鏡，斑斑白絲鬢。豈複更藏年，實年君不信。',24,'御定全唐詩/json/432.json','["皎皎青銅鏡，斑斑白絲鬢。豈複更藏年，實年君不信。"]'),
('yuding-50','新秋','白居易','唐','御定全唐诗','yuding','','[]','西風飄一葉，庭前颯已涼。風池明月水，衰蓮白露房。',36,'御定全唐詩/json/432.json','["西風飄一葉，庭前颯已涼。風池明月水，衰蓮白露房。", "其奈江南夜，綿綿自此長。"]'),
('yuding-51','夜雨','白居易','唐','御定全唐诗','yuding','','[]','早蛩啼複歇，殘燈滅又明。隔窗知夜雨，芭蕉先有聲。',24,'御定全唐詩/json/432.json','["早蛩啼複歇，殘燈滅又明。隔窗知夜雨，芭蕉先有聲。"]'),
('yuding-52','秋江送客','白居易','唐','御定全唐诗','yuding','','[]','秋鴻次第過，哀猿朝夕聞。是日孤舟客，此地亦離群。',48,'御定全唐詩/json/432.json','["秋鴻次第過，哀猿朝夕聞。是日孤舟客，此地亦離群。", "濛濛潤衣雨，漠漠冒帆雲。不醉潯陽酒，煙波愁殺人。"]'),
('yuding-53','感逝寄遠','白居易','唐','御定全唐诗','yuding','','[]','昨日聞甲死，今朝聞乙死。知識三分中，二分化為鬼。',108,'御定全唐詩/json/432.json','["昨日聞甲死，今朝聞乙死。知識三分中，二分化為鬼。", "逝者不復見，悲哉長已矣。存者今如何，去我皆萬里。", "平生知心者，屈指能有幾。通果澧鳳州，眇然四君子。", "相思俱老大，浮世如流水。應歎舊交遊，凋零日如此。", "何當一杯酒，開眼笑相視。"]'),
('yuding-54','秋月','白居易','唐','御定全唐诗','yuding','','[]','夜初色蒼然，夜深光浩然。稍轉西廊下，漸滿南窗前。',60,'御定全唐詩/json/432.json','["夜初色蒼然，夜深光浩然。稍轉西廊下，漸滿南窗前。", "況是綠蕪地，複茲清露天。落葉聲策策，驚鳥影翩翩。", "棲禽尚不穩，愁人安可眠。"]'),
('yuding-0','朱陳村','白居易','唐','御定全唐诗','yuding','','[]','徐州古豐縣，有村曰朱陳。去縣百餘裏，桑麻青氛氳。',408,'御定全唐詩/json/433.json','["徐州古豐縣，有村曰朱陳。去縣百餘裏，桑麻青氛氳。", "機梭聲劄劄，牛驢走紜紜。女汲澗中水，男采山上薪。", "縣遠官事少，山深人俗淳。有財不行商，有丁不入軍。", "家家守村業，頭白不出門。生為村之民，死為村之塵。", "田中老與幼，相見何欣欣。一村唯兩姓，世世為婚姻。", "親疏居有族，少長遊有群。黃雞與白酒，歡會不隔旬。", "生者不遠別，嫁娶先近鄰。死者不遠葬，墳墓多繞村。", "既安生與死，不苦形與神。所以多壽考，往往見玄孫。", "我生禮義鄉，少小孤且貧。徒學辨是非，只自取辛勤。", "世法貴名教，士人重冠婚。以此自桎梏，信為大謬人。", "十歲解讀書，十五能屬文。二十舉秀才，三十為諫臣。", "下有妻子累，上有君親恩。承家與事國，望此不肖身。", "憶昨旅遊初，迨今十五春。孤舟三適楚，羸馬四經秦。", "晝行有饑色，夜寢無安魂。東西不暫住，來往若浮雲。", "離亂失故鄉，骨肉多散分。江南與江北，各有平生親。", "平生終日別，逝者來年聞。朝憂臥至暮，夕哭坐達晨。", "悲火燒心曲，愁霜侵鬢根。一生苦如此，長羨村中民。"]'),
('yuding-1','讀鄧魴詩','白居易','唐','御定全唐诗','yuding','','[]','塵架多文集，偶取一卷披。未及看姓名，疑是陶潛詩。',132,'御定全唐詩/json/433.json','["塵架多文集，偶取一卷披。未及看姓名，疑是陶潛詩。", "看名知是君，惻惻令我悲。詩人多蹇厄，近日誠有之。", "京兆杜子美，猶得一拾遺。襄陽孟浩然，亦聞鬢成絲。", "嗟君兩不如，三十在布衣。擢第祿不及，新婚妻未歸。", "少年無疾患，溘死于路歧。天不與爵壽，唯與好文詞。", "此理勿複道，巧曆不能推。"]'),
('yuding-2','寄元九','白居易','唐','御定全唐诗','yuding','','[]','晨雞才發聲，夕雀俄斂冀。晝夜往復來，疾如出入息。',120,'御定全唐詩/json/433.json','["晨雞才發聲，夕雀俄斂冀。晝夜往復來，疾如出入息。", "非徒改年貌，漸覺無心力。自念因念君，俱為老所逼。", "君年雖校少，憔悴謫南國。三年不放歸，炎瘴消顏色。", "山無殺草霜，水有含沙蜮。健否遠不知，書多來年得。", "願君少愁苦，我亦加餐食。各保金石軀，以慰長相憶。"]'),
('yuding-3','秋夕','白居易','唐','御定全唐诗','yuding','','[]','葉聲落如雨，月色白似霜。夜深方獨臥，誰為拂塵床。',24,'御定全唐詩/json/433.json','["葉聲落如雨，月色白似霜。夜深方獨臥，誰為拂塵床。"]'),
('yuding-4','夜雨','白居易','唐','御定全唐诗','yuding','','[]','我有所念人，隔在遠遠鄉。我有所感事，結在深深腸。',84,'御定全唐詩/json/433.json','["我有所念人，隔在遠遠鄉。我有所感事，結在深深腸。", "鄉遠去不得，無日不瞻望。腸深解不得，無夕不思量。", "況此殘燈夜，獨宿在空堂。秋天殊未曉，風雨正蒼蒼。", "不學頭陀法，前心安可忘。"]'),
('yuding-5','秋霽','白居易','唐','御定全唐诗','yuding','','[]','金火不相待，炎涼雨中變。林晴有殘蟬，巢冷無留燕。',96,'御定全唐詩/json/433.json','["金火不相待，炎涼雨中變。林晴有殘蟬，巢冷無留燕。", "沉吟卷長簟，愴惻收團扇。向夕稍無泥，閒步青苔院。", "月出砧杵動，家家搗秋練。獨對多病妻，不能理針線。", "冬衣殊未制，夏服行將綻。何以迎早秋，一杯聊自勸。"]'),
('yuding-6','歎老三首','白居易','唐','御定全唐诗','yuding','','[]','晨興照青鏡，形影兩寂寞。少年辭我去，白髮隨梳落。',240,'御定全唐詩/json/433.json','["晨興照青鏡，形影兩寂寞。少年辭我去，白髮隨梳落。", "萬化成於漸，漸衰看不覺。但恐鏡中顏，今朝老於昨。", "人年少滿百，不得長歡樂。誰會天地心，千齡與龜鶴。", "吾聞善醫者，今古稱扁鵲。萬病皆可治，唯無治老藥。", "我有一握發，梳理何稠直。昔似玄雲光，今如素絲色。", "匣中有舊鏡，欲照先歎息。自從頭白來，不欲明磨拭。", "鴉頭與鶴頸，至老常如墨。獨有人鬢毛，不得終身黑。", "前年種桃核，今歲成花樹。去歲新嬰兒，今年已學步。", "但驚物長成，不覺身衰暮。去矣欲何如，少年留不住。", "因書今日意，遍寄諸親故。壯歲不歡娛，長年當悔悟。"]'),
('yuding-7','送兄弟回雪夜','白居易','唐','御定全唐诗','yuding','','[]','日晦雲氣黃，東北風切切。時從村南還，新與兄弟別。',132,'御定全唐詩/json/433.json','["日晦雲氣黃，東北風切切。時從村南還，新與兄弟別。", "離襟淚猶濕，回馬嘶未歇。欲歸一室坐，天陰多無月。", "夜長火消盡，歲暮雨凝結。寂寞滿爐灰，飄零上階雪。", "對雪畫寒灰，殘燈明複滅。灰死如我心，雪白如我發。", "所遇皆如此，頃刻堪愁絕。回念入坐忘，轉憂作禪悅。", "平生洗心法，正為今宵設。"]'),
('yuding-8','溪中早春','白居易','唐','御定全唐诗','yuding','','[]','南山雪未盡，陰嶺留殘白。西澗冰已消，春溜含新碧。',96,'御定全唐詩/json/433.json','["南山雪未盡，陰嶺留殘白。西澗冰已消，春溜含新碧。", "東風來幾日，蟄動萌草坼。潛知陽和功，一日不虛擲。", "愛此天氣暖，來拂溪邊石。一坐欲忘歸，暮禽聲嘖嘖。", "蓬蒿隔桑棗，隱映煙火夕。歸來問夜餐，家人烹薺麥。"]'),
('yuding-9','同友人尋澗花','白居易','唐','御定全唐诗','yuding','','[]','聞有澗底花，貰得村中酒。與君來校遲，已逢搖落後。',72,'御定全唐詩/json/433.json','["聞有澗底花，貰得村中酒。與君來校遲，已逢搖落後。", "臨觴有遺恨，悵望空溪口。記取花發時，期君重攜手。", "我生日日老，春色年年有。且作來歲期，不知身健否。"]'),
('yuding-10','登村東古塚','白居易','唐','御定全唐诗','yuding','','[]','高低古時塚，上有牛羊道。獨立最高頭，悠哉此懷抱。',72,'御定全唐詩/json/433.json','["高低古時塚，上有牛羊道。獨立最高頭，悠哉此懷抱。", "回頭向村望，但見荒田草。村人不愛花，多種栗與棗。", "自來此村住，不覺風光好。花少鶯亦稀，年年春暗老。"]'),
('yuding-11','夢裴相公','白居易','唐','御定全唐诗','yuding','','[]','五年生死隔，一夕魂夢通。夢中如往日，同直金鑾宮。',96,'御定全唐詩/json/433.json','["五年生死隔，一夕魂夢通。夢中如往日，同直金鑾宮。", "仿佛金紫色，分明冰玉容。勤勤相眷意，亦與平生同。", "既寤知是夢，憫然情未終。追想當時事，何殊昨夜中。", "自我學心法，萬緣成一空。今朝為君子，流涕一沾胸。"]'),
('yuding-12','晝寢','白居易','唐','御定全唐诗','yuding','','[]','坐整白單衣，起穿黃草履。朝餐盥漱畢，徐下階前步。',72,'御定全唐詩/json/433.json','["坐整白單衣，起穿黃草履。朝餐盥漱畢，徐下階前步。", "暑風微變候，晝刻漸加數。院靜地陰陰，鳥鳴新葉樹。", "獨行還獨臥，夏景殊未暮。不作午時眠，日長安可度。"]'),
('yuding-13','別行簡','白居易','唐','御定全唐诗','yuding','','[]','漠漠病眼花，星星愁鬢雪。筋骸已衰憊，形影仍分訣。',72,'御定全唐詩/json/433.json','["漠漠病眼花，星星愁鬢雪。筋骸已衰憊，形影仍分訣。", "梓州二千里，劍門五六月。豈是遠行時，火雲燒棧熱。", "何言巾上淚，乃是腸中血。念此早歸來，莫作經年別。"]'),
('yuding-14','觀兒戲','白居易','唐','御定全唐诗','yuding','','[]','髫齔七八歲，綺紈三四兒。弄塵複鬥草，盡日樂嬉嬉。',72,'御定全唐詩/json/433.json','["髫齔七八歲，綺紈三四兒。弄塵複鬥草，盡日樂嬉嬉。", "堂上長年客，鬢間新有絲。一看竹馬戲，每憶童騃時。", "童騃饒戲樂，老大多憂悲。靜念彼與此，不知誰是癡。"]'),
('yuding-15','歎常生','白居易','唐','御定全唐诗','yuding','','[]','西村常氏子，臥疾不須臾。前旬猶訪我，今日忽雲殂。',84,'御定全唐詩/json/433.json','["西村常氏子，臥疾不須臾。前旬猶訪我，今日忽雲殂。", "時我病多暇，與之同野居。園林青藹藹，相去數裏餘。", "村鄰無好客，所遇唯農夫。之子何如者，往還猶勝無。", "於今亦已矣，可為一長籲。"]'),
('yuding-16','寄元九','白居易','唐','御定全唐诗','yuding','','[]','一病經四年，親朋書信斷。窮通合易交，自笑知何晚。',144,'御定全唐詩/json/433.json','["一病經四年，親朋書信斷。窮通合易交，自笑知何晚。", "元君在荊楚，去日唯雲遠。彼獨是何人，心如石不轉。", "憂我貧病身，書來唯勸勉。上言少愁苦，下道加餐飯。", "憐君為謫吏，窮薄家貧褊。三寄衣食資，數盈二十萬。", "豈是貪衣食，感君心繾綣。念我口中食，分君身上暖。", "不因身病久，不因命多蹇。平生親友心，豈得知深淺。"]'),
('yuding-17','以鏡贈別','白居易','唐','御定全唐诗','yuding','','[]','人言似明月，我道勝明月。明月非不明，一年十二缺。',84,'御定全唐詩/json/433.json','["人言似明月，我道勝明月。明月非不明，一年十二缺。", "豈如玉匣裏，如水常澄澈。月破天暗時，圓明獨不歇。", "我慚貌醜老，繞鬢斑斑雪。不如贈少年，回照青絲發。", "因君千里去，持此將為別。"]'),
('yuding-18','城上對月，期友人不至','白居易','唐','御定全唐诗','yuding','','[]','古人惜晝短，勸令秉燭遊。況此迢迢夜，明月滿西樓。',72,'御定全唐詩/json/433.json','["古人惜晝短，勸令秉燭遊。況此迢迢夜，明月滿西樓。", "複有盈尊酒，置在城上頭。期君君不至，人月兩悠悠。", "照水煙波白，照人肌發秋。清光正如此，不醉即須愁。"]'),
('yuding-19','念金鑾子二首','白居易','唐','御定全唐诗','yuding','','[]','衰病四十身，嬌癡三歲女。非男猶勝無，慰情時一撫。',168,'御定全唐詩/json/433.json','["衰病四十身，嬌癡三歲女。非男猶勝無，慰情時一撫。", "一朝舍我去，魂影無處所。況念夭劄時，嘔啞初學語。", "始知骨肉愛，乃是憂悲聚。唯思未有前，以理遣傷苦。", "忘懷日已久，三度移寒暑。今日一傷心，因逢舊乳母。", "與爾為父子，八十有六旬。忽然又不見，邇來三四春。", "形質本非實，氣聚偶成身。恩愛元是妄，緣合暫為親。", "念茲庶有悟，聊用遣悲辛。暫將理自奪，不是忘情人。"]'),
('yuding-20','對酒','白居易','唐','御定全唐诗','yuding','','[]','人生一百歲，通計三萬日。何況百歲人，人間百無一。',132,'御定全唐詩/json/433.json','["人生一百歲，通計三萬日。何況百歲人，人間百無一。", "賢愚共零落，貴賤同埋沒。東岱前後魂，北邙新舊骨。", "複聞藥誤者，為愛延年術。又有憂死者，為貪政事筆。", "藥誤不得老，憂死非因疾。誰言人最靈，知得不知失。", "何如會親友，飲此杯中物。能沃煩慮消，能陶真性出。", "所以劉阮輩，終年醉兀兀。"]'),
('yuding-21','渭村雨歸','白居易','唐','御定全唐诗','yuding','','[]','渭水寒漸落，離離蒲稗苗。閑傍沙邊立，看人刈葦苕。',60,'御定全唐詩/json/433.json','["渭水寒漸落，離離蒲稗苗。閑傍沙邊立，看人刈葦苕。", "近水風景冷，晴明猶寂寥。複茲夕陰起，野色重蕭條。", "蕭條獨歸路，暮雨濕村橋。"]'),
('yuding-22','諭懷','白居易','唐','御定全唐诗','yuding','','[]','黑頭日已白，白麵日已黑。人生未死間，變化何終極。',60,'御定全唐詩/json/433.json','["黑頭日已白，白麵日已黑。人生未死間，變化何終極。", "常言在己者，莫若形與色。一朝改變來，止遏不能得。", "況彼身外事，悠悠通與塞。"]'),
('yuding-23','喜友至留宿','白居易','唐','御定全唐诗','yuding','','[]','村中少賓客，柴門多不開。忽聞車馬至，雲是故人來。',60,'御定全唐詩/json/433.json','["村中少賓客，柴門多不開。忽聞車馬至，雲是故人來。", "況值風雨夕，愁心正悠哉。願君且同宿，盡此手中杯。", "人生開口笑，百年都幾回。"]'),
('yuding-24','西原晚望','白居易','唐','御定全唐诗','yuding','','[]','花菊引閑行，行上西原路。原上晚無人，因高聊四顧。',120,'御定全唐詩/json/433.json','["花菊引閑行，行上西原路。原上晚無人，因高聊四顧。", "南阡有煙火，北陌連墟墓。村鄰何蕭疏，近者猶百步。", "吾廬在其下，寂寞風日暮。門外轉枯蓬，籬根伏寒兔。", "故園汴水上，離亂不堪去。近歲始移家，飄然此村住。", "新屋五六間，古槐八九樹。便是衰病身，此生終老處。"]'),
('yuding-25','感鏡','白居易','唐','御定全唐诗','yuding','','[]','美人與我別，留鏡在匣中。自從花顏去，秋水無芙蓉。',60,'御定全唐詩/json/433.json','["美人與我別，留鏡在匣中。自從花顏去，秋水無芙蓉。", "經年不開匣，紅埃覆青銅。今朝一拂拭，自照憔悴容。", "照罷重惆悵，背有雙盤龍。"]'),
('yuding-26','村居臥病三首','白居易','唐','御定全唐诗','yuding','','[]','戚戚抱羸病，悠悠度朝暮。夏木才結陰，秋蘭已含露。',216,'御定全唐詩/json/433.json','["戚戚抱羸病，悠悠度朝暮。夏木才結陰，秋蘭已含露。", "前日巢中卵，化作雛飛去。昨日穴中蟲，蛻為蟬上樹。", "四時未嘗歇，一物不暫住。唯有病客心，沉然獨如故。", "新秋久病容，起步村南道。盡日不逢人，蟲聲遍荒草。", "西風吹白露，野綠秋仍早。草木猶未傷，先傷我懷抱。", "朱顏與玄鬢，強健幾時好。況為憂病侵，不得依年老。", "種黍三十畝，雨來苗漸大。種薤二十畦，秋來欲堪刈。", "望黍作冬酒，留薤為春菜。荒村百物無，待此養衰瘵。", "葺廬備陰雨，補褐防寒歲。病身知幾時，且作明年計。"]'),
('yuding-27','沐浴','白居易','唐','御定全唐诗','yuding','','[]','經年不沐浴，塵垢滿肌膚。今朝一澡濯，衰瘦頗有餘。',72,'御定全唐詩/json/433.json','["經年不沐浴，塵垢滿肌膚。今朝一澡濯，衰瘦頗有餘。", "老色頭鬢白，病形支體虛。衣寬有剩帶，發少不勝梳。", "自問今年幾，春秋四十初。四十已如此，七十複何知。"]'),
('yuding-28','栽松二首','白居易','唐','御定全唐诗','yuding','','[]','小松未盈尺，心愛手自移。蒼然澗底色，雲濕煙霏霏。',96,'御定全唐詩/json/433.json','["小松未盈尺，心愛手自移。蒼然澗底色，雲濕煙霏霏。", "栽植我年晚，長成君性遲。如何過四十，種此數寸枝。", "得見成陰否，人生七十稀。", "愛君抱晚節，憐君含直文。欲得朝朝見，階前故種君。", "知君死則已，不死會淩雲。"]'),
('yuding-29','病中友人相訪','白居易','唐','御定全唐诗','yuding','','[]','臥久不記日，南窗昏複昏。蕭條草簷下，寒雀朝夕聞。',72,'御定全唐詩/json/433.json','["臥久不記日，南窗昏複昏。蕭條草簷下，寒雀朝夕聞。", "強扶床前杖，起向庭中行。偶逢故人至，便當一逢迎。", "移榻就斜日，披裘倚前楹。閒談勝服藥，稍覺有心情。"]'),
('yuding-30','自覺二首','白居易','唐','御定全唐诗','yuding','','[]','四十未為老，憂傷早衰惡。前歲二毛生，今年一齒落。',264,'御定全唐詩/json/433.json','["四十未為老，憂傷早衰惡。前歲二毛生，今年一齒落。", "形骸日損耗，心事同蕭索。夜寢與朝餐，其間味亦薄。", "同歲崔舍人，容光方灼灼。始知年與貌，衰盛隨憂樂。", "畏老老轉迫，憂病病彌縛。不畏複不憂，是除老病藥。", "朝哭心所愛，暮哭心所親。親愛零落盡，安用身獨存。", "幾許平生歡，無限骨肉恩。結為腸間痛，聚作鼻頭辛。", "悲來四支緩，泣盡雙眸昏。所以年四十，心如七十人。", "我聞浮屠教，中有解脫門。置心為止水，視身如浮雲。", "鬥擻垢穢衣，度脫生死輪。胡為戀此苦，不去猶逡巡。", "回念發弘願，願此見在身。但受過去報，不結將來因。", "誓以智慧水，永洗煩惱塵。不將恩愛子，更種悲憂根。"]'),
('yuding-31','夜雨有念','白居易','唐','御定全唐诗','yuding','','[]','以道治心氣，終歲得晏然。何乃戚戚意，忽來風雨天。',168,'御定全唐詩/json/433.json','["以道治心氣，終歲得晏然。何乃戚戚意，忽來風雨天。", "既非慕榮顯，又不恤饑寒。胡為悄不樂，抱膝殘燈前。", "形影暗相問，心默對以言。骨肉能幾人，各在天一端。", "吾兄寄宿州，吾弟客東川。南北五千里，吾身在中間。", "欲去病未能，欲住心不安。有如波上舟，此縛而彼牽。", "自我向道來，於今六七年。煉成不二性，消盡千萬緣。", "唯有恩愛火，往往猶熬煎。豈是藥無效，病多難盡蠲。"]'),
('yuding-32','寄楊六','白居易','唐','御定全唐诗','yuding','','[]','青宮官冷靜，赤縣事繁劇。一閑複一忙，動作經時隔。',144,'御定全唐詩/json/433.json','["青宮官冷靜，赤縣事繁劇。一閑複一忙，動作經時隔。", "清觴久廢酌，白日頓虛擲。念此忽踟躕，悄然心不適。", "豈無舊交結，久別或遷易。亦有新往還，相見多形跡。", "唯君於我分，堅久如金石。何況老大來，人情重姻戚。", "會稀歲月急，此事真可惜。幾回開口笑，便到髭須白。", "公門苦鞅掌，盡日無閑隙。猶冀乘暝來，靜言同一夕。"]'),
('yuding-33','送春','白居易','唐','御定全唐诗','yuding','','[]','三月三十日，春歸日複暮。惆悵問春風，明朝應不住。',120,'御定全唐詩/json/433.json','["三月三十日，春歸日複暮。惆悵問春風，明朝應不住。", "送春曲江上，眷眷東西顧。但見撲水花，紛紛不知數。", "人生似行客，兩足無停步。日日進前程，前程幾多路。", "兵刀與水火，盡可違之去。唯有老到來，人間無避處。", "感時良為已，獨倚池南樹。今日送春心，心如別親故。"]'),
('yuding-34','哭李三','白居易','唐','御定全唐诗','yuding','','[]','去年渭水曲，秋時訪我來。今年常樂裏，春日哭君回。',60,'御定全唐詩/json/433.json','["去年渭水曲，秋時訪我來。今年常樂裏，春日哭君回。", "哭君仰問天，天意安在哉。若必奪其壽，何如不與才。", "落然身後事，妻病女嬰孩。"]'),
('yuding-35','別李十一後重寄','白居易','唐','御定全唐诗','yuding','','[]','秋日正蕭條，驅車出蓬蓽。回望青門道，目極心鬱鬱。',96,'御定全唐詩/json/433.json','["秋日正蕭條，驅車出蓬蓽。回望青門道，目極心鬱鬱。", "豈獨戀鄉土，非關慕簪紱。所愴別李君，平生同道術。", "俱承金馬詔，聯秉諫臣筆。共上青雲梯，中途一相失。", "江湖我方往，朝廷君不出。蕙帶與華簪，相逢是何日。"]'),
('yuding-36','初出藍田路作','白居易','唐','御定全唐诗','yuding','','[]','停驂問前路，路在秋雲裏。蒼蒼縣南道，去途從此始。',84,'御定全唐詩/json/433.json','["停驂問前路，路在秋雲裏。蒼蒼縣南道，去途從此始。", "絕頂忽上盤，眾山皆下視。下視千萬峰，峰頭如浪起。", "朝經韓公坡，夕次藍橋水。潯陽近四千，始行七十裏。", "人煩馬蹄跙，勞苦已如此。"]'),
('yuding-37','仙娥峰下作','白居易','唐','御定全唐诗','yuding','','[]','我為東南行，始登商山道。商山無數峰，最愛仙娥好。',96,'御定全唐詩/json/433.json','["我為東南行，始登商山道。商山無數峰，最愛仙娥好。", "參差樹若插，匼匝雲如抱。渴望寒玉泉，香聞紫芝草。", "青崖屏削碧，白石床鋪縞。向無如此物，安足留四皓。", "感彼私自問，歸山何不早。可能塵土中，還隨眾人老。"]'),
('yuding-38','微雨夜行','白居易','唐','御定全唐诗','yuding','','[]','漠漠秋雲起，稍稍夜寒生。但覺衣裳濕，無點亦無聲。',24,'御定全唐詩/json/433.json','["漠漠秋雲起，稍稍夜寒生。但覺衣裳濕，無點亦無聲。"]'),
('yuding-39','再到襄陽訪問舊居','白居易','唐','御定全唐诗','yuding','','[]','昔到襄陽日，髯髯初有髭。今過襄陽日，髭鬢半成絲。',72,'御定全唐詩/json/433.json','["昔到襄陽日，髯髯初有髭。今過襄陽日，髭鬢半成絲。", "舊遊都是夢，乍到忽如歸。東郭蓬蒿宅，荒涼今屬誰。", "故知多零落，閭井亦遷移。獨有秋江水，煙波似舊時。"]'),
('yuding-40','寄微之三首','白居易','唐','御定全唐诗','yuding','','[]','江州望通州，天涯與地末。有山萬丈高，有江千里闊。',252,'御定全唐詩/json/433.json','["江州望通州，天涯與地末。有山萬丈高，有江千里闊。", "間之以雲霧，飛鳥不可越。誰知千古險，為我二人設。", "通州君初到，鬱鬱愁如結。江州我方去，迢迢行未歇。", "道路日乖隔，音信日斷絕。因風欲寄語，地遠聲不徹。", "生當複相逢，死當從此別。", "君遊襄陽日，我在長安住。今君在通州，我過襄陽去。", "襄陽九裏郭，樓堞連雲樹。顧此稍依依，是君舊遊處。", "蒼茫兼葭水，中有潯陽路。此去更相思，江西少親故。", "去國日已遠，喜逢物似人。如何含此意，江上坐思君。", "有如河嶽氣，相合方氛氳。狂風吹中絕，兩處成孤雲。", "風回終有時，雲合豈無因。努力各自愛，窮通我爾身。"]'),
('yuding-41','舟中雨夜','白居易','唐','御定全唐诗','yuding','','[]','江雲暗悠悠，江風冷修修。夜雨滴船背，風浪打船頭。',36,'御定全唐詩/json/433.json','["江雲暗悠悠，江風冷修修。夜雨滴船背，風浪打船頭。", "船中有病客，左降向江州。"]'),
('yuding-42','夜聞歌者','白居易','唐','御定全唐诗','yuding','','[]','夜泊鸚鵡洲，江月秋澄澈。鄰船有歌者，發詞堪愁絕。',96,'御定全唐詩/json/433.json','["夜泊鸚鵡洲，江月秋澄澈。鄰船有歌者，發詞堪愁絕。", "歌罷繼以泣，泣聲通複咽。尋聲見其人，有婦顏如雪。", "獨倚帆檣立，娉婷十七八。夜淚如真珠，雙雙墮明月。", "借問誰家婦，歌泣何淒切。一問一沾襟，低眉終不說。"]'),
('yuding-43','江樓聞砧','白居易','唐','御定全唐诗','yuding','','[]','江人授衣晚，十月始聞砧。一夕高樓月，萬里故園心。',24,'御定全唐詩/json/433.json','["江人授衣晚，十月始聞砧。一夕高樓月，萬里故園心。"]'),
('yuding-44','宿東林寺','白居易','唐','御定全唐诗','yuding','','[]','經窗燈焰短，僧爐火氣深。索落廬山夜，風雪宿東林。',24,'御定全唐詩/json/433.json','["經窗燈焰短，僧爐火氣深。索落廬山夜，風雪宿東林。"]'),
('yuding-45','憶洛下故園','白居易','唐','御定全唐诗','yuding','','[]','潯陽遷謫地，洛陽離亂年。煙塵三川上，炎瘴九江邊。',36,'御定全唐詩/json/433.json','["潯陽遷謫地，洛陽離亂年。煙塵三川上，炎瘴九江邊。", "鄉心坐如此，秋風仍颯然。"]'),
('yuding-46','贈別崔五','白居易','唐','御定全唐诗','yuding','','[]','朝送南去客，暮迎北來賓。孰雲當大路，少遇心所親。',120,'御定全唐詩/json/433.json','["朝送南去客，暮迎北來賓。孰雲當大路，少遇心所親。", "勞者念息肩，熱者思濯身。何如愁獨日，忽見平生人。", "平生已不淺，是日重殷勤。問從何處來，及此江亭春。", "江天春多陰，夜月隔重雲。移尊樹間飲，燈照花紛紛。", "一會不易得，餘事何足雲。明旦又分手，今夕且歡忻。"]'),
('yuding-47','春晚寄微之','白居易','唐','御定全唐诗','yuding','','[]','三月江水闊，悠悠桃花波。年芳與心事，此地共蹉跎。',60,'御定全唐詩/json/433.json','["三月江水闊，悠悠桃花波。年芳與心事，此地共蹉跎。", "南國方譴謫，中原正兵戈。眼前故人少，頭上白髮多。", "通州更迢遞，春盡複如何。"]'),
('yuding-48','漸老','白居易','唐','御定全唐诗','yuding','','[]','今朝複明日，不覺年齒暮。白髮逐梳落，朱顏辭鏡去。',72,'御定全唐詩/json/433.json','["今朝複明日，不覺年齒暮。白髮逐梳落，朱顏辭鏡去。", "當春頗愁寂，對酒寡歡趣。遇境多愴辛，逢人益敦故。", "形質屬天地，推遷從不住。所怪少年心，銷磨落何處。"]'),
('yuding-49','送幼史','白居易','唐','御定全唐诗','yuding','','[]','淮右寇未散，江西歲再徂。故里干戈地，行人風雪途。',36,'御定全唐詩/json/433.json','["淮右寇未散，江西歲再徂。故里干戈地，行人風雪途。", "此時與爾別，江畔立踟躕。"]'),
('yuding-50','夜雪','白居易','唐','御定全唐诗','yuding','','[]','已訝衾枕冷，複見窗戶明。夜深知雪重，時聞折竹聲。',24,'御定全唐詩/json/433.json','["已訝衾枕冷，複見窗戶明。夜深知雪重，時聞折竹聲。"]'),
('yuding-51','寄行簡','白居易','唐','御定全唐诗','yuding','','[]','鬱鬱眉多斂，默默口寡言。豈是願如此，舉目誰與歡。',96,'御定全唐詩/json/433.json','["鬱鬱眉多斂，默默口寡言。豈是願如此，舉目誰與歡。", "去春爾西征，從事巴蜀間。今春我南謫，抱疾江海壖。", "相去六千里，地絕天邈然。十書九不達，何以開憂顏。", "渴人多夢飲，饑人多夢餐。春來夢何處，合眼到東川。"]'),
('yuding-52','首夏','白居易','唐','御定全唐诗','yuding','','[]','孟夏百物滋，動植一時好。麋鹿樂深林，蟲蛇喜豐草。',144,'御定全唐詩/json/433.json','["孟夏百物滋，動植一時好。麋鹿樂深林，蟲蛇喜豐草。", "翔禽愛密葉，遊鱗悅新藻。天和遺漏處，而我獨枯槁。", "一身在天末，骨肉皆遠道。舊國無來人，寇戎塵浩浩。", "沉憂竟何益，只自勞懷抱。不如放身心，冥然任天造。", "潯陽多美酒，可使杯不燥。湓魚賤如泥，烹炙無昏早。", "朝飯山下寺，暮醉湖中島。何必歸故鄉，茲焉可終老。"]'),
('yuding-53','孟夏思渭村舊居寄舍弟','白居易','唐','御定全唐诗','yuding','','[]','嘖嘖雀引雛，稍稍筍成竹。時物感人情，憶我故鄉曲。',240,'御定全唐詩/json/433.json','["嘖嘖雀引雛，稍稍筍成竹。時物感人情，憶我故鄉曲。", "故園渭水上，十載事樵牧。手種榆柳成，陰陰覆牆屋。", "兔隱豆苗肥，鳥鳴桑椹熟。前年當此時，與爾同遊矚。", "詩書課弟侄，農圃資童僕。日暮麥登場，天晴蠶坼簇。", "弄泉南澗坐，待月東亭宿。興發飲數杯，悶來棋一局。", "一朝忽分散，萬里仍羈束。井鮒思反泉，籠鶯悔出穀。", "九江地卑濕，四月天炎燠。苦雨初入梅，瘴雲稍含毒。", "泥秧水畦稻，灰種畬田粟。已訝殊歲時，仍嗟異風俗。", "閑登郡樓望，日落江山綠。歸雁拂鄉心，平湖斷人目。", "殊方我漂泊，舊裏君幽獨。何時同一瓢，飲水心亦足。"]'),
('yuding-54','早蟬','白居易','唐','御定全唐诗','yuding','','[]','六月初七日，江頭蟬始鳴。石楠深葉裏，薄暮兩三聲。',72,'御定全唐詩/json/433.json','["六月初七日，江頭蟬始鳴。石楠深葉裏，薄暮兩三聲。", "一催衰鬢色，再動故園情。西風殊未起，秋思先秋生。", "憶昔在東掖，宮槐花下聽。今朝無限思，雲樹繞湓城。"]'),
('yuding-55','感情','白居易','唐','御定全唐诗','yuding','','[]','中庭曬服玩，忽見故鄉履。昔贈我者誰，東鄰嬋娟子。',120,'御定全唐詩/json/433.json','["中庭曬服玩，忽見故鄉履。昔贈我者誰，東鄰嬋娟子。", "因思贈時語，特用結終始。永願如履綦，雙行複雙止。", "自吾謫江郡，漂蕩三千里。為感長情人，提攜同到此。", "今朝一惆悵，反復看未已。人只履猶雙，何曾得相似。", "可嗟複可惜，錦表繡為裏。況經梅雨來，色黯花草死。"]'),
('yuding-56','南湖晚秋','白居易','唐','御定全唐诗','yuding','','[]','八月白露降，湖中水方老。旦夕秋風多，衰荷半傾倒。',72,'御定全唐詩/json/433.json','["八月白露降，湖中水方老。旦夕秋風多，衰荷半傾倒。", "手攀青楓樹，足蹋黃蘆草。慘澹老容顏，冷落秋懷抱。", "有兄在淮楚，有弟在蜀道。萬里何時來，煙波白浩浩。"]'),
('yuding-57','郡廳有樹，晚榮早凋，人不識名，因題其上','白居易','唐','御定全唐诗','yuding','','[]','潯陽郡廳後，有樹不知名。秋先梧桐落，春後桃李榮。',120,'御定全唐詩/json/433.json','["潯陽郡廳後，有樹不知名。秋先梧桐落，春後桃李榮。", "五月始萌動，八月已凋零。左右皆松桂，四時鬱青青。", "豈量雨露恩，沾濡不均平。榮枯各有分，天地本無情。", "顧我亦相類，早衰向晚成。形骸少多病，三十不豐盈。", "毛鬢早改變，四十白髭生。誰教兩蕭索，相對此江城。"]'),
('yuding-58','感秋懷微之','白居易','唐','御定全唐诗','yuding','','[]','葉下湖又波，秋風此時至。誰知濩落心，先納蕭條氣。',72,'御定全唐詩/json/433.json','["葉下湖又波，秋風此時至。誰知濩落心，先納蕭條氣。", "推移感流歲，漂泊思同志。昔為煙霄侶，今作泥塗吏。", "白鷗毛羽弱，青鳳文章異。各閉一籠中，歲晚同憔悴。"]'),
('yuding-59','因沐感發，寄朗上人二首','白居易','唐','御定全唐诗','yuding','','[]','年長身轉慵，百事無所欲。乃至頭上發，經年方一沐。',144,'御定全唐詩/json/433.json','["年長身轉慵，百事無所欲。乃至頭上發，經年方一沐。", "沐稀發苦落，一沐仍半禿。短鬢經霜蓬，老面辭春木。", "強年過猶近，衰相來何速。應是煩惱多，心焦血不足。", "漸少不滿把，漸短不盈尺。況茲短少中，日夜落複白。", "既無神仙術，何除老死籍。只有解脫門，能度衰苦厄。", "掩鏡望東寺，降心謝禪客。衰白何足言，剃落猶不惜。"]'),
('yuding-60','早蟬','白居易','唐','御定全唐诗','yuding','','[]','月出先照山，風生先動水。亦如早蟬聲，先入閒人耳。',60,'御定全唐詩/json/433.json','["月出先照山，風生先動水。亦如早蟬聲，先入閒人耳。", "一聞愁意結，再聽鄉心起。渭上新蟬聲，先聽渾相似。", "衡門有誰聽，日暮槐花裏。"]'),
('yuding-61','苦熱喜涼','白居易','唐','御定全唐诗','yuding','','[]','經時苦炎暑，心體但煩倦。白日一何長，清秋不可見。',96,'御定全唐詩/json/433.json','["經時苦炎暑，心體但煩倦。白日一何長，清秋不可見。", "歲功成者去，天數極則變。潛知寒燠間，遷次如乘傳。", "火雲忽朝斂，金風俄夕扇。枕簟遂清涼，筋骸稍輕健。", "因思望月侶，好蔔迎秋宴。竟夜無客來，引杯還自勸。"]'),
('yuding-62','早秋晚望，兼呈韋侍郎','白居易','唐','御定全唐诗','yuding','','[]','九派繞孤城，城高生遠思。人煙半在船，野水多於地。',96,'御定全唐詩/json/433.json','["九派繞孤城，城高生遠思。人煙半在船，野水多於地。", "穿霞日腳直，驅雁風頭利。去國來幾時，江上秋三至。", "夫君亦淪落，此地同飄寄。憫默向隅心，摧頹觸籠翅。", "且謀眼前計，莫問胸中事。潯陽酒甚濃，相勸時時醉。"]'),
('yuding-63','司馬宅','白居易','唐','御定全唐诗','yuding','','[]','雨徑綠蕪合，霜園紅葉多。蕭條司馬宅，門巷無人過。',36,'御定全唐詩/json/433.json','["雨徑綠蕪合，霜園紅葉多。蕭條司馬宅，門巷無人過。", "唯對大江水，秋風朝夕波。"]'),
('yuding-64','司馬廳獨宿','白居易','唐','御定全唐诗','yuding','','[]','荒涼滿庭草，偃亞侵簷竹。府吏下廳簾，家僮開被襆。',48,'御定全唐詩/json/433.json','["荒涼滿庭草，偃亞侵簷竹。府吏下廳簾，家僮開被襆。", "數聲城上漏，一點窗間燭。官曹冷似冰，誰肯來同宿。"]'),
('yuding-65','夢與李七、庾三十三同訪元九','白居易','唐','御定全唐诗','yuding','','[]','夜夢歸長安，見我故親友。損之在我左，順之在我右。',144,'御定全唐詩/json/433.json','["夜夢歸長安，見我故親友。損之在我左，順之在我右。", "雲是二月天，春風出攜手。同過靖安裏，下馬尋元九。", "元九正獨坐，見我笑開口。還指西院花，仍開北亭酒。", "如言各有故，似惜歡難久。神合俄頃間，神離欠伸後。", "覺來疑在側，求索無所有。殘燈影閃牆，斜月光穿牖。", "天明西北望，萬里君知否。老去無見期，踟躕搔白首。"]'),
('yuding-66','秋槿','白居易','唐','御定全唐诗','yuding','','[]','風露颯已冷，天色亦黃昏。中庭有槿花，榮落同一晨。',96,'御定全唐詩/json/433.json','["風露颯已冷，天色亦黃昏。中庭有槿花，榮落同一晨。", "秋開已寂寞，夕隕何紛紛。正憐少顏色，複歎不逡巡。", "感此因念彼，懷哉聊一陳。男兒老富貴，女子晚婚姻。", "頭白始得志，色衰方事人。後時不獲已，安得如青春。"]'),
('yuding-67','答元郎中、楊員外喜烏見寄','白居易','唐','御定全唐诗','yuding','','[]','南宮鴛鴦地，何忽烏來止。故人錦帳郎，聞烏笑相視。',44,'御定全唐詩/json/433.json','["南宮鴛鴦地，何忽烏來止。故人錦帳郎，聞烏笑相視。", "疑烏報消息，望我歸鄉里。我歸應待烏頭白，"]'),
('yuding-0','初入峽有感','白居易','唐','御定全唐诗','yuding','','[]','上有萬仞山，下有千丈水。蒼蒼兩岸間，闊狹容一葦。',145,'御定全唐詩/json/434.json','["上有萬仞山，下有千丈水。蒼蒼兩岸間，闊狹容一葦。", "瞿唐呀直瀉，灩澦屹中峙。未夜黑岩昏，無風白浪起。", "大石如刀劍，小石如牙齒。一步不可行，況千三百里。", "苒箬竹蔑zB，欹危楫師趾。一跌無完舟，吾生系於此。", "常聞仗忠信，蠻貊可行矣。自古漂沉人，豈盡非君子。", "況吾時與命，蹇舛不足恃。常恐不才身，複作無名死。"]'),
('yuding-1','過昭君村','白居易','唐','御定全唐诗','yuding','','[]','靈珠產無種，彩雲出無根。亦如彼姝子，生此遐陋村。',156,'御定全唐詩/json/434.json','["靈珠產無種，彩雲出無根。亦如彼姝子，生此遐陋村。", "至麗物難掩，遽選入君門。獨美眾所嫉，終棄出塞垣。", "唯此希代色，豈無一顧恩。事排勢須去，不得由至尊。", "白黑既可變，丹青何足論。竟埋代北骨，不返巴東魂。", "慘澹晚雲水，依稀舊鄉園。妍姿化已久，但有村名存。", "村中有遺老，指點為我言。不取往者戒，恐貽來者冤。", "至今村女面，燒灼成瘢痕。"]'),
('yuding-2','自江州至忠州','白居易','唐','御定全唐诗','yuding','','[]','前在潯陽日，已歎賓朋寡。忽忽抱憂懷，出門無處寫。',72,'御定全唐詩/json/434.json','["前在潯陽日，已歎賓朋寡。忽忽抱憂懷，出門無處寫。", "今來轉深僻，窮峽巔山下。五月斷行舟，灩堆正如馬。", "巴人類猿狖，矍鑠滿山野。敢望見交親，喜逢似人者。"]'),
('yuding-3','初到忠州登東樓，寄萬州楊八使君','白居易','唐','御定全唐诗','yuding','','[]','山束邑居窄，峽牽氣候偏。林巒少平地，霧雨多陰天。',144,'御定全唐詩/json/434.json','["山束邑居窄，峽牽氣候偏。林巒少平地，霧雨多陰天。", "隱隱煮鹽火，漠漠燒畬煙。賴此東樓夕，風月時翛然。", "憑軒望所思，目斷心涓涓。背春有去雁，上水無來船。", "我懷巴東守，本是關西賢。平生已不淺，流落重相憐。", "水梗漂萬里，籠禽囚五年。新恩同雨露，遠郡鄰山川。", "書信雖往復，封疆徒接連。其如美人面，欲見杳無緣。"]'),
('yuding-4','郡中','白居易','唐','御定全唐诗','yuding','','[]','鄉路音信斷，山城日月遲。欲知州近遠，階前摘荔枝。',24,'御定全唐詩/json/434.json','["鄉路音信斷，山城日月遲。欲知州近遠，階前摘荔枝。"]'),
('yuding-5','西樓夜','白居易','唐','御定全唐诗','yuding','','[]','悄悄複悄悄，城隅隱林杪。山郭燈火稀，峽天星漢少。',48,'御定全唐詩/json/434.json','["悄悄複悄悄，城隅隱林杪。山郭燈火稀，峽天星漢少。", "年光東流水，生計南枝鳥。月沒江沉沉，西樓殊未曉。"]'),
('yuding-6','東樓曉','白居易','唐','御定全唐诗','yuding','','[]','脈脈複脈脈，東樓無宿客。城暗雲霧多，峽深田地窄。',48,'御定全唐詩/json/434.json','["脈脈複脈脈，東樓無宿客。城暗雲霧多，峽深田地窄。", "宵燈尚留焰，晨禽初展翮。欲知山高低，不見東方白。"]'),
('yuding-7','寄王質夫','白居易','唐','御定全唐诗','yuding','','[]','憶始識君時，愛君世緣薄。我亦吏王畿，不為名利著。',192,'御定全唐詩/json/434.json','["憶始識君時，愛君世緣薄。我亦吏王畿，不為名利著。", "春尋仙遊洞，秋上雲居閣。樓觀水潺潺，龍潭花漠漠。", "吟詩石上坐，引酒泉邊酌。因話出處心，心期老岩壑。", "忽從風雨別，遂被簪纓縛。君作出山雲，我為入籠鶴。", "籠深鶴殘悴，山遠雲飄泊。去處雖不同，同負平生約。", "今來各何在，老去隨所托。我守巴南城，君佐征西幕。", "年顏漸衰颯，生計仍蕭索。方含去國愁，且羨從軍樂。", "舊遊疑是夢，往事思如昨。相憶春又深，故山花正落。"]');
